-- Poems batch 62
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c50c667a-756b-48f2-841e-05800c651b1f','放達詩','賀知章','唐','唐诗','tang','','[]','落花真好些，一醉一回顛。',45,'全唐诗/poet.tang.52000.json','["落花真好些，一醉一回顛。", "（《詩式》卷一）（按：《全唐詩》卷一一二錄句，缺題，今補錄之。", "）。"]'),
('53092264-3d37-4ead-8da6-5f9c11e85881','送賀秘監歸會稽詩','韋堅','唐','唐诗','tang','','[]','解印辭榮祿，遊真奉德音。',61,'全唐诗/poet.tang.52000.json','["解印辭榮祿，遊真奉德音。", "贈行天藻下，餞席上台臨。", "遠馭仙山鶴，常懷帝里心。", "無因同執袂，相望但霑襟。", "（《會稽掇英總集》卷二）。"]'),
('a50093d0-64db-4de9-8404-6cd3cce55ea0','送賀秘監歸會稽詩','李適之','唐','唐诗','tang','','[]','聖代全高尚，玄風闡道微。',111,'全唐诗/poet.tang.52000.json','["聖代全高尚，玄風闡道微。", "筵開百僚（《廣卓異記》作「壺」）餞，詔許二疏歸。", "仙記題金籙，朝章換（《廣卓異記》作「披」）羽衣。", "悄然承睿藻，行路滿光輝。", "（同前。", "以樂史《廣卓異記》卷三所錄相校。", "《廣卓異記》原署「左丞相李適之。", "」）。"]'),
('f65059a5-439a-46ab-92b5-ab3794de607f','遊法華寺','李邕','唐','唐诗','tang','','[]','山勢轉深看更好，嶺霞谿霧沒樓臺。',78,'全唐诗/poet.tang.52000.json','["山勢轉深看更好，嶺霞谿霧沒樓臺。", "異時花向陰崖發，遠處泉從青壁來。", "世界自知千古促，賢愚悉被四時催。", "須知此地堪終老，七竅終成一片灰。", "（見《會稽掇英總集》卷八）。"]'),
('b84470a6-7fb0-46b1-9fc8-3dd514123018','日賦附歌','李邕','唐','唐诗','tang','','[]','披雲覩日兮日則明，就日瞻雲兮心若驚。',46,'全唐诗/poet.tang.52000.json','["披雲覩日兮日則明，就日瞻雲兮心若驚。", "日爾一日兮何道，時哉幾時兮此生。", "（見《文苑英華》卷二）。"]'),
('50d68cca-ace6-4d1a-9491-5566e56f6666','題滑州公府大廳樑上（題擬）','李邕','唐','唐诗','tang','','["\u9ec4\u6cb3"]','大廈中構，山屹雲斗。',91,'全唐诗/poet.tang.52000.json','["大廈中構，山屹雲斗。", "黃河畎澮，太行培塿。", "整庶宣風，緝戎備寇。", "鎮寧一方，光輔元后。", "（見民國二十一年鉛印本王蒲園等纂《重修滑縣志》卷十二《金石》錄宋趙世長《天禧二年滑州公府大廳記》引）。"]'),
('936eb2bc-af1a-4424-b196-6aa6f3063871','秋夜泊江[渚]（諸） 一','李邕','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','夜聞木葉落，疑是洞庭秋。',55,'全唐诗/poet.tang.52000.json','["夜聞木葉落，疑是洞庭秋。", "中宵起□望，正見滄江流。", "□風□□□，山月隱城樓。", "[潯]（尋）陽幾萬里，朝夕泛孤[舟]。"]'),
('fddc401c-fe41-4216-90bf-c3be067e12fd','秋夜泊江[渚]（諸） 二','李邕','唐','唐诗','tang','','[]','我有方寸心，安在六尺軀。',74,'全唐诗/poet.tang.52000.json','["我有方寸心，安在六尺軀。", "懷山復懷□，□□□□□。", "水能澄不渾，劍用持復酬。", "珠已含報恩，□□□□□。", "□□貧與富，但願一相知。", "（以上二首見伯三六一九卷）。"]'),
('6b49c6c4-1a99-44e2-af1c-5f549323857b','送賀秘監歸會稽詩','李瓘','唐','唐诗','tang','','[]','官著朝中貴，才傳海上名。',71,'全唐诗/poet.tang.52000.json','["官著朝中貴，才傳海上名。", "早年常好道，晚歲更遺榮。", "授籙歸三洞，還車謁四明。", "東門詔送日，揮涕盡羣英。", "（見《會稽掇英總集》卷二。", "原署「嗣許王瓘」）。"]'),
('b511ca4a-001d-416c-8145-31d954bee562','送賀秘監歸會稽詩','杜昆吾','唐','唐诗','tang','','[]','辰象降星精，登朝隱吏幷。',77,'全唐诗/poet.tang.52000.json','["辰象降星精，登朝隱吏幷。", "求珠謝軒冕，放舄指蓬瀛。", "擲地文章逸，匡儲羽翼成。", "江邊丹障起，雲外綠輿迎。", "落落神仙意，悽悽離別情。", "聖恩殊未已，何獨厭承明？", "（同前）。"]'),
('aaa47497-b27a-44a0-8b24-f95276afafc0','奉答燕公 一','王琚','唐','唐诗','tang','','[]','誰道零陵守，東過此地遊。',72,'全唐诗/poet.tang.52000.json','["誰道零陵守，東過此地遊。", "友僚同省閣，昆弟接荆州。", "我逐江潭雁，君隨海上鷗。", "屢傷神氣阻，久別鬢毛秋。", "疑嶺春應徧，陽臺兩欲收。", "主人情未盡，高駕少淹留。"]'),
('eb26ad54-4731-480b-b35f-bb63e57cb3c3','奉答燕公 二','王琚','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','語別意淒淒，零陵湘水西。',355,'全唐诗/poet.tang.52000.json','["語別意淒淒，零陵湘水西。", "佳人金谷返，愛（一作「遊」）子洞庭迷。", "舊館逢花發，他山值鳥啼。", "江天千里望，誰見綠蘋齊？", "（均見《結一廬叢書》本《張說之文集》卷七）（按：結一廬本此二詩下署「王琚」。", "《四部叢刊》影印龍池草堂刊本《張說之集》收張說《贈趙公》後，無署名。", "《全唐詩》卷九八均收趙冬曦名下，實誤。", "趙公爲王琚之封爵，岑仲勉先生《唐集質疑·趙公》已有考證，可參看。", "友人陳祖言撰《張說年譜》云：「前一首第三句『友寮同省閣』，琚先天元年八月擢拜中書侍郎，說二年七月爲中書令，即爲『同省閣』。", "……而冬曦無此經歷。", "兩首詩俱言及零陵守，冬曦亦無此經歷。", "又前首五、六句『我逐江潭雁，君隨海上鷗』，冬曦爲從六品下之侍御史，階卑辭謙，在其地唱酬詩中均無此等平起平坐之語。", "且說離岳赴荆，冬曦送之，說則未嘗送冬曦也，故知必非冬曦詩。", "」）。"]'),
('e863cef2-760e-474f-8d62-13a5b83a58ae','蒲津迎駕','席豫','唐','唐诗','tang','','[]','回鸞下蒲坂，飛旆指秦京。',110,'全唐诗/poet.tang.52000.json','["回鸞下蒲坂，飛旆指秦京。", "雕上黃雲送，關中紫氣迎。", "霞朝看馬色，月曉聽雞鳴。", "防拒連山險，長橋壓水平。", "省方知化洽，察俗覺時清。", "天下長無事，空餘襟帶名。", "（見唐芮挺章編《國秀集》卷上）（按：《全唐詩》卷六四誤作宋鼎作，今移正。", "）。"]'),
('ef9f8558-6d33-4e3a-bd8a-9a416a4e0db8','送賀秘監歸會稽詩','席豫','唐','唐诗','tang','','[]','南山四皓德，東海二疏名。',91,'全唐诗/poet.tang.52000.json','["南山四皓德，東海二疏名。", "功遂知身退，心微覺道成。", "霓裳明主賜，鶴駕列仙迎。", "詔餞出中野，朋歡留上京。", "灞橋春水溢，稽嶺白雲生。", "此去三千里，那堪長別情。", "（見宋孔延之編《會稽掇英總集》卷二）。"]'),
('cb61a8ff-aa1a-44fa-9e95-a07641acf268','送賀秘監歸會稽詩','何千里','唐','唐诗','tang','','[]','錫鼎昇天幾萬春，裔孫今復出囂塵。',69,'全唐诗/poet.tang.52000.json','["錫鼎昇天幾萬春，裔孫今復出囂塵。", "姓名當繫上清籙，齒髮不知何代人？", "暫應客星過世主，旋歸吳市作遺民。", "遼東鶴駕忽飛去，揮手無言辭紫宸。", "（同前）。"]'),
('ea8cafaa-5482-4511-8aea-5a836c77905d','擬採桑曲','吳兢','唐','唐诗','tang','','[]','羅敷十五六，採桑城南道。',37,'全唐诗/poet.tang.52000.json','["羅敷十五六，採桑城南道。", "（見宋陳元龍《片玉集注》卷十《早梅芳》之二注引）。"]'),
('1d4722a6-9d57-4e5d-b14b-4ea13dea81c4','送賀秘監歸會稽詩','李巖','唐','唐诗','tang','','[]','遠節忘榮趣，全真悟道微。',62,'全唐诗/poet.tang.52000.json','["遠節忘榮趣，全真悟道微。", "登朝四皓客，辭老二疏歸。", "聖主欽玄德，台臣餞羽衣。", "丹丘不可接，鳧舄幾時飛。", "（見《會稽掇英總集》卷二）。"]'),
('74bb4527-a0da-4b1a-b3d9-d901c2fd492d','送賀秘監歸會稽詩','郭虛己','唐','唐诗','tang','','[]','白首輕軒冕，黃冠重隱淪。',53,'全唐诗/poet.tang.52000.json','["白首輕軒冕，黃冠重隱淪。", "嚴陵垂釣日，疏廣散金辰。", "北闕辭明主，東門別故人。", "以茲敦雅俗，玄化盡歸真。", "（同前）。"]'),
('27eaef9d-9e2d-4790-8855-b0b833af5667','送賀秘監歸會稽詩','李璆','唐','唐诗','tang','','[]','止足人高尚，遺榮子獨前。',63,'全唐诗/poet.tang.52000.json','["止足人高尚，遺榮子獨前。", "詣臺飛舄日，辭闕挂冠年。", "象服歸丹扆，霓裳降紫天。", "仙舟望不及，朝野共推賢。", "（同前。", "原署「褒信郡王璆」）。"]'),
('169b327f-bfe4-4e19-a882-1feb7e652e4e','中書壁畫山水','李林甫','唐','唐诗','tang','','[]','八載忝司存。',36,'全唐诗/poet.tang.52000.json','["八載忝司存。", "（見《全唐詩》卷一一八孫逖《奉和李右相中書壁畫山水》注引）。"]'),
('6bac1e5b-823d-48d5-9537-3e2d4881a836','送賀秘監歸會稽詩','康珽','唐','唐诗','tang','','[]','解綬申知足，歸元道益真。',162,'全唐诗/poet.tang.52000.json','["解綬申知足，歸元道益真。", "離章垂睿作，祖帳別羣臣。", "紫禁辭明主，青溪訪羽人。", "賞延忠孝著，榮耀故鄉春。", "（見宋孔延之《會稽掇英總集》卷二）（按：《會稽掇英總集》此詩作者作「康璡」。", "今檢《御史臺精舍題名》及《金石錄》卷七錄《唐康珽告》、《寶刻叢編》錄《復齋碑錄》收《大理少卿康公夫人河間郡君許氏墓志》諸石刻，皆作「康珽」，故從之。", "）。"]'),
('ea031ad2-ef23-484e-a974-0b26db7927cb','和黃三安仁山莊五首 一','崔顥','唐','唐诗','tang','','[]','春到郭園靜，冰開水木清。',48,'全唐诗/poet.tang.52000.json','["春到郭園靜，冰開水木清。", "俄聞北山客，虛淡遲聲榮。", "不獨閑爲貴，兼將山自名。", "古人情亦爾，君識古人情。"]'),
('a5e6f409-5e93-42b8-8df1-3a9e2256d0e5','和黃三安仁山莊五首 二','崔顥','唐','唐诗','tang','','[]','結宇因青嶂，開門對綠疇。',48,'全唐诗/poet.tang.52000.json','["結宇因青嶂，開門對綠疇。", "樹交花相色，谿合水同流。", "竹逕春來掃，蘭罇暝不收。", "無心亦無事，鼓腹醉中遊。"]'),
('01b5b997-464f-4fb7-b286-c8effd3ce2df','和黃三安仁山莊五首 三','崔顥','唐','唐诗','tang','','[]','車馬東城路，尋君至北山。',48,'全唐诗/poet.tang.52000.json','["車馬東城路，尋君至北山。", "爲從人境出，彌覺世情閑。", "月在清潭上，風歸暗篠間。", "此時心最得，長嘯不能還。"]'),
('2a4015fd-6761-457a-837d-f7582a11030f','和黃三安仁山莊五首 四','崔顥','唐','唐诗','tang','','[]','耕種春須了，幽人晚到家。',51,'全唐诗/poet.tang.52000.json','["耕種春須了，幽人晚到家。", "琴中來遠吹，竹裏映殘霞。", "谷鳥牽垂葉，池魚洩（疑）水花。", "朝留半樽酒，細酌倚山槎。"]'),
('a0bae716-6de5-446c-ac70-5645ec90d8c8','和黃三安仁山莊五首 五','崔顥','唐','唐诗','tang','','[]','幽客嵒（疑）中坐，農人野外居。',150,'全唐诗/poet.tang.52000.json','["幽客嵒（疑）中坐，農人野外居。", "報來禾近種，城去麥堪鋤。", "夏色歸舟壑，春光逐碧虛。", "君開山海記，共我摘園蔬。", "（日本藏唐抄本《新撰類林抄》卷四）（按：《國秀集》卷中、《文苑英華》卷三一八、《全唐詩》卷二五八收第二首爲蔣洌詩，《全唐詩》卷二○○又誤作岑參詩，均題作《南溪別業》，文字稍異。", "今仍重收，俟考詳。", "）。"]'),
('227de91e-5481-4e38-b89e-ba9912ebc553','西亭即事','李頎','唐','唐诗','tang','','[]','桃李皆開盡，芳菲漸覺闌。',51,'全唐诗/poet.tang.52000.json','["桃李皆開盡，芳菲漸覺闌。", "鳥聲愁暮雨，花色寂（疑）春寒。", "倚石攀藤蔓，窺林數竹竿。", "葛巾常半著，何處似當閒。"]'),
('2227a83e-3477-43ab-afb2-81b93bf34eea','陳十六東亭','李頎','唐','唐诗','tang','','[]','餘春伴蝴蝶，把酒聽黃鸝。',54,'全唐诗/poet.tang.52000.json','["餘春伴蝴蝶，把酒聽黃鸝。", "最是淹留處，殘花三兩枝。", "（同前。", "以上二首據日本大阪市立美術館編《唐抄本》影印本校）。"]'),
('23c62c87-4447-4361-86af-35def3a0977b','送李大貶南陽','李頎','唐','唐诗','tang','','[]','鴻聲斷續暮天遠，柳影蕭疎秋日寒。',35,'全唐诗/poet.tang.52000.json','["鴻聲斷續暮天遠，柳影蕭疎秋日寒。", "（《千載佳句》卷上《四時部·暮秋》）。"]'),
('e4310d61-fdea-4c34-ad3f-06579a2088d4','裴將軍劍舞賦附歌','喬潭','唐','唐诗','tang','','[]','洸洸武臣，耀雄劍兮清邊塵。',62,'全唐诗/poet.tang.52000.json','["洸洸武臣，耀雄劍兮清邊塵。", "威戎夷兮率土來賓（一作「威遠夷兮率來賓」），焉用輕裙之妓女，長袖之才人。", "（見《文苑英華》卷八二）。"]'),
('7d82ae4f-6b54-481d-bb56-ae07e7393581','羣玉山賦附歌','喬潭','唐','唐诗','tang','','[]','彼天子兮塵外鑣，登靈臺兮意飄飄。',43,'全唐诗/poet.tang.52000.json','["彼天子兮塵外鑣，登靈臺兮意飄飄。", "吾君得道兮異於是，不自求兮自逍遙。", "（同前書卷二十九）。"]'),
('92cb2dfb-967d-4c7c-90ce-b8c4f33d8365','秋晴曲江望太一納歸雲賦附歌','喬潭','唐','唐诗','tang','','[]','節彼南山兮人所瞻，施此雲雨兮濟君欲。',18,'全唐诗/poet.tang.52000.json','["節彼南山兮人所瞻，施此雲雨兮濟君欲。"]'),
('c69448fb-a767-492e-bc65-222dd521375d','同前賦附歸雲之曲','喬潭','唐','唐诗','tang','','[]','歸雲之狀兮不一，歸雲之趣兮難儔。',63,'全唐诗/poet.tang.52000.json','["歸雲之狀兮不一，歸雲之趣兮難儔。", "雲不以朝脯而異賞，士不以前後而異求。", "誠在位之如是，知夫鴻漸之高秋。", "（均見《文苑英華》卷十一）。"]'),
('0c926ec1-eb1b-43fd-be15-9941585e1061','河陽店家女（僅存六句）','李康成','唐','唐诗','tang','','[]','因緣苟合會（《適園叢書》本及《文獻通考·經籍考》皆作「會合」），萬里猶同鄉。',358,'全唐诗/poet.tang.52000.json','["因緣苟合會（《適園叢書》本及《文獻通考·經籍考》皆作「會合」），萬里猶同鄉。", "運命倘不諧，隔壁無津梁。", "傳語王家子，何爲不自量？", "（見宋劉克莊《後邨先生大全集》卷一七七《詩話續集》引康成輯《玉臺後集》）（〖1〗劉克莊云：《玉臺後集》「中間自載其詩八首，……如《河陽店家女》長篇一首，押五十二韻，若欲與《木蘭》及『孔雀東南飛』之作方駕者。", "末云：『因緣……津梁。", "』亦佳。", "但木蘭始代父征伐，終潔身來歸；仲卿妻死不事二夫，二篇庶幾發乎情性，止乎禮義。", "店家女則異是。", "王嫗兒雖蓬頭歷齒，母許婿之矣，女慕鄭家郎裘馬之盛，背母而奔之，康成卒章都無譏貶，反云：『傳語王家子，何爲不自量？", "』豈詩人之義哉！」按：《文獻通考·經籍考》摘錄後村語，僅至「亦佳」止，《全唐詩》卷二百三據以收入，缺末二句，本事亦未詳。", "今具錄之，以供治盛唐詩者參詳。", "）。"]'),
('7b5bd444-56eb-40e0-81cb-a9cfe7d270ee','自詠','范液','唐','唐诗','tang','','[]','長吟太息問皇天，神通由來也已偏。',257,'全唐诗/poet.tang.52000.json','["長吟太息問皇天，神通由來也已偏。", "一名國士皆貧病，但是裨兵總有錢。", "（見唐封演《封氏聞見記》卷十）（《封氏聞見記》云：「范液有口才，薄命，所向不偶。", "曾爲詩曰：『舉意三江竭，興心四海枯。", "南遊李邕死，北望守珪殂。", "』液欲投謁二公，皆會其淪歿，故云。", "然宗叔范純家富于財，液每有所求，純常給與之非一。", "純曾謂液曰：『君有才而困于貧，今可試自詠。", "』液命紙筆立操而竟。", "其詩曰〖詩略〗。", "純大笑曰：『教君自詠，何駡我乎？", "』不以爲過。", "」按：前一詩《全唐詩》已收入，「守珪」誤作「宋珪」，守珪指張守珪，與李邕皆天寶間卒，因知液爲天寶間人。", "）。"]'),
('1a062dc0-c36c-4580-9bd9-83cdedd11e2b','鳳凰之歌','李解','唐','唐诗','tang','','[]','處分明兮繫舒慘，一人慶兮萬物感。',52,'全唐诗/poet.tang.52000.json','["處分明兮繫舒慘，一人慶兮萬物感。", "羽族猶得以效珍，微生何久於習坎。", "（見《文苑英華》卷八四《鳳凰儀賦》附）。"]'),
('87b7a780-5349-4c95-946b-6d0c9ff62ec4','古意','蔣冽','唐','唐诗','tang','','[]','昨夜巫山中，失却陽臺女。',79,'全唐诗/poet.tang.52000.json','["昨夜巫山中，失却陽臺女。", "今朝粧閣裏，獨伴楚王語。", "（見《文苑英華》卷二百五）（按：《才調集》卷十收此詩爲蔣藴作，《全唐詩》卷七九九收入。", "未詳孰是，今兩存之。", "）。"]'),
('30b1d604-38b9-48e6-831c-5de093e84f10','觀會稽圖','褚朝陽','唐','唐诗','tang','','[]','良使求圖籍，工人巧思饒。',66,'全唐诗/poet.tang.52000.json','["良使求圖籍，工人巧思饒。", "全移會稽郡，不散浙江潮。", "夏禹猶卑室，秦皇尚斷橋。", "宛然山水趣，誰道故鄉遙。", "（見孔延之《會稽掇英總集》卷十五）。"]'),
('c7a9fb47-2b59-4cc4-8067-0fd433e79b87','渡浙江問舟中人（存目）（按：以上三首，《四部叢刊》影印本殷璠《河嶽英靈集》卷中作崔國輔詩。同書附孫毓修校記引毛斧季、何義門校本。爲二卷本，較近殷氏原本，卷下亦以諸詩屬崔。然《全唐詩》卷一六○均收作孟浩然詩。孟詩初由王士源輯集，宋以後流傳漸紊。另《國秀集》卷中收《渡浙江》爲孟作。此三詩究爲誰作，尚俟考詳。因其出處甚早，姑存目。）','崔國輔','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.52000.json','["空。"]'),
('2e3d60e4-f83a-4f3e-b765-2f3632d94bd0','','齊光乂','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.52000.json','["。"]'),
('e872a020-4b6a-44d5-8bc4-2a58f3726cb2','送賀秘監歸會稽詩','齊光乂','唐','唐诗','tang','','[]','晚歲朝真隱，皇情諒不違。',62,'全唐诗/poet.tang.52000.json','["晚歲朝真隱，皇情諒不違。", "辭家五十載，今日復東歸。", "祖帳臨青道，天章降紫微。", "顧嗟軒冕者，誰與比光輝？", "（見《會稽掇英總集》卷二）。"]'),
('fc7cbbc0-0925-4a45-9c83-1c44e24059a7','讖句','李遐周','唐','唐诗','tang','','[]','木易若逢山下鬼，定知此處喪金環。',42,'全唐诗/poet.tang.52000.json','["木易若逢山下鬼，定知此處喪金環。", "（見《新編分門古今類事》卷十四引《青瑣高議》佚文）。"]'),
('1cff9176-9a38-40b7-8e3e-02420a3402b9','句','蔡希寂','唐','唐诗','tang','','[]','象筵列虛白，幽偈清心胸。',44,'全唐诗/poet.tang.52000.json','["象筵列虛白，幽偈清心胸。", "（見《吟窗雜錄》卷二六《歷代吟譜》，又見吳琯《盛唐詩紀》卷三）。"]'),
('d01a4fb9-9fef-473e-b104-8142f91b9d24','句','祖詠','唐','唐诗','tang','','[]','搘頤笑來客，頭上有朝簪。',21,'全唐诗/poet.tang.52000.json','["搘頤笑來客，頭上有朝簪。", "（《詩式》卷四）。"]'),
('70a22351-21d4-4dc4-9d33-1f07d21fd9b5','句','楊貴妃','唐','唐诗','tang','','[]','迎娘歌喉玉䆗窱，蠻兒舞帶金葳蕤。',78,'全唐诗/poet.tang.52000.json','["迎娘歌喉玉䆗窱，蠻兒舞帶金葳蕤。", "（《斷腸詩集前集》卷六《會魏夫人席上……》鄭元佐注引《羣玉雜俎》引《楊妃外傳》引。", "今本《楊妃外傳》無此二句。", "詩當出依託。", "）。"]'),
('6979ac9c-0a26-4aeb-aa2c-39375e234a0f','泰階六符賦附歌','婁玄穎','唐','唐诗','tang','','[]','君臣穆兮純化清，玉衡正兮泰階平。',42,'全唐诗/poet.tang.52000.json','["君臣穆兮純化清，玉衡正兮泰階平。", "嘉曆數兮無極，配乾坤兮永貞。", "（見《文苑英華》卷九）。"]'),
('76812e8b-fd7f-4bea-a6fb-71ba20f1e24b','掌上蓮峰賦附歌','呂令問','唐','唐诗','tang','','[]','苔至滑兮石無蹤，道不可得，仙不可逢。',46,'全唐诗/poet.tang.52000.json','["苔至滑兮石無蹤，道不可得，仙不可逢。", "儻賜一丸生羽翼，願輕舉於三峰。", "（見《文苑英華》卷二八）。"]'),
('d2056ef6-45e2-4fe3-929f-c4057c45f922','駕幸天安宮賦附邑老田父歌','呂令問','唐','唐诗','tang','','[]','歲既稔而時清，我后來兮應天行。',72,'全唐诗/poet.tang.52000.json','["歲既稔而時清，我后來兮應天行。", "東都士庶扶輪送，西土諸侯掃地迎。", "君之德兮德無有，路旁勞賚皆牛酒。", "乘輿一至長安城，千秋萬歲南山壽。", "（見前書卷五八）。"]'),
('b0b474a1-be11-434a-b662-7ef8fdd366ef','新安江林（存目）（按：見《才調集》卷七。《全唐詩》卷二八一收作章八元詩。）','陶翰','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.52000.json','["空。"]'),
('c63f6891-3915-42a7-bb29-601934063956','弔軹道賦附邵平歌','王昌齡','唐','唐诗','tang','','[]','道不虛行兮，史鰌沒位，吾寧范伯之徒歟，感夷齊而多愧。',97,'全唐诗/poet.tang.52000.json','["道不虛行兮，史鰌沒位，吾寧范伯之徒歟，感夷齊而多愧。", "麟鳳遠去，龍則死之，河水洋洋兮，先師莫歸。", "往者不可諫，來者吾誰欺？", "始退身以進道，曷颺言而受非，彼蕭相國知予乎布衣。", "（見《文苑英華》卷一三○）。"]'),
('0cf5203f-6507-4e43-a049-c98d17a2948e','雲山清曉','王昌齡','唐','唐诗','tang','','[]','蒼深翠淺瀑崢潺，豈謂譏秦始愛山。',62,'全唐诗/poet.tang.52000.json','["蒼深翠淺瀑崢潺，豈謂譏秦始愛山。", "一炬咸陽機冢赤，紫霄巍立曉雲間。", "（見《古今圖書集成·山川典》卷一七三。", "此首當出後人依託。", "）。"]'),
('796a2ab8-be28-4d0b-b74c-d349300b179e','四時調玉燭','王昌齡','唐','唐诗','tang','','[]','祥光長赫矣，佳號得溫其。',28,'全唐诗/poet.tang.52000.json','["祥光長赫矣，佳號得溫其。", "（見宋葛立方《韻語陽秋》卷三）。"]'),
('d99f944a-aa0c-43f1-9244-c5ee79ae88d1','梅詩','王昌齡','唐','唐诗','tang','','[]','落落寞寞路不分，夢中喚作梨花雲。',181,'全唐诗/poet.tang.52000.json','["落落寞寞路不分，夢中喚作梨花雲。", "（見《苕溪漁隱叢話前集》卷四、《野客叢書》卷六引曾慥《高齋詩話》、龍榆生《東坡樂府箋》卷二《西江月》注引南宋傅藻注引。", "）（按：《墨莊漫錄》卷六載此詩全篇，以爲王建作，詳本書卷十八。", "然曾慥時代較早，當有所據。", "蘇軾《西江月》詞末句云：「不與梨花同夢。", "」自跋云：「詩人王昌齡夢中作梅花詩。", "」傅注因引此二句。", "其時代較曾慥更早。", "今互收。", "）。"]'),
('3b7cd64c-505e-4196-b98c-403d25e8928e','送別','王昌齡','唐','唐诗','tang','','[]','河口餞南客，進帆清江水。',12,'全唐诗/poet.tang.52000.json','["河口餞南客，進帆清江水。"]'),
('21792ec1-f78b-47ef-8b64-90f606512c2b','送友人之安南','王昌齡','唐','唐诗','tang','','[]','還舟望炎海，楚葉下秋水。',63,'全唐诗/poet.tang.52000.json','["還舟望炎海，楚葉下秋水。", "（均見《文鏡秘府論》地卷《十七勢》引王昌齡《詩格》。", "市河世寧《全唐詩逸》卷上收四句，缺題，今重錄。", "）。"]'),
('ff945796-4ca6-410d-8458-243c9d483b07','句（附存）','王昌齡','唐','唐诗','tang','','[]','王維詩天子，杜甫詩宰相。',108,'全唐诗/poet.tang.52000.json','["王維詩天子，杜甫詩宰相。", "（見宋葉廷珪《海錄碎事》卷十九引《王昌齡集》。", "似出後人依托。", "）（按：《全唐詩》卷一四一收昌齡《小敷谷龍潭祠作》，第十九句缺一字。", "汲克閣本《唐詩紀事》卷二四引此詩不缺，此句作「奔飛振串梁」。", "）。"]'),
('884eaf68-4d11-47f6-a5fb-dc6a0ff07cee','送賀秘監歸會稽詩','韋斌','唐','唐诗','tang','','[]','抗情遺黼冕，高步出氛埃。',65,'全唐诗/poet.tang.52000.json','["抗情遺黼冕，高步出氛埃。", "橫海鴻飛遠，登仙鶴語催。", "希微餘第宅，怳惚視嬰孩。", "桃實三千歲，何當獻壽來？", "（見孔延之《會稽掇英總集》卷二）。"]'),
('1f59e92d-a11b-4d5f-9a27-002e3e5d09f0','送賀秘監歸會稽詩','韋述','唐','唐诗','tang','','[]','二疏方告老，四皓盡歸山。',65,'全唐诗/poet.tang.52000.json','["二疏方告老，四皓盡歸山。", "藹藹都門別，仍看衣錦還。", "霓裳標逸氣，丹竈理童顏。", "一遇真仙侶，羣心難可攀。", "（見孔延之《會稽掇英總集》卷二）。"]'),
('1190fc51-31ee-4dca-864f-1d9843ba0d39','破陣樂','哥舒翰','唐','唐诗','tang','','[]','西戎最沐恩深，犬羊違背生心。',87,'全唐诗/poet.tang.52000.json','["西戎最沐恩深，犬羊違背生心。", "神將驅兵出塞，橫行海畔生擒。", "石堡巖高萬丈，雕窠霞外千尋。", "一喝盡屬唐國，將知應合天心。", "（見伯三六一九卷。", "轉錄自任半塘先生《唐聲詩》下編第十附錄。", "）。"]'),
('c455f600-bb79-4b35-a67a-c27c24b08767','題鳳凰山','哥舒翰','唐','唐诗','tang','','[]','彩鳳雙飛翼，宛然半巖間。',25,'全唐诗/poet.tang.52000.json','["彩鳳雙飛翼，宛然半巖間。", "（《記纂淵海》卷二十五）。"]'),
('e732ba32-8920-44ea-aa75-ca62ea79d4d5','白金小還丹歌 一','羅公遠','唐','唐诗','tang','','[]','法藥變化，無非水精。',40,'全唐诗/poet.tang.52000.json','["法藥變化，無非水精。", "六芝潤色，黃芽自生。", "陽光不起，陰流無聲。", "道方秘易，學者難成。"]'),
('43c3ed62-21a8-4355-b505-9a2dd3a39122','白金小還丹歌 二','羅公遠','唐','唐诗','tang','','[]','既養黃男，先禁家鬼。',40,'全唐诗/poet.tang.52000.json','["既養黃男，先禁家鬼。", "盡死扶金，餘生制水。", "世人能明，並窮斯理。", "親奉聖言，事難自揣。"]'),
('a3e8e298-83a9-4ed0-8215-dde83f7c8638','白金小還丹歌 三','羅公遠','唐','唐诗','tang','','[]','籠虛其底，免被炎馳。',40,'全唐诗/poet.tang.52000.json','["籠虛其底，免被炎馳。", "知白守黑，清黃一支。", "能忌陰穢，不逾百時。", "延生大道，易解難知。"]'),
('3052c46b-6d0c-43ec-990b-81ba76f683ba','白金小還丹歌 四','羅公遠','唐','唐诗','tang','','[]','黃子淳淑，自娶玄妃。',40,'全唐诗/poet.tang.52000.json','["黃子淳淑，自娶玄妃。", "金成力厚，藥就身肥。", "土宅三分，火房二儀。", "至德消陰，純陽幽微。"]'),
('a676f35d-7fc4-470b-9286-3fc4ee83b305','白金小還丹歌 五','羅公遠','唐','唐诗','tang','','[]','一味白金，固人衰朽。',40,'全唐诗/poet.tang.52000.json','["一味白金，固人衰朽。", "雜性難防，同心易守。", "服食千粒，百日無咎。", "萬痾漸除，天地同壽。"]'),
('6f01130f-4f3c-40b2-a885-256c556b0d68','白金小還丹歌 六','羅公遠','唐','唐诗','tang','','[]','言依口訣，親貴手傳。',40,'全唐诗/poet.tang.52000.json','["言依口訣，親貴手傳。", "七日自伏，萬刻牢堅。", "千鍊萬煑，託在五賢。", "好藴金器，不絕玄關。"]'),
('03939ef9-c2cb-446f-8154-93e7a73a6cdf','白金小還丹歌 七','羅公遠','唐','唐诗','tang','','[]','赭塗四壁，丹守圓扉。',40,'全唐诗/poet.tang.52000.json','["赭塗四壁，丹守圓扉。", "一居火匱，二處灰池。", "五蟾可保，三烏無疑。", "道情未速，益日加奇。"]'),
('88cac6b4-a759-4076-a629-31138a51be1d','白金小還丹歌 八','羅公遠','唐','唐诗','tang','','[]','一黃二白，三銖兩作。',40,'全唐诗/poet.tang.52000.json','["一黃二白，三銖兩作。", "養至滿蟾，生其高鶴。", "事忌他非，道身自樂。", "傳受非人，天殃地虐。"]'),
('73b2cecd-5acd-4b59-9e21-3244f46a1892','白金小還丹歌 九','羅公遠','唐','唐诗','tang','','[]','芽屬黃男，藥屬玄女。',40,'全唐诗/poet.tang.52000.json','["芽屬黃男，藥屬玄女。", "外助無非，玉芝清醑。", "俗士多聞，道君少語。", "用物參差，虛受辛苦。"]'),
('9cb851a3-5b5e-447a-b79c-62ca25423cb0','白金小還丹歌 十','羅公遠','唐','唐诗','tang','','[]','銅鐵壞形，丹灰損力。',40,'全唐诗/poet.tang.52000.json','["銅鐵壞形，丹灰損力。", "欲驗其神，須存本色。", "一陰一陽，事易候則。", "異族同羣，自種荆棘。"]'),
('b0699bf0-8c81-45de-9d38-65d66e49f11f','白金小還丹歌 十一','羅公遠','唐','唐诗','tang','','[]','殺青龍，須白虎，自然感化無風雨。',311,'全唐诗/poet.tang.52000.json','["殺青龍，須白虎，自然感化無風雨。", "雪花飛，雪花飛，魂歸魄亦歸。", "聚散既由壬癸水，玉神華蓋體無爲。", "湧泉水，湧泉水，春夏秋冬深無底。", "要行天下時，厚暖自然制。", "（見《正統道藏》本元陽子輯《還丹歌訣》卷上。", "此書爲北宋前之著。", "）（按：此組詩原題作「青城羅真人上明皇《白金小還丹歌》」，詩前有小引云：「帝問真人曰：『道本無二，同歸乎一。", "藥有多功，身寧濟惠。", "願垂憫念，速救餘生。", "』真人曰：『身在和炁，藥同元滋，二道符機，衰朽自差，莫希大藥，日月難期。", "一味白金，延年益壽，仙人保秘，不妄虛傳，但能秘之，無輕泄爾。", "』凡一十二首。", "」似爲後人所加。", "《太平廣記》卷二二云公遠「因以《三峯歌》八首以進焉，其大旨乃玄素黃赤之使、還纓泝流之事」。", "今不存。", "）。"]'),
('b6b37b3d-774b-4e5b-b401-8e751db11bd2','大還丹口訣','羅公遠','唐','唐诗','tang','','[]','世人不知丹有神，試喫狼毒必害人。',378,'全唐诗/poet.tang.52000.json','["世人不知丹有神，試喫狼毒必害人。", "將知世上有善惡，何不將身近善鄰。", "女媧鍊得五常氣，變化成形補天地。", "三十六筭世間知，七十二石列具位。", "天得一而能長，地得一而方久。", "金得火而轉精，木成炭而不朽。", "故知唯鍊唯精，大還如何不有？", "凝我神，定我心，志精可以成黃金。", "河車本向鉛中取，姹女還須汞裏尋。", "傍思之物謾周彰，太一出水入公量。", "淮南調鼎彭祖嘗，得道同歸不死鄉。", "固濟精研須緘密，一文一武莫踈失。", "釜下唯鋪淥海鹽，鑪中少用槫桑日。", "紫煙碧焰噴人香，赫奕魚鱗透日光。", "須同魏伯雲中去，莫學姮娥月裏藏。", "酆都落名天府記，地下陰官大怖畏。", "兵刃水火不能忤，何但蟲蛇兼虎兕。", "亭亭金骨皆堅牢，鬱鬱綠身徧綠毛。", "曾觀東海幾廻變，數度曾偷王母桃。", "乘龍駕鶴傾城市，驅策雷公使神鬼。", "七日應歸緱氏山，千年少別遼東水。", "道是易，亦大難，青龍白虎自相盤。", "陰車濕，陽車乾，夫妻相對卦中安。", "四方未住霑顏色，五箇王侯盡罷官。"]'),
('72706db0-7f84-4fcc-a027-e8baa6e418f7','','張司馬','唐','唐诗','tang','','[]','張司馬，名不詳，乾元中任劍州司馬。',52,'全唐诗/poet.tang.52000.json','["張司馬，名不詳，乾元中任劍州司馬。", "著有《玄晉蘇元明太清石壁記》三卷。", "詩二首。", "（傳據《新唐書·藝文志》）。"]'),
('504efa15-7435-40ed-bd99-2615012cc6af','還丹口訣','張司馬','唐','唐诗','tang','','[]','九九之中乾體開，華池金液自徘徊。',80,'全唐诗/poet.tang.52000.json','["九九之中乾體開，華池金液自徘徊。", "陰陽鼎上先光彩，鉛花鑪裏考三才。", "即知造化由人手，術正藥真神自來。", "到此修時應出世，四時不用苦相催。", "（五代後蜀人著《大還丹照鑒》）。"]'),
('febe19dd-40ce-4a97-9bfb-7b3875b53258','歌','張司馬','唐','唐诗','tang','','[]','其色光輝耀日月，無窮改變不思議。',37,'全唐诗/poet.tang.52000.json','["其色光輝耀日月，無窮改變不思議。", "但住鉛砂成寶後，歇頭一任丙丁吹。", "（同前）。"]'),
('e162cf19-9693-44ea-bc6c-85278022b6cb','大還丹口訣','崔玄真','唐','唐诗','tang','','[]','岷山寶室九仙居，日月縈迴洞底虛。',392,'全唐诗/poet.tang.52000.json','["岷山寶室九仙居，日月縈迴洞底虛。", "爲有真人常鎮此，玉留盤結氣長舒。", "曾遊海嶠崑丘客，遠控龍駢亦探賾。", "鍊得精華九轉成，中有白銀相韞積。", "月中玉兔坎中陽，外柔形容內有剛。", "二象雄雌同一體，還如金向水中藏。", "金水相合是魂魄，三才變異誠難測。", "倐然龍虎兩交幷，化得龍兒在杳冥。", "狀似凝酥黃芽雪，亦如玄圃玉華結。", "本非世上起機心，元是真人留祕訣。", "留祕訣，不參差，晃山石室有丹砂。", "至道之人依此法，飛取青龍作一家。", "季魂周天成氣質，重與水銀相固密。", "似子還婚小女兒，蘇張下說情難失。", "相傳此物是黃芽，重重金鼎貯金華，制成雄黃偃藥砂。", "六一緘封須祕密，莫教神室有纖瑕。", "火候初從一陽起，乾坤兩卦成終始。", "文經武緯啓靈機，一法先王傳祕旨。", "蟾蜍天上盡還生，丹鼎開時見道情。", "每度恢奇別起象，璘㻞紅紫狀難名。", "却取金合雄作匱，世光流盡赤龍飛。", "燒金學道岷山子，親得真人受玄旨。", "玄旨唯論汞與鉛，修得黃芽身不死。", "鍊丹鍊志兼鍊神，不營名利顯清芬。"]'),
('742b9fb7-d569-4f1e-83fd-8580177773f7','題泗水亭','許遠','唐','唐诗','tang','','[]','春風落東林，綠葉翳重陰。',71,'全唐诗/poet.tang.52000.json','["春風落東林，綠葉翳重陰。", "流鶯坐花塢，宛傳來清音。", "和光沛天地，樂意同人心。", "卷簾出庭戶，獨立蒼苔深。", "（《海昌勝跡志》卷二。", "此首承陶敏先生錄示。", "）。"]'),
('32e79a93-ce66-4083-a0d3-bd5b060ecc7b','同房侍御竹園新亭與邢大判官同遊','張垍','唐','唐诗','tang','','[]','隱隱春城東，朦朧陳近深。',159,'全唐诗/poet.tang.52000.json','["隱隱春城東，朦朧陳近深。", "君子顧榛莽，興言傷古今。", "決河道新流，疎逕蹤舊林。", "開亭俯川陸，時景宜招尋。", "肅穆逢使軒，寅猶事登臨。", "忝遊芝蘭下，還對桃李陰。", "峯遠白波來，氣喧黃鳥吟。", "因覩歌頌作，始知經濟心。", "灌（疑）壇（疑）縣（小川環樹疑此字涉下文而衍）有遺風，單父多鳴琴。", "誰得久州縣，蒼生懷德音。", "（日本藏唐抄本《新撰類林抄》卷四）。"]'),
('03ef8f72-40ba-4c79-b6b1-f04472080005','謁聖容','渾惟明','唐','唐诗','tang','','[]','法雨震天雷，祁山一半頹。',48,'全唐诗/poet.tang.52000.json','["法雨震天雷，祁山一半頹。", "鱗鱗碧玉色，寂寂現如來。", "縲髻從烟合，圓光滿月開。", "從茲一頂謁，永劫去塵埃。"]'),
('ed56c0d7-8ec6-4748-9345-dd7dbe06e0d5','吐蕃党舍人臨刑','渾惟明','唐','唐诗','tang','','[]','生死誰能免，嗟君最可憐。',67,'全唐诗/poet.tang.52000.json','["生死誰能免，嗟君最可憐。", "幼男猶在抱，老母未終年。", "爲復冥徒任，爲當命合然。", "設將泉下事，時向夢中傳。", "（均見伯三六一九卷，原署「渾維明」）。"]'),
('887edca6-4dd2-468f-95cc-005e9624e8f6','述懷','史昂','唐','唐诗','tang','','[]','昔在{亠/樂，木=水}（疑應作「灤」）河外，征馬倦風塵。',64,'全唐诗/poet.tang.52000.json','["昔在{亠/樂，木=水}（疑應作「灤」）河外，征馬倦風塵。", "今來洛陽道，人事復艱辛。", "有策懷明主，無媒託近臣。", "君門不可見，歸去淥山春。"]'),
('98e3ea1a-7f9c-4d72-9648-25a617908cee','野外遙[占]渾將軍','史昂','唐','唐诗','tang','','[]','山頭一隊欲陵（當作「凌」）雲，白馬紅旗纓（此處衍一字）出衆羣。',64,'全唐诗/poet.tang.52000.json','["山頭一隊欲陵（當作「凌」）雲，白馬紅旗纓（此處衍一字）出衆羣。", "諸人氣色不如此，祇應者箇是將軍。", "（見伯三六一九卷、伯三八八五卷）。"]'),
('c1c71ea2-4d8c-4635-af5d-e0b1c572186a','書訣','張懷瓘','唐','唐诗','tang','','[]','剡紙易墨，心圓管直。',102,'全唐诗/poet.tang.52000.json','["剡紙易墨，心圓管直。", "漿深色濃，萬毫齊力。", "先臨告誓，次寫《黃庭》。", "骨豐肉潤，入妙通靈。", "努如直槊，勒若橫釘。", "虛專妥帖，毆鬬崢嶸。", "開張鳳翼，聳擢芝英。", "粗不爲重，細不爲輕。", "纖微向背，毫髮死生。", "工之未盡，已擅時名。"]'),
('b4da27f3-2e8f-49fa-b4f5-ef9a4de6452b','詩','張懷瓘','唐','唐诗','tang','','[]','向展右背，長伸左足。',101,'全唐诗/poet.tang.52000.json','["向展右背，長伸左足。", "峻角一支，潛虛半腹。", "已放則留，無垂不縮。", "分若抵背，合還口並目。", "似側暎斜，似斜附曲。", "覃精一字，工歸自得。", "盈虛統視聯行，妙在相承起伏。", "（均見宋朱長文《墨池編》卷二引張懷瓘《玉堂禁經》）。"]'),
('84e940c7-1b10-4ea2-a1d5-42a0a36dd9ba','石榴詩','史思明','唐','唐诗','tang','','[]','三月四月紅花裏，五月六月瓶子裏。',49,'全唐诗/poet.tang.52000.json','["三月四月紅花裏，五月六月瓶子裏。", "作刀割破黃胞衣，六七千箇赤男女。", "（見唐姚汝能《安祿山事跡》卷下）。"]'),
('2f38cce9-28d8-421d-a7eb-333d9e9ed438','以櫻桃賜子朝義及周贄（題擬）','史思明','唐','唐诗','tang','','[]','櫻桃一籠子，半赤一半黃（《太平廣記》卷四九五引《芝田錄》此句作「半已赤，半已黃」）。',86,'全唐诗/poet.tang.52000.json','["櫻桃一籠子，半赤一半黃（《太平廣記》卷四九五引《芝田錄》此句作「半已赤，半已黃」）。", "一半與懷王，一半與周贄。", "（同前）（按：《全唐詩》卷八六九收此詩，首句缺二字，今重錄。", "）。"]'),
('f6df88c9-6051-4f7f-9871-1d5d561ab414','長生草','王維','唐','唐诗','tang','','[]','老根那復占春晴，能住虛根自發生。',29,'全唐诗/poet.tang.52000.json','["老根那復占春晴，能住虛根自發生。", "（見《剡錄》卷十。", "疑僞）。"]'),
('67872764-9baa-4113-a600-5f95ac63c635','四大無主偈','本淨','唐','唐诗','tang','','[]','四大無[主]（心）（從《景德傳燈錄》改）復如水，遇曲逢直無彼此。',78,'全唐诗/poet.tang.52000.json','["四大無[主]（心）（從《景德傳燈錄》改）復如水，遇曲逢直無彼此。", "淨穢兩處不生心，壅決何曾有二意。", "境觸（《景德傳燈錄》作「觸境」）但似水無心，在世縱橫有何事。"]'),
('12c72645-37f1-4d52-b054-4302bba51df0','見聞覺知偈','本淨','唐','唐诗','tang','','[]','見聞覺知無障礙，聲香味觸常三昧。',75,'全唐诗/poet.tang.52000.json','["見聞覺知無障礙，聲香味觸常三昧。", "如鳥空中只沒（《景德傳燈錄》作「麽」）飛，無取無捨無憎愛。", "若會應處本無心，方（《景德傳燈錄》作「始」）得名爲觀自在。", "。"]'),
('9944e828-bff8-4914-b20c-94741b25d9d7','無修偈','本淨','唐','唐诗','tang','','[]','見道方修道，不見復何修。',61,'全唐诗/poet.tang.52000.json','["見道方修道，不見復何修。", "道性如虛空，虛空何處（《景德傳燈錄》作「所」）修。", "遍觀修道者，撥火覓浮漚。", "但看弄傀儡，線斷一時休。"]'),
('84fc263c-dd14-492f-9c3f-1bd8171684b9','背道逐教偈','本淨','唐','唐诗','tang','','[]','道體本無修，不修自合道。',61,'全唐诗/poet.tang.52000.json','["道體本無修，不修自合道。", "若起修道心，此人未（《景德傳燈錄》作「不」）會道。", "棄却一真性，却入鬧浩浩。", "忽逢修道人，第一莫向道。"]'),
('f9e48be0-1fe9-4c4f-a41d-144a94186435','真妄偈','本淨','唐','唐诗','tang','','[]','窮（《景德傳燈錄》作「推」）真真無相，窮妄妄無形。',62,'全唐诗/poet.tang.52000.json','["窮（《景德傳燈錄》作「推」）真真無相，窮妄妄無形。", "返觀推窮心，知心亦假名。", "會道既（《景德傳燈錄》作「亦」）如此，到頭亦只寧。"]'),
('715f5059-1f8d-4f26-90f6-c81efac839a0','善惡二根不實偈','本淨','唐','唐诗','tang','','[]','善既從心生，惡豈離心有。',90,'全唐诗/poet.tang.52000.json','["善既從心生，惡豈離心有。", "善惡是外緣，於心實不有。", "捨惡送何處，取善令誰守？", "傷嗟二見人，攀緣兩頭走。", "忽悟無生本（《景德傳燈錄》作「若悟本無心」），始會（《景德傳燈錄》作「悔」）從前咎。"]'),
('052cd1eb-c406-430c-ad15-1c13a1999d89','來往如夢偈','本淨','唐','唐诗','tang','','[]','亦知（《景德傳燈錄》作「視生」）如在夢，睡（《景德傳燈錄》作「夢」）裏實是鬧。',157,'全唐诗/poet.tang.52000.json','["亦知（《景德傳燈錄》作「視生」）如在夢，睡（《景德傳燈錄》作「夢」）裏實是鬧。", "忽覺萬事休，還同睡時覺（《景德傳燈錄》作「悟」）。", "智者會悟夢，迷人信夢鬧。", "會夢無（《景德傳燈錄》作「如」）兩般，一悟無別悟。", "富貴與貧賤，更亦無別道（《景德傳燈錄》作「更無分別路」。", "《祖堂集》卷三、《景德傳燈錄》卷五、《五燈會元》卷二）。"]'),
('00a16385-1ebb-4923-a397-23253e7a0498','紫陽真人歌（幷序）','盧象','唐','唐诗','tang','','[]','君不見先生耳鼻有仙骨，自號狂生中有物。',377,'全唐诗/poet.tang.52000.json','["君不見先生耳鼻有仙骨，自號狂生中有物。", "金華侍講三十年，兒戲公卿與簪笏。", "青門抗行謝客兒，健筆連羈王獻之。", "長安素絹書欲徧，主人愛惜常保持。", "每歎二疏不足道，復言四皓常枯槁。", "去年寢疾彌數旬，神鬼盈庭謀一老。", "長男泣血求司命，少女[顰]（頻）眉誦《靈寶》。", "還如簡子復歸來，更與洪崖同壽考。", "上書北闕言授籙。", "稅駕東州願修道。", "初聞行路猶未信，果達吾君謂之好。", "山陰舊宅作仙壇，湖上閑田種芝草。", "鏡湖之水含杳冥，會稽仙洞多精靈。", "須乘赤鯉遊滄海，當以羣鵝寫道經。", "皇恩贈詩四十字，明主賜金三十鎰。", "供帳傾朝一送歸，雙童駟馬從茲出。", "迴看紫綬若輕塵，遠別青門嗟故人。", "鴛鷺差池攀羽蓋，虹霓夭矯翊車輪。", "田田列侍浮丘伯，曾子榮過朱買臣。", "余高若是有先覺，滅蹟歸根從大樸。", "千載悠悠等令威，十洲漫漫思方朔。", "歸去來，青牛頓足少遲迴。", "忽然雲霧不相見，唯有飄飄香氣來。", "（見宋孔延之編《會稽掇英總集》卷二）。"]'),
('da1dedce-bc04-4a9d-ac50-66c8616a31cf','寄雲門亮師','盧象','唐','唐诗','tang','','[]','玄度常稱支道林，南山隱處白雲深。',40,'全唐诗/poet.tang.52000.json','["玄度常稱支道林，南山隱處白雲深。", "一去人間長不見，千峰萬壑樹森森。", "（同前書卷七）。"]'),
('2a3cc1ff-4c2d-4ec4-b47e-9ea9d31b392e','詩送玄靜先生赴金壇（題擬）','玄宗皇帝李隆基','唐','唐诗','tang','','[]','紫府煙霞士，玄宗道德師。',329,'全唐诗/poet.tang.52000.json','["紫府煙霞士，玄宗道德師。", "心將萬籟合，志與九仙期。", "絕俗遺塵境，同人喜濟時。", "訪經遊玉洞，敷教入瑤墀。", "茅嶺追餘跡，金壇赴遠思。", "陰宮春舊記，陽觀飭新祠。", "緬想埋雙璧，長懷採五芝。", "真靈若可遇，鸞鶴佇來茲。", "（詳後。", "此首又見《嘉定鎮江志》卷二十）（按：《茅山志》卷二收玄宗賜李玄靜先生勑書二十四通，此詩見第三道勑內。", "此勑書全文錄如次：「勑。", "廣陵李鍊師，上清品人也。", "抗志雲霞，和光代俗。", "爲予修福靈跡，將赴金壇，故賦詩寵行，以美其志。", "〖詩略〗尊師抱一守中，探微昭遠，能回貞潔，發揮道門。", "遂與太和先生啓是仙宗，起予虔奉，崇飭靈跡，廣求真經。", "則詩以寵行，物將厚意，永慰歧路，以彰禮賢也。", "所謝知。", "」又按，據同書同卷所附玄靜先生等表奏，知此詩爲天寶六載九月二十五日作，由高力士宣賜。", "）。"]'),
('65a13d73-4835-44af-9217-73ba21b8f797','詩送玄靜先生暫還廣陵（幷序）','玄宗皇帝李隆基','唐','唐诗','tang','','[]','楊許開真籙，夫君密契傳。',48,'全唐诗/poet.tang.52000.json','["楊許開真籙，夫君密契傳。", "九星連紫蓋，雙景合丹田，玉簡龜臺職，金壇洞府仙。", "猶期禦風便，朝夕候泠然。"]'),
('7465bea0-1be0-45d6-823e-a5b5f5ed84d2','詩送玄靜先生歸廣陵（幷序）','玄宗皇帝李隆基','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','默受王倪道，逾深尹喜師。',234,'全唐诗/poet.tang.52000.json','["默受王倪道，逾深尹喜師。", "欣同八景會，更叶九丹時。", "鸞鶴遙煙境，江山渺別思。", "當遷洞庭日，留念上京期。", "（以上三首幷見《正統道藏》本元劉大彬撰《茅山志》卷二）（按：據同書同卷附玄靜先生等表奏，前二詩中之一首爲天寶十載九月十四日由內侍袁思藝宣勑。", "又玄靜先生即李含光，爲茅山宗第十三代宗師，事跡詳《顏魯公文集》卷七《有唐茅山玄靖先生廣陵李君碑銘》。", "〖1〗《輿地紀勝》卷十七《建康府》「碑記」云：「《賜李煉師詩詔》，唐道士任良友書。", "玄宗所賜詩，凡三首，貞元十四年刻石。", "在茅山。", "」）。"]'),
('982ce316-0746-45c2-bb37-a69b8873c4ed','送道士薛季昌還山（補序）','玄宗皇帝李隆基','唐','唐诗','tang','','["\u8861\u5c71"]','空（按：此詩《全唐詩》卷三已收入。',136,'全唐诗/poet.tang.52000.json','["空（按：此詩《全唐詩》卷三已收入。", "茲據唐李沖昭《南嶽小錄》補序。", "《大正新修大藏經》第五十一冊收宋陳田夫《南嶽總勝集》卷下，載此序異文較多，另錄如次以備攷：「煉師志慕玄門，棲心南嶽。", "及登道籙，忽然來辭，願歸舊山，以守虛白。", "不違雅志，且重精修，若遇真人靈藥，時來城闕也。", "」）。"]'),
('bea70707-00ea-4090-ae55-4339ba6b70c6','批答安祿山賀雪兼賜口號（題擬）','玄宗皇帝李隆基','唐','唐诗','tang','','[]','臘月忻三[白]（日），嘉平安四鄰。',118,'全唐诗/poet.tang.52000.json','["臘月忻三[白]（日），嘉平安四鄰。", "預知天下稔，先爲物華春。", "（見上海古籍出版社排印本《安祿山事迹》卷上）（〖1〗《安祿山事迹》：「其〖天寶九載〗冬，久無雪，至十二月十四日乃雪，祿山表賀焉。", "玄宗批答兼口號以賜之曰〖詩略〗。", "其見重如此。", "」）。"]'),
('be7a2594-116c-4f8f-8358-2e5e8bda4826','攻玉賦附卞生追怨之歌','趙昂','唐','唐诗','tang','','[]','昔之玉在石，石在山，山有玉兮隱其間。',77,'全唐诗/poet.tang.52000.json','["昔之玉在石，石在山，山有玉兮隱其間。", "今則石爲錯，玉爲環，環亦獻兮君解顏。", "遂與生芻爲比，與郄桂同攀。", "豈辛勤於道路，徒抱泣於荆蠻。", "（見《文苑英華》卷一一五）。"]'),
('4ec63b9e-8969-4cfa-897a-b1312d660019','江夏送倩公歸漢東（幷序）','李白','唐','唐诗','tang','','[]','彼美漢東國，川藏明月輝。',45,'全唐诗/poet.tang.52000.json','["彼美漢東國，川藏明月輝。", "寧知喪亂後，更有一珠歸。", "（錄自影宋蜀刻本《李太白文集》卷二十七）。"]'),
('246a6cf2-c8db-443e-b581-64f6d35c3df5','別匡山','李白','唐','唐诗','tang','','["\u5e90\u5c71"]','曉峰如畫碧參差（碑作「參差碧」），藤影風搖拂檻垂。',205,'全唐诗/poet.tang.52000.json','["曉峰如畫碧參差（碑作「參差碧」），藤影風搖拂檻垂。", "野徑來多將犬伴，人間歸晚帶（碑作「待」）樵隨。", "看雲客倚啼猿樹，洗鉢僧臨失鶴（一作「鷺」，或作「鶩」）池。", "莫怪無心戀清境，已將書劍許明時。", "（見光緒《重修江油縣志》卷二十四）（陳廣福《李白的〈別匡山〉詩考》謂江油縣匡山書院存宋熙寧元年《勅賜中和大明寺住持碑》，碑文云：「玄宗朝翰林學士李白字太白，少爲當縣小吏，後於此山讀書，於喬松滴翠之平有十載。", "」文中錄此詩。", "）。"]'),
('864837b3-b784-45cd-bc64-0821886709fe','太華觀','李白','唐','唐诗','tang','','[]','厄磴層層上太華，白雲深處有人家。',69,'全唐诗/poet.tang.52000.json','["厄磴層層上太華，白雲深處有人家。", "道童對月閒吹笛，仙子乘雲遠駕車。", "恠石堆山如坐虎，老藤纏樹似騰蛇。", "曾聞玉井金河在，會見蓬萊十丈花。", "（同前）。"]'),
('33a6c7a9-7b78-4cae-8bdf-157f70e256e4','觀佽飛斬蛟龍圖讚','李白','唐','唐诗','tang','','[]','佽飛斬長蛟，遺圖畫中見。',82,'全唐诗/poet.tang.52000.json','["佽飛斬長蛟，遺圖畫中見。", "登舟既虎嘯，激水方龍戰。", "驚波動連山，拔劍曳雷電。", "鱗摧白刃下，血染滄江變。", "感此壯古人，千秋（一作「載」）若對面。", "（見《李太白文集》卷二十八）。"]'),
('f60a15ad-8775-467a-84d3-051280507e11','地藏菩薩讚','李白','唐','唐诗','tang','','[]','本心若虛空，清淨無一物。',65,'全唐诗/poet.tang.52000.json','["本心若虛空，清淨無一物。", "焚蕩淫怒癡，圓寂了見佛。", "五綵圖聖像，悟真非妄傳。", "掃雪萬病盡，爽然清凉天。", "讚此功德海，永爲曠代宣。", "（同前）。"]'),
('3d3d21cd-e805-43c1-9509-d72d83994064','獨坐敬亭山（其二）','李白','唐','唐诗','tang','','[]','合沓牽數峰，奔地鎮平楚。',57,'全唐诗/poet.tang.52000.json','["合沓牽數峰，奔地鎮平楚。", "中間最高頂，髣髴接天語。", "（見《宛陵郡志備要》。", "又見嘉慶廿年刊洪亮吉纂《寧國府志》卷二四）。"]'),
('47617aaf-9f47-4c4a-bc2e-e423d4e1c6fd','秀華亭','李白','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','遙望九華峰，誠然是九華。',113,'全唐诗/poet.tang.52000.json','["遙望九華峰，誠然是九華。", "蒼顏耐風雪，奇態燦雲霞。", "曜日凝成錦，凌霄增壁崖。", "何當餘蔭照，天造洞仙家。", "（見《青陽縣志·藝文志》及《九華山志》卷八）（〖1〗《李白在安徽》云：秀華亭在九華山麓，五溪橋側，延壽寺前。", "亭已圮，遺址猶存。", "）。"]'),
('b18d8740-167c-4fe8-9673-7bcd4d8e5ef3','煉丹井','李白','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','聞說神仙晉葛洪，煉丹曾此占雲峰。',85,'全唐诗/poet.tang.52000.json','["聞說神仙晉葛洪，煉丹曾此占雲峰。", "庭前廢井今猶在，不見長松見短松。", "（見《宛陵郡志備要》卷一。", "又見嘉慶《寧國府志》卷二四）（〖1〗《李白在安徽》云：井在九華山臥雲庵北面。", "）。"]'),
('0cc5c752-5c9f-43be-9bb6-89963f0e8683','宿無相寺','李白','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','頭陀懸萬仞，遠眺望華峰。',233,'全唐诗/poet.tang.52000.json','["頭陀懸萬仞，遠眺望華峰。", "聊借金沙水，洗開九芙蓉。", "煙嵐隨遍覽，踏屐走雙龍。", "明日登高去，山僧孰與從？", "禪床今暫歇，枕月臥青松。", "更盡聞呼鳥，恍來報曉鐘。", "（詳後，以上四首，皆轉錄自常秀峰等著《李白在安徽》。", "）（〖1〗《李白在安徽》云：此詩刻於清道光十年《重建無相寺碑記》。", "無相寺在九華山頭陀嶺下，旁有一泉，名金沙，李白在九華時曾遊此。", "無相寺建於唐初，治平元年賜額，道光間重修。", "此詩保存有兩種可能：一，無相寺舊時碑文刻有此詩；二，爲康熙時禮部尚書吳襄收藏，吳姓修寺捐資最多。", "）。"]'),
('f75c5aea-e9f3-45b7-b71d-95b712721330','詠方廣詩','李白','唐','唐诗','tang','','["\u8861\u5c71"]','聖寺閑棲睡眼醒，此時何處最幽清？',49,'全唐诗/poet.tang.52000.json','["聖寺閑棲睡眼醒，此時何處最幽清？", "滿窗明月天風靜，玉磬時聞一兩聲。", "（見宋陳田夫《南嶽總勝集》卷中）。"]'),
('8c494cf3-95cc-4f93-b6f7-4e5c9ce843ad','上清寶鼎詩二首（附存） 一','李白','唐','唐诗','tang','','[]','朝披夢澤雲（甲、乙、戊本作「雲夢澤」），笠釣青茫茫。',425,'全唐诗/poet.tang.52000.json','["朝披夢澤雲（甲、乙、戊本作「雲夢澤」），笠釣青茫茫。", "尋絲（甲作「流」、乙作「綠」）得雙鯉，中有三（乙作「二」）元章。", "篆字若丹蛇，逸（乙作「遶」）勢如飛翔。", "歸來問天老（甲、戊作「姥」）奧（甲、戊作「妙」）義不可量。", "金刀（甲作「刃」）割青素（甲作「紫」），靈文爛煌煌。", "嚥（甲、戊作「燕」）服十二環（戊作「鐶」），奄（甲、戊作「想」）見仙人房。", "暮跨（丙作「騎」）紫鱗（丙作「麟」）去，海氣侵肌凉。", "龍子善（戊作「喜」）變化，化作梅花妝。", "贈（甲、戊作「遺」）我纍纍（乙作「疊疊」）珠，靡靡（甲作「非」）明月光。", "勸我穿絳（乙作「絡」）縷（甲、戊作「樓」），繫作裙（戊、丁作「裾」）間襠（甲作「當」，戊作「璫」）。", "挹（甲、戊作「揖」）子（甲作「予」，丁戊作「余」）以攜（甲作「疾」，乙作「詞」，丁、戊作「辭」）去，談笑聞遺（甲、乙、戊作「餘」）香。", "（按：《全唐詩》卷一八五據《王直方詩話》錄「房」、「涼」、「光」三韻，《全唐詩續補遺》卷四錄「茫」、「涼」二韻。", "）。"]'),
('4407e6ca-9d88-4b1f-ba7f-f101d7e0f133','上清寶鼎詩二首（附存） 二','李白','唐','唐诗','tang','','["\u8861\u5c71"]','人生燭上花，光（乙作「火」）滅巧妍盡。',901,'全唐诗/poet.tang.52000.json','["人生燭上花，光（乙作「火」）滅巧妍盡。", "春風繞樹頭，日與化（戊作「花」）工（丁作「花工」）進。", "只（戊作「惟」）知雨露貪，不聞（丁、戊作「念」）零落盡（甲無以上二句）。", "我昔（乙、戊作「昔我」）飛骨時，慘見當塗墳。", "青松靄朝（丁、戊作「明」）霞，縹緲山（戊作「上」）丁村。", "既死明月魄，無復（丁、戊作「彼」）玻璃（乙、戊作「瓈」）魂。", "念此一脫灑（戊作「酒」），長嘯祭（甲、乙、戊作「登」）崑崙。", "醉著鸞皇（甲、丁、戊作「鳳」）衣，星斗俯可捫。", "（見瞿蛻園、朱金城《李白集校注》卷三十《詩文補遺》錄蘇軾書李白詩墨跡。", "出校各本，甲本爲趙令畤《侯鯖錄》卷二，乙本指《增修詩話總龜》卷十一引《王直方詩話》，丙本指《全唐詩》卷一八五引《王直方詩話》，丁本指《李白詩校注》據《唐宋詩醇》所錄校語，戊本指《津逮秘書》本《東坡題跋》卷二）（〖1〗《東坡題跋》卷二：「余頃在京師，有道人相訪，風骨甚異，語論不凡，自云常與物外諸公往還，口誦此二篇，云東華上清監清逸真人李太白作也。", "」〖2〗《侯鯖錄》卷二：「東坡先生在嶺南，言元祐中有見李白酒肆中誦其近詩云：『朝披夢澤雲，笠釣青茫茫。", "』此非世人語也。", "少游嘗手錄其全篇，少游敍云：『觀頃在京師，有道人相訪，風骨甚異，語論不凡，自云嘗與物外諸公往還，口誦二篇，云東華上清監清逸真人李白作也。", "』」）（〖3〗《王直方詩話》：「元祐八年，東坡帥定武，李方叔、王仲弓別於惠濟，出示南嶽典寶東華李真人像，又出此二詩，曰此李真人作也。", "近有人於江上遇之得此，云即李太白也。", "」〖4〗《苕溪漁隱叢話前集》卷五引東坡云：「予都下見有人携一紙文書，字則顏魯公也，墨跡如未乾，紙亦新健，其詩曰：『朝披夢澤雲，笠釣青茫茫。", "』此語非太白不能道也。", "」今按：此詩第二首云：「我昔飛骨時，慘見當塗墳。", "」顯然非李白所作。", "就前所錄北宋諸家有關獲得此詩的記錄而言，其作者約有以下幾種可能：其一，北宋道士托名李白作；其二，李真人作，後傳成李白作；其三，北宋道士錄唐時遺詩而獻於東坡；其四，東坡自作而僞稱得之於他人，亦如解《八陣圖》而稱少陵託夢之類。", "今莫詳孰是。", "因此二詩出處甚早，《全唐詩》及今賢補遺已錄存其片斷，故爲補足而附存之。", "）。"]'),
('383492e2-2ecc-4aa5-88ca-f9fead3bc4f1','句','李白','唐','唐诗','tang','','[]','眼前有景道不得，崔顥題詩在上頭。',52,'全唐诗/poet.tang.52000.json','["眼前有景道不得，崔顥題詩在上頭。", "（見《苕溪漁隱叢話前集》卷五引李畋《該聞錄》、《後村詩話前集》卷一。", "）。"]'),
('ba1cc096-f2f8-4f3f-8c08-7e2d9b3dcb8a','','王嚴光','唐','唐诗','tang','','[]','嚴光，自稱釣鰲客。',36,'全唐诗/poet.tang.52000.json','["嚴光，自稱釣鰲客。", "安史亂後任棣州司戶。", "詩二句。", "（《全唐詩》無王嚴光詩）。"]'),
('b16eb35c-8df1-43c8-8b3d-113f482ffa36','詩','王嚴光','唐','唐诗','tang','','[]','郡將雖乘馬，羣官總是驢。',141,'全唐诗/poet.tang.52000.json','["郡將雖乘馬，羣官總是驢。", "（見唐封演《封氏聞見記》卷十）（按：《封氏聞見記》云：「王嚴光頗有文才，而性卓詭。", "既無所達，自稱釣鰲客。", "……兵亂之後，嚴光年鬚已衰，任棣州司戶。", "時刺史有馬，州佐已下多乘驢，嚴光作詩曰〖略〗。", "對衆吟誦，以爲笑樂。", "」按：封演爲大曆間人，因知兵亂即指安史之亂。", "）。"]'),
('1707725f-7f84-4574-a478-c54e8055bf1d','刺當塗者','王志安','唐','唐诗','tang','','[]','末刼蘭香科下人，衣冠禮樂與君臣。',101,'全唐诗/poet.tang.52000.json','["末刼蘭香科下人，衣冠禮樂與君臣。", "如來若向閻浮出，莫現從來丈六身。", "（同前）（按：《封氏聞見記》云：「補闕王志安晚不得志，久遊恒、趙之間，人畏其口，莫敢引用。", "志安作詩以刺當塗者云〖略〗。", "見者彌增怨忌。", "」）。"]'),
('397e5f69-615f-4a65-acf2-e0c23eb1c69a','懷歐陽山人嚴秀才','神迥','唐','唐诗','tang','','[]','鴉鳴東牖曙，草秀南湖春。',276,'全唐诗/poet.tang.52000.json','["鴉鳴東牖曙，草秀南湖春。", "（《十萬卷樓叢書》本皎然《詩式》卷四）（按：《詩式》誤作「祖迥」，今據《吟窗雜錄》卷三十二、《四友齋叢說》卷二十四、《全唐詩》卷八五一定爲神迥作。", "《吟窗雜錄》題作《懷歐陽山人》。", "《全唐詩》收此二句，缺題。", "又其小傳云：「臨晉人。", "姓田。", "貞觀間流化岷峨，爲道俗宗仰。", "」殆據《續高僧傳》卷十五。", "按唐有二神迥，另一爲寶應間越州僧，見《宋高僧傳》卷二九。", "檢《詩式》錄其詩於嚴維、皇甫冉等詩後，知應爲肅代間人。", "詩中提到之南湖，亦在越中。", "詩題中之嚴秀才，疑即長期居於越中之嚴）（維。", "因知此詩應爲越州僧神迥作，《全唐詩》誤，今爲移正補題重錄。", "）。"]'),
('d0435bff-97b7-4f01-8b31-1b1e25db6581','詩 一','寒山','唐','唐诗','tang','','[]','梵志死去來，魂識（《天聖廣燈錄》作「魄」）見閻老。',127,'全唐诗/poet.tang.52000.json','["梵志死去來，魂識（《天聖廣燈錄》作「魄」）見閻老。", "讀盡百王書，未免（《天聖廣燈錄》作「不兌」）受捶拷。", "一稱南無佛，皆以成佛道。", "（見《續藏經》本五代風穴延沼禪師《風穴語錄》、《天聖廣燈錄》卷十五、《古尊宿語錄》卷七《風穴禪師語錄》、《五燈會元》卷十一引）。"]'),
('938861c3-e515-4aa0-9ea0-1e80efea32c6','詩 二','寒山','唐','唐诗','tang','','[]','井底生紅塵，高峰起波（《五燈會元》作「白」）浪。',84,'全唐诗/poet.tang.52000.json','["井底生紅塵，高峰起波（《五燈會元》作「白」）浪。", "石女生石兒，龜毛寸寸長。", "若要學菩提，但看此牓（《五燈會元》作「模」）樣。", "（《天聖廣燈錄》卷二十三、《五燈會元》卷十五）。"]'),
('88dff215-8255-4f1f-b47e-f38acd896e3a','頌 一','拾得','唐','唐诗','tang','','[]','無瞋是持（《五燈會元》作「嗔即是」）戒，心淨是（《五燈會元》作「即」）出家。',116,'全唐诗/poet.tang.52000.json','["無瞋是持（《五燈會元》作「嗔即是」）戒，心淨是（《五燈會元》作「即」）出家。", "我性與汝（《五燈會元》作「你」）合，一切法無差。", "（見吳越釋延壽《宗鏡錄》卷二十四、宋普濟《五燈會元》卷二。", "）（按：《全唐詩續補遺》卷二誤收此首爲寒山詩。", "）。"]'),
('083b302d-9719-4df5-965b-15225e6bd344','頌 二','拾得','唐','唐诗','tang','','[]','東陽海水清，水清復見底。',116,'全唐诗/poet.tang.52000.json','["東陽海水清，水清復見底。", "靈源流法泉，斫水刀而痕。", "我見頑愚士，燈心拄須彌。", "寸樵煮大海，足抹大地石，蒸沙成飯無，磨甎將爲鏡。", "說食終不飽，直須著力行。", "恢恢大丈夫，堂堂六尺土。", "枉死埋塚下，可惜孤標物。", "（同前書卷三十三。", "此條承陳允吉師告知）。"]'),
('de24fa99-d92f-4174-ae58-c1e2c956d96a','喜陸侍御破石埭草寇東峰亭賦詩','蘇㝢','唐','唐诗','tang','','[]','獨坐理戎行，安邊策最長。',167,'全唐诗/poet.tang.52000.json','["獨坐理戎行，安邊策最長。", "霜臺雷電振，雲漢翼箕張。", "決策威千里，除妖靜一方。", "林巒開罨畫，泉石韻宮商。", "戍罷涇川外，烽閑句水陽。", "肅清淮海後，誰不詠時康。", "（見嘉慶十一年刊洪亮吉纂《涇縣志》卷三十）（按：趙紹祖《涇川金石記》載北宋熙寧二年蔣之奇跋此詩文，知之奇當時曾重刻此碑。", "清代碑已不存，而諸詩則載於縣志中。", "同唱五人，惟㝢詩《全唐詩》失收。", "）。"]'),
('fa705ac8-3281-4b0c-8039-c423fefd8f2b','送賀秘監歸會稽詩','嚴向','唐','唐诗','tang','','[]','孤雲去住本無機，却指蒼梧下翠微。',78,'全唐诗/poet.tang.52000.json','["孤雲去住本無機，却指蒼梧下翠微。", "錫鼎爲傳仙族在，泛槎還入海煙歸。", "客星一夜淩光武，華表千年送令威。", "聞道葛洪丹竈畔，至今霜果有金衣。", "（見《會稽掇英總集》卷二）。"]'),
('cb98b5b8-7eb2-483f-a0b1-b4c9febdd4f2','與林元籍郊行舉對（題擬）','鄭虔','唐','唐诗','tang','','[]','石壓筍斜出。',119,'全唐诗/poet.tang.52000.json','["石壓筍斜出。", "（虔）谷陰花後開。", "（元籍）（見《全浙詩話》卷五引《三台詩話》）（〖1〗《三台詩話》云：「鄭司戶虔初至台，見風俗樸野，選民間子弟教之。", "一日與弟子林元籍輩郊行，舉一對曰〖略〗。", "元籍應聲云〖略〗。", "司戶大驚異曰：何教化神速如是。", "」）。"]'),
('e8d889a4-7740-426f-841f-8bbe0f17e7bd','奉和聖製雨中春望詩','苗晉卿','唐','唐诗','tang','','[]','雨後山川光正發，雲端花柳意無窮。',16,'全唐诗/poet.tang.52000.json','["雨後山川光正發，雲端花柳意無窮。"]'),
('719949bf-69cc-44f7-8677-d3f6ab647bee','奉和行幸詩','苗晉卿','唐','唐诗','tang','','[]','接仗風雲動，迎軍鳥獸舞。',69,'全唐诗/poet.tang.52000.json','["接仗風雲動，迎軍鳥獸舞。", "（均見清趙殿成《王右丞集箋注》卷二十二《魏郡太守河北採訪處置使上黨苗八德政碑》、《吟窗雜錄》卷二六《歷代吟譜》）。"]'),
('e248d48c-5c7c-4a45-8e97-fe2d9f62fe2e','餞故人','高適','唐','唐诗','tang','','[]','祈君辭丹豁（孫疑爲「丹墀」之誤），負仗（孫疑爲「杖」字之誤）歸海隅。',117,'全唐诗/poet.tang.52000.json','["祈君辭丹豁（孫疑爲「丹墀」之誤），負仗（孫疑爲「杖」字之誤）歸海隅。", "離庭自蕭索，別心何鬱紆。", "天高白雲斷，野曠青山孤。", "欲知腸斷處，明月照江湖。", "（〖1〗孫欽善云：「此詩原集缺佚，據敦煌殘卷伯三六一九補。", "當作於天寶十一載秋，時在長安。", "」）。"]'),
('c02b7e7f-533c-4461-befb-6c0423de7e67','送蕭判官賦得黃花戍','高適','唐','唐诗','tang','','[]','君不見黃花曲裏黃，戍日蕭蕭帶寒樹。',329,'全唐诗/poet.tang.52000.json','["君不見黃花曲裏黃，戍日蕭蕭帶寒樹。", "（孫云：「以上二句疑有缺字，姑作此斷。", "」）樓上篇（孫云「借作偏」）臨北斗星，門前宜（孫云「當作直，與上句偏成對文」）至西州路。", "每到爪時（孫云：「爪，《集韻》：『本又作叉，或作蚤、騷。", "』爪時，即早時。", "」今按：「爪時」應爲「瓜時」之誤，用《左傳》典。", "作早時解亦不可通）更卒來，祇對黃花□□□。", "（孫云：「外句末字模糊不清。", "」今按：此句疑缺末三字）樓中幾度哭明月，笛裏何人吹《落梅》？", "多君莫不推才傑（孫云：「原作𭪪傑俗字」），欲奏平戎赴天闕。", "轅門杯酒別交親，去去雲霄羽翼新。", "知君馬上貂裘暖，須念黃花久戍人。", "（以上三首均錄自孫欽善《高適集校注》）（〖1〗孫欽善云：「此詩作於任職哥舒翰幕府期間。", "原集缺佚，據敦煌殘集伯三一九五補。", "」）。"]'),
('3eae263b-c784-4836-af0b-de4254b2cf83','奉贈賀郎詩一首','高適','唐','唐诗','tang','','[]','報[賀]（駕）郎，莫潛藏。',158,'全唐诗/poet.tang.52000.json','["報[賀]（駕）郎，莫潛藏。", "障門終不免，何用漫思量。", "清酒濃如雞，臛㹠與白羊。", "不論空蒜酢，兼要好椒薑。", "姑娣能無語，多言有侍娘。", "不知何日辦，急共婦平章。", "如其意不決，請問阿耶孃。", "（見伯二九七六卷）（按：原卷連錄四首詩，不署作者。", "前三首爲《自薊北歸》、《宴別郭尚書》、《題李別駕壁》〖原卷缺題〗皆高適作，疑此詩亦爲其所作。", "）。"]'),
('af597c8a-fe6f-4cb9-b97d-0175fba37407','題石門','釋玄宗','唐','唐诗','tang','','[]','雙扉啓（《咸淳臨安志》作「起」）巖石，塵客過應稀。',113,'全唐诗/poet.tang.52000.json','["雙扉啓（《咸淳臨安志》作「起」）巖石，塵客過應稀。", "千古掩不得，從教雲夜歸。", "（見清釋廣賓《西天目祖山志》卷五）（按：此詩最早見收於南宋潛說友《咸淳臨安志》卷二十六，謂「世傳唐玄宗有詩」云云。", "明皇平行跡未及東南，詩顯非其所作。", "）。"]'),
('bf9a3cac-33ca-4533-909f-f4524e422df4','題石門洞','釋玄宗','唐','唐诗','tang','','[]','密竹流泉不居熱，洞門深沉風雨歇。',73,'全唐诗/poet.tang.52000.json','["密竹流泉不居熱，洞門深沉風雨歇。", "洗出清風快活天，醉弄江南謝家月。", "（見《康熙青田縣志》卷十二《藝文》下「七言絕」。", "以上二首，皆承張靖龍同志錄示。", "）。"]'),
('9079a429-bafc-4e2e-9c39-9503c6b8089b','沙門崇惠登刀梯歌（幷序○題擬）','□釗','唐','唐诗','tang','','[]','百尺凌空倚劍梯，千峰迴（疑應作「迥」）拔（一作「枝」）接天霓。',384,'全唐诗/poet.tang.52000.json','["百尺凌空倚劍梯，千峰迴（疑應作「迥」）拔（一作「枝」）接天霓。", "鏖鑪霜明鳥道（一作「邊」）齋，龍泉金鐶生虹蜺。", "刀爲樹，劍作山，應真飛錫遊其間。", "一步一登，揮手攀毛，七星燦爛光斑斑。", "干將劍刃兩離披（一作「柀」），碧光焰，上人履之不爲嶮；鏌鎁刀，銛鋒鋭鍔可吹毛，如今蹈之不足勞。", "白若雪，青如冰，龜甲魚鱗幾百層，四部覩之，戰戰兢兢，萬仞峰頭見一僧。", "賓鐵文，青蛇色，蒨𮑕崢嶸寒岌嶷。", "不傷不損難可測，方是大悲解脫力。", "自古武臣矜劍術，舞之杸（疑爲「投」字）之皆不失。", "視之膽攝（一作「欇」）身慄慄，誰道揮戈移白日？李廣舊傳百戰功，何如今日見神通？紫衣襜襜飛入空，出沒縱橫[蹈]白刃（一本多「中」字）兮，[蹈白刃兮]光翡翠，黯黯精光和能利。", "（見《大正新脩大藏經》第五十二冊釋圓照集《代宗朝贈司空大辨正廣智三藏和上〖即不空〗表制集》卷六。", "其後尚收《崇惠登刀梯頌》及崇惠《謝賜紫衣幷賀表》）。"]'),
('536f946b-7bb2-4f9c-b091-d955d2943210','','張誠','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.52000.json','["。"]'),
('4f1da0ea-4617-48de-a351-6598d5d8985b','詠懷','張誠','唐','唐诗','tang','','[]','論成方辯命，賦罷即歸田。',45,'全唐诗/poet.tang.52000.json','["論成方辯命，賦罷即歸田。", "（見《白氏長慶集》卷四十一《唐贈尚書工部侍郎吳郡張公神道碑銘》）。"]'),
('dcf93d9e-3273-48c4-8aeb-73319ac220f4','湘夫人祠','太易','唐','唐诗','tang','','[]','靈祠古木合，波颺大江濆。',99,'全唐诗/poet.tang.52000.json','["靈祠古木合，波颺大江濆。", "未作湘南雨，知爲何處雲。", "苔痕澀珠履，草色妬羅裙。", "妙鼓彤雲瑟，羈臣不可聞。", "（見明刻本《唐僧弘秀集》卷八、《古今禪藻集》卷四）（按：《全唐詩》卷八一○收此詩，有闕文，今重錄。", "）。"]'),
('dba3e591-1f24-4680-bf26-68a7b594d084','答智威偈（題擬） 一','慧忠','唐','唐诗','tang','','[]','念想由來幻，性自無終始。',25,'全唐诗/poet.tang.52000.json','["念想由來幻，性自無終始。", "若得此中意，長波當自止。", "。"]'),
('5568739b-d258-47a4-94c1-e76a1e864bb4','答智威偈（題擬） 二','慧忠','唐','唐诗','tang','','[]','虛無是實體，人我何所存。',36,'全唐诗/poet.tang.52000.json','["虛無是實體，人我何所存。", "妄情不須息，即汎般若船。", "（見《五燈會元》卷二）。"]'),
('7f178267-ce7e-4b0e-8efb-231f2ff34806','感舊賦附歌','岑參','唐','唐诗','tang','','[]','東海之水化爲田，北溟之魚飛上天。',225,'全唐诗/poet.tang.52000.json','["東海之水化爲田，北溟之魚飛上天。", "城有時而復，陵有時而遷，理固常矣，人亦其然。", "觀夫陌上豪貴，當年高位，歌鐘拂天，鞍馬照地，積黃金以自滿，矜青雲之坐致，高館招其賓朋，重門疊其車騎。", "及其高堂傾，曲池平，雀羅空悲其處所，門客肯念其生平？已矣夫！世路崎嶇，孰爲後圖？豈無疇日之光榮，何今人之棄予。", "彼乘軒而不恤爾後，曾不愛我之覉孤。", "歎君門兮何深，顧盛時而向隅。", "攬蕙草以惆悵，步衡門而踟躕。", "強學以待，知音不無。", "思達人之惠顧，庶有望於亨衢。", "（見《文苑英華》卷九一）。"]'),
('7e1a3b91-19f8-45bf-9602-02f48f59cb51','江行遇梅花之作','岑參','唐','唐诗','tang','','[]','江畔梅花白如雪，使我思鄉膓欲斷。',298,'全唐诗/poet.tang.52000.json','["江畔梅花白如雪，使我思鄉膓欲斷。", "摘得一枝在手中，無人遠向金閨說。", "願得青鳥啣此花，西飛直送到我家。", "胡姬正在臨窗下，獨織留黃淺碧紗。", "此鳥啣花胡姬前，胡姬見花知我憐。", "千說萬說由不得，一夜抱花空館眠。", "（見伯二五五五卷，轉錄自《文獻》十三輯廖立《敦煌殘卷岑詩辨》）（〖1〗李嘉言《岑詩繫年》云：「案岑參江陵人，而足跡不及江陵以東。", "此曰：『西飛直送到吾家』，其非岑作明矣。", "」〖2〗廖立云：「今覈對膠片，此詩題下署名爲岑參〖原字作𠫭〗，不知何故《繫年》未提此點。", "」「詩中所言胡姬，恐怕也是寄託之辭，勿須考證岑參家中是否真有一個胡姬。", "這是寫詩，不是寫史，香草美人，均非實指。", "《江行》爲岑參之作，似勿須多辨。", "」）。"]'),
('912b38fa-92f5-4a54-87a4-87f5f7957368','寒食夜蘇二宅','杜甫','唐','唐诗','tang','','[]','寒食明堪坐，春參夕已垂。',223,'全唐诗/poet.tang.52000.json','["寒食明堪坐，春參夕已垂。", "好風經柳葉，清風照花枝。", "客淚聞歌掩，歸心畏酒知。", "佳辰邀賞遍，忽忽更何爲？", "（見宋蒲積中《古今歲時雜詠》卷十一）（按：《古今歲時雜詠》各類詩均分爲古詩、今詩二部分，古詩爲宋綬《歲時雜詠》原編，今詩始爲蒲積中所輯。", "宋綬爲宋敏求之父，卒於慶曆初。", "其時王洙本《杜工部集》雖已編成，尚未刊布。", "宋綬所據材料，有爲王洙未及見者。", "《古今歲時雜詠》在宋明二代流布未廣，故治杜詩者多未見之。", "此詩各本《杜集》皆失收，今亟錄出，以供治杜者研究。", "）。"]'),
('ffca4612-5d51-42a7-bfd9-4d3045e05dbc','閬中行','杜甫','唐','唐诗','tang','','[]','豺狼當路，無地遊從。',57,'全唐诗/poet.tang.52000.json','["豺狼當路，無地遊從。", "（《雲溪友議》卷上《嚴黃門》）（按：此二句疑即杜甫《發閬中》首句「前有毒蛇後猛虎」之異傳。", "）。"]'),
('8a50b03d-2611-4c8b-8778-8422710acd15','石文詩（附存）','杜甫','唐','唐诗','tang','','[]','詩王本在陳芳國，九夜捫之麟篆熟，聲振扶桑享天福。',119,'全唐诗/poet.tang.52000.json','["詩王本在陳芳國，九夜捫之麟篆熟，聲振扶桑享天福。", "（見馮贄《雲仙雜記》卷一引《文覽》）（按：此詩可斷定非杜甫作。", "《雲仙雜記》一書，傳爲唐末人馮贄作，後人雖有疑其爲宋人僞託者，然所舉諸證尚不足以定讞。", "今仍從舊說視作唐人之作姑附存杜甫名下。", "）。"]'),
('df5dd484-77bd-458b-b489-d5af23bebf90','句','杜甫','唐','唐诗','tang','','[]','狨擲寒條馬見驚。',79,'全唐诗/poet.tang.52000.json','["狨擲寒條馬見驚。", "（見《增修詩話總龜前集》卷二引《楊文公談苑》）（按：《詩話總龜》卷十六引《零陵總記》錄杜陵《朝陽巖歌》一首，《全唐詩》卷二四一收作元結詩。", "）。"]'),
('993bb291-4506-4bd8-81c3-d3884d267fa4','順心上人山池','皇甫冉','唐','唐诗','tang','','[]','南榮對廬{馮/廾}，宴坐日於斯。',52,'全唐诗/poet.tang.52000.json','["南榮對廬{馮/廾}，宴坐日於斯。", "細草汀洲色，輕風楊柳枝。", "磬聲催暮鳥，泉影入春池。", "則異人間世，唯當幽客知。"]'),
('5239363b-2cde-4562-83bc-afbd6dbf1b2d','題陳勝林園','皇甫冉','唐','唐诗','tang','','[]','閉門不肯偶時人，荒竹閑園莫厭貧。',52,'全唐诗/poet.tang.52000.json','["閉門不肯偶時人，荒竹閑園莫厭貧。", "臘後春風能幾日？家中芳草自相親。", "（均見日本藏唐抄本《新撰類林抄》卷四）。"]'),
('31b65386-11e4-41cc-94d9-ce3aec4e0c58','醉歌 一','元結','唐','唐诗','tang','','[]','元子樂矣。',37,'全唐诗/poet.tang.52000.json','["元子樂矣。", "（元子）何樂亦然，何樂亦然？", "（和者）我雲我山，我林我泉（元子）。"]'),
('ec1fc6d5-ac3d-45a0-8efa-9f5c7cb3dd8d','醉歌 二','元結','唐','唐诗','tang','','[]','元子樂矣。',55,'全唐诗/poet.tang.52000.json','["元子樂矣。", "（元子）何樂然爾，何樂然爾？", "（和者）我鼻我目，我口我耳。", "（元子）（見《唐文粹》卷四三元結《心規》）。"]'),
('f83e61a1-7a69-4c78-8fd5-bec2eab8eb29','惡圓之士歌','元結','唐','唐诗','tang','','[]','寧方爲皁，不圓爲卿。',40,'全唐诗/poet.tang.52000.json','["寧方爲皁，不圓爲卿。", "寧方爲汙辱，不圓爲顯榮。", "（見《唐文粹》卷四三元結《惡圓》）。"]'),
('fae1c5cb-e3cc-4217-a393-39590417da00','桃花（題擬）','元結','唐','唐诗','tang','','[]','桃源自有長生路，却是秦皇不得知。',167,'全唐诗/poet.tang.52000.json','["桃源自有長生路，却是秦皇不得知。", "（見《全芳備祖前集》卷八「桃花」門）（按：《淳熙三山志》卷三十六收元結《贈靈石俱胝詩》云：「萬計千謀總不真，虛將文字役心神。", "俱胝祇念三行咒，自得名超一世人。", "」元結平生未至閩中。", "《淳熙三山志》云：「靈石俱胝院，……唐武宗時僧元修始庵於此，誦七俱胝咒治疾祟。", "」事亦在元結身後。", "疑此詩爲北宋官閩之元絳作。", "）。"]'),
('7610f47f-6378-4f25-a94f-4b058ea5175b','送賀秘監歸會稽詩','于休烈','唐','唐诗','tang','','[]','飛名紫府內，抗手白雲鄉。',62,'全唐诗/poet.tang.52000.json','["飛名紫府內，抗手白雲鄉。", "道與松喬匹，榮辭園綺行。", "夫君既鶴駕，幼子復霓裳。", "少別留宸藻，東南歸路光。", "（見《會稽掇英總集》卷二）。"]'),
('50e2339b-da5a-4711-8c4b-332bd5c3d6e6','授衣賦附歌','周存','唐','唐诗','tang','','[]','愁霜落兮歲已終，秋雁吟兮悲遠空。',47,'全唐诗/poet.tang.52000.json','["愁霜落兮歲已終，秋雁吟兮悲遠空。", "短褐不完兮憂思充，庭蕭蕭兮冷暮風。", "（見《文苑英華》卷一一三）。"]'),
('c0dd13e4-cbe3-463f-972b-60e9c7363daa','逢鄉友','杜寂','唐','唐诗','tang','','[]','苦吟吟不足，爭忍話離羣。',35,'全唐诗/poet.tang.52000.json','["苦吟吟不足，爭忍話離羣。", "（見《吟窗雜錄》卷十三梅堯臣《續金針詩格》）。"]'),
('e5c39bad-3720-4833-aa6b-fa1e15df8afb','江州臥疾送李侍御歌（題擬）','李華','唐','唐诗','tang','','[]','江沉沉兮雨淒淒，洲渚沒兮玄雲低，傷別心兮聞鼓鼙。',51,'全唐诗/poet.tang.52000.json','["江沉沉兮雨淒淒，洲渚沒兮玄雲低，傷別心兮聞鼓鼙。", "（見《文苑英華》卷七二○李華《江州臥疾送李侍御序》）。"]'),
('56e79ec3-3a80-406f-8cd0-baedd2e428aa','詠雙澗','李華','唐','唐诗','tang','','[]','千峰排碧落，雙澗合清漣。',23,'全唐诗/poet.tang.52000.json','["千峰排碧落，雙澗合清漣。", "（《記纂淵海》卷九）。"]'),
('281bc805-818c-4844-84a4-d1eed2933d8b','題像','明瓚','唐','唐诗','tang','','[]','攜筇小步踏蒼苔，遙指青山雲正開。',32,'全唐诗/poet.tang.52000.json','["攜筇小步踏蒼苔，遙指青山雲正開。", "澗水松風聽不絕，又教童子抱琴來。"]'),
('03a921a1-d4b7-4c6f-9dc1-32768f2246d8','辭名','明瓚','唐','唐诗','tang','','[]','三十年來獨掩關，使符那得到青山？',50,'全唐诗/poet.tang.52000.json','["三十年來獨掩關，使符那得到青山？", "休將瑣末人間事，換我一生林下閒。", "（以上二首均見《沅湘耆舊集》卷十）。"]'),
('08808d35-8bbe-44f6-91ee-3ad20cdbb574','樂道歌','明瓚','唐','唐诗','tang','','["\u8861\u5c71"]','兀然無事無改換，無事何須論一段。',580,'全唐诗/poet.tang.52000.json','["兀然無事無改換，無事何須論一段。", "直心無散亂，他事不須斷，過去已過去，未來更（《燈錄》作「猶」）莫（黃庭堅書本作「何用」）算。", "兀然無事坐（黃作「事」），何曾有人喚？", "向外覓功（黃作「工」）夫，總是癡頑漢。", "糧不畜一粒，逢飯但知{埶/食}（黃作「知{口馵}」，《燈錄》同黃，注：「陟立切」）。", "世間多少（黃作「事」）人，相趁渾不及。", "我不樂生（黃作「昇」）天，亦不愛福田。", "饑來喫飯（黃作「饑來一鉢飯」），困來即臥（黃作「展脚」《燈錄》無「臥」字）眠。", "愚人笑我，智乃知賢（《燈錄》作「焉」，黃作「愚人以爲笑，智者謂之然」）。", "不是癡鈍，本體如然。", "（此下黃多「非愚亦非智，不是空中去」二句）要去即去，要住即住（二「即」字，黃皆作「如是」）。", "身被（《燈錄》作「披」）一破[衲]（納）（從《燈錄》改），脚著孃生袴。", "多言復多語，由來反相悮（黃作「誤」）。", "若欲度衆生，無過且自度。", "莫謾求真佛，真佛不可見。", "妙性及靈臺，何曾受[薰]（勳）（從《燈錄》改）煉（黃作「鍊」）。", "心是無事心，面是孃生面。", "劫石可移動（黃作「動搖」），箇中難（《燈錄》作「無」）改變。", "無事本無事（黃無以上三字），何須讀文字？", "削除人我本，冥合箇中意。", "種種勞筋骨，不如林間（《燈錄》作「下」）睡兀兀。", "舉頭見日高（黃作「出」），乞飯從頭餧（《燈錄》、黃作「𢫫」）。", "將功用功，展轉冥朦。", "取則（《燈錄》作「即」）不得，不取自通。"]'),
('f7eaeae5-0fee-49e7-aeae-715c03e6749e','','鄭轅','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.52000.json','["。"]'),
('747d1cf2-9d84-47a8-a2b1-d39d93539d9a','遊枋口（幷序） 蒙泉','鄭轅','唐','唐诗','tang','','[]','丹洞吐細泉，宛轉蒼苔里。',36,'全唐诗/poet.tang.52000.json','["丹洞吐細泉，宛轉蒼苔里。", "凝碧時含光，流洩復如此。", "誰知山下泉，來洗幽人耳。"]'),
('7a6a1a4f-8cc1-4d8a-a2fa-bd9a3e2bda17','遊枋口（幷序） 薜荔壁','鄭轅','唐','唐诗','tang','','[]','薜荔生空山，幽姿媚苔壁。',36,'全唐诗/poet.tang.52000.json','["薜荔生空山，幽姿媚苔壁。", "根封石燕泥，花似乳竇滴。", "靈均沒已久，榮落誰人惜。"]'),
('c1d05337-74e6-48a3-815a-ac190bc2b198','遊枋口（幷序） 石筍高','鄭轅','唐','唐诗','tang','','[]','竦榦青山下，卓立白雲際。',156,'全唐诗/poet.tang.52000.json','["竦榦青山下，卓立白雲際。", "濯似春筠莖，奇如夏峰勢。", "賞者空往來，亭亭幾千里。", "（見乾隆二十四年刊蕭應植纂《濟源縣志》卷十六）（〖1〗《縣志》跋云：「鄭轅以下三人，《舊志》列於明時，今改正。", "《全唐詩》旁搜博採，有鄭轅，餘無考。", "」〖2〗清孫星衍《寰宇訪碑錄》卷四著錄河南濟源唐代石刻有「監察御史鄭轅詩，正書，無年月。", "」）。"]'),
('58b58857-5692-4c21-99df-956a779aae0f','','崔全素','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.52000.json','["。"]'),
('f5f2368d-9919-4da9-b5fe-472e443e2e9a','與鄭轅薛晏遊枋口同賦三韻詩（題擬） 蒙泉','崔全素','唐','唐诗','tang','','[]','溪轉聞鳴泉，林疎渲蒼蘚。',36,'全唐诗/poet.tang.52000.json','["溪轉聞鳴泉，林疎渲蒼蘚。", "䔩潔來潺湲，凝光散清淺。", "未知適所從，空山漫流衍。"]'),
('59089ba6-2a14-46ba-8865-b719744b4e7a','與鄭轅薛晏遊枋口同賦三韻詩（題擬） 薜荔壁','崔全素','唐','唐诗','tang','','[]','芳姿抱青巒，根蔓殊衆品。',36,'全唐诗/poet.tang.52000.json','["芳姿抱青巒，根蔓殊衆品。", "水淨隱簾珠，雲開露屏錦。", "瀝瀝巖風來，幽香洩清澟。"]'),
('1fb1ba4d-aabf-42ea-bdf7-e90e4a1388f2','與鄭轅薛晏遊枋口同賦三韻詩（題擬） 石筍高','崔全素','唐','唐诗','tang','','[]','石筍生孤標，屹立青冥直。',67,'全唐诗/poet.tang.52000.json','["石筍生孤標，屹立青冥直。", "根橫曉浪痕，籜卷春雲色。", "稜稜長鈞鋒，應使山魅惕。", "（同前）（按：三詩原收鄭轅詩後，題作「同賦」，今重爲擬題。", "）。"]'),
('2a654690-18d3-4083-85b7-84858d27e576','與鄭轅崔全素遊枋口同賦三韻詩（題擬） 蒙泉','薛晏','唐','唐诗','tang','','[]','嘖蘇出深竇，欣然傍欹壁。',36,'全唐诗/poet.tang.52000.json','["嘖蘇出深竇，欣然傍欹壁。", "清潄疎林澄，光淨寒石白。", "一勞意渴甚，挽翫此水碧。"]'),
('ad34e693-70ab-4dbf-a35c-2b2459937c20','與鄭轅崔全素遊枋口同賦三韻詩（題擬） 薜荔壁','薛晏','唐','唐诗','tang','','[]','誰種薜荔花？盤根上幽石。',36,'全唐诗/poet.tang.52000.json','["誰種薜荔花？盤根上幽石。", "玲瓏珠綴曉，香靄岑嵐夕。", "却誤貪寢人，遺衣挂苔壁。"]'),
('ea01b8c5-d10b-4064-9c3f-8af9c8c80090','與鄭轅崔全素遊枋口同賦三韻詩（題擬） 石筍高','薛晏','唐','唐诗','tang','','[]','峭筍倚溪壖，雄標屹霞境。',71,'全唐诗/poet.tang.52000.json','["峭筍倚溪壖，雄標屹霞境。", "雲披看卷籜，波靜見垂影。", "頓翼已棲林，殘陽方在頂。", "（同前）（按：三詩原收鄭轅、崔全素詩後，題作「同賦」，今重爲擬題。", "）。"]'),
('8076267f-1af6-4e11-9ed5-41d1116bcdce','偈','應真','唐','唐诗','tang','','[]','湘之南，潭之北，中有黃金充一國。',100,'全唐诗/poet.tang.52000.json','["湘之南，潭之北，中有黃金充一國。", "無影樹下合同船，琉璃殿上無知識。", "（見《景德傳燈錄》卷六，、《五燈會元》卷二、《佛祖歷代通載》卷十四、《釋氏稽古略》卷三、《江西詩徵》卷八七、日本《大燈國師語錄》卷下）。"]'),
('1fd67a6d-84e8-406b-80ac-d6af8b7f5f7e','題琅琊山寺道標道揖二上人東峰禪室時助成此□□築斯地','李幼卿','唐','唐诗','tang','','[]','佛寺秋山裏，僧堂絕頂邊。',155,'全唐诗/poet.tang.52000.json','["佛寺秋山裏，僧堂絕頂邊。", "同依妙樂土，別占淨居天。", "轉壁千林合，歸房一逕穿。", "豁心羣壑盡，駭目半空懸。", "錫杖棲雲濕，繩床挂月圓。", "經行躡霞雨，跬步隔嵐煙。", "地勝情非繫，言忘意可傳。", "憑虛堪喻道，封境自安禪。", "每貯歸休巔，多慙愛深偏。", "助君成此地，一到一留連。", "（安徽人民出版社出版《瑯琊山石刻選》載拓片。", "此詩承周勳初先生錄示。", "）。"]'),
('d737b4e8-f999-4220-a1a5-f4b32722530d','偈','無住','唐','唐诗','tang','','[]','婦是沒耳伽，男女蘭單杻。',34,'全唐诗/poet.tang.52000.json','["婦是沒耳伽，男女蘭單杻。", "爾是沒價奴，至老不得走。", "（《歷代法寶記》）。"]'),
('7da062bc-1481-411a-ace5-d81fc32f52b1','茶偈','無住','唐','唐诗','tang','','[]','幽谷生靈草，堪爲入道媒。',53,'全唐诗/poet.tang.52000.json','["幽谷生靈草，堪爲入道媒。", "樵人採其葉，美味入流杯。", "靜虛澄虛識，明心照會臺。", "不勞人氣力，直聳法門開。", "（同前）。"]'),
('9c8af96c-4e31-483f-901c-1ec981045449','故功德使涼國公李將軍挽歌詞二首 一','趙遷','唐','唐诗','tang','','[]','業盛唐堯際，功成文子軍。',48,'全唐诗/poet.tang.52000.json','["業盛唐堯際，功成文子軍。", "累承三帝寵，六比五臣勳。", "畫角悲寒吹，愁笳咽曉雲。", "聖朝忠義骨，今日委荒墳。"]'),
('7e2844a8-01ef-425e-a99b-92005348b64a','故功德使涼國公李將軍挽歌詞二首 二','趙遷','唐','唐诗','tang','','[]','大樹悲風起，將軍去不迴。',170,'全唐诗/poet.tang.52000.json','["大樹悲風起，將軍去不迴。", "撫棺心益痛，臨穴淚難裁。", "曉月繁霜草，幽泉掩夜臺。", "更聞歌伴哭，觸物盡成哀。", "（見《大正新修大藏經》第五十二冊釋圓照集《代宗朝贈司空大辨正廣智三藏和上〖即不空〗表制集》卷五）（按：二詩題下署「前左領軍衛兵曹參軍翰林待詔趙遷」。", "同書卷六有同人大曆十一年《賀平李靈曜表》。", "同人撰《不空行狀》見《大正新修大藏經》卷四十九冊。", "）。"]'),
('2a1fc436-c486-444d-8e2e-4abf68ffa44a','揚州崔行軍水亭泛舟望月醼集賦詩（幷序）','獨孤及','唐','唐诗','tang','','[]','明月借秋興，流光在此池。',75,'全唐诗/poet.tang.52000.json','["明月借秋興，流光在此池。", "山公顧我厚，酩酊稱未疲。", "勿謂嘉會易，但憂離別隨。", "飽君醉中德，敢使松心移。", "（見《四部叢刊初編》影清趙懷玉刊本《毘陵集》卷十六）。"]'),
('beb9e2a3-0a0a-4b10-a721-d84a87f61eab','登姑蘇臺賦附歌','任公叔','唐','唐诗','tang','','[]','中心不必兮子胥何爲？',59,'全唐诗/poet.tang.52000.json','["中心不必兮子胥何爲？", "懷直道而驟諫，遭重昏之見危。", "將漁父以抗迹，且垂釣於江湄。", "（見《文苑英華》卷五二《登姑蘇臺賦》附）。"]'),
('f9ef58b4-40ff-4e25-95b9-e38f305365e8','句','張謂','唐','唐诗','tang','','[]','家無阿堵物，門有寧馨兒。',37,'全唐诗/poet.tang.52000.json','["家無阿堵物，門有寧馨兒。", "（見宋莊季裕《雞肋編》卷下、高似孫《緯略》卷一）。"]'),
('35d23269-c6b5-4b8c-a653-ba618e4ecf28','句','崔峒','唐','唐诗','tang','','[]','石梯青嶂下，茅屋白雲間。',35,'全唐诗/poet.tang.52000.json','["石梯青嶂下，茅屋白雲間。", "（見明刻本《錦繡萬花谷》卷二十五「隱逸」門）。"]'),
('2bf2a16e-c9e4-4807-a2d5-4d9b9965ced1','句 一','吳筠','唐','唐诗','tang','','[]','家住青山下，時向青山上。',33,'全唐诗/poet.tang.52000.json','["家住青山下，時向青山上。", "（見宋談鑰《嘉泰吳興志》卷四「青山」條）。"]'),
('31ce9d65-6cb1-4b03-8e60-700a5c494150','句 二','吳筠','唐','唐诗','tang','','[]','垂花臨碧澗，清翠依丹巘。',28,'全唐诗/poet.tang.52000.json','["垂花臨碧澗，清翠依丹巘。", "（《全芳備祖後集》卷七《棗》）。"]'),
('d0c8d457-ff2f-437e-9fe9-bee08c71a3de','消暑樓詩','崔載華','唐','唐诗','tang','','[]','卷簾對斜橋。',27,'全唐诗/poet.tang.52000.json','["卷簾對斜橋。", "（見《嘉泰吳興志》卷十九「霅溪支港」條）。"]'),
('29ff157f-46c5-491a-8b80-ef0e991bad04','望歸舟','張繼','唐','唐诗','tang','','[]','暮春（《適園叢書》本《後村詩話》作「莫莫」）望歸客，依依江上船。',77,'全唐诗/poet.tang.52000.json','["暮春（《適園叢書》本《後村詩話》作「莫莫」）望歸客，依依江上船。", "潮落猶有信，去楫未知旋。", "（見《後邨先生大全集》卷一七七《詩話續集》引李康成《玉臺後集》）。"]'),
('6287fc36-a7b0-4be5-8865-ad3214b18972','代書索鏡','張繼','唐','唐诗','tang','','[]','情親留故鏡，賤子感遺簪。',82,'全唐诗/poet.tang.52000.json','["情親留故鏡，賤子感遺簪。", "漢月經時掩，胡[塵與]歲深。", "珠還仍向浦，鵲遶會歸林。", "早晚清光至，窺予白髮親。", "（影印本《詩淵》第二冊第一五三二頁，所缺二字據《詩式》卷四補）。"]'),
('074373eb-91ac-4db6-b4fc-1c862b42e919','剡縣法臺寺灌頂壇詩','張繼','唐','唐诗','tang','','[]','九燈傳像法，七夜會龍華。',57,'全唐诗/poet.tang.52000.json','["九燈傳像法，七夜會龍華。", "月靜金田廣，幡搖銀漢斜。", "香壇分地位，寶印辨根牙。", "試問因緣者，清溪無數沙。", "（《剡錄》卷八）。"]'),
('832e82e2-fc4a-48cc-a14a-6a5fed6cb505','送客','張繼','唐','唐诗','tang','','[]','頻年獨對鴛鴦綺，計日雙飛鸚鵡洲。',37,'全唐诗/poet.tang.52000.json','["頻年獨對鴛鴦綺，計日雙飛鸚鵡洲。", "（見宋王象之《輿地紀勝》卷六七《鄂州》）。"]'),
('918b289d-ac15-4b0f-a28f-d1fa352cf7d8','酬李端得山中道友書見寄之作（題擬）','苗發','唐','唐诗','tang','','[]','馬融方直校，閱檢復持鉛。',330,'全唐诗/poet.tang.52000.json','["馬融方直校，閱檢復持鉛。", "素業高風繼，青春壯思全。", "論文多在夜，宿寺不虛年。", "自署區中職，同荒郭外田。", "山鄰三徑絕，野意八行傳。", "煮玉矜新法，留符識舊仙。", "涵苔溪溜淺，搖浪竹橋懸。", "複洞潛棲燕，疏楊半翳蟬。", "詠歌雖有和，雲錦獨成妍。", "應以馮唐老，相譏示此篇。", "（見江標影宋書棚本《李端詩集》卷三）（按：《全唐詩》卷二八六以此詩爲李端詩，題作「酬前駕部員外郎苗發」，實誤。", "檢影宋書棚本此詩附於李端《得山中道友書寄苗錢二員外》後，題作「酬前」，下署「駕部員外郎苗發」，殆爲苗發酬答李端見寄之作而附入李端集者。", "後代輾轉刻印，誤將苗發職銜與詩題相連，遂誤成端詩。", "類似情況，在唐人原集中甚常見，如竇叔向詩誤歸已經繼之類，岑仲勉、李嘉言二先生已指出。", "苗發與張芬詩誤歸李端，亦屬同類型錯誤。", "）。"]'),
('5c1bbfc0-f4f0-450b-8051-f9da918ecc7a','垂白之老擊壤歌（題擬）','李子卿','唐','唐诗','tang','','[]','功成作樂兮帝力則那，樂正崇德兮雅頌則多，雲門之典兮大呂之歌，金石節奏兮絲竹駢羅，天地已正兮神人以和，兩堦舞羽兮三邊止戈，擊壤鼓腹兮不識其他。',107,'全唐诗/poet.tang.52000.json','["功成作樂兮帝力則那，樂正崇德兮雅頌則多，雲門之典兮大呂之歌，金石節奏兮絲竹駢羅，天地已正兮神人以和，兩堦舞羽兮三邊止戈，擊壤鼓腹兮不識其他。", "客有獻成功之頌，九重深兮其若何！（見《文苑英華》卷七四《功成作樂賦》附）。"]'),
('253963e5-b435-4d32-b807-52559fa9ba5c','授衣歌（題擬）','李子卿','唐','唐诗','tang','','[]','天之高兮無不覆，君之大兮無不祐。',78,'全唐诗/poet.tang.52000.json','["天之高兮無不覆，君之大兮無不祐。", "生人殖物，既庶且富。", "爾在（原注：「疑」）于時，爾茅于晝。", "霜始降兮女工就，歲時窮兮寒衣授。", "（見同書卷一一三《府試授衣賦》附）。"]'),
('fb130508-dbb5-4e51-b54d-78603a7e98a1','投龍洞','玄覽','唐','唐诗','tang','','[]','水溜空沿石，雲扃不見人。',44,'全唐诗/poet.tang.52000.json','["水溜空沿石，雲扃不見人。", "川源世上異，日月洞中春。", "（見《輿地紀勝》卷二《臨安府·名勝》）。"]'),
('9dddbcd8-cc6d-4bd6-8bb4-6661e757a7b8','題戴徵君幽居','王綬','唐','唐诗','tang','','[]','高臥雲煙外，幽居靜者心。',132,'全唐诗/poet.tang.52000.json','["高臥雲煙外，幽居靜者心。", "門庭新種竹，桃李舊成林。", "窗戶泉聲入，池塘柳色深。", "松花多醴酒，終日會知音。", "（日本藏唐抄本《新撰類林抄》卷四）（按：《李端詩集》卷中有《送戴徵士還山》，戴徵士、戴徵君當爲同一人，因知王綬與李端同時。", "《新撰類林抄》收詩以開元、大曆間作者爲主。", "）。"]'),
('f51adf32-5061-401b-bc7e-bd3a9375773b','五言登郡北佛龕一首','李嘉祐','唐','唐诗','tang','','[]','石壁江城後，籃輿晚蹔登。',48,'全唐诗/poet.tang.52000.json','["石壁江城後，籃輿晚蹔登。", "古龕千塔佛，秋樹一山僧。", "清磬和虛籟，香泉吐暗藤。", "願將身灑掃，求官復作能。"]'),
('3162926e-b85e-4d1d-83a3-6630a17a40d4','七言謁倍城縣南香積寺老師一首','李嘉祐','唐','唐诗','tang','','[]','竹林青青山寺幽，老僧禪坐對江流。',67,'全唐诗/poet.tang.52000.json','["竹林青青山寺幽，老僧禪坐對江流。", "長眉（塵）亷襜寂不語，能令過客小低頭。", "黃昏鐘竟香煙起，行舟去去心何已。", "回看石壁蓮花宮，紗燈一點蒙籠裏。"]'),
('adae3c85-305a-46b9-9050-6c83342db983','七言登北山寺西閣樓馮禪師茶酌贈崔少府一首','李嘉祐','唐','唐诗','tang','','[]','開[士]（土）相逢暮飲茶，高樓並坐望三巴。',145,'全唐诗/poet.tang.52000.json','["開[士]（土）相逢暮飲茶，高樓並坐望三巴。", "碧嶂不知何劫石，清江流盡幾恒沙。", "鑪煙處處香慈竹，溪雨朝朝潤覺花。", "道勝自然長法喜，應令遷客小溈華。", "（均見日本藏唐抄本《唐詩卷》）（按：《咸淳毘陵志》卷二十二收嘉祐《寄毘陵徹公》詩，《全唐詩》卷五七三收作賈島詩，孰作尚難確定，姑附識於此，以俟考詳。", "）。"]'),
('dfecdba6-72c7-48b3-9868-47ecbc9bf09f','題杜舍人林亭','錢起','唐','唐诗','tang','','[]','來訪龍樓客，時逢酒甕新。',107,'全唐诗/poet.tang.52000.json','["來訪龍樓客，時逢酒甕新。", "花齊雲入幕，苔徑竹迎人。", "鵲喜嬌遲日，鶯啼惜暮春。", "不須耽小隱，南院在平津。", "（見元駱天驤《類編長安志》卷九勝遊類樊川范公五居條引，據《中國古都研究》收黃永年先生《述〈類編長安志〉》一文轉引。", "）。"]'),
('e601bc5a-6acf-49f4-8af5-6bea6a024459','宿雲門寺','錢起','唐','唐诗','tang','','[]','山寺宜靜夜，禪房開竹扉。',62,'全唐诗/poet.tang.52000.json','["山寺宜靜夜，禪房開竹扉。", "支公方晤語，孤月復清暉。", "一磬響丹壑，千燈明翠微。", "平生厭浮世，茲夕更忘歸。", "（見《會稽掇英總集》卷六）。"]'),
('0738e46b-851f-4ef8-b506-fa6edf97856d','芝草（題擬）','錢起','唐','唐诗','tang','','[]','豈如玉殿生三秀，詎有銅池出五雲。',63,'全唐诗/poet.tang.52000.json','["豈如玉殿生三秀，詎有銅池出五雲。", "陌上堯樽傾北斗，樓前舜樂動南薰。", "（《全芳備祖後集》卷十一《芝草》。", "此四句爲「七言律詩散聯」）。"]'),
('26a05d92-10f6-4ba3-957c-aa80ed13f000','芭蕉（題擬）','錢起','唐','唐诗','tang','','[]','幸有青絲用，寧將衆草同。',61,'全唐诗/poet.tang.52000.json','["幸有青絲用，寧將衆草同。", "心虛含夕露，葉大怯秋風。", "細響安禪後，濃陰坐夏中。", "由來何所喻，持以問支公。", "（見前書卷十三《芭蕉》）。"]'),
('1b5c53bf-05b8-4c71-aa60-960d0db64d10','送友人入蜀','錢起','唐','唐诗','tang','','[]','遠路接天末，怪君與我違。',62,'全唐诗/poet.tang.52000.json','["遠路接天末，怪君與我違。", "客程千嶂裏，鳥道片雲飛。", "樹色連青漢，泉聲出翠微。", "錦城花月下，才子定忘歸。", "（見《全蜀藝文志》卷二十）。"]'),
('5bd6e892-cfff-45c6-bd9b-88e9d1543eb9','送歸客','錢起','唐','唐诗','tang','','[]','京口三秋衰葉落，潯陽千里暮潮生。',35,'全唐诗/poet.tang.52000.json','["京口三秋衰葉落，潯陽千里暮潮生。", "（《千載佳句》卷下《別離部·行旅》）。"]'),
('ceb6de3c-e926-4870-9338-010e17057af6','贈錢起（題擬）','楊員外','唐','唐诗','tang','','[]','黃卷讀來今已老，白頭受屈不曾言。',154,'全唐诗/poet.tang.52000.json','["黃卷讀來今已老，白頭受屈不曾言。", "（見《錢考功集》卷八《酬考功楊員外見贈佳句》自注引）（按：《郎官石柱題名》考功員外郎一欄殘泐過甚，存名僅五十二人，無楊姓者。", "勞《考》卷十復自羣書採摭補遺，有楊於陵貞元八年後曾任此職，其時已較後。", "頗此人即與錢起有過往之楊綰，然兩《唐書》本傳皆不云其任考外事。", "姑存疑以俟考詳。", "）。"]'),
('38d01423-e62a-4473-8f9b-4f10f6c0aa1b','遊荆溪','嚴維','唐','唐诗','tang','','[]','銅官之山溪水南，周處廟前多夕嵐。',85,'全唐诗/poet.tang.52000.json','["銅官之山溪水南，周處廟前多夕嵐。", "看捲雲帆歌白苧，勸嘗春酒破黃柑。", "長林獨往誰能覓，幽事相關性所耽。", "若欲避喧那畏虎，尚從地主結松龕。", "（見嘉慶二年刊寧楷等纂《宜興縣志》卷十）。"]'),
('6a5ef821-6aab-4773-9c33-0bf715b24bd1','劍詩','嚴維','唐','唐诗','tang','','[]','舞揮秦日月，爲整漢山河。',35,'全唐诗/poet.tang.52000.json','["舞揮秦日月，爲整漢山河。", "（見《吟窗雜錄》卷十四正字王玄《詩中旨格》）。"]'),
('fcbdf61c-2e67-4241-9fec-e88280cc4207','句','嚴維','唐','唐诗','tang','','[]','觀身岸額離根草，論命江頭不繫舟。',128,'全唐诗/poet.tang.52000.json','["觀身岸額離根草，論命江頭不繫舟。", "（見《日本古典文學大系》七三冊藤原公任《和漢朗詠集》卷下《無常》）（〖1〗川口久雄校注《和漢朗詠集》云：「底本注作者爲『羅維』，柿村氏以爲『羅維當係嚴維之誤』。", "」其說是。", "《全唐詩》卷七七○收羅維《水精環》，即爲嚴維之誤。", "）。"]'),
('ce7c2bed-34fe-49d3-a68f-bc3361099686','贈王叔雅兄弟（題擬）','嚴維','唐','唐诗','tang','','[]','萬里天連水，孤舟弟與兄。',54,'全唐诗/poet.tang.52000.json','["萬里天連水，孤舟弟與兄。", "（見《古刻叢抄》收唐許志雍撰《唐故江南西道觀察判官監察御史裏行太原王公墓誌銘》引）。"]'),
('a10962a4-cc5c-4994-8c13-7e0f61b43abe','頌鮮于叔明（題擬）','嚴氏','唐','唐诗','tang','','[]','三院四人簪白筆，一門三鎮擁朱幡。',105,'全唐诗/poet.tang.52000.json','["三院四人簪白筆，一門三鎮擁朱幡。", "（見《輿地紀勝》卷一五四《潼川軍》引《潼川舊記》引《鮮于叔明神道碑》載）（按：《舊唐書》卷一二二《李叔明傳》謂「大曆末，有閬州嚴氏子上疏」云云，因知此二句詩作者，爲大曆末人。", "）。"]'),
('04b5990c-8295-49ec-94fd-c03e691d2d44','珮賦附歌','胡運','唐','唐诗','tang','','[]','佩玉蘂兮德音發，中規矩兮聲不歇。',63,'全唐诗/poet.tang.52000.json','["佩玉蘂兮德音發，中規矩兮聲不歇。", "馳畋獵兮思敬慎，壽考不亡兮長歲月。", "端法服兮臨魏闕，羣后覲兮萬方謁。", "（見《文苑英華》卷一一一）。"]'),
('3d3c39ee-61c7-423e-9e11-f3658fcbc74e','','崔生','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.52000.json','["。"]'),
('253393f9-badf-4fb0-9345-b13b5ca48a2c','思紅綃妓詩（題擬）','崔生','唐','唐诗','tang','','[]','誤到蓬山頂上遊，明璫玉女動星眸。',51,'全唐诗/poet.tang.52000.json','["誤到蓬山頂上遊，明璫玉女動星眸。", "朱扉半掩深宮月，應照璚芝雪豔愁。", "（見《太平廣記》卷一九四引《傳奇》）。"]'),
('bb06f985-3a45-400d-8c7d-1bddd1598345','同李使君渭遊等慈寺（題擬）','崔公輔','唐','唐诗','tang','','[]','淮陽清靜理，永嘉山水心。',150,'全唐诗/poet.tang.52000.json','["淮陽清靜理，永嘉山水心。", "（見《輿地紀勝》卷一五七《資州》）（〖1〗《輿地紀勝》云：「李渭爲本州刺史，有詩刻留等慈寺。", "時與前進士崔公輔同遊，崔有詩略曰：『淮陽清靜理，永嘉山水心。", "』」二句爲公輔頌渭之作。", "《全唐詩續補遺》卷十九據《蜀中名勝記》收作李渭詩，誤。", "又《杜少陵集》卷十五有《贈崔十三評事公輔》）。"]'),
('b7744bc5-b9a7-4211-ba29-0054f8e2905c','','路應','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('276d593e-07af-4711-b847-5fa0b6aa0c69','游南雁蕩','路應','唐','唐诗','tang','','[]','雁蕩峯高豈易梯，筇鞋極處與天齊。',115,'全唐诗/poet.tang.53000.json','["雁蕩峯高豈易梯，筇鞋極處與天齊。", "蟾宮隱隱步將到，日駕亭亭手可提。", "織女支機堪索石，仙翁花雨不霑泥。", "詩懷到此清如許，欲向銀河蘸筆題。", "（見周喟《南雁蕩山志》卷七《詩外編》引陳玭《嘉靖南雁蕩山志》）（按：路應詩及小傳皆承張靖同志錄示。", "）。"]'),
('76274435-8ce2-4204-af1a-1b2fbb28c51f','贈饒州韋之晉別駕','朱灣','唐','唐诗','tang','','[]','天道不可問，問天天杳冥。',295,'全唐诗/poet.tang.53000.json','["天道不可問，問天天杳冥。", "如何正月霜，百卉皆凋零。", "爝火亂白日，夜光雜飛螢。", "賈生賢大夫，所以離漢庭。", "河色本異洛，渭流頗殊涇。", "清濁共朝宗，滔滔曾莫停。", "巨川用舟楫，傅說匡武丁。", "大船膠潢洿，不使濟滄溟。", "中夜擊唾壺，仰頭望天庚。", "三台位尚闕，羣象徒熒熒。", "鸞翮時暫鎩，龍門晝常扃。", "心傾下士盡，眼顧貧交青。", "幽室養虛白，香茶陶性靈。", "應將混榮辱，詎肯甘羶腥。", "至道是吾本，浮雲勞我形。", "手中菩提子，身外《蓮花經》。", "興來步出門，長嘯臨江亭。", "毫端灑垂露，賦裏搖文星。", "大音比呌鐘，大智同挈缾。", "巴歌利節曲，布鼓隨雷霆。", "陋巷一簟食，在原雙鶺[鴒]（領）。", "每懷受施恩，長記座右銘。", "食惠飽復飯，飲仁醉還醒。", "綿綿寄生葉，泛泛無根萍。"]'),
('6c462775-1484-40d4-b373-c2959effbefb','韋使君席詠拗籠籌得茲字','朱灣','唐','唐诗','tang','','[]','幸得陪樽俎，良籌復在茲。',62,'全唐诗/poet.tang.53000.json','["幸得陪樽俎，良籌復在茲。", "獻酬君有禮，賞罰我無私。", "莫怪斜相向，還將正自持。", "一朝權入手，看取令行時。", "（同前第二冊第一三二○頁）。"]'),
('a13c4fc7-78fe-4427-9a63-49b6b30c115a','題潘岳六城南莊莊是源贊善處','陳潤','唐','唐诗','tang','','[]','原公舊路唯三徑，潘岳新年已二毛。',134,'全唐诗/poet.tang.53000.json','["原公舊路唯三徑，潘岳新年已二毛。", "（《千載佳句》卷上《人事部·閑居》）（按：《全唐詩逸》卷中誤收此詩爲溫達作，今移正。", "又《全唐詩逸》卷中據《文鏡秘府論》天卷錄陳閏《罷官後却歸舊居詩》，別作一人，實誤。", "陳閏應即陳潤，《文苑英華》卷一五七、卷二九八錄潤詩皆作陳閏，可證。", "）。"]'),
('e7d2356a-0ac3-429b-a110-616e94e4d3d7','呈史君（名巖） 一','楊旬','唐','唐诗','tang','','[]','夔郡楊椿作狀元，爲文司權四十年。',32,'全唐诗/poet.tang.53000.json','["夔郡楊椿作狀元，爲文司權四十年。", "推情貸活人無數，累積陰功感上天。"]'),
('5bdd082e-17df-4824-b4c1-313cf3f2d3f3','呈史君（名巖） 二','楊旬','唐','唐诗','tang','','[]','人道公門不可入，我道公門好修行。',124,'全唐诗/poet.tang.53000.json','["人道公門不可入，我道公門好修行。", "若使曲直無顛倒，脚踏蓮花步步生。", "（《卐續藏經》本宋佚名《金剛經感應傳》）（按：《金剛經感應傳》云楊旬常持《金剛》、《般若》，感動上天，其子楊椿省試得九十六名，殿試魁天下。", "所述科舉之事，顯爲宋制，疑詩亦爲宋人依託。", "）。"]'),
('4adaef0a-5fa6-4781-9f55-0b852991cfd1','寄姜窈窕詩','張叔良','唐','唐诗','tang','','[]','几上博山靜不焚，匡牀愁臥對斜曛。',47,'全唐诗/poet.tang.53000.json','["几上博山靜不焚，匡牀愁臥對斜曛。", "犀梳寶鏡人何處？半枕蘭香空綠雲。", "（《瑯嬛記》卷上引《本傳》）。"]'),
('e7e1a962-1ac9-4248-8374-4ab7a457f6d5','詩','姜窈窕','唐','唐诗','tang','','[]','數行心因鯉魚傳，輕放金鈎繡帳懸。',183,'全唐诗/poet.tang.53000.json','["數行心因鯉魚傳，輕放金鈎繡帳懸。", "不是嬌慵貪晝臥，衆中無處看花牋。", "（同前卷下引《本傳》）（按：《瑯嬛記》云「張叔良字房卿，大曆中與姜窈窕相悅」。", "錄二人詩三首。", "今檢《唐詩紀事》卷三一載，張叔良爲廣德二年登進士第，與此云大曆相合。", "姜窈窕詩二首，其中《春思》「門前梅柳爛春輝」一首，《全唐詩》卷八○二作張窈窕詩。", "張、姜故事，或出後人附會，而詩作則似別有依據，故仍錄存之。", "）。"]'),
('06b02b4d-d426-4035-aa63-38d3db703d8d','','張翔','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('00a801a4-e0ed-4d90-bfc1-549d2be20266','經羅淵弔屈原','張翔','唐','唐诗','tang','','[]','讜言忠諫阻春霄，放逐南荒澤國遙。',95,'全唐诗/poet.tang.53000.json','["讜言忠諫阻春霄，放逐南荒澤國遙。", "五夢楚蘭香易染，一魂香水渺難招。", "風聲落日心逾壯，魚腹終天恨未消。", "却借微香薦蘋藻，海門何處問漁樵？", "（光緒《湘陰縣圖志》卷四。", "此詩及張翔事跡，皆從陶敏先生所告）。"]'),
('07856e1d-7b5a-45d6-b4d4-5400925efb14','浮萍賦附歌','常袞','唐','唐诗','tang','','[]','大江之水東西流，別有孤萍朝夕浮。',46,'全唐诗/poet.tang.53000.json','["大江之水東西流，別有孤萍朝夕浮。", "莫言此中長汎汎，終當結實觸王舟。", "（見《文苑英華》卷一四九）。"]'),
('13885a73-2f4a-4027-acea-0b225b5034b1','太原進鐵鏡賦附歌','喬琳','唐','唐诗','tang','','[]','金之精兮衆寶所參，鏡之明兮羣象所含。',50,'全唐诗/poet.tang.53000.json','["金之精兮衆寶所參，鏡之明兮羣象所含。", "清至瑩兮氛埃不雜，明至察兮醜類相慙。", "（見《文苑英華》卷一○五）。"]'),
('61833461-f5c3-40d8-b7bf-b5ece0f9207c','大曆年浙東聯唱集 松花壇茶宴聯句（元本不注名姓於聯句下）','浙東衆詩人','唐','唐诗','tang','','[]','幾歲松花下，今來草色平。',216,'全唐诗/poet.tang.53000.json','["幾歲松花下，今來草色平。", "衣冠遊佛剎，鼓角望軍城。", "亂竹邊溪暗，孤雲向嶺明。", "遶壇煙樹老，入殿雨花輕。", "山磬入天界，風泉遠近聲。", "夜禪三世晤，朝梵一章清。", "上砌莓苔遍，緣窗薜荔生。", "焚香忘世慮，啜茗長幽情。", "聚土何年置，修心此地成。", "道緣雲起滅，人世月虧盈。", "蟬噪林當曉，虹生澗欲晴。", "水流驚歲序，塵網悟簪纓。", "池上蓮無著，籬間槿自榮。", "因知性不染，更識理常精。", "從此應貪味，非惟悔近名。", "山棲多自愜，林臥欲無營。", "已接追凉處，仍陪問法行。", "賞心殊未遍，惆悵暮鐘鳴。"]'),
('a51031fd-0f94-4ba2-a7ce-afc85fee7bc2','大曆年浙東聯唱集 尋法華寺西溪聯句','浙東衆詩人','唐','唐诗','tang','','[]','（賈弇陳允初呂渭張叔政〖肅代間人，《全唐文》卷四三六存《對棄農判》一篇〗鮑防周頌〖京兆人，天寶進士，永泰中爲慈溪令，官至大理寺司直。',368,'全唐诗/poet.tang.53000.json','["（賈弇陳允初呂渭張叔政〖肅代間人，《全唐文》卷四三六存《對棄農判》一篇〗鮑防周頌〖京兆人，天寶進士，永泰中爲慈溪令，官至大理寺司直。", "據《元和姓纂》卷五、《太平廣記》卷三八二、《登科記考》卷二七〗□成用〖不詳〗鄭槩嚴維）常願山水遊，靈奇賞皆遍。", "（賈弇）雲端訪潭洞，林下徵茂彥。", "（允初）枕石愛閑眠，尋源樂清宴。", "（呂渭）探幽漸有趣，憑險恣流眄。", "（張叔政）竹影思挂冠，湍聲忘搖扇。", "（鮑防）旁登樵子徑，却望金人殿。", "（周頌）蘿葉朝架煙，松花暮飛霰。", "（□成用）蟬聲掩清管，雲色緣素練。", "（鄭槩）從事暮澄清，看以得方便。", "（嚴維）攀崖屢迴互，絕迹無健羨。", "（允初）野客歸路逢，山僧入林見。", "（賈弇）雲林會獨往，世道從交戰。", "（鮑防）塔廟年代深，雲霞朝夕變。", "（周頌）潛流注隈隩，觸石乍踐濺。", "（□用）逸興發山林，道情忘貴賤。", "（鄭槩）臨流日復夕，應接空無倦。", "（嚴維）。"]'),
('068726af-a513-4549-a172-4e0cb3edf698','大曆年浙東聯唱集 雲門寺小溪茶宴懷院中諸公','浙東衆詩人','唐','唐诗','tang','','[]','（嚴維謝良弼〖謝良輔之昆仲，曾任中書舍人。',192,'全唐诗/poet.tang.53000.json','["（嚴維謝良弼〖謝良輔之昆仲，曾任中書舍人。", "據顧況《禮部員外郎陶氏集序》〗裴晃〖不詳〗呂渭鄭槩陳允初庾騤〖不詳〗賈肅〖不詳〗）喜從林下會，還憶府中賢。", "（嚴維）石門雲路裏，花宮玉笥前。", "（謝良弼）日移侵岸竹，溪引出山泉。", "（裴晃）猨飲無人處，琴聽淺溜邊。", "（呂渭）黃粱誰共飯，香茗憶同煎。", "（鄭槩）暫與真僧對，遙知靜者便。", "（允初）清言皆亹亹，佳句又翩翩。", "（庾騤）竟日懷君子，沉吟對暮天。", "（賈肅）。"]'),
('f32b3e1b-9802-41ff-aa6e-f9df924eec2e','大曆年浙東聯唱集 徵鏡湖故事','浙東衆詩人','唐','唐诗','tang','','[]','將尋[煉]（練）（從《緯略》卷十改，《剡溪》卷六作「鍊」）藥井，更逐賣樵風。',238,'全唐诗/poet.tang.53000.json','["將尋[煉]（練）（從《緯略》卷十改，《剡溪》卷六作「鍊」）藥井，更逐賣樵風。", "（允初。", "《剡溪》誤作「凡初」）刻石秦（《剡溪》作「泰」）山上，探書禹穴中。", "（呂渭）溪邊尋五老，橋上覓雙童。", "（嚴維）梅市西陵近，蘭亭上道通。", "（謝良弼）雷門驚鶴去，射的驗年豐。", "（賈肅）古寺思王令，孤潭憶謝公。", "（鄭槩）帆開巖上石，劍出浦間銅。", "（庾騤）興裏還尋戴，東山更向東。", "（裴晃。", "《歷代詩話》本《韻語陽秋》卷五引作「裴勉」，《類編》本作「裴冕」，均誤。", "影宋本《韻語陽秋》及《剡錄》均作「裴晃」，不誤。", "）。"]'),
('ce800899-3b4a-4256-9245-09c3dc21b5cd','大曆年浙東聯唱集 自雲門還泛若耶入鏡湖寄院中諸公','浙東衆詩人','唐','唐诗','tang','','[]','（謝良弼呂渭鄭槩嚴維裴晃陳允初蕭幼和〖不詳〗）山中秋賞罷，溪上晚歸時。',138,'全唐诗/poet.tang.53000.json','["（謝良弼呂渭鄭槩嚴維裴晃陳允初蕭幼和〖不詳〗）山中秋賞罷，溪上晚歸時。", "（謝良弼）出谷秦人望，經湖謝客期。", "（呂渭）日斜愁路遠，風橫畏舟遲。", "（鄭槩）章句懷文友，途程問檝師。", "（嚴維）淺沙遊蚌蛤，危石起鸕鷀。", "（裴晃）落葉飛孤戍，橫塘向古祠。", "（允初）行行多興逸，無處不相思。", "（蕭幼和）。"]'),
('0dd34820-9738-49f0-9e61-2225e9359fa8','大曆年浙東聯唱集 秋日宴嚴長史宅','浙東衆詩人','唐','唐诗','tang','','[]','（鄭槩裴晃嚴維徐嶷〖東海人。',241,'全唐诗/poet.tang.53000.json','["（鄭槩裴晃嚴維徐嶷〖東海人。", "《宋高僧傳》卷十五〗張著〖字處晦，常山人。", "鷟孫，任剡尉，著《翰林盛事》一卷。", "據《直齋書錄解題》卷五〗范絳〖不詳〗劉全白沈仲昌闕名）北客來江外，秋山到越中。", "（鄭槩）故交多此見，清興復能同。", "（裴晃）落木秦山近，衡門鏡水通。", "（嚴維）簷前苔繞砌，籬下菊成叢。", "（徐嶷）泫泫花承露，泠泠葉動風。", "（鄭槩）卷簾看彩翠，對酒命絲桐。", "（張著）戊日辭巢燕，商天向浦鴻。", "（范絳）騫開通細雨，笑語望秋空。", "（劉全白）嬾竹霜天綠，殘花醉裏紅。", "（仲昌）客遊驚落葉，更使恨風蓬。", "（闕名）。"]'),
('b950f6df-7efe-456c-906e-54fd855c5732','大曆年浙東聯唱集 嚴氏園林（六言）','浙東衆詩人','唐','唐诗','tang','','[]','（嚴維鄭槩王綱〖大曆九年以大理司直充崑山縣令，首建縣學。',301,'全唐诗/poet.tang.53000.json','["（嚴維鄭槩王綱〖大曆九年以大理司直充崑山縣令，首建縣學。", "據《玉峯志》卷上《學校》、卷中《名宦》〗沈仲昌賈全〖長樂人，弇弟。", "大曆四年進士。", "歷任咸陽縣令、戶部員外郎、常州刺史、浙東觀察使，永貞元年卒。", "據《柳河東集》卷十二《先友記》、《陸宣公翰苑集》卷四、《郎官石柱題名考》卷十二、《會稽掇英總集》卷十八、《舊唐書·憲宗紀》〗段格〖不詳〗劉題〖不詳〗）策杖山橫綠野，乘舟水入衡門。", "（嚴維）客來多從業縣，僧去還指煙村。", "（鄭槩）春韭青青耐剪，香粳日日宜飧。", "（王綱）自愧薄霑冠冕，何如樂在丘園。", "（沈仲昌）鳥散紛紛花落，人行處處苔痕。", "（賈全）水池偏多白鷺，畦隔半是芳蓀。", "（段格）柳徑共知歸郭，暮雲誰使當軒。", "（劉題）。"]'),
('13519bf5-6b64-4ca1-b714-858a0da4b8c3','大曆年浙東聯唱集 柏梁體狀雲門山物（幷序）','浙東衆詩人','唐','唐诗','tang','','[]','（秦瑀〖不詳〗鮑防李聿〖玄宗時清漳令，遷尚書郎。',121,'全唐诗/poet.tang.53000.json','["（秦瑀〖不詳〗鮑防李聿〖玄宗時清漳令，遷尚書郎。", "據《全唐文》卷四三五〗李清杜奕袁邕呂渭崔泌〖不詳。", "《新唐書·宰相世系表》博陵安平崔氏有刑部員外郎崔泌，爲湜弟，時代稍早，非是。", "〗陳允初鄭槩杜倚〖京兆人，淹玄孫，左衛將軍。", "據《元和姓纂》卷六〗）。"]'),
('8ccbcd88-4b92-4ceb-9f76-76566f37da35','大曆年浙東聯唱集','浙東衆詩人','唐','唐诗','tang','','[]','幡竿映水出蒲檣。',265,'全唐诗/poet.tang.53000.json','["幡竿映水出蒲檣。", "（秦瑀）榴花向陽臨鏡妝。", "（鮑防）子規一聲猿斷腸。", "（李聿）殘雲入戶起爐香。", "（李清）晴虹夭矯架危梁。", "（杜奕）輕蘿縹緲挂霓裳。", "（袁邕）月臨影殿玉毫光。", "（呂渭）粉帶新篁白簡霜。", "（崔泌）玲瓏珠綴魚網張。", "（陳允初）高枝反舌巧如簧。", "（鄭槩）風搖寶鐸佩鏘鏘。", "（秦瑀）古松擁腫懸如囊。", "（杜倚）雨垂珠箔映迴廊。", "（李聿）薔薇綠刺半緘長。", "（鮑防）五粒松英大麥芒。", "（李清）古藤蚴蟉毒龍驤。", "（杜奕）深林怪石猛虎藏。", "（袁邕）古碑勒字棋局方。", "（呂渭）山僧行道鴻鴈行（崔泌）亭亭孤筍綠沉鎗。", "（鄭槩）蜂窼倒掛枯蓮房。", "（允初）燃燈幽殿星煌煌。", "（杜倚）。"]'),
('0df0b203-3179-4218-aa6f-43621cea65a8','大曆年浙東聯唱集 花巖寺松潭','浙東衆詩人','唐','唐诗','tang','','[]','（張叔政嚴維呂渭賈弇周頌鄭槩陳允初□成用）山下花巖會，松間水積深。',249,'全唐诗/poet.tang.53000.json','["（張叔政嚴維呂渭賈弇周頌鄭槩陳允初□成用）山下花巖會，松間水積深。", "（張叔政）晚荷交亂影，疎竹引輕陰。", "（嚴維）雲散千巖暮，風生萬木吟。", "（呂渭）循涯通妙理，步勝獲幽尋。", "（賈弇）望鳥知無迹，看猿欲學心。", "（周頌）浮榮指西景，微尚寄東岑。", "（鄭槩）待月開山閤，聞鐘出石林。", "（允初）波文搖翠壁，蟬響續幽琴。", "（張叔政）永日陪霜簡，通宵聽梵音。", "（賈弇）機閑任情性，道勝等浮沉。", "（□成用）賞異方終古，佳遊幾度今。", "（嚴維）自然輕執簡，寧敢忘抽簪。", "（允初）過見心皆妄，驅馳力未任。", "（呂渭）從來謝公意，山水愛登臨。", "（周頌）。"]'),
('e1d6ce67-ebf3-46ce-b98b-a36c5ee092a2','大曆年浙東聯唱集 入五雲溪寄諸公聯句（從一字至九字）（按：《全唐詩》卷七八九收本詩，題作《一字至九字詩聯句》，爲後人擬題，原題實缺。另五言詩二句下漏書作者呂渭。今爲補題，詩不重錄。）','浙東衆詩人','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.53000.json','["空。"]'),
('def47c59-47fd-4016-80b3-080d930a8bf9','大曆年浙東聯唱集 登法華寺最高頂憶院中諸公（從一字至九字）','浙東衆詩人','唐','唐诗','tang','','[]','（周頌□成用張叔政賈弇[鮑防]嚴維呂渭鄭槩陳允初）身，心。',736,'全唐诗/poet.tang.53000.json','["（周頌□成用張叔政賈弇[鮑防]嚴維呂渭鄭槩陳允初）身，心。", "（周頌）城郭，山林。", "（□成用）望處遠，到時深。", "（張叔政）雲崖杳杳，煙樹沉沉。", "（賈弇）嘯侶時停策，探幽或撫琴。", "[鮑防]得法小枝小葉，懷人如玉如金。", "（嚴維）月色前庭清靜觀，梵聲初夜海潮音。", "（呂渭）思君子山深不可見，登高頂望遠欲相尋。", "（鄭槩）何事歸舟客興櫂不駛，君不見紅蓮綠荇沙禽。", "（允初）（〖1〗《通志·藝文志》八著錄：「《大曆年浙東聯唱集》二卷。", "」《嘉泰會稽志》卷十四《嚴維傳》云：「大曆中與鄭槩、裴晃、徐嶷、王綱等宴其園宅，聯句賦詩，世傳《浙東唱和》。", "」卷十三云：「嚴長史園林，頗名於唐，大曆中有聯句者六人。", "」卷十八云：「松花壇，唐大曆中嚴維、呂渭茶宴於此，聯句云〖略〗。", "」〖2〗桑世昌《蘭亭考》卷十二云：「鮑防、嚴維、劉全白、宋迪，共三十五人具姓名。", "大曆中唱和五十七人。", "」今按：嚴維等大曆唱和原集，今已不存。", "宋人引錄其詩者有：《歲時雜詠》收一首，《唐詩紀事》收一首，《會稽掇英總集》收詩十二首又偈十一首，《剡錄》收一首，《蘭亭考》收一首，《嘉泰會稽志》收片斷若干。", "另宋刻唐人別集附見三首。", "綜計各書所收，今存此次唱和詩凡十四首又偈十一首。", "與唱者除本書前列三十人外，可考知者尚有劉蕃、樊珣、丘丹、范淹、吳筠、□迥〖疑爲劉迥〗、任逵、謝良輔、宋迪等九人，凡三十九人，已超過《蘭亭考》所舉之三十五人。", "這一組詩，《全唐詩》卷七八九收《中元日鮑端公宅遇吳師聯句》、《酒語聯句各分一字》、《一字至九字詩聯句》三首，《全唐詩續補遺》卷五收《經蘭亭故池聯句》〖收嚴維名下〗，餘十首皆錄如上。", "另《會稽掇英總集》卷十五收《雲門寺濟公上方偈》十一首，皆爲四言之作，《全唐文》未全收。", "姑附錄於次，以存該集完貌，爲研究者提供參讀的便利。", "）。"]'),
('c687d524-01bf-45bf-bdb2-c7c92d7bd56e','鮑防《雲門寺濟公上方偈序》 同人《護戒刀偈》','浙東衆詩人','唐','唐诗','tang','','[]','剖妄妄絕，決機機壞。',20,'全唐诗/poet.tang.53000.json','["剖妄妄絕，決機機壞。", "彼堅鋼刀，護身聞戒。"]'),
('f95facfe-a745-40a1-9607-f6f03ce0167f','鮑防《雲門寺濟公上方偈序》 李聿《茗侶偈》','浙東衆詩人','唐','唐诗','tang','','[]','采采春渚，芳香天與。',21,'全唐诗/poet.tang.53000.json','["采采春渚，芳香天與。", "滌慮破煩，靈芝之侶。", "。"]'),
('62472843-7824-4990-93df-7b849ad08ae2','鮑防《雲門寺濟公上方偈序》 杜奕《芭蕉偈》','浙東衆詩人','唐','唐诗','tang','','[]','幽山淨土，生此芭蕉。',20,'全唐诗/poet.tang.53000.json','["幽山淨土，生此芭蕉。", "無心起喻，覺路非遙。"]'),
('2d784fe1-b476-4838-9119-baa03ce8be3e','鮑防《雲門寺濟公上方偈序》 缺名《山啄木偈》','浙東衆詩人','唐','唐诗','tang','','[]','爾禽啄木，惡蠹傷木。',20,'全唐诗/poet.tang.53000.json','["爾禽啄木，惡蠹傷木。", "愈木無病，巢枝自足。"]'),
('533c8e18-6d2d-485c-bd11-26434197960e','鮑防《雲門寺濟公上方偈序》 缺名《澡瓶偈》','浙東衆詩人','唐','唐诗','tang','','[]','靈圓取相，塵垢是澡。',20,'全唐诗/poet.tang.53000.json','["靈圓取相，塵垢是澡。", "定水清淨，救彼熱惱。"]'),
('3c12c00d-9073-457a-8651-88bd54b2caa1','鮑防《雲門寺濟公上方偈序》 鄭槩《山石榴偈》','浙東衆詩人','唐','唐诗','tang','','[]','何方而有，天上人間。',20,'全唐诗/poet.tang.53000.json','["何方而有，天上人間。", "色空我性，對爾空山。"]'),
('d805e212-a63c-42ac-ad48-8766a1d493dc','鮑防《雲門寺濟公上方偈序》 杜倚《漉水囊偈》','浙東衆詩人','唐','唐诗','tang','','[]','裂素成器，給我救彼。',20,'全唐诗/poet.tang.53000.json','["裂素成器，給我救彼。", "密淨圓靈，護生絜水。"]'),
('75c03711-35e6-46a1-bbd7-db0953fddd89','鮑防《雲門寺濟公上方偈序》 袁邕《藤偈》','浙東衆詩人','唐','唐诗','tang','','[]','得彼柔性，契茲佛乘。',20,'全唐诗/poet.tang.53000.json','["得彼柔性，契茲佛乘。", "豈無衆木，我喻垂藤。"]'),
('4069352c-5530-4171-a51c-2ebdbcba4251','鮑防《雲門寺濟公上方偈序》 崔泌《薔薇偈》','浙東衆詩人','唐','唐诗','tang','','[]','護草木性，植彼薔薇。',20,'全唐诗/poet.tang.53000.json','["護草木性，植彼薔薇。", "眼根不染，見爾色非。"]'),
('b13ef034-7e61-4e0e-b301-ab24d91c51da','鮑防《雲門寺濟公上方偈序》 缺名《斑竹杖偈》','浙東衆詩人','唐','唐诗','tang','','[]','護性維戒，扶身在杖。',21,'全唐诗/poet.tang.53000.json','["護性維戒，扶身在杖。", "動必由道，心無來往。", "。"]'),
('bc3ab7cf-aba1-49e7-a5b1-81bad2924b62','鮑防《雲門寺濟公上方偈序》 任逵《題天章寺偈》','浙東衆詩人','唐','唐诗','tang','','[]','降伏心住，自在心住。',21,'全唐诗/poet.tang.53000.json','["降伏心住，自在心住。", "有心且住，無心即住。", "。"]'),
('68c5f12a-441b-4263-99d9-16919ad4c358','早梅','李端','唐','唐诗','tang','','[]','不知近水花先發，疑是經冬雪未銷。',34,'全唐诗/poet.tang.53000.json','["不知近水花先發，疑是經冬雪未銷。", "（《千載佳句》卷下《草木部·梅》）。"]'),
('fcfc1e8f-29d3-47f5-b9aa-d44d63b7967f','湖南歸夢','李端','唐','唐诗','tang','','[]','歸夢不知湖水濶，夜來還到洛陽城。',29,'全唐诗/poet.tang.53000.json','["歸夢不知湖水濶，夜來還到洛陽城。", "（同前《別離部·旅情》）。"]'),
('31908213-dcf6-457b-9700-cb181d2784bb','送李使君貶郴州','張南史','唐','唐诗','tang','','[]','竹符辭漢守，桂酒奠湘君。',33,'全唐诗/poet.tang.53000.json','["竹符辭漢守，桂酒奠湘君。", "（見《十萬卷樓叢書》本皎然《詩式》卷五）。"]'),
('58cb3e15-396e-49fc-93fd-837291dfbc20','上林白鹿賦附歌','蕭昕','唐','唐诗','tang','','[]','德由庾兮羣物湊，協嘉祥兮擾靈獸。',43,'全唐诗/poet.tang.53000.json','["德由庾兮羣物湊，協嘉祥兮擾靈獸。", "感訢合於天符，遂充塞於君囿。", "（見《文苑英華》卷八九）。"]'),
('d44afb3a-30ba-4e47-832d-309157ffa7e8','奉同秘書苗丞菘陽山閑居引','吉中孚','唐','唐诗','tang','','[]','有山𨁟兮有水潺湲，王孫獨往兮春草經年。',152,'全唐诗/poet.tang.53000.json','["有山𨁟兮有水潺湲，王孫獨往兮春草經年。", "溪路獨行兮到時何處？", "漁父相見兮水上天邊。", "犬吠前村兮極浦，迴風入林兮微月映戶。", "白石磷磷兮曲（小川氏疑爲「迸」字）水泥（疑）衣，哀猿啾啾兮空山半雨。", "谷口蒼茫兮天陰，人間離別兮年月深。", "花迷流水不知處，心憶君家難得（小川氏定爲「後」）尋。", "（日本藏唐抄本《新撰類林抄》卷四）。"]'),
('406814ae-e98c-46a3-b7c0-49f21b181397','地儉','劉方平','唐','唐诗','tang','','[]','地儉朝陽滿，天邊宿霧收。',67,'全唐诗/poet.tang.53000.json','["地儉朝陽滿，天邊宿霧收。", "風兼殘雪起，河帶斷冰流。", "北闕馳心極，南圖尚旅遊。", "登臨思不已，何處得銷愁？", "（影印本《詩淵》第三冊第二○六二頁）。"]'),
('861334cc-50eb-49b3-b6bd-d4529c15def7','五言普門上人蘭若一首','郎士元','唐','唐诗','tang','','[]','支公身欲老，常在沃[洲]（州）多。',100,'全唐诗/poet.tang.53000.json','["支公身欲老，常在沃[洲]（州）多。", "惠力堪傳教，禪功久伏魔。", "山雲隨坐夏，幽草伴頭陀。", "借問迴心後，賢愚去幾何？", "（按：《全唐詩》卷二四九收此詩爲皇甫冉作。", "然《唐詩卷》約在元和前後書，爲時甚早，故仍存之。", "）。"]'),
('381ff411-5aeb-4ef0-a895-7600d3789ac6','五言南岳寺普上人院一首','郎士元','唐','唐诗','tang','','[]','雲深石澗寺，樹老遠公房。',68,'全唐诗/poet.tang.53000.json','["雲深石澗寺，樹老遠公房。", "終日風□□，□秋景氣涼。", "醍醐蒙□味，□□□□□。", "□見無生理，空山坐道場。", "（以上二首均見日本藏唐抄本《唐詩卷》）。"]'),
('5c3d52a7-fc89-457b-b685-db9aa6358628','寄靈一上人初還雲門','郎士元','唐','唐诗','tang','','[]','寒山白雲裏，法侶自招攜。',212,'全唐诗/poet.tang.53000.json','["寒山白雲裏，法侶自招攜。", "竹徑通城下，松門隔水西。", "方同沃洲去，不作武陵迷。", "髣髴心知（《全唐詩》作「遙看」）處，高峰（《全唐詩》作「秋風」）是會稽。", "（見《會稽掇英總集》卷七）（按：《全唐詩》卷三八四收此詩爲張籍作。", "今檢《宋高僧傳》卷十五、《文苑英華》卷八六四獨孤及撰《揚州慶雲寺律師一公塔碑》，知靈一卒於寶應元年，年三十六。", "張籍生年難確考，但在大曆間殆無可疑。", "張籍生於靈一卒後，此詩非其作甚明。", "郎士元與靈一同時，詩應爲其作。", "）。"]'),
('2788c790-2114-482e-980d-0463c3c4f05e','駐節太康','郎士元','唐','唐诗','tang','','[]','霜葉飛紅過夏墟，金風吹鴈集荒渠。',130,'全唐诗/poet.tang.53000.json','["霜葉飛紅過夏墟，金風吹鴈集荒渠。", "鞭揮清渭分流外，目送烏江遠樹餘。", "五子歌聲猶在耳，十旬獵迹已成畬。", "天時人因堪惆悵，悶對牙旗展簿書。", "（影印文淵閣《四庫全書》本《河南通志》卷七四、民國廿二年刊劉盼遂纂《太康縣志》卷六、《古今圖書集成·職方典》卷三八八《開封府部》）。"]'),
('a7733c16-3e71-418f-b09b-a1d2928bf226','詩','郎士元','唐','唐诗','tang','','[]','假守昭平郡，當門桂水清。',89,'全唐诗/poet.tang.53000.json','["假守昭平郡，當門桂水清。", "海遙稀蚌跡，峽近足灘聲。", "峽東江盤天影隨，輕船隻下幾危機。", "初晴古木猿三叫，未晚陰崖日半規。", "篁竹數家何處是？清清一曲幾首詩。", "（《四庫》本《記纂淵海》卷十五）。"]'),
('bc90c4d0-66cc-4489-819b-5e4f08689dcc','送皎[然]（照）上人歸山','郎士元','唐','唐诗','tang','','[]','雲陰鳥道苔方合，雪映龍潭水更清。',35,'全唐诗/poet.tang.53000.json','["雲陰鳥道苔方合，雪映龍潭水更清。", "（《千載佳句》卷上《地理部·山中》）。"]'),
('0b0bcabe-4322-4cc3-8681-7e11ef05e258','句 一','郎士元','唐','唐诗','tang','','[]','江山幾路分。',28,'全唐诗/poet.tang.53000.json','["江山幾路分。", "（《江湖小集》卷三紹嵩《江浙紀行集句詩》）。"]'),
('883deb88-b6c7-4ecf-89eb-9fd2fa458929','句 二','郎士元','唐','唐诗','tang','','[]','上潮吞海日。',11,'全唐诗/poet.tang.53000.json','["上潮吞海日。", "（同前）。"]'),
('105f3fef-957e-421c-9d1e-f5245b4ca6a8','句 三','郎士元','唐','唐诗','tang','','[]','寂寞舟中誰供問。',28,'全唐诗/poet.tang.53000.json','["寂寞舟中誰供問。", "（《江湖小集》卷二二李龏《剪綃集》引）。"]'),
('9b2793ea-e3db-48aa-b655-fdc4007c21fd','句 四','郎士元','唐','唐诗','tang','','[]','馬令無茶分。',122,'全唐诗/poet.tang.53000.json','["馬令無茶分。", "（見劉克莊《後村大全集》卷一八四《詩話新集》）（〖1〗劉克莊云：「余記唐人雜書載士元嘗對客有『馬令無茶分』之戲。", "北平王一日飲客，士元與焉。", "坐間，北平醉飽設茗供，連沃數碗，士元老不能禁，即席吐利交下。", "滿坐大笑。", "今不省出處，當攷。", "」）。"]'),
('5e38801a-1bc6-426b-88f7-9f2f25a29ca9','白角樽歌','劉商','唐','唐诗','tang','','[]','或謂輕冰盛沆瀣（海氣也。',26,'全唐诗/poet.tang.53000.json','["或謂輕冰盛沆瀣（海氣也。", "）（見宋吳聿《觀林詩話》）。"]'),
('e33facd3-c545-433a-8fc3-f37a2777b4ba','建中四年十月感事（題擬）','嚴巨川','唐','唐诗','tang','','[]','煙塵忽起犯中原，自古臨危道貴存。',329,'全唐诗/poet.tang.53000.json','["煙塵忽起犯中原，自古臨危道貴存。", "手持禮器空垂淚，心憶明君不敢言。", "落日胡笳吟上苑，通宵虜將醉西園。", "傳烽萬里無師至，累代何人受漢恩。", "（見唐趙元一撰《奉天錄》卷二）（〖1〗《奉天錄》卷二：「八日，泚于宣政殿僭即大位，愚智莫不血怒。", "衛者多是軍人，周行不過數十，自稱大秦皇帝，年號應天。", "僞赦書云：『幽囚之中，神器自至，豈朕薄德所能經營。", "』彭偃之詞。", "冊文，太常少卿樊系之撰。", "文成，服藥而卒。", "故嚴巨川詩曰〖詩略〗。", "」〖2〗《奉天錄》卷一：「時有風情女子李季蘭上泚詩，言多悖逆，故闕而不錄。", "皇帝再剋京師，召季蘭而責之曰：『汝何不學嚴巨川有詩云：「手持禮器空垂淚，心憶明君不敢言」？", "』遂令撲殺之。", "」今按：詳此段紀事，似巨川于朱泚亂時亦陷身賊中，至德宗收京，因此詩而得寬宥。", "）。"]'),
('7f076384-a464-464d-9921-13c7ab5fceb7','','論惟明','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('b80768b1-524e-4749-8e19-def89d9a9be8','朱泚亂定後上皇帝（題擬）','論惟明','唐','唐诗','tang','','[]','豺狼暴宮闕，拔塗凌丹墀。',63,'全唐诗/poet.tang.53000.json','["豺狼暴宮闕，拔塗凌丹墀。", "花木久不芳，羣凶亦自疑。", "既爲皇帝枯，亦爲皇帝滋。", "艸木尚多感，報恩須及時。", "（見唐趙元一《奉天錄》卷四）。"]'),
('dae5e7a2-55be-4d08-b97f-04d1f6bcf284','和蕭郎中遊蘭若','朱放','唐','唐诗','tang','','[]','愛彼雲外人，來取澗底泉。',120,'全唐诗/poet.tang.53000.json','["愛彼雲外人，來取澗底泉。", "風吹芭蕉折，鳥啄梧桐穿。", "（見《十萬卷樓叢書》本皎然《詩式》卷三。", "同書卷四錄前二句。", "）（按：《全唐詩》卷三一五錄四句，缺題，又末字「穿」作「落」，故分作二斷句，蓋沿《吟窗雜錄》刪節本《詩式》之誤所致，今重錄改正之。", "）。"]'),
('11c90e9e-f28e-47b7-b5f2-a456a0220bda','釣渚亭','暢當','唐','唐诗','tang','','[]','花發多遠意，鳧鴈有閒情。',37,'全唐诗/poet.tang.53000.json','["花發多遠意，鳧鴈有閒情。", "遲暉耿不暮，平江寂無聲。", "（見《唐詩紀事》卷二七）。"]'),
('430b58ff-909a-4698-89ff-43964378a3c5','建寧王哀詞二首（末句）','李泌','唐','唐诗','tang','','[]','良弓摧折久，誰識是龍韜。',53,'全唐诗/poet.tang.53000.json','["良弓摧折久，誰識是龍韜。", "（見《吟窗雜錄》卷二四《歷代吟譜》）按：《全唐詩》卷一○九收此二句，缺題，今重錄。"]'),
('524f0997-6462-4e6b-b8ff-18391552f67a','句 一','李泌','唐','唐诗','tang','','[]','夷門一把平安火，定逐恒山候騎來。',33,'全唐诗/poet.tang.53000.json','["夷門一把平安火，定逐恒山候騎來。", "（《四庫》本《記纂淵海》卷二一）。"]'),
('d8edeb92-cfa6-44c9-a040-1a0f632b9e39','句 二','李泌','唐','唐诗','tang','','[]','粉容冰艷玉玲瓏。',27,'全唐诗/poet.tang.53000.json','["粉容冰艷玉玲瓏。", "（《江湖小集》卷二十李龏《梅花衲》）。"]'),
('e459cc18-94d9-4365-9db9-a41e31ab51ac','酬秦徵君徐少府春日見集','戴叔倫','唐','唐诗','tang','','[]','終日愧無政，與君聊散（《剡錄》作「放」）襟。',253,'全唐诗/poet.tang.53000.json','["終日愧無政，與君聊散（《剡錄》作「放」）襟。", "城根山半腹，亭影水中心。", "朗詠竹窗靜，野情花徑深。", "那能有餘興，不作剡溪尋。", "（見《文苑英華》卷二三○、卷三一六、高似孫《剡錄》卷六、卷十。", "）（按：《全唐詩》卷一九○收作韋應物詩，誤。", "宋本《韋集》無此詩。", "明刻《文苑英華》卷二三○此詩前爲應物詩，此詩失署作者，後人因此致誤。", "《文苑英華》卷二三○周必大等校該詩云：「集作《奉酬秦徵君系春日撫州西亭野望兼寄徐少府》。", "」叔倫曾任撫州刺史。", "卷三一六即題作《撫州西亭》，署「戴叔倫」作。", "中華書局影印本新編目錄已糾正明刻本之誤。", "）。"]'),
('42811d28-da0e-4532-bd93-89a2b20f944d','詩','戴叔倫','唐','唐诗','tang','','[]','雲開方見日，潮盡爐峰出。',40,'全唐诗/poet.tang.53000.json','["雲開方見日，潮盡爐峰出。", "石壁轉棠陰，鄱陽寄茅室。", "（《輿地紀勝》卷二三《饒州》）。"]'),
('9707068d-3ceb-4c32-a81d-a9a1d902b9f2','新池','戴叔倫','唐','唐诗','tang','','[]','鄰僧猶未起，明月早先知。',35,'全唐诗/poet.tang.53000.json','["鄰僧猶未起，明月早先知。", "（見《吟窗雜錄》卷十四正字王玄《詩中旨格》）。"]'),
('864799d0-5c04-4c68-a368-a5e11a937b79','喜嚴侍御蜀還贈嚴秘書','戴叔倫','唐','唐诗','tang','','[]','（按：以上三詩，《文苑英華》卷二五五收作戴叔倫詩，卷二五六復收作清江詩。',52,'全唐诗/poet.tang.53000.json','["（按：以上三詩，《文苑英華》卷二五五收作戴叔倫詩，卷二五六復收作清江詩。", "尚難遽定誰作，姑存目俟考。", "）空。"]'),
('8e11087c-8de6-4ed7-8e9a-37aff277f7ce','贈淮西賈兵馬使','戴叔倫','唐','唐诗','tang','','[]','（按：《文苑英華》卷三○○收作戴叔倫詩，卷二五七收作清江詩。',65,'全唐诗/poet.tang.53000.json','["（按：《文苑英華》卷三○○收作戴叔倫詩，卷二五七收作清江詩。", "尚難遽定誰作，姑存目。", "以上四首，《全唐詩》卷八一二均收清江名下。", "）空。"]'),
('6b0881ac-8657-4bbf-b121-7d239161bee6','','李博士','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('201b6e45-7a32-4f65-ac98-74668851976a','問韋應物（題擬）','李博士','唐','唐诗','tang','','[]','宋生昔登覽。',252,'全唐诗/poet.tang.53000.json','["宋生昔登覽。", "（中缺）那能顧蓬蓽。", "（見《韋蘇州集》卷五《李博士弟以余罷官居同德精舍共有伊陸名山之期久而未去枉詩見問中云宋生昔登覽末云那能顧蓬蓽直寄鄙懷聊以爲答》）（按：韋應物另有《寄酬李博士永寧主簿叔廳見待》、《答李博士》、《同德寺雨後寄元侍御李博士》、《同德閣期元侍御李博士不至各投贈二首》，均與同人之作，唯其名不詳。", "傅璇琮先生《韋應物繫年考證》定應物退居同德寺爲永泰元年棄洛陽丞後。", "頗疑此人即與應物過從甚密之李儋，出姑臧大房，給事中昇期之子，官至殿中侍御史，見《新唐書·宰相世系表》。", "俟得確證定之。", "）。"]'),
('19e3e20c-ca90-4eb0-a146-bc858af596a8','同姜氾水題裴司馬東齋','劉長卿','唐','唐诗','tang','','[]','不記鄱陽郡，俱因謫官過。',147,'全唐诗/poet.tang.53000.json','["不記鄱陽郡，俱因謫官過。", "白雲心已矣，滄海意如何？", "蔾杖全吾道，榴花養太和。", "春風騎馬醉，江月釣漁歌。", "步履侵苔廨，頃冠拂薜蘿。", "遠山終日在，芳草傍人多。", "莫學靈均悵，愁竟楚水波。", "（《新撰類林鈔》卷四，據小川環樹錄文。", "）（按：《全唐詩》卷一四九收此詩，題作《同姜濬題裴式微餘干東齋》。", "內容大異，今重錄。", "）。"]'),
('138f861a-bd44-43a4-8fd7-4c05cb741640','過鄭山人所居','劉長卿','唐','唐诗','tang','','[]','一逕人尋谷口村，春山犬吠武陵源。',101,'全唐诗/poet.tang.53000.json','["一逕人尋谷口村，春山犬吠武陵源。", "青苔滿地無行處，深咲桃花獨閉門。", "（同前）（按：《全唐詩》卷一五○收本詩，內容大異，今重錄。", "《千載佳句》卷上《人事部·閑居》收後二句，詩題不同，《全唐詩逸》卷上已收入。", "）。"]'),
('889e8b5b-d646-4f31-baf7-ad0227bef696','將赴湖南湖上別皇甫曾','劉長卿','唐','唐诗','tang','','["\u897f\u6e56"]','此去君何恨，南行我更遙。',63,'全唐诗/poet.tang.53000.json','["此去君何恨，南行我更遙。", "東西湖渺渺，離別雨瀟瀟。", "綠山通春谷，青山過板橋。", "潯陽如枉棹，千里有歸潮。", "（見席刻《劉隨州詩集》卷二）。"]'),
('678cae0c-9856-4a1e-aab3-095caa497f55','送靈澈遠雲門','韋應物','唐','唐诗','tang','','[]','我歡常在夢，無心解傷別。',38,'全唐诗/poet.tang.53000.json','["我歡常在夢，無心解傷別。", "千里萬里人，祇似眼中月。", "（見《會稽掇英總集》卷七）。"]'),
('f4354792-a786-4490-9f24-2f50fd94b450','早春詩','韋應物','唐','唐诗','tang','','[]','南園柳色動，野塘春水生。',38,'全唐诗/poet.tang.53000.json','["南園柳色動，野塘春水生。", "屢遊煩將吏，獨此守山城。", "（見《能改齋漫錄》卷十一）。"]'),
('a7864286-0efc-4293-bc33-9edbc8a367bd','芳草澗','韋應物','唐','唐诗','tang','','[]','青青滿地鋪顏色，曲曲一灣流水聲。',73,'全唐诗/poet.tang.53000.json','["青青滿地鋪顏色，曲曲一灣流水聲。", "總爲遊人逞風景，亂雲初捲碧天空。", "（見嘉靖《六合縣志》卷八，上海圖書館據天一閣藏本所攝顯微膠卷。", "原注出《嘉定志》）。"]'),
('69abfd6f-ab7d-4349-880f-1354444d597d','春雪（存目）','韋應物','唐','唐诗','tang','','[]','（按：此詩見《文苑英華》卷一五四。',67,'全唐诗/poet.tang.53000.json','["（按：此詩見《文苑英華》卷一五四。", "《唐詩紀事》卷七、《萬首唐人絕句》卷二五、《全唐詩》卷一百作東方虬詩。", "未詳孰是，姑存目以俟考。", "）空。"]'),
('5359e11f-0d36-40cf-8570-94c86cb27013','將赴渭北對月懷晝上人（題擬）','楊華','唐','唐诗','tang','','[]','悠然顧山侶。',37,'全唐诗/poet.tang.53000.json','["悠然顧山侶。", "（見《皎然集》卷一《五言酬烏程楊明府將赴渭北對月見懷》注引）。"]'),
('da5fa04b-2469-4fb1-b175-1761307c7f02','悲春','殷濟','唐','唐诗','tang','','[]','青青柳色萬家春，獨掩荆扉對苦辛。',48,'全唐诗/poet.tang.53000.json','["青青柳色萬家春，獨掩荆扉對苦辛。", "山月有時來照戶，蕃歌無夜不傷人。", "荒村寂寂鷄鳴早，窮巷喧喧犬吠頻。"]'),
('2bd9f5fa-5244-4a5d-a91c-485856b07805','秦閨怨 一','殷濟','唐','唐诗','tang','','[]','幽閨情自苦，何事更逢春？',48,'全唐诗/poet.tang.53000.json','["幽閨情自苦，何事更逢春？", "萱草侵堦綠，垂楊闇戶新。", "鏡中絲髮亂，窗外鳥聲頻。", "對此芳菲景，長宵轉憶君。"]'),
('db67ff36-08a9-48c3-8856-3bd735fccd28','秦閨怨 二','殷濟','唐','唐诗','tang','','[]','春至感心傷，低眉入洞房。',53,'全唐诗/poet.tang.53000.json','["春至感心傷，低眉入洞房。", "征夫天外別，拋妾鎮[漁]（魚）陽。", "有意連新月，無情理舊妝。", "長流雙瞼淚，獨恨對芬芳。"]'),
('0783d204-3eee-4c20-9307-53ebe5dd5eaa','憶北府弟妹（二首） 一','殷濟','唐','唐诗','tang','','[]','骨肉東西各一方，弟兄南北斷肝腸。',96,'全唐诗/poet.tang.53000.json','["骨肉東西各一方，弟兄南北斷肝腸。", "離情祇向天邊碎，壯志還隨行處傷。", "不料此心分兩國，誰知翻屬二君王。", "艱難少有安中土，經亂多從胡虜鄉。", "獨羨春秋連影雁，每思羽翼幷成行。", "題詩泣盡東流水，欲話無人問短長。"]'),
('3cdb4325-5806-4eb9-a0c3-7df2eefc4225','憶北府弟妹（二首） 二','殷濟','唐','唐诗','tang','','[]','與爾俱成淪沒世，艱難終日各東西。',69,'全唐诗/poet.tang.53000.json','["與爾俱成淪沒世，艱難終日各東西。", "胡笳曉聽心長共，漢月[宵]（霄）看意自迷。", "獨泣空房襟上血，孤眠永夜夢中啼。", "何時骨肉園林會，不向天涯聞鼓鞞。"]'),
('7ec61cf0-463a-44e1-8e2a-7fcc72dbf099','奉憶北庭楊侍御留後','殷濟','唐','唐诗','tang','','[]','不幸同俘縶，常悲海雁孤。',48,'全唐诗/poet.tang.53000.json','["不幸同俘縶，常悲海雁孤。", "如何一朝事，流落在天隅？", "永夜多寂寞，秋深獨鬱紆。", "欲知相憶甚，終日淚成珠。"]'),
('af240669-6504-4680-bb2e-ce8ce3cd49ee','歲日送王十三判官之松州幕','殷濟','唐','唐诗','tang','','[]','異方新歲自然悲，三友那堪更別離。',64,'全唐诗/poet.tang.53000.json','["異方新歲自然悲，三友那堪更別離。", "虜酒未傾心已醉，愁容相顧懶題詩。", "三邊罷戰猶長策，二國通和藉六奇。", "佇聽鶯遷當此日，歸鴻莫使尺書遲。"]'),
('b2aafa0c-b8a2-4236-b62e-48ae043297f0','冬[宵]（霄）感懷','殷濟','唐','唐诗','tang','','[]','切切霜風入夜寒，微微孤燭客心難。',38,'全唐诗/poet.tang.53000.json','["切切霜風入夜寒，微微孤燭客心難。", "長[宵]（霄）獨恨流離苦，直到平明淚不乾。", "。"]'),
('268f46e6-6f68-4e6a-ba91-de0937abfc4a','歎路傍枯骨','殷濟','唐','唐诗','tang','','[]','行行遍歷盡沙場，只是偏教此意傷。',32,'全唐诗/poet.tang.53000.json','["行行遍歷盡沙場，只是偏教此意傷。", "從來征戰皆空地，徒使驕矜掩異方。"]'),
('6957f845-445a-45af-b8bb-bf44fcc57645','言懷','殷濟','唐','唐诗','tang','','[]','愁緒足悲歌，離心似網羅。',48,'全唐诗/poet.tang.53000.json','["愁緒足悲歌，離心似網羅。", "二年分兩國，萬里一長河。", "磧外人行少，天邊雁叫多。", "懷鄉不得死，皆是惜天涯。"]'),
('c9998ee3-8c7d-4cee-9887-f8f3d867e028','見花發有思','殷濟','唐','唐诗','tang','','[]','花未發，增所思，及見花開轉益悲。',32,'全唐诗/poet.tang.53000.json','["花未發，增所思，及見花開轉益悲。", "花開未發尚有期，獨我情懷未見時。"]'),
('c5eeb4ab-4529-4ec8-b64c-3243e6902c72','無名歌','殷濟','唐','唐诗','tang','','[]','天下沸騰積年歲，米到千錢人失計。',269,'全唐诗/poet.tang.53000.json','["天下沸騰積年歲，米到千錢人失計。", "附郭種得二頃田，磨折不充十一稅。", "今年苗稼看更弱，[枌]（一作「墳」）榆產業須拋却。", "不知天下有幾人，但見波逃如雨脚。", "去去如同不繫舟，隨波逐水泛長流。", "漂泊已經千里外，誰人不帶兩鄉愁？", "舞女庭前厭酒肉，不知百姓餓眠宿。", "君不見城外空墻遙，將軍只是栽花竹。", "君看城外恓惶處，段段茅花如柳葉（一作「{葜大=糸}」）。", "海鷰銜泥欲作巢，空堂無人却飛去。", "（按：此首又見伯三六二○卷，不署名，今據校。", "此本末多數句：「所在君侯，不須惱亂。", "發意害彼，不知自傷，此世報行惡名，當來必酬苦果。", "」似與此詩無關。", "又此首及下二首疑非殷濟詩。", "）。"]'),
('70d1b756-0d50-4482-be3d-b7e83188e5ea','夢歸還','殷濟','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('81e12072-b95f-4af6-8cda-eeccffb21a91','夢歸還 一','殷濟','唐','唐诗','tang','','[]','春來相思每隨風，萬里關山想自通。',32,'全唐诗/poet.tang.53000.json','["春來相思每隨風，萬里關山想自通。", "夢裏宛然歸舊國，覺來還在虜營中。"]'),
('a8848ad2-962d-4e1b-b891-1e5075a55f78','夢歸還 二','殷濟','唐','唐诗','tang','','[]','春來有幸却承恩，花裏含啼入殿門。',43,'全唐诗/poet.tang.53000.json','["春來有幸却承恩，花裏含啼入殿門。", "殘妝不用添紅粉，且待君王見淚痕。", "（均見伯三八一二卷）。"]'),
('d945acb9-1d28-4599-9554-9b16537191bf','草庵歌','希遷','唐','唐诗','tang','','[]','吾結草庵無寶貝，飯了從容圖睡快。',270,'全唐诗/poet.tang.53000.json','["吾結草庵無寶貝，飯了從容圖睡快。", "成時初見茅草新，破後還將茅草蓋。", "住庵人，鎮常在，不屬中間與內外。", "人住處，我不住，世人愛處我不愛。", "庵雖小，含法界，方丈老人相體解。", "上乘菩薩信無疑，中下聞之必生怪。", "問此庵，壞不壞，壞與不壞主元在。", "不居南北與東西，基上堅牢以爲最。", "青松下，明窗內，玉殿朱樓未爲對。", "納帔幪頭萬事休，此時山僧都不會。", "住此庵，休作解，誰誇鋪席圖人買。", "迴光返照便歸來，廓達靈根非向背。", "遇祖師，親訓誨，結草爲庵莫生退。", "百年拋却任縱橫，擺手便行且無罪。", "千種言，萬般解，祇要交君長不解。", "欲識庵中不死人，豈離而今遮皮袋。", "（見《景德傳燈錄》卷三十）。"]'),
('a737bb26-d9cb-49ba-a129-5603f8363771','參同契','希遷','唐','唐诗','tang','','[]','竺土大僊心，東西密相付。',280,'全唐诗/poet.tang.53000.json','["竺土大僊心，東西密相付。", "人根有利鈍，道無南北祖。", "靈源明皎潔，枝派暗流注。", "執事元是迷，契理亦非悟。", "門門一切境，迴互不迴互。", "迴而更相涉，不爾依位住。", "色本殊質象，聲元異樂苦。", "暗合上中言，明明清濁句。", "四大性自復，如子得其母。", "火熱風動搖，水濕地堅固。", "眼色耳音聲，鼻香舌鹼醋。", "然依一一法，依根葉分布。", "本末須歸宗，尊卑用其語。", "當明中有暗，勿以暗相遇。", "當暗中有明，勿以明相覩。", "明暗各相對，比如前後步。", "萬物自有功，當言用及處。", "事存函蓋合，理應箭鋒拄。", "承言須會宗，勿自立規矩。", "觸目不會道，運足焉知路。", "進步非近遠，迷隔山河固。", "謹白參玄人，光陰莫虛度。", "（同前。", "又見《五燈會元》卷五）。"]'),
('96a4e6db-1960-44d7-8600-19c7237a8a11','偈','希遷','唐','唐诗','tang','','[]','從來共住不知名，任運相將作（《五燈會元》作「祇」）摩行。',76,'全唐诗/poet.tang.53000.json','["從來共住不知名，任運相將作（《五燈會元》作「祇」）摩行。", "自古上賢猶不識，造次常（《五燈會元》作「凡」）流豈可明。", "（見《祖堂集》卷四、《五燈會元》卷五）。"]'),
('81c5ac5a-7585-4b6c-8331-019ca09435ee','頌','大同濟禪師','唐','唐诗','tang','','[]','十二時中那事別，子丑寅卯吾今說。',44,'全唐诗/poet.tang.53000.json','["十二時中那事別，子丑寅卯吾今說。", "若會唯心萬法空，釋迦彌勒從茲決。", "（見《五燈會元》卷五）。"]'),
('9dccbcc7-459f-45a1-a55c-a3f795a3f10e','','張芬','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('5937ae6f-2482-4844-b5db-1777fa7d0106','酬李端山中見期不至（題擬）','張芬','唐','唐诗','tang','','[]','君家舊林壑，寄在亂峰西。',181,'全唐诗/poet.tang.53000.json','["君家舊林壑，寄在亂峰西。", "近日春雲滿，相思路亦迷。", "聞鐘投野寺，待月過前溪。", "悵望成幽夢，依依識故蹊。", "（見江標影宋書棚本《唐詩五十家小集·李端詩集》卷二）（按：《全唐詩》卷二八五收此詩於李端名下，題作《酬前大理寺評事張芬》。", "檢影宋書棚本，此詩附於李端《山中期張芬不至》後，題作《酬前》，署「大理評事張芬」。", "此爲張芬詩附收於李集，作李詩誤。", "另參本書卷十一苗發詩附考。", "）。"]'),
('f9c7c099-e7dd-4a5f-a194-f9c8bdc527ce','上陽春辭','楊衡','唐','唐诗','tang','','[]','聖皇自在（《千載佳句》卷下作「有」）長生殿，不向蓬萊王母家。',117,'全唐诗/poet.tang.53000.json','["聖皇自在（《千載佳句》卷下作「有」）長生殿，不向蓬萊王母家。", "（見《日本古典文學大系》七三冊藤原公任《和漢朗詠集》卷下《帝王》）（〖1〗川口久雄校注云：架藏私注本題作《上陽春辭》，《千載佳句·禁中》作《上春詞》，柿村本作《上陽春詞》）。"]'),
('12817f2d-0f3c-4287-94a8-da1692924462','句','楊衡','唐','唐诗','tang','','[]','欲問皇天天更遠。',17,'全唐诗/poet.tang.53000.json','["欲問皇天天更遠。", "（胡偉《宮詞》）。"]'),
('64248fd5-63e9-4c49-9d82-2a216df9a1b0','詩','徐浩','唐','唐诗','tang','','[]','祖德道場下，往來三十秋。',39,'全唐诗/poet.tang.53000.json','["祖德道場下，往來三十秋。", "白頭方問法，朗月特相留。", "（《至大金陵新志》卷十二下）。"]'),
('5bbc4dc9-227a-4236-91f8-b1ccfb85640e','天台智者大師畫贊','顏真卿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','天台大師俗姓陳，其名智顗華容人。',386,'全唐诗/poet.tang.53000.json','["天台大師俗姓陳，其名智顗華容人。", "隋煬皇帝崇明因，號爲智者誠敬申。", "師初孕育靈異頻，彩烟浮空光照鄰。", "堯眉舜目熙若春，禪慧悲智嚴其身。", "長沙佛前發弘誓，定光菩薩示冥契。", "恍如登山臨海際，上指伽藍畢身世。", "東謁大蘇求真諦，智同靈鷲聽法偈。", "得宿命通弁無礙，旋陀羅尼華三昧。", "居常西面化在東，八載瓦官闡玄風。", "敷演智度發禪蒙，梁陳舊德皆仰崇。", "遂入天台華頂中，因見定光符昔夢。", "降魔制敵爲法雄，胡僧開道精感通。", "又有聖賢垂秘旨，時平國清即名寺。", "贖得魚梁五百里，其中放生講流水。", "後主三禮洞庭裏，請爲菩薩戒弟子。", "煬皇世鎮臨江涘，金城說會求制止。", "香火事訖乃西旋，渚宮聽衆逾五千。", "建立精舍名玉泉，橫亘萬里皆稟緣。", "煬皇啓請回法船，非禪不智求弘宣。", "遂著《淨名精義傳》，因令徐柳參其玄。", "帝既西趍移象魏，師因東還遂初志。", "半山忽與沙門顛，俄傾逡巡偡韜秘。", "止觀大師名法源，親事左溪弘度門。", "二威灌頂誦師言，同稟思文龍樹尊。"]'),
('41e97c18-ab59-453b-b7ba-eeb6ed7862ea','桃源（題擬）','李臯','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','當時避地乾坤窄，此地安家日月長。',50,'全唐诗/poet.tang.53000.json','["當時避地乾坤窄，此地安家日月長。", "草色幾經壇杏改，浪花猶帶洞庭香。", "（見《輿地紀勝》卷六八《常德府》）。"]'),
('3ea58ecb-2db5-4e2b-8eec-138c9964d4b6','遊南鴈詩','李臯','唐','唐诗','tang','','[]','鴈蕩諸奇不可窮，石梁華表遠淩空。',151,'全唐诗/poet.tang.53000.json','["鴈蕩諸奇不可窮，石梁華表遠淩空。", "乾坤誰道洞中小，日月曾從牖裏通。", "詞客墨苔觀照耀，飛仙環佩聽玲瓏。", "何當偕得緱山鶴，駕入嶙峋翠幾重。", "（見同治丙寅刊齊召南纂《溫州府志》）（按：張靖龍云：「見清周喟《南雁蕩山志》卷七《詩外編》引明人陳玭《嘉靖南雁蕩志》，又見乾隆《平陽縣志》卷二，題作《游橫陽雁蕩山詩》。", "」）。"]'),
('c81b3dbd-7e2c-4b42-90e9-163d8b74376e','','青霞子','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('723b6eee-4d46-42a2-a38a-b0ef981625bd','龍虎元旨歌 一','青霞子','唐','唐诗','tang','','[]','天地初分日月高，狀如雞子復如桃。',32,'全唐诗/poet.tang.53000.json','["天地初分日月高，狀如雞子復如桃。", "陰陽真氣知時節，直待三年脫戰袍。"]'),
('9d4ceb5e-5f2d-4b6f-825c-2d8b3cf0c0fc','龍虎元旨歌 二','青霞子','唐','唐诗','tang','','[]','大道分明在眼前，時人不會誤歸泉。',32,'全唐诗/poet.tang.53000.json','["大道分明在眼前，時人不會誤歸泉。", "黃芽本是乾坤氣，神水根基與汞連。"]'),
('1a9b2173-dd5f-4d84-b99b-d7bcbf31df91','龍虎元旨歌 三','青霞子','唐','唐诗','tang','','[]','龍虎丹砂義最幽，五神金內汞鉛流。',32,'全唐诗/poet.tang.53000.json','["龍虎丹砂義最幽，五神金內汞鉛流。", "千朝變紫雲飛去，直至大羅天上頭。"]'),
('c789bdf0-6fea-46ed-8e8a-0e56cb91ceca','龍虎元旨歌 四','青霞子','唐','唐诗','tang','','[]','認得根源不用忙，三三合九有純陽。',32,'全唐诗/poet.tang.53000.json','["認得根源不用忙，三三合九有純陽。", "潛通變化神光見，從此朝天近玉皇。"]'),
('45dfdbed-c0da-4810-b0b8-2e9d9cc24ecf','龍虎元旨歌 五','青霞子','唐','唐诗','tang','','[]','用鉛須得汞相和，二性爲親女唱歌。',32,'全唐诗/poet.tang.53000.json','["用鉛須得汞相和，二性爲親女唱歌。", "鍊到紫河車地動，白雲相伴鶴來過。"]'),
('33b42804-6dee-4650-98bc-674ad6129d9e','龍虎元旨歌 六','青霞子','唐','唐诗','tang','','[]','合其天地合其元，子母相逢不敢言。',32,'全唐诗/poet.tang.53000.json','["合其天地合其元，子母相逢不敢言。", "先汞後鉛真道大，莫教失伴鶴歸天。"]'),
('a7d9589d-806e-454a-8083-a9ccbfb6abb2','龍虎元旨歌 七','青霞子','唐','唐诗','tang','','["\u6cf0\u5c71"]','此寶從來二八傳，吉年吉月入爐安。',104,'全唐诗/poet.tang.53000.json','["此寶從來二八傳，吉年吉月入爐安。", "千朝火候依時節，必定芽成汞已乾。", "（按：《龍虎元旨》末云：「東嶽董師元於貞元五年受之於羅浮山隱士青霞子，貞元十九年傳受劍州司馬張陶，開成三年京師傳族弟汾，成長契五年傳成君。", "」）。"]'),
('4cabad79-7f22-461c-a9e9-8a0371c9704c','雲門山','秦系','唐','唐诗','tang','','[]','十年遊罷古招提，路入雲門峻似梯。',90,'全唐诗/poet.tang.53000.json','["十年遊罷古招提，路入雲門峻似梯。", "秀氣漸分秦望嶺，寒身猶入若耶溪。", "天開霽色澄千里，稻熟秋香互萬畦。", "多少靈蹤待窮覽，却愁回馭日平西。", "（見《古今圖書集成·山川典》卷一一四《雲門山部》）。"]'),
('4785da05-0eac-4ab6-a47e-49b2a110bf53','送常州司士崔千里（題擬）','姚明敭','唐','唐诗','tang','','[]','官屈須推命，時危莫厭貧。',79,'全唐诗/poet.tang.53000.json','["官屈須推命，時危莫厭貧。", "城樓近江水，潮退看垂輪。", "（《千唐誌齋藏誌》九八三頁崔恕撰《唐故登仕郎常州司士參軍襲武城縣開國伯崔府君墓誌銘》引。", "此則承陶先生告知。", "）。"]'),
('e76db489-1a13-42ce-a521-3ae91209bbac','開元觀陪杜大夫中元日觀樂','戎昱','唐','唐诗','tang','','[]','（按：《全唐詩》卷二七○收此詩，第八句缺一字。',56,'全唐诗/poet.tang.53000.json','["（按：《全唐詩》卷二七○收此詩，第八句缺一字。", "《古今歲時雜詠》卷二八錄此詩不缺，此句作「好風油幕動高煙」。", "）空。"]'),
('d1c633ce-3c74-4594-9169-e0cf7a24ed55','運斤賦附歌','席夔','唐','唐诗','tang','','[]','彼二子兮以藝相崇，得一理兮其心則同。',48,'全唐诗/poet.tang.53000.json','["彼二子兮以藝相崇，得一理兮其心則同。", "運斤在手誠可懼，堅立不動神之雄。", "（見《文苑英華》卷一○一）。"]'),
('c94a0340-f429-4218-ac9a-84f1f3323fe8','怒李京兆（題擬）','裴延齡','唐','唐诗','tang','','[]','近日兼放髭鬚白，猶向人前作背面。',26,'全唐诗/poet.tang.53000.json','["近日兼放髭鬚白，猶向人前作背面。", "（見《大唐傳載》）。"]'),
('a92607ca-6a92-49ef-9afb-11aaa881e5f8','劍詩','盧綸','唐','唐诗','tang','','[]','太平時節無人看，雪刃閒封滿匣塵。',86,'全唐诗/poet.tang.53000.json','["太平時節無人看，雪刃閒封滿匣塵。", "（見《吟窗雜錄》卷十四《詩中旨格》）（按：《吟窗雜錄》本作者名作「處綸」，茲依《詩學指南》卷四改正。", "《全唐詩》卷八四九收作處默詩，疑誤。", "）。"]'),
('60b061a4-d07e-4cbb-a5f3-1f5f4be92ed6','竇五判官罷舉赴商州辟書袖文相訪書懷話舊因抒鄙懷（按：此詩見《竇氏聯珠集》，下署「重表兄太府卿賜紫金魚袋韋渠牟」。《全唐詩》卷三一四收本詩，題作《贈竇五判官》，刪略過甚，今爲補原題，詩不重錄。）','韋渠牟','唐','唐诗','tang','','[]','空。',2,'全唐诗/poet.tang.53000.json','["空。"]'),
('b779dbde-1303-4f61-a021-d9a933db31d5','句','懷素','唐','唐诗','tang','','[]','人人來問此中妙，懷素自云初不知。',320,'全唐诗/poet.tang.53000.json','["人人來問此中妙，懷素自云初不知。", "（見明汪珂玉《汪氏珊瑚網法書題跋》卷二《藏真草書清淨經》附劉世昌跋引）（按：《全唐詩》卷八○八收懷素詩二首，傳云：「懷素，京兆人，從玄奘法師出家，上元三年，詔住西太原寺，尋歸西京。", "以草書名。", "」此傳實將同名之另一僧事跡誤入。", "玄奘法嗣懷素，事跡詳《開元釋教錄》卷九，《宋高僧傳》卷十四，精於四分律，未聞其能詩善書。", "所收二詩，皆以草書名世之長沙僧懷素作。", "《題張僧繇醉僧圖》，出《圖畫見聞志》卷五：「又僧繇曾作《醉僧圖》傳於世，長沙僧懷素有詩云〖略。", "〗」又米芾《書史》云：「懷素草書『祝融高座對寒峰』綠絹帖兩行，此字最佳，石紫微常刻石。", "」所引一句，即《寄衡嶽僧》之首句。", "《沅湘耆舊集》卷十收二詩歸長沙草書僧，是。", "）。"]'),
('c60bd6fd-e54f-4f4b-95a0-cdd86bc9a5e2','五言答李師尚','皎然','唐','唐诗','tang','','[]','雅篇忽見遺，婉□開緘發。',179,'全唐诗/poet.tang.53000.json','["雅篇忽見遺，婉□開緘發。", "惠風搖精思，瓊蕋疑花□。", "（下缺）（見《四部叢刊》本《皎然集》卷一）（按：《皎然集》錄此詩四句後，尚有「空門青山月」至「來稅丘中轍」共七句。", "檢《全唐詩》卷八一五，此七句爲《酬李司直縱諸公冬日遊妙喜寺題照昱二上人房寄長城潘丞述》一詩之末七句。", "可知原本在《五言答李師尚》前四行後，適有缺頁或缺行，刊刻者不審，遂將二詩合成一篇，今爲析出。", "）。"]'),
('ad34e0e9-d29c-4106-a809-2b0fd00a7760','三言重擬五雜俎','皎然','唐','唐诗','tang','','[]','五雜俎，篋中線。',130,'全唐诗/poet.tang.53000.json','["五雜俎，篋中線。", "往復還，雙飛燕。", "不得已，長門怨。", "（晝。", "下缺。", "見同書卷十。", "）（按：原詩應爲與顏真卿等聯句，今僅存皎然之作。", "又按：《全唐詩》卷七九四聯句《秋日潘述自長城至霅上……》第十句皎然詩缺一字。", "明刻本《吳興藝文補》卷四三錄此詩不缺，此句爲「懽敍難兼遂」。", "）。"]'),
('0d8721b3-3012-4abc-afaf-ed8279cf4f13','句','陸羽','唐','唐诗','tang','','[]','行坐誦佛書。',30,'全唐诗/poet.tang.53000.json','["行坐誦佛書。", "（見齊己《白蓮集》卷九《過陸鴻漸舊居》自注引）。"]'),
('c06d4d14-42a8-4c2e-83d5-f56c282c1374','與耿湋聯句','陸羽','唐','唐诗','tang','','[]','城裏攜籠萬壑前。',26,'全唐诗/poet.tang.53000.json','["城裏攜籠萬壑前。", "（羽。", "下闕。", "見席刻本《耿湋詩集》）。"]'),
('d533ffc4-b725-4653-89e3-ce26721c8e0c','入南澗','鮑君徽','唐','唐诗','tang','','[]','殘芳𦶜蘭馥，照水何花紅。',12,'全唐诗/poet.tang.53000.json','["殘芳𦶜蘭馥，照水何花紅。"]'),
('14288bb1-77c2-48ad-9fa5-966e9578e6f2','閑[宵]（霄）望月','鮑君徽','唐','唐诗','tang','','[]','轉扇來清風，援琴飛白雪。',12,'全唐诗/poet.tang.53000.json','["轉扇來清風，援琴飛白雪。"]'),
('575198d9-2117-4ef5-967f-f5a920da59a5','晚眺','鮑君徽','唐','唐诗','tang','','[]','遠樹擁川斷，晴雲抱日流。',32,'全唐诗/poet.tang.53000.json','["遠樹擁川斷，晴雲抱日流。", "（均見《吟窗雜錄》卷三十《古今才婦》）。"]'),
('e32a0167-27b0-4bbc-9083-0fbcad864550','寶應初征史朝義過虢州題僧寺壁（題擬）','德宗皇帝李适','唐','唐诗','tang','','[]','高僧居淨域，客子戀皇宮。',527,'全唐诗/poet.tang.53000.json','["高僧居淨域，客子戀皇宮。", "試訪毘耶室，旋（《大典》作「施」）遊方丈中。", "禪林吹梵響，忍草散香風。", "妙說三元（《大典》作「玄」）義，能談不二宗。", "色空雙已滅，內外兩緣同。", "識盡無生理，乃覺出凡（《大典》作「梵」，《金文最》作「樊」）籠。", "（見光緒二年刊高錦榮纂《靈寶縣志》卷八《藝文》下。", "又見《金文最》卷七一許安仁大定十六年撰《御題寺重即唐德宗詩碑》（徐俊告）、《永樂大典》卷一三八二三引《洛陽志》〖張忱石告〗）（按：《永樂大典》引《洛陽志》：「御題寺，寺在靈寶南里。", "唐寶應元年，德宗以皇子爲天下兵馬元帥，統兵征史朝義過）（之，題詩壁間。", "厥後十七年即位，寺僧玄覺詣長安求寺額，詔以御題名之。", "」其後又錄無名氏詩云：「解鞍投宿得禪宮，識破浮生萬境空。", "夜靜稍□簷外雨，朝來知是葉間風。", "」此詩未詳何代何人所作，姑附此。", "清畢沅《中州金石記》卷五：「御題寺唐德宗詩碣，大定十六年立，許安仁記幷書，在御碑寺。", "額正書云：『御題寺唐德宗天章碑。", "』下爲五律詩一首。", "知年月人名者，據黃叔璥《中州金石攷》也。", "」今按：《縣志》錄此詩原題作《題御碑寺》，然寺名因德宗此詩而得名，詩題顯爲後人追補。", "今重爲擬題。", "黃叔璥書未見。", "碑記，《縣志》亦未收。", "有關史事，兩《唐書》、《通鑑》所記甚詳，不具錄。", "）。"]'),
('0ac0e1c4-88b1-4786-ac99-ba56a69709cf','贈何遐','韋臯','唐','唐诗','tang','','[]','腰間寶劍七星文，掌上彎弓掛六鈞。',75,'全唐诗/poet.tang.53000.json','["腰間寶劍七星文，掌上彎弓掛六鈞。", "箭發雲中雙鴈落，始知秦地有將軍。", "（見《輿地紀勝》卷一四五《簡州》）（按：《全唐詩》卷三一四收此詩，有缺文，今重錄。", "）。"]'),
('e0b5cc2f-f6ca-435a-b733-6ff323ea50dd','靈巖述舊','歐陽詹','唐','唐诗','tang','','[]','不到靈巖又二年，重來風景尚依然。',96,'全唐诗/poet.tang.53000.json','["不到靈巖又二年，重來風景尚依然。", "層巒迥出青霄外，倦鳥歸飛夕照邊。", "坐愛雲林泉石好，行尋煖谷野橋連。", "同遊不覺天將晚，暫借僧房一榻眠。", "（見嘉靖《略陽縣志》卷六、光緒三十年重刊譚瑀《略陽縣志》卷四）。"]'),
('ab6b212b-6f3c-4df1-a370-5723501ea483','登汾上閣','鄭儋','唐','唐诗','tang','','[]','汾樓秋水濶，宛似到閶門。',118,'全唐诗/poet.tang.53000.json','["汾樓秋水濶，宛似到閶門。", "惆悵江湖思，惟將南客論。", "（見《歐陽行周文集》卷九《陪太原鄭行軍中丞登汾上閣中丞詩曰汾樓秋水濶宛似到閶門惆悵江湖思惟將南客論南客即儋也輒書即事上答》）（按：《全唐詩》卷七八三收此詩於鄭中丞名下，今考定爲鄭儋作。", "）。"]'),
('e403ec58-d2d0-4405-bf61-00019503e976','江南春 一','許稷','唐','唐诗','tang','','[]','江南正月春花早，梅花柳花夾長道。',16,'全唐诗/poet.tang.53000.json','["江南正月春花早，梅花柳花夾長道。"]'),
('f904dc01-63de-491e-a253-4ed43051d6b5','江南春 二','許稷','唐','唐诗','tang','','[]','江南二月春光半，杏白桃紅香蘂散。',16,'全唐诗/poet.tang.53000.json','["江南二月春光半，杏白桃紅香蘂散。"]'),
('3c848c7c-12eb-47f9-92da-66aede6fb334','江南春 三','許稷','唐','唐诗','tang','','[]','江南三月春光暮，蝴蝶閑飛遶深圃。',35,'全唐诗/poet.tang.53000.json','["江南三月春光暮，蝴蝶閑飛遶深圃。", "（見《吟窗雜錄》卷二九《歷代吟譜》）。"]'),
('c419dd67-145c-4df5-aa0c-a2b0243b765f','龍池（題擬）','張崇傑','唐','唐诗','tang','','[]','爰有寒泉碧玉泓，天淵千古湛澄清。',35,'全唐诗/poet.tang.53000.json','["爰有寒泉碧玉泓，天淵千古湛澄清。", "（見影天一閣藏《正德青州府志》卷六）。"]'),
('a17b9e67-e646-4f2f-8524-33fd876523e9','遊雲門','崔子向','唐','唐诗','tang','','[]','長松落落勝天台，佛殿經牕半嶺開。',46,'全唐诗/poet.tang.53000.json','["長松落落勝天台，佛殿經牕半嶺開。", "郭裏鐘聲山裏去，上方流水下方來。", "（見《會稽掇英總集》卷六）。"]'),
('59b31220-8df4-4d10-9738-b3267f85da80','寄勸俗兄弟二首 一','法照','唐','唐诗','tang','','[]','同氣連枝本自榮，些些言語莫傷情。',16,'全唐诗/poet.tang.53000.json','["同氣連枝本自榮，些些言語莫傷情。"]'),
('23909c3e-2783-4dc6-8d7d-587b24caa7bd','寄勸俗兄弟二首 二','法照','唐','唐诗','tang','','[]','兄弟同居忍便安，莫因毫末起爭端。',53,'全唐诗/poet.tang.53000.json','["兄弟同居忍便安，莫因毫末起爭端。", "眼前生子又兄弟，留與兒孫作樣看。", "（見影清光緒抄本張鵬翼修《洋縣志》卷七）。"]'),
('4c1f4880-4438-4ed5-8aca-e26aef5f92be','示門人頌','紅螺山和尚','唐','唐诗','tang','','[]','紅螺山子近邊夷，度得之流半是奚。',44,'全唐诗/poet.tang.53000.json','["紅螺山子近邊夷，度得之流半是奚。", "共語問醻都不會，可憐祇解那斯祁。", "（見《五燈會元》卷三）。"]'),
('d690fba1-7da0-4bc0-8a73-e5e26c71df33','湘妃廟','周渭','唐','唐诗','tang','','[]','代變時遷事跡存，見來誰不暗消魂。',151,'全唐诗/poet.tang.53000.json','["代變時遷事跡存，見來誰不暗消魂。", "上程此日湘江過，依舊修篁有舊痕。", "（見《永樂大典》卷五七六九，中華書局影印本第六十冊。", "）（按：《永樂大典》署「御史周謂」作。", "《周君墓誌銘》云：「拜監察御史，董選補於南方。", "南方吏理清而風俗阜，抑君是賴，復命其勞，轉殿中侍御史。", "」詩或即渭此次南行時作。", "「謂」爲「渭」之誤。", "）。"]'),
('7a11ce1c-3c17-4e06-ae10-d776d611a750','','陳詡','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('0febf41b-c8b5-432c-8d8f-2b6364c49fd6','新雷','陳詡','唐','唐诗','tang','','[]','一聲離碧海，萬里發芽生。',32,'全唐诗/poet.tang.53000.json','["一聲離碧海，萬里發芽生。", "（見《吟窗雜錄》卷十四《詩中旨格》引）。"]'),
('d7e522cd-3392-4a9b-a7a8-ec41174ffe06','紫玉見南山賦附歌','李覲','唐','唐诗','tang','','[]','歸大素兮遠蠻屏，有瑞玉兮見霄嶺。',57,'全唐诗/poet.tang.53000.json','["歸大素兮遠蠻屏，有瑞玉兮見霄嶺。", "浮紫氣於雲際，混清輝於水影。", "庶南山之不騫，期我皇之惟永。", "（見《文苑英華》卷八六）。"]'),
('60f5d7e4-2bea-4785-8cdd-16e1bf83ae65','七言宿西臺江寄別南間寺一首','陳羽','唐','唐诗','tang','','[]','曾寄中天第一峰，新辭石室與巖松。',32,'全唐诗/poet.tang.53000.json','["曾寄中天第一峰，新辭石室與巖松。", "歸舟獨宿寒江上，夜半遙聽雲外鐘。"]'),
('45dde79a-bada-41dc-8bf4-d79517e57b6a','五言宿妙喜寺贈遠公一首','陳羽','唐','唐诗','tang','','[]','空學西天客，冥然生意長。',56,'全唐诗/poet.tang.53000.json','["空學西天客，冥然生意長。", "夏高雲納愁近壇涼（此聯抄本原缺二字）。", "月半生空處，孤燈宿上方。", "欲離夕字想，何法御心王。", "。"]'),
('a5aff7b4-009b-4cb2-bb2f-195917324a45','五言秋夜南間寺江尚院翫月一首','陳羽','唐','唐诗','tang','','[]','圓月吐青[□]，蕭寥天宇寬。',70,'全唐诗/poet.tang.53000.json','["圓月吐青[□]，蕭寥天宇寬。", "凝光與空[□]，虛寂兩無端。", "露重草衣濕，[□□]竹泉寒。", "欲持高潔意，長此共林巒。", "（均見日本藏唐抄本《唐詩卷》）。"]'),
('0254bcd5-b7b9-43c3-9a6c-b2a8f8aba5a1','送最澄闍梨還日本詩','陸質','唐','唐诗','tang','','[]','海東國主尊台教，遣僧來聽《妙法華》。',339,'全唐诗/poet.tang.53000.json','["海東國主尊台教，遣僧來聽《妙法華》。", "歸來香風滿衣裓，講堂日出映朝霞。", "（見日本比睿山無量院沙門慈本〖一七九四--一八六八〗在文久二年〖一八六二〗撰《天台霞標》第四篇第一卷。", "轉錄自《中國哲學史研究》一九八五年第一期刊日本戶崎哲彥撰《留傳日本的有關陸質的史料及若干考證》。", "此篇承束景南先生告知。", "）（按：慈本於詩下注云：「此詩未知出於何書。", "慈本獲之希烈宿稱鈔書中也。", "原本海作汝，妙作於，慈本依義改之。", "或曰：此詩載在《禪宗日工集》，又改數字載之《本朝高僧傳》某傳也。", "」戶崎氏考證此詩又見於《空華老師日用工夫略集》卷一，第二句作「故遣僧來聽《法華》」。", "約在公元一三○○年前後即傳爲陸質詩。", "但吳顗等九人送最澄詩，皆爲五言律詩，唯此首爲七言古絕，「因此，該詩疑爲後人假托之作，或以意採錄。", "」）。"]'),
('3c6c47b1-bd77-4576-a71f-7ee86a3fff63','答復禮禪師《真妄偈》（題擬）','澄觀','唐','唐诗','tang','','[]','迷真妄念生，悟真妄即止。',70,'全唐诗/poet.tang.53000.json','["迷真妄念生，悟真妄即止。", "能迷非常迷，安得長相似。", "從來未曾悟，故說妄無始。", "知妄本自真，方是恒妙理。", "分別心未忘，何由出生死。", "（《林間錄》卷上）。"]'),
('aafef9ef-57d1-4cda-ad11-ff3702caaba0','台州相送詩一首（送最澄上人還日本國敍）','吳顗','唐','唐诗','tang','','[]','重譯越滄溟，來求觀行經。',99,'全唐诗/poet.tang.53000.json','["重譯越滄溟，來求觀行經。", "問鄉朝指日，尋路夜看星。", "得法心念喜，乘杯體自寧。", "扶桑一念到，風水豈勞形？", "（見最澄《顯戒論緣起》卷上，轉錄自張步雲《唐代逸詩輯存》。", "參《東南文化》一九九○年六期周琦等錄文。", "）。"]'),
('91843347-96cb-46f3-b526-b1d87e79c103','送最澄上人還日本國','孟光','唐','唐诗','tang','','[]','往歲來求請，新年受法歸。',53,'全唐诗/poet.tang.53000.json','["往歲來求請，新年受法歸。", "衆香隨貝葉，一雨潤禪衣。", "素舸輕翻浪，征帆背落暉。", "遙知到本國，相見道流稀。", "（同前）。"]'),
('a1afc5ff-f303-4d15-870e-99de1f49bafa','送最澄上人還日本國','毛渙','唐','唐诗','tang','','[]','萬里求文教，王春愴別離。',120,'全唐诗/poet.tang.53000.json','["萬里求文教，王春愴別離。", "未（日本甲本注：「未，應作來。", "」）傳不住相，歸集祖行詩。", "舉筆論蕃意，焚香問漢儀。", "莫言滄海濶，杯度自應知。", "（同前）（按：此詩原署「台州臨縣令毛渙」，台州有臨海縣，無臨縣，「臨縣」應即指臨海縣，「臨」下脫去「海」字。", "）。"]'),
('3149cf05-af6f-4c05-9538-255b6bc22784','送最澄上人還日本國','崔謩','唐','唐诗','tang','','[]','一葉來自東，路在滄溟中。',53,'全唐诗/poet.tang.53000.json','["一葉來自東，路在滄溟中。", "遠思日邊國，却逐波上國。", "問法言語異，傳經文字同。", "何當至本處，定作玄門宗。", "（同前）。"]'),
('82e86161-3f75-42f7-86bb-283985a79f0b','送最澄上人還日本國','全濟時','唐','唐诗','tang','','[]','家與扶桑近，煙波望不窮。',53,'全唐诗/poet.tang.53000.json','["家與扶桑近，煙波望不窮。", "來求貝葉偈，遠過海龍宮。", "流水隨歸處，征帆遠向東。", "相思渺無畔，應使夢魂通。", "（同前）。"]'),
('f58e6e7a-1998-4db8-bd97-608e204cc37c','','行滿','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('aa78827f-c1ae-477d-8930-62fc0883ffc8','送最澄上人還日本國','行滿','唐','唐诗','tang','','[]','異域鄉音別，觀心法性同。',53,'全唐诗/poet.tang.53000.json','["異域鄉音別，觀心法性同。", "來時求半偈，去罷悟真空。", "貝葉翻經疏，歸程大海東。", "何當到本國，繼踵大師風。", "（同前）。"]'),
('42ea5e37-6239-47a9-bb00-acd22768969a','送最澄上人還日本國','許蘭','唐','唐诗','tang','','[]','道高心轉實，德重意唯堅。',67,'全唐诗/poet.tang.53000.json','["道高心轉實，德重意唯堅。", "不懼洪波遠，中華訪法緣。", "精勤同忍可，廣學等彌天。", "歸到扶桑國，迎人擁海壖。", "（日本甲本注：「壖，應作煙。", "」同前）。"]'),
('868fe0f5-f452-43a0-a612-4de91d3fe24a','送最澄上人還日本國','幻夢','唐','唐诗','tang','','[]','劫（疑「却」）返扶桑路，還乘舊葉船。',90,'全唐诗/poet.tang.53000.json','["劫（疑「却」）返扶桑路，還乘舊葉船。", "上潮看浸日，翻浪欲陷（日本甲本注：「陷，應作滔。", "」）天。", "求宿寧逾日（日本甲本注：「日，疑月。", "」），雲行詎隔年？", "遠將乾竺法，歸去化生緣。", "（同前）。"]'),
('0fe41047-6d3a-4949-be25-456ef1a7b286','送最澄上人還日本國','林暈','唐','唐诗','tang','','[]','求獲真乘妙，言歸倍有情。',82,'全唐诗/poet.tang.53000.json','["求獲真乘妙，言歸倍有情。", "玄關心地得，鄉思日邊生。", "作梵慈雲布，浮杯漲海清。", "看看達彼岸，長老散華迎。", "（同前）（按：自吳顗以下九人詩，均轉引自張步雲《唐代逸詩輯存》。", "）。"]'),
('f0e3c601-7eb9-417c-a52c-01924612fa16','扣舷歌 一','黃子野','唐','唐诗','tang','','[]','早潮初上海門開，漠漠彤雲雪作堆。',32,'全唐诗/poet.tang.53000.json','["早潮初上海門開，漠漠彤雲雪作堆。", "一百六峰都掩盡，不知何處有僧來。"]'),
('d0be3234-43f3-4276-8e3c-3a7a68788a4f','扣舷歌 二','黃子野','唐','唐诗','tang','','[]','幾日江頭醉不醒，滿天風雪臥滄溟。',67,'全唐诗/poet.tang.53000.json','["幾日江頭醉不醒，滿天風雪臥滄溟。", "定知酒伴無尋處，門外松濤坐獨聽。", "（《堅瓠壬集》卷一引明徐𤊹《榕陰新檢》。", "以上二詩承張靖龍同志錄示。", "）。"]'),
('9c0c941d-5413-4963-bd28-809c04b6287b','詩偈 一','龐藴','唐','唐诗','tang','','[]','楞伽寶山高，四面無行路。',108,'全唐诗/poet.tang.53000.json','["楞伽寶山高，四面無行路。", "惟有達道人，乘空到彼處。", "羅漢若悟空，擲錫騰空去。", "緣覺若悟空，醒見三生事。", "菩薩若悟空，十方同一處。", "諸佛若悟空，妙理空中住。", "空理真法身，法身即常住。", "佛身祇這是，迷人自不悟。", "一切若不空，苦厄從何度。"]'),
('397fc01c-88de-4acc-99b3-8e071769d380','詩偈 二','龐藴','唐','唐诗','tang','','[]','大海濶三千，巨深五六萬。',108,'全唐诗/poet.tang.53000.json','["大海濶三千，巨深五六萬。", "余特七尺軀，入裏飲一頓。", "當時枯竭盡，龍王自出現。", "大閱經藏門，請爲說一徧。", "依如說無法，龍王悟知見。", "賣君髻中珠，隱在如來殿。", "戴將軍陳頭，賊降不敢戰。", "世上有仁人，得永離貧賤。", "不貪有爲身，當見如來面。"]'),
('4180447d-6449-43a0-9d27-6d4c42ea11c4','詩偈 三','龐藴','唐','唐诗','tang','','[]','日輪漸漸短，光陰一何促。',108,'全唐诗/poet.tang.53000.json','["日輪漸漸短，光陰一何促。", "身如水上沫，命似當風燭。", "常須慎四虵，持心捨三毒。", "相見論脩道，更莫著婬慾。", "婬慾暫時情，長劫入地獄。", "縱令得出來，異形人不識。", "或時成四足，或是總無足。", "可惜好人身，變作醜頭畜。", "今是預報知，行行須努力。"]'),
('7182685e-6433-4ca7-a29e-81fe5e4209de','詩偈 四','龐藴','唐','唐诗','tang','','[]','余家久住山，早已離城市。',146,'全唐诗/poet.tang.53000.json','["余家久住山，早已離城市。", "草屋有三間，一間長丈二。", "一間安葛五，一間塵六四。", "余家自內房，終日閒無事。", "昨因黑月二十五，初夜飲酒醉，兩人相渾雜，種種調言氣。", "余家不奈煩，放火燒屋積。", "葛五成灰燼，塵六無一二。", "有物蕩淨盡，惟餘空閑地。", "自身赤裸裸，體上無衣被。", "更莫憂盜賊，逍遙安樂睡。", "一等被火燒，同行不同利。"]'),
('7b5fcad0-b3ab-431c-856a-04adbe05b5d0','詩偈 五','龐藴','唐','唐诗','tang','','[]','出家捨煩惱，煩惱還同住。',132,'全唐诗/poet.tang.53000.json','["出家捨煩惱，煩惱還同住。", "癡心覓福田，騃意承救度。", "十二因緣管，無繇免來去。", "依智不依識，依義不依語。", "佛心一子地，蠢動皆男女。", "平等如虛空，善惡俱無取。", "既不造天堂，誰受三塗苦。", "有無盡無餘，乘空能自度。", "神作如來身，智作如來庫。", "涌出波羅蜜，流通正道路。", "渾身加身佛，迷人自不悟。"]'),
('35954355-314d-4d67-90e3-a614ae682d96','詩偈 六','龐藴','唐','唐诗','tang','','[]','八十隨形好，相有三十二。',132,'全唐诗/poet.tang.53000.json','["八十隨形好，相有三十二。", "四諦及三乘，同一無生智。", "名爲一合相，非是人同類。", "凡夫共佛同，一體無有異。", "若論心與境，懸隔不相似。", "凡夫惟妄想，攀緣徧天地。", "常懷三毒心，損他將自利。", "佛心常慈悲，善惡無有二。", "蠢動諸衆生，心同一子地。", "六識空無生，六塵將布施。", "意根成妙覺，七識平等智。"]'),
('4a11b33f-2fa1-4364-826c-fe6e9d5ce188','詩偈 七','龐藴','唐','唐诗','tang','','[]','富兒空毛行，貧兒把他物。',120,'全唐诗/poet.tang.53000.json','["富兒空毛行，貧兒把他物。", "被物牽入廛，買賣不得出。", "覺暮便歸舍，黃昏黑漆漆。", "所求不稱意，合家加啾唧。", "自無般若性，乏欠波羅蜜。", "把繩入草裏，自繫百年畢。", "實是可憐許，冥冥不見日。", "富兒雖空手，家中甚富溢。", "自有無盡藏，不假外緣物。", "周流用不窮，要者從理出。"]'),
('950eeec2-9fab-4157-a919-92e399629ad3','詩偈 八','龐藴','唐','唐诗','tang','','[]','古時不異今，今時不異古。',120,'全唐诗/poet.tang.53000.json','["古時不異今，今時不異古。", "生事日日滅，有所不能作。", "世上乏錢財，守空無貨賂。", "理詩日日新，朽宅時時故。", "聞船未破漏，愛河須早渡。", "出過三江口，逍遙神自悟。", "損之又損之，俄成貝多樹。", "臨行途路難，無船可相渡。", "業老見閻公，沒你分疎處。", "若見優曇花，處處無疑慮。"]'),
('899584ea-3d52-48d6-ae4b-30046377fd3f','詩偈 九','龐藴','唐','唐诗','tang','','[]','世上蠢蠢者，相見只論錢，張三五百貫，李四有幾千，趙大折却本，五六太迍邅。',96,'全唐诗/poet.tang.53000.json','["世上蠢蠢者，相見只論錢，張三五百貫，李四有幾千，趙大折却本，五六太迍邅。", "口常談三業，心中慾火然。", "癡狼咬肚熱，貪鬼撮頭牽。", "有脚復有足，開眼常睡眠。", "羅剎同心腹，何日見青天。", "青天不可見，地獄結因緣。"]'),
('946da0ca-bd4b-4d58-bf49-7aeb71491e93','詩偈 十','龐藴','唐','唐诗','tang','','[]','故宅守真妻，不好求外色。',96,'全唐诗/poet.tang.53000.json','["故宅守真妻，不好求外色。", "真妻生男女，長大同榮辱。", "外色有男女，長成愛作賊。", "有妻累我來，牽我入牢獄。", "我亦早識渠，誘引入吾室。", "內外總團圓，同飡一鉢食。", "食飽斷虛妄，無相即無福。", "若論真寂理，同歸無所得。"]'),
('33a92fca-11f3-4a8b-86cf-3f794c087b37','詩偈 十一','龐藴','唐','唐诗','tang','','[]','昔日在有時，常被有人欺，一相（《宗鏡錄》卷四八作「總總」）生分別，見聞多是非。',162,'全唐诗/poet.tang.53000.json','["昔日在有時，常被有人欺，一相（《宗鏡錄》卷四八作「總總」）生分別，見聞多是非。", "已後入無時（《宗鏡錄》作「後向無中坐」），又被無人欺，一向看心坐，冥冥無所知。", "有無俱是執，何處是無爲？有無同一體，諸相盡皆（《宗鏡錄》作「皆盡」）離。", "心同虛空故，虛空是我師（《宗鏡錄》作「無所依」）。", "若論無相理，惟我（《宗鏡錄》作「有」）父王知。"]'),
('4ee23cdd-1fa8-43ed-82a1-ab266260ce07','詩偈 十二','龐藴','唐','唐诗','tang','','[]','老來無氣力，房舍不能修。',96,'全唐诗/poet.tang.53000.json','["老來無氣力，房舍不能修。", "基頹柱根朽，椽梠脫差抽。", "泥塗零落盡，四壁空颼颼。", "舉頭看梁柱，星星見白頭。", "慧雲降法雨，智水沃心流。", "家中空豁豁，屋倒亦何憂。", "山莊草菴破，余歸大宅遊。", "生生不揀處，隨類說無求。"]'),
('dd9397a0-bfe4-437c-a3f3-e9125a6d3812','詩偈 十三','龐藴','唐','唐诗','tang','','[]','人有五般花，花蘭（一本云「花爛」）變成香。',141,'全唐诗/poet.tang.53000.json','["人有五般花，花蘭（一本云「花爛」）變成香。", "氤氳滿故宅，供養本爺娘。", "有人見不識，報道十月桑。", "外塵一念愛，合成五色囊。", "囊中起三柱，柱上有千梁。", "梁變成地獄，地獄作天堂。", "緣箇一羣賊，自作自消亡。", "縱令存草命，何時還故鄉？", "文字說定慧，定慧是爺娘。", "何不依理智，逐色在他鄉。", "早須歸大宅，孝順見爺娘。"]'),
('3407b4bc-9422-4cae-90eb-65ffa6874f7b','詩偈 十四','龐藴','唐','唐诗','tang','','[]','爺娘聞子來，端坐見咍咍。',61,'全唐诗/poet.tang.53000.json','["爺娘聞子來，端坐見咍咍。", "我所有寶藏，分付鑰匙開。", "非論窮子富，舉國免三災。", "如意用無盡，更不受胞胎。", "逍遙無障礙，終日見如來。", "。"]'),
('568ae776-67df-4abb-8c89-1904aec8390d','詩偈 十五','龐藴','唐','唐诗','tang','','[]','如來愍諸子，平等無高下。',84,'全唐诗/poet.tang.53000.json','["如來愍諸子，平等無高下。", "諸子自愚癡，所以難教化。", "直心是道場，子心轉姦詐。", "遣子淨三業，轉愛論俗話。", "遣子內脩真，向外轉尋假。", "遣子學無相，捻他有相把。", "無諍最第一，論義成相駡。"]'),
('f3cf7a03-7069-4508-a79f-13ba3935fcb3','詩偈 十六','龐藴','唐','唐诗','tang','','[]','無貪勝布施，無癡勝坐禪。',121,'全唐诗/poet.tang.53000.json','["無貪勝布施，無癡勝坐禪。", "無瞋勝持戒，無念勝求緣。", "盡見（《祖堂集》卷十五作「現」）凡夫事，夜來安樂眠。", "寒時向火坐，火本實（《祖堂集》作「寔本」）無烟。", "不忌（《祖堂集》作「怕」）黑闇女，不求功德天。", "任運生方便，皆同般若船。", "若能如是學，功德實無邊。"]'),
('3a4c8387-a4f9-4657-a29a-0e5014606eb1','詩偈 十七','龐藴','唐','唐诗','tang','','[]','十方同一等，此是真如寺。',84,'全唐诗/poet.tang.53000.json','["十方同一等，此是真如寺。", "裏有無量壽，本來無名字。", "凡夫不入理，心緣世上事。", "乞錢買瓦木，蓋他虛空地。", "却被六賊驅，背却真如智。", "終日受艱辛，妄想圖名利。", "如此學道人，累劫終不至。"]'),
('3fd77afa-03de-459a-aafb-a2a65aea65f3','詩偈 十八','龐藴','唐','唐诗','tang','','[]','無有報龐大，空空無處坐。',84,'全唐诗/poet.tang.53000.json','["無有報龐大，空空無處坐。", "家內空空空，空空無有貨。", "日在空裏行，日沒空裏臥。", "空坐空吟詩，詩空空相和。", "莫怪純用空，空是諸佛座。", "世人不別寶，空即是實貨。", "若嫌無有空，自是諸佛定。"]'),
('ddbc240d-a017-46f5-b0d5-4650be8b7743','詩偈 十九','龐藴','唐','唐诗','tang','','[]','有人有所知，有事有是非。',84,'全唐诗/poet.tang.53000.json','["有人有所知，有事有是非。", "聞道無相理，心執不生疑。", "五歲更不長，祇作阿孩兒。", "將拳口裏咬，百年不肯離。", "假花雖端正，究竟不充飢。", "都緣癡孩子，不識是權宜。", "如來無相理，有作盡皆非。"]'),
('2c74a4f7-eedb-4e9d-a764-b91566a6233c','詩偈 二十','龐藴','唐','唐诗','tang','','[]','合瞋不須假，合喜不須喜。',84,'全唐诗/poet.tang.53000.json','["合瞋不須假，合喜不須喜。", "喜即婬慾生，瞋即毒蛇起。", "毒蛇起猛火，婬慾成貪鬼。", "猛火和貪鬼，癡狼咬心底。", "妄想如恆沙，煩惱無遮止。", "無明黑漆漆，渴來飲鹹水。", "終日緣事走，不肯入空理。"]'),
('cffd4a47-f5e1-49a6-89ac-ec51d5e33589','詩偈 二十一','龐藴','唐','唐诗','tang','','[]','我見好畜生，知是嘍羅漢。',87,'全唐诗/poet.tang.53000.json','["我見好畜生，知是嘍羅漢。", "枉法取人錢，誇道能計算。", "得即渾家用，受苦沒人伴。", "有力任他騎，棒鞭脊上楦。", "觜上著{金革}頭，口中銜鐵片。", "項領被磨穿，鼻孔芒繩絆。", "自種還自收，佛也不能斷。"]'),
('99ea5df9-a8ff-4361-9a0a-1f2c0fed595e','詩偈 二十二','龐藴','唐','唐诗','tang','','[]','癡兒無智慧，自嫌阿爺醜。',84,'全唐诗/poet.tang.53000.json','["癡兒無智慧，自嫌阿爺醜。", "阿娘生得身，嫌孃無面首。", "拋却親爺孃，外邊逐色走。", "六親相將作，尋常不開口。", "恆遊十二月，月月飲欲酒。", "夜夜不曾醒，醉吐飼猪狗。", "如此惡男子，緣事不了手。"]'),
('e372f312-0cfe-4e70-a349-224cfcfd7696','詩偈 二十三','龐藴','唐','唐诗','tang','','[]','余有一寶劍，非是世間鐵。',84,'全唐诗/poet.tang.53000.json','["余有一寶劍，非是世間鐵。", "成來更不磨，晶晶白如雪。", "氣衝浮雲散，光照三千徹。", "吼作獅子聲，百獸皆腦裂。", "外國盡歸降，衆生悉磨滅。", "滅已復還生，還生作金鐍。", "帶將處處行，樂者即爲說。"]'),
('04ba5549-8d1a-4ec1-a9a6-97256fe6c294','詩偈 二十四','龐藴','唐','唐诗','tang','','[]','知余轉般若，見余轉金剛，合掌恭敬了，不動見空王。',72,'全唐诗/poet.tang.53000.json','["知余轉般若，見余轉金剛，合掌恭敬了，不動見空王。", "亦勝身命施，亦勝坐天堂，亦勝五臺供，亦勝求西方。", "於住而無住，其福不可量。", "有爲如夢幻，無相契真常。"]'),
('afe1ae6b-4552-4872-a661-69cc3a2b3e2d','詩偈 二十五','龐藴','唐','唐诗','tang','','[]','如來大慈悲，廣演波羅蜜。',72,'全唐诗/poet.tang.53000.json','["如來大慈悲，廣演波羅蜜。", "了知三界苦，殷勤勸君出。", "得之不肯修，寔是頑皮物。", "他是已成佛，汝是當成佛。", "當成自不成，是誰之過失？", "已後累劫苦，莫尤過去佛。"]'),
('b0f06566-7569-4224-a14a-bdc47438a25a','詩偈 二十六','龐藴','唐','唐诗','tang','','[]','誰家郎君子，開眼造地獄。',72,'全唐诗/poet.tang.53000.json','["誰家郎君子，開眼造地獄。", "枉法取人錢，養那一羣賊。", "饒伊家戶大，業成出不得。", "除非輪迴滿，換形償他力。", "看君騎底驢，總是如此色。", "無事被鞭杖，有理說不得。"]'),
('b5104436-6de6-4cd0-83b3-4e7d68f38e94','詩偈 二十七','龐藴','唐','唐诗','tang','','[]','愚人打瓮破，求人望錮護。',72,'全唐诗/poet.tang.53000.json','["愚人打瓮破，求人望錮護。", "惡法得錢財，布施擬補處。", "物色不相當，此事無煩做。", "縱然有少福，那得地獄去。", "罪福當頭行，何時相值遇。", "自本猶折却，安得有利路。"]'),
('3f9d984a-b9a2-4494-9f97-0cb0dca21300','詩偈 二十八','龐藴','唐','唐诗','tang','','[]','先須持五戒，方始得人身。',72,'全唐诗/poet.tang.53000.json','["先須持五戒，方始得人身。", "有財將布施，身即不窮貧。", "若行十善業，聞道得天人。", "天人生滅福，來去如車輪。", "有爲接梵世，不及一毫真。", "更欲談玄妙，慮恐法王瞋。"]'),
('6631753f-ac71-4163-87de-77bd3e596cb7','詩偈 二十九','龐藴','唐','唐诗','tang','','[]','一皮較一皮，孫子不如兒。',72,'全唐诗/poet.tang.53000.json','["一皮較一皮，孫子不如兒。", "坐禪勝讀經，讀經勝有爲。", "尋文不識理，棄母養阿姨。", "阿姨是色身，阿孃是法體。", "色身是文字，法入無爲理。", "文字有生滅，無相宛然爾。"]'),
('5d166ac5-d6d2-4f7d-bf66-7b7281f5b9e2','詩偈 三十','龐藴','唐','唐诗','tang','','[]','佛教本無妄，句句須論實。',72,'全唐诗/poet.tang.53000.json','["佛教本無妄，句句須論實。", "尅己饒益他，俗所謂陰騭。", "遮莫是天王，饒君宰相侄。", "世間有貴賤，業力還同一。", "語汝富貴人，貧兒莫欺屈。", "習重業力成，翻覆難得出。"]'),
('2811d110-7061-4c6e-8cab-0e6f42b8351d','詩偈 三十一','龐藴','唐','唐诗','tang','','[]','自恨己身癡，有事無人知。',72,'全唐诗/poet.tang.53000.json','["自恨己身癡，有事無人知。", "橫展兩脚睡，至曉不尋思。", "諸佛爲我爺，我是世尊兒。", "兒今已長大，替父爲導師。", "父子同宅住，寸步不相離。", "法身無相貌，世人那得知。"]'),
('4181d421-024d-4f92-bfab-7c9a2fffe6be','詩偈 三十二','龐藴','唐','唐诗','tang','','[]','此箇一羣賊，生生欺主人。',72,'全唐诗/poet.tang.53000.json','["此箇一羣賊，生生欺主人。", "即今識汝也，不共汝相親。", "你若不伏我，我則處處說。", "教人總識汝，遣汝行路絕。", "你若能伏我，我亦不分別。", "共汝同一身，永離於生滅。"]'),
('5866bcad-d87f-4aa5-937a-2edb5264d967','詩偈 三十三','龐藴','唐','唐诗','tang','','[]','世人重珍寶，我則不如然。',72,'全唐诗/poet.tang.53000.json','["世人重珍寶，我則不如然。", "名聞即知足，富貴心不緣。", "唯樂簞瓢飲，無求澡鏡銓。", "饑食西山稻，渴飲本源泉。", "寒披無相服，熱來松下眠。", "知身無究竟，任運了殘年。"]'),
('5bb4c7c9-4258-4a01-8d46-ec86d72176f9','詩偈 三十四','龐藴','唐','唐诗','tang','','[]','霧重日難出，雲厚月朦朧。',72,'全唐诗/poet.tang.53000.json','["霧重日難出，雲厚月朦朧。", "有心求覓佛，晝夜用心功。", "見夢言將實，聞真耳却聾。", "羣賊當路坐，道理若爲通。", "見性若玲瓏，多求說處通。", "取他凡聖語，到頭渾是空。"]'),
('dad3ccae-4765-4037-8ce5-3037f345ee8c','詩偈 三十五','龐藴','唐','唐诗','tang','','[]','云何爲人演，離相說如如，心鏡俱空靜，無實亦無虛。',72,'全唐诗/poet.tang.53000.json','["云何爲人演，離相說如如，心鏡俱空靜，無實亦無虛。", "心通常嘿用，出世入無餘。", "梵釋咸恭敬，菩薩亦同居。", "語是凡夫語，理合釋迦書。", "若能如是學，不枉用功夫。"]'),
('fa154c97-350a-42cd-a3cc-82c64e470ca7','詩偈 三十六','龐藴','唐','唐诗','tang','','[]','寅朝飲稀粥，飯後兩束薪，貨得二升米，支我有餘身。',72,'全唐诗/poet.tang.53000.json','["寅朝飲稀粥，飯後兩束薪，貨得二升米，支我有餘身。", "身無飢火逼，安余無相神。", "神安佛土淨，內外絕埃塵。", "無間說般若，豁達啟關津。", "火燒家計盡，全成無事人。"]'),
('8a69d787-54ed-41dc-814d-38a47421df38','詩偈 三十七','龐藴','唐','唐诗','tang','','[]','圓鏡朗如日，湧出無礙智。',72,'全唐诗/poet.tang.53000.json','["圓鏡朗如日，湧出無礙智。", "梵語波羅蜜，唐家無量義。", "說者說無相，離者離文字。", "但說無上道，利他還自利。", "若能入理行，不動到如地。", "緣事常區區，不如展脚睡。"]'),
('e2d68198-68da-4b40-9582-a237ebb721bc','詩偈 三十八','龐藴','唐','唐诗','tang','','[]','我觀三界有，有人披草舍。',72,'全唐诗/poet.tang.53000.json','["我觀三界有，有人披草舍。", "虵鼠同穴住，白日恆如夜。", "鳩鴿爲親情，羅剎同心話。", "五狗常嘷吠，思之令人怕。", "我觀總是幻，虛空名亦假。", "放牛喫草菴，三生同一化。"]'),
('24c7a43e-b522-4040-9b7d-60afdd516aa1','詩偈 三十九','龐藴','唐','唐诗','tang','','[]','如來一真智，徧滿娑婆界。',84,'全唐诗/poet.tang.53000.json','["如來一真智，徧滿娑婆界。", "殷勤說方便，有人自不解。", "無處不生心，有處多貪愛。", "心王作黑業，教他口懺悔。", "口懺心不改，心口相違背。", "不服無心藥，病根總不差。", "著相求菩提，不免還他債。"]'),
('0cd70c0c-f9c3-41ed-89be-a09f6173050d','詩偈 四十','龐藴','唐','唐诗','tang','','[]','香山有栴檀，寶山無伊蘭。',60,'全唐诗/poet.tang.53000.json','["香山有栴檀，寶山無伊蘭。", "金山照毛頭，毛頭百億寬。", "淨心空室坐，妙德四方安。", "空生知內外，相事付阿難。", "如能達此理，無處即泥洹。"]'),
('6b9a7992-7c2d-44f6-8c71-cfdf782bf973','詩偈 四十一','龐藴','唐','唐诗','tang','','[]','若能相用語，教君一箇訣。',72,'全唐诗/poet.tang.53000.json','["若能相用語，教君一箇訣。", "捻取三毒箭，一時總抝折。", "田地成四空，五狗牙總缺。", "色藴自消亡，六賊俱磨滅。", "閻羅成法王，羅剎成菩薩。", "勿論己一身，舉國一時悅。"]'),
('1371323f-a390-420b-aeea-6f7375b27e65','詩偈 四十二','龐藴','唐','唐诗','tang','','[]','達人知是幻，縱損心亦如。',72,'全唐诗/poet.tang.53000.json','["達人知是幻，縱損心亦如。", "諸天不免難，況復此閻浮。", "須尋無上理，莫更苦踟躕。", "衣食纔方足，不用積盈餘。", "少欲有湼槃，知足非凡夫。", "當來無地獄，現在出三塗。"]'),
('e7c676b8-8101-4a09-8f5c-702fe5ad8114','詩偈 四十三','龐藴','唐','唐诗','tang','','[]','外若絕攀緣，歡喜常現前。',72,'全唐诗/poet.tang.53000.json','["外若絕攀緣，歡喜常現前。", "本來何所得，吉祥自現形。", "空生成長老，燃燈常照明。", "彌勒是同學，釋迦是長兄。", "神通次第坐，無勞問姓名。", "名相有差別，法身同一形。"]'),
('ba64eb0a-7f1b-4abf-8f83-1cf18820e157','詩偈 四十四','龐藴','唐','唐诗','tang','','[]','大乘一等義，本自無遮閉。',60,'全唐诗/poet.tang.53000.json','["大乘一等義，本自無遮閉。", "凡夫著相求，心生有執滯。", "無心爲真宗，空寂爲本體。", "無問亦無說，常照勿使廢。", "佛子行道已，更莫愁來去。"]'),
('0f9be6f8-1efd-476b-8f6e-e0d2762df9f6','詩偈 四十五','龐藴','唐','唐诗','tang','','[]','無念清涼寺，藴空真五臺。',60,'全唐诗/poet.tang.53000.json','["無念清涼寺，藴空真五臺。", "對鏡心無垢，當情心死灰。", "妙理於中現，優曇空裏開。", "無求真法眼，離相見如來。", "若能如是學，不動出三災。"]'),
('ad16f785-ab02-4e21-af62-be994d49b9e3','詩偈 四十六','龐藴','唐','唐诗','tang','','[]','常聞阿閦佛，擬向東方討。',60,'全唐诗/poet.tang.53000.json','["常聞阿閦佛，擬向東方討。", "今日審思維，不動自然到。", "語汝守門奴，何須苦煩燥。", "我奏父王知，與汝改名號。", "破却有爲功，顯示無爲道。"]'),
('8449f17a-f0a9-4170-b179-b000bb31c2ae','詩偈 四十七','龐藴','唐','唐诗','tang','','[]','識樂衆生樂，緣繩枉（《宗鏡錄》卷四十作「妄」）走作。',96,'全唐诗/poet.tang.53000.json','["識樂衆生樂，緣繩枉（《宗鏡錄》卷四十作「妄」）走作。", "智樂菩薩樂，無繩亦無縛。", "若有發心者，直須學無作。", "莫道怕落空，得空亦不惡。", "見鑛不別（《宗鏡錄》作「識」）金，入鑛（《宗鏡錄》作「爐」）方知錯。"]'),
('eda10fad-7d11-4403-910e-79c9f02a3fe1','詩偈 四十八','龐藴','唐','唐诗','tang','','[]','苦痛役身心，勞神覓官職。',60,'全唐诗/poet.tang.53000.json','["苦痛役身心，勞神覓官職。", "暫得色毛披，拍按作瞋色。", "口口打奴兵，聲聲遣拔肋。", "聞道送王老，曲亦變成直。", "縱令有理道，分疎亦不得。"]'),
('9beb919c-1f3b-4d3a-823c-057c3436a2d4','詩偈 四十九','龐藴','唐','唐诗','tang','','[]','家長自飲酒，舉家一時醉。',60,'全唐诗/poet.tang.53000.json','["家長自飲酒，舉家一時醉。", "失火燒故宅，運水沃空地。", "水火當頭發，三災一時起。", "空中鳩鴿舞，騾來助放屁。", "因中無好花，結果亦天理。"]'),
('59c80ca0-a7d1-4891-abdb-39c7fbaa1c71','詩偈 五十','龐藴','唐','唐诗','tang','','[]','學道迷路人，實是可憐許。',60,'全唐诗/poet.tang.53000.json','["學道迷路人，實是可憐許。", "被賊妄牽纏，惡緣取次與。", "有法遍娑婆，開眼看佛語。", "洗舌讀經典，和經弄蛇鼠。", "動念三界成，迷失當時路。"]'),
('4753f403-bb60-47ba-91db-d73433571966','詩偈 五十一','龐藴','唐','唐诗','tang','','[]','身現凡夫事，內照自分明。',60,'全唐诗/poet.tang.53000.json','["身現凡夫事，內照自分明。", "三千大千界，滿中諸衆生。", "剎那造有業，了了總知情。", "納安芥子裏，稱爲無相經。", "常持人不識，念時無色聲。"]'),
('219b42b7-afce-4da8-b7a4-3892836bde78','詩偈 五十二','龐藴','唐','唐诗','tang','','[]','學佛作夢事，不須論地獄。',60,'全唐诗/poet.tang.53000.json','["學佛作夢事，不須論地獄。", "天堂總越却，六識爲僮僕。", "心心無所住，處處塵不著。", "五道絕人行，無心是極樂。", "空裏見優曇，衆生作橋彴。"]'),
('6cb8a4fa-bb80-48ba-98bb-4c540fa08102','詩偈 五十三','龐藴','唐','唐诗','tang','','[]','欲得速成佛，祇學無生忍。',60,'全唐诗/poet.tang.53000.json','["欲得速成佛，祇學無生忍。", "非常省心力，當時煩惱盡。", "七寶藏門開，智慧無窮盡。", "廣演波羅蜜，無心可鄙吝。", "祇恐着有人，愚癡自不信。"]'),
('d7c81b32-6f8d-4888-b29e-7a7e9f69c02b','詩偈 五十四','龐藴','唐','唐诗','tang','','[]','世人皮上黠，心裏沒頭癡。',60,'全唐诗/poet.tang.53000.json','["世人皮上黠，心裏沒頭癡。", "他貪目前利，焉知已後非。", "謾胡欺得漢，誇道手脚遲。", "走向見閻老，倒拖研米槌。", "恐君不覺悟，今日報君知。"]'),
('3d833482-d3ea-4598-ae1d-52309e82131c','詩偈 五十五','龐藴','唐','唐诗','tang','','[]','中人樂寂靜，下士好威儀。',60,'全唐诗/poet.tang.53000.json','["中人樂寂靜，下士好威儀。", "菩薩心無礙，同凡凡不知。", "佛是無相體，何須有相持。", "但令心了事，遮莫外人疑。", "如人渴飲水，冷暖心自知。"]'),
('fd593ced-287f-4939-8ef2-93b5cfc180c0','詩偈 五十六','龐藴','唐','唐诗','tang','','[]','識若不受塵，心亦不顛狂。',60,'全唐诗/poet.tang.53000.json','["識若不受塵，心亦不顛狂。", "妙智作心師，名爲破有王。", "須臾證六度，動用五種香。", "此即真極樂，亦是真西方。", "釋迦無量壽，同居此道場。"]'),
('4d3d83c1-4e01-4ccc-8ea1-63e1470c2544','詩偈 五十七','龐藴','唐','唐诗','tang','','[]','俗務不廢作，內秘貪心學。',60,'全唐诗/poet.tang.53000.json','["俗務不廢作，內秘貪心學。", "世上假名聞，超然總莫着。", "息念三界空，無求出五濁。", "法報皆圓滿，意根成正覺。", "若能如此修，輪王亦不博。"]'),
('d1fc0a3a-856a-4ab7-9760-d79131fef1dd','詩偈 五十八','龐藴','唐','唐诗','tang','','[]','五藴若實有，則合有色形。',60,'全唐诗/poet.tang.53000.json','["五藴若實有，則合有色形。", "五藴若實無，則合無形聲。", "祇爲假名字，所以妄來停。", "若了名相空，事盡總惺惺。", "心王無障礙，擺撥三界行。"]'),
('495acdfe-378b-45e9-8013-e5cad98f4243','詩偈 五十九','龐藴','唐','唐诗','tang','','[]','我是凡夫身，樂說真如理。',48,'全唐诗/poet.tang.53000.json','["我是凡夫身，樂說真如理。", "爲性不慳貪，常行平等施。", "凡夫事有爲，佛智超生死。", "作佛作凡夫，一切自繇你。"]'),
('7ff35a58-70ea-4b02-a33e-286aa2b056b9','詩偈 六十','龐藴','唐','唐诗','tang','','[]','耳聞無相理，眼空不受色。',60,'全唐诗/poet.tang.53000.json','["耳聞無相理，眼空不受色。", "鼻嗅無相香，舌嘗無相食。", "身着無相衣，竟隨無相得。", "心靜越諸天，神清見彌勒。", "十方同一乘，無心記南北。"]'),
('0b4fee40-25c5-44aa-b552-900f4446616a','詩偈 六十一','龐藴','唐','唐诗','tang','','[]','慈悲說斯法，現疾爲衆生。',60,'全唐诗/poet.tang.53000.json','["慈悲說斯法，現疾爲衆生。", "純陀獻後供，妙德亦同行。", "名相有差別，法身同一形。", "化身千萬億，方便立空名。", "不須執有法，圓通最大精。"]'),
('823259a5-c1d1-4b24-aa0f-761c1e5a24c5','詩偈 六十二','龐藴','唐','唐诗','tang','','[]','欲得真成佛，無心於萬物。',60,'全唐诗/poet.tang.53000.json','["欲得真成佛，無心於萬物。", "心如鏡亦如，真智從如出。", "定慧等莊嚴，廣演波羅蜜。", "流通十方界，諸有不能疾。", "報汝學道人，祇麼便成佛。"]'),
('c12507e9-4ceb-4844-be5f-f9dc0b14853d','詩偈 六十三','龐藴','唐','唐诗','tang','','[]','讀（《祖堂集》作「奉」）經須解義，解義始（《宗鏡錄》卷三三作「即」）修行。',120,'全唐诗/poet.tang.53000.json','["讀（《祖堂集》作「奉」）經須解義，解義始（《宗鏡錄》卷三三作「即」）修行。", "若能依義學（《祖堂集》作「了義教」），即入湼槃城。", "讀經（前引二書均作「如其」）不解義，多見不如盲。", "緣（《宗鏡錄》作「尋」）文廣占地，心中（前引二書均作「牛」）不肯耕。"]'),
('ab0c30b6-db11-4107-8bac-88568b16ab50','詩偈 六十四','龐藴','唐','唐诗','tang','','[]','有人道不得，是伊心王黑。',60,'全唐诗/poet.tang.53000.json','["有人道不得，是伊心王黑。", "不能自了事，埋藏一羣賊。", "羣賊多貪癡，緣事說是非。", "心王被賊使，劫劫無出期。", "見花不識樹，果熟始應知。"]'),
('2cd4bfea-25ce-4fc8-a14b-299f31ae6f13','詩偈 六十五','龐藴','唐','唐诗','tang','','[]','君家住聚落，余自居山谷。',60,'全唐诗/poet.tang.53000.json','["君家住聚落，余自居山谷。", "山空無有物，聚落百種有。", "有者喫飯食，無者空張口。", "口空肚亦空，還將空喫有。", "有盡物歸空，同體無前後。"]'),
('73eb8066-aff5-44a3-a4ca-766ffb223f77','詩偈 六十六','龐藴','唐','唐诗','tang','','[]','諸佛與衆生，元來同一家。',60,'全唐诗/poet.tang.53000.json','["諸佛與衆生，元來同一家。", "不識親尊長，外面認假爺。", "優曇不肯摘，專採葫蘆花。", "葫蘆花未落，常被三五枷。", "如斯之等類，輪轉劫恆沙。"]'),
('9205713e-1087-476a-9626-ec799374abd3','詩偈 六十七','龐藴','唐','唐诗','tang','','[]','余爲田舍翁，世上最貧窮。',60,'全唐诗/poet.tang.53000.json','["余爲田舍翁，世上最貧窮。", "家中無一物，啟口說空空。", "舊時惡知識，總度作師僧。", "和合一處坐，常教聽大乘。", "食時與持鉢，惟我一人供。"]'),
('b2c7518d-2ab8-4683-82cf-856a1889e7a3','詩偈 六十八','龐藴','唐','唐诗','tang','','[]','平等無有二，終日同宅住。',60,'全唐诗/poet.tang.53000.json','["平等無有二，終日同宅住。", "世人不了妄，心生外緣取。", "取得外相佛，樂却變成苦。", "苦即諸法生，大海從何渡。", "爲報知音者，好好看道路。"]'),
('1d4af41b-4e90-4196-b8e2-8c829e9b2ba7','詩偈 六十九','龐藴','唐','唐诗','tang','','[]','故宅有寶珠，却向田野求。',61,'全唐诗/poet.tang.53000.json','["故宅有寶珠，却向田野求。", "這箇一羣賊，賺你徒悠悠。", "泥上搽粧粉，壁上塗渾油。", "愚人見夢事，讚歎道能修。", "臘月三十日，元無一物收。", "。"]'),
('bd3dd74a-7c96-44c8-9fb7-4705e9ffb005','詩偈 七十','龐藴','唐','唐诗','tang','','[]','山中失却心，任運騰騰語。',60,'全唐诗/poet.tang.53000.json','["山中失却心，任運騰騰語。", "語即說空空，空中無虵鼠。", "有心波浪起，無心是淨土。", "淨土生真佛，佛還傳佛語。", "佛能度衆生，衆生是佛母。"]'),
('c95a4cd0-16e3-4d08-89b1-a09638b4b6a2','詩偈 七十一','龐藴','唐','唐诗','tang','','[]','心王不能了，何不依真智。',60,'全唐诗/poet.tang.53000.json','["心王不能了，何不依真智。", "一吼百獸伏，盡見無生理。", "無生理甚寬，無心無可看。", "非內外中間，非生死湼槃。", "諸法無住處，遨遊神自安。"]'),
('400f0e09-800f-47e3-98f5-0f8dfd4e459f','詩偈 七十二','龐藴','唐','唐诗','tang','','[]','外求非是寶，無念自家珍。',48,'全唐诗/poet.tang.53000.json','["外求非是寶，無念自家珍。", "心外求佛法，總是倒行人。", "般若名尚假，豈可更依文。", "有相皆虛妄，無形實是真。"]'),
('055c8991-9a19-49d4-ae76-38c3b0474da2','詩偈 七十三','龐藴','唐','唐诗','tang','','[]','意根無自性，萬法本來虛。',48,'全唐诗/poet.tang.53000.json','["意根無自性，萬法本來虛。", "外塵都不有，三界自然無。", "五藴今何在，盡總入無餘。", "河沙過去佛，並在一毛如。"]'),
('8b9de435-6d71-4ca1-b8e1-7f95879ef46f','詩偈 七十四','龐藴','唐','唐诗','tang','','[]','人有一卷經，無相亦（《祖堂集》卷十五作「復」）無名。',84,'全唐诗/poet.tang.53000.json','["人有一卷經，無相亦（《祖堂集》卷十五作「復」）無名。", "無人能（《祖堂集》作「解」）轉讀，有我不能聽。", "如能轉讀得，入理契無生。", "非論菩薩道，佛亦不勞（《祖堂集》作「要」）成。"]'),
('6f3900c5-d2bd-44e5-92ba-991842d28245','詩偈 七十五','龐藴','唐','唐诗','tang','','[]','阿爺當殿坐，子向前頭立。',48,'全唐诗/poet.tang.53000.json','["阿爺當殿坐，子向前頭立。", "父子同宅住，小魔不敢入。", "時開無盡藏，貧者相供給。", "得之永不窮，免得生憂悒。"]'),
('87e108e1-9e77-4522-ac09-e8de83d37174','詩偈 七十六','龐藴','唐','唐诗','tang','','[]','欲得真醍醐，三毒須去除。',48,'全唐诗/poet.tang.53000.json','["欲得真醍醐，三毒須去除。", "嗅無酥酪氣，自見如意珠。", "劫火燒不然，泛海浪中浮。", "昔日強索者，今日作他奴。"]'),
('9ac22fef-e31f-4179-9bd2-1fb3bb6aa3da','詩偈 七十七','龐藴','唐','唐诗','tang','','[]','報汝尋真理，偷生佯不聞。',49,'全唐诗/poet.tang.53000.json','["報汝尋真理，偷生佯不聞。", "及其身命卒，心口便紛紜。", "我命不能與，將錢別僱人。", "爲讀如來教，救護我精神。", "。"]'),
('7d919a18-abb9-4e18-a883-96a261c30f38','詩偈 七十八','龐藴','唐','唐诗','tang','','[]','城內數萬戶，不奈我恆一。',48,'全唐诗/poet.tang.53000.json','["城內數萬戶，不奈我恆一。", "時時師子吼，禽獸俱皆卒。", "教作羅睺羅，無蹤持戒律。", "但知入理坐，日頭骨咄出。"]'),
('bb174e31-7c54-42b0-a655-504d68495766','詩偈 七十九','龐藴','唐','唐诗','tang','','[]','衆生多品類，諸佛祇一般。',48,'全唐诗/poet.tang.53000.json','["衆生多品類，諸佛祇一般。", "庶人見天子，知隔幾重關。", "若有過人策，欲見亦不難。", "策中契聖理，坐取國家官。"]'),
('69d3d8ca-0a20-40f2-a1eb-a92747a6ddff','詩偈 八十','龐藴','唐','唐诗','tang','','[]','智度本來如，衆生病盡除。',48,'全唐诗/poet.tang.53000.json','["智度本來如，衆生病盡除。", "又度作護法，一切入無餘。", "過去恆沙佛，皆同此一途。", "如能達此理，凡夫非凡夫。"]'),
('9206b51f-871e-48ae-8526-a05b7bf3cb02','詩偈 八十一','龐藴','唐','唐诗','tang','','[]','四大本無情，清虛無色聲。',48,'全唐诗/poet.tang.53000.json','["四大本無情，清虛無色聲。", "達人悟空理，知法本無生。", "諸佛常現前，妙德亦同行。", "無無無障礙，心牛不肯耕。"]'),
('17fb9fe5-d195-4c8d-a026-54b724a0dbbf','詩偈 八十二','龐藴','唐','唐诗','tang','','[]','塵六門前喚，無情呼不入。',48,'全唐诗/poet.tang.53000.json','["塵六門前喚，無情呼不入。", "二彼總空空，自然唇不濕。", "從此絕因緣，葛五隨緣出。", "惟有空寂舍，圓八同金七。"]'),
('ea172efb-05c1-4a03-9984-c449785fb183','詩偈 八十三','龐藴','唐','唐诗','tang','','[]','入理如箭射，尋文轉相背。',48,'全唐诗/poet.tang.53000.json','["入理如箭射，尋文轉相背。", "直道不肯行，識路成迷退。", "心王不了事，公臣生執礙。", "爲此一羣賊，生死如踏碓。"]'),
('104a2a78-76ca-4878-b39f-beeafa2ce492','詩偈 八十四','龐藴','唐','唐诗','tang','','[]','覺他欲打你，着脚即須抽。',48,'全唐诗/poet.tang.53000.json','["覺他欲打你，着脚即須抽。", "已後再相見，他羞我不羞。", "忍辱第一道，歷劫無冤讎。", "此是無生縣，不屬湼槃洲。"]'),
('f6aaf393-ab8c-4500-8624-07f8f5e3771f','詩偈 八十五','龐藴','唐','唐诗','tang','','[]','駡他無便宜，在應却得穩。',49,'全唐诗/poet.tang.53000.json','["駡他無便宜，在應却得穩。", "無瞋神自安，駡他還自損。", "忍得有法利，駡他還折本。", "瞋喜同一如，循世不悶悶。", "。"]'),
('1da4492f-4dd7-45c8-adca-6a69c26b0f63','詩偈 八十六','龐藴','唐','唐诗','tang','','[]','識業人稀少，迷途者衆多。',48,'全唐诗/poet.tang.53000.json','["識業人稀少，迷途者衆多。", "苦中生樂想，無喜強絃歌。", "不飲尋常醉，昏昏溺愛河。", "含笑造殃咎，後苦莫由他。"]'),
('0b8ec10a-ab8c-4c1e-890f-4a074bf51305','詩偈 八十七','龐藴','唐','唐诗','tang','','[]','耳聞他駡詈，心知口莫對。',48,'全唐诗/poet.tang.53000.json','["耳聞他駡詈，心知口莫對。", "惡亦不須嫌，好亦不須愛。", "豁達無關津，虛空無罣礙。", "此真不動物，亦名觀自在。"]'),
('50a7f74f-1e82-40da-973a-1fb9b868453c','詩偈 八十八','龐藴','唐','唐诗','tang','','[]','仰手是天堂，覆手是地獄。',48,'全唐诗/poet.tang.53000.json','["仰手是天堂，覆手是地獄。", "地獄與天堂，我心都不屬。", "化城猶不止，豈況諸天福。", "一切都不求，曠然無所得。"]'),
('1a49f16f-d299-4615-a733-cbff588fe117','詩偈 八十九','龐藴','唐','唐诗','tang','','[]','佛有一等慈，有人心不知。',48,'全唐诗/poet.tang.53000.json','["佛有一等慈，有人心不知。", "一切皆平等，貧富總憐伊。", "富者你莫貪，貧者你莫癡。", "無貪心自靜，無癡意莫思。"]'),
('1b473d4c-73c1-4656-879b-080ce3a3aad5','詩偈 九十','龐藴','唐','唐诗','tang','','[]','白衣不執相，真理從空生。',48,'全唐诗/poet.tang.53000.json','["白衣不執相，真理從空生。", "祇爲心無礙，智慧出縱橫。", "唯論師子吼。", "不許野干鳴。", "菩提稱最妙，猶呵是假名。"]'),
('2a0472fe-d8e7-4441-8ae6-f82c521913e1','詩偈 九十一','龐藴','唐','唐诗','tang','','[]','從根誅則絕，從根修則滅。',48,'全唐诗/poet.tang.53000.json','["從根誅則絕，從根修則滅。", "若能雙株斷，三乘盡超越。", "此非凡夫言，妙吉分明說。", "如來所療治，一差不復發。"]'),
('7d108e6f-ec8e-48a2-94d1-2b622bf288c2','詩偈 九十二','龐藴','唐','唐诗','tang','','[]','久種善根深，同塵塵不侵。',48,'全唐诗/poet.tang.53000.json','["久種善根深，同塵塵不侵。", "非關塵不染，自是我無心。", "無心心不起，超三越十地。", "究竟真如果，到頭祇箇是。"]'),
('49331de3-b518-472b-948e-5c369616169c','詩偈 九十三','龐藴','唐','唐诗','tang','','[]','凡夫智量狹，妄說有難易。',49,'全唐诗/poet.tang.53000.json','["凡夫智量狹，妄說有難易。", "離相如虛空，盡契諸佛智。", "戒相如虛空，迷人自作持。", "病根不肯拔，執是弄花枝。", "。"]'),
('91dbb533-2b40-4bf3-abaf-7e61d885fea9','詩偈 九十四','龐藴','唐','唐诗','tang','','[]','牽牛駕空車，共入無爲宅。',48,'全唐诗/poet.tang.53000.json','["牽牛駕空車，共入無爲宅。", "無爲宅甚寬，衆生却嫌窄。", "十方同一空，何曾有間隔。", "有法入不得，無心是度厄。"]'),
('e8868536-0a31-4c54-aaae-fc3aceec7cbc','詩偈 九十五','龐藴','唐','唐诗','tang','','[]','世間最上事，唯有修道強。',48,'全唐诗/poet.tang.53000.json','["世間最上事，唯有修道強。", "若悟無生理，三界自消亡。", "藴空妙德現，無念是清涼。", "此即迷陀土，何處覓西方。"]'),
('c647114f-f9b4-48af-bbd6-2fb2a47149c6','詩偈 九十六','龐藴','唐','唐诗','tang','','[]','寶珠內衣裏，繫來無量時。',48,'全唐诗/poet.tang.53000.json','["寶珠內衣裏，繫來無量時。", "遇六惡知識，又常假慈悲。", "牽我飲欲酒，醉臥都不知。", "情盡酒復醒，自見本道師。"]'),
('c23beef4-0279-4941-a2ad-4d7a285f3f85','詩偈 九十七','龐藴','唐','唐诗','tang','','[]','世人重珍寶（《宗鏡錄》卷十五作「但重金」），我貴（《宗鏡錄》作「愛」）剎那靜。',131,'全唐诗/poet.tang.53000.json','["世人重珍寶（《宗鏡錄》卷十五作「但重金」），我貴（《宗鏡錄》作「愛」）剎那靜。", "金多亂人心，靜見真如性。", "性空法亦空（《宗鏡錄》作「性通法亦通」），十八絕（《宗鏡錄》作「斷」）行蹤。", "但自心無礙。", "何愁神（《宗鏡錄》作「聲」）不通。", "（《法藏碎金錄》卷四、卷五錄前四句）。"]'),
('5d1c4e2f-4b57-49f2-8d74-a8eafca96810','詩偈 九十八','龐藴','唐','唐诗','tang','','[]','端坐求如法，如法轉相違。',48,'全唐诗/poet.tang.53000.json','["端坐求如法，如法轉相違。", "拋法無心取，始自却來歸。", "無求出三界，有念則成癡。", "求佛覓解脫，不是丈夫兒。"]'),
('9a3d7319-1f7c-46b9-a75d-5db7a9f466af','詩偈 九十九','龐藴','唐','唐诗','tang','','[]','惡心滿三界，口即念彌陀。',62,'全唐诗/poet.tang.53000.json','["惡心滿三界，口即念彌陀。", "心口相違背，羣賊轉轉多。", "一塵起萬境，倐忽徧婆娑。", "色聲求（《宗鏡錄》卷十五作「取」）佛道，結果盡成魔。"]'),
('601592b7-4d7b-4b26-bef9-553569149bed','詩偈 一○○','龐藴','唐','唐诗','tang','','[]','佛亦不離心，心亦不離佛。',48,'全唐诗/poet.tang.53000.json','["佛亦不離心，心亦不離佛。", "心寂即菩提，心然即有物。", "物即變成魔，無即無諸佛。", "若能如是用，十八從何出。"]'),
('aaa08c03-450b-42f5-8bea-6d86ff6cb892','詩偈 一○一','龐藴','唐','唐诗','tang','','[]','羊車誘下愚，鹿車載中夫。',48,'全唐诗/poet.tang.53000.json','["羊車誘下愚，鹿車載中夫。", "大乘爲上士，鵬巢鶴不居。", "鷦鷯住蚊睫，居士咄盲驢。", "若論質利帝，畢竟一乘無。"]'),
('797bc41e-8cf4-47a4-9711-1edec2401bf9','詩偈 一○二','龐藴','唐','唐诗','tang','','[]','有（《祖堂集》卷十五作「世」）人嫌龐老，龐老不嫌他（《祖庭事苑》卷二作「它」）。',98,'全唐诗/poet.tang.53000.json','["有（《祖堂集》卷十五作「世」）人嫌龐老，龐老不嫌他（《祖庭事苑》卷二作「它」）。", "開門待知識，知識不來過。", "心如具三學，塵識不相和（《祖堂集》無此二句）。", "一丸療萬（《祖堂集》作「百」）病，不假藥方多。"]'),
('003da74c-847d-4369-9df6-959a50e4ad29','詩偈 一○三','龐藴','唐','唐诗','tang','','["\u957f\u6c5f"]','淼淼長江水，周而還復始。',48,'全唐诗/poet.tang.53000.json','["淼淼長江水，周而還復始。", "昏昏三界人，輪迴亦如此。", "輪迴改形貌，長江色不異。", "改貌勞神識，終須到佛地。"]'),
('f49b4dc6-44fe-4857-9fba-2766e107b8da','詩偈 一○四','龐藴','唐','唐诗','tang','','[]','睡來展脚睡，悟理起題詩。',48,'全唐诗/poet.tang.53000.json','["睡來展脚睡，悟理起題詩。", "詩中無別意，唯勸破貪癡。", "貪瞋癡若盡，便是世尊兒。", "無煩問師匠，心王應自知。"]'),
('f9b6153f-d7c7-45ce-8337-bdc54e3a8792','詩偈 一○五','龐藴','唐','唐诗','tang','','[]','世人重名利，余心總不然。',48,'全唐诗/poet.tang.53000.json','["世人重名利，余心總不然。", "束薪貨升米，清水鐵鐺煎。", "覺熟捻鐺下，將身近畔邊。", "時時拋入口，腹飽肚無言。"]'),
('fcc95438-9507-4d1b-988f-179a1af3b570','詩偈 一○六','龐藴','唐','唐诗','tang','','[]','行學非真道，徒勞神與軀。',66,'全唐诗/poet.tang.53000.json','["行學非真道，徒勞神與軀。", "千里尋月影（《宗鏡錄》卷四一作「千生尋水月」），終是枉工夫。", "不悟緣聲色，當今學者疎。", "但看起滅處，此箇是真如。"]'),
('a1380ffc-6db3-45f7-bfef-02de716aaf0f','詩偈 一○七','龐藴','唐','唐诗','tang','','[]','教君殺賊法，不用苦多方。',48,'全唐诗/poet.tang.53000.json','["教君殺賊法，不用苦多方。", "慧劍當心刺，心亡法亦亡。", "心亡極樂國，法亡即西方。", "賊爲象馬用，神自作空王。"]'),
('f1771a49-7401-4c43-8f59-ab233981ebb6','詩偈 一○八','龐藴','唐','唐诗','tang','','[]','不用苦多聞，看他彼上人。',66,'全唐诗/poet.tang.53000.json','["不用苦多聞，看他彼上人。", "百憶及日用，元在一毛塵（《宗鏡錄》卷十八作「纂在一毛鱗」）。", "心但寂無相，即出無明津。", "若能如是學，幾許省精神。"]'),
('9fa3b36d-0e03-4cd1-981f-b32dcd9bad97','詩偈 一○九','龐藴','唐','唐诗','tang','','[]','慚愧好心王，生在蓮華堂。',48,'全唐诗/poet.tang.53000.json','["慚愧好心王，生在蓮華堂。", "恆持般若劍，終日帶浮囊。", "常懷第一義，外國賴恩光。", "五百長者子，相隨歸故鄉。"]'),
('d39522b1-1887-43cf-a3e0-9b06131dfb43','詩偈 一一○','龐藴','唐','唐诗','tang','','[]','慚愧好意根，無自亦無他。',48,'全唐诗/poet.tang.53000.json','["慚愧好意根，無自亦無他。", "無自身無垢，無他塵不加。", "常居清靜地，知有不能過。", "舊時惡知識，總見阿彌陀。"]'),
('278baac5-5978-4af0-9b0b-791ef42ddf3a','詩偈 一一一','龐藴','唐','唐诗','tang','','[]','慚愧好舌根，常開大道門。',48,'全唐诗/poet.tang.53000.json','["慚愧好舌根，常開大道門。", "世間三有事，實是不能論。", "相逢唯說道，更莫敍寒溫。", "了知世相假，俗理也徒煩。"]'),
('45a8e9e7-ea51-4ae1-b3cc-76fbeeb33506','詩偈 一一二','龐藴','唐','唐诗','tang','','[]','慚愧一雙耳，常思解脫聲。',48,'全唐诗/poet.tang.53000.json','["慚愧一雙耳，常思解脫聲。", "若論俗語話，實是不能聽。", "聞財耳不納，聞色心不生。", "不受有無語，何慮不惺惺。"]'),
('dcc34ac0-7396-407a-95e9-8e761872e7bb','詩偈 一一三','龐藴','唐','唐诗','tang','','[]','慚愧一雙眼，曾見數般人。',60,'全唐诗/poet.tang.53000.json','["慚愧一雙眼，曾見數般人。", "端正亦不愛，醜陋亦不瞋，當頭異國色，何須妄起塵。", "低頭自形相，都無一處真。", "身心如幻化，滿眼沒怨親。"]'),
('8908c7cd-3959-40b7-b480-1c22276c023d','詩偈 一一四','龐藴','唐','唐诗','tang','','[]','慚愧一軀身，梵號波羅柰。',137,'全唐诗/poet.tang.53000.json','["慚愧一軀身，梵號波羅柰。", "被賊一羣使，尋常不自在。", "亦名爲枯井，亦名爲韛袋。", "亦名朽故宅，亦名幻三昧。", "佛駡作死屍，乘屍渡大海。", "大海元無水，死屍非是船。", "熟看世上事，總是假因緣。", "若了身心相，空裏任橫眠。", "具此六慚愧，實是不求天。", "（以上一百十四首均見咸豐元年刊于頔編《龐居士語錄》卷中）。"]'),
('366aad62-d63f-4f40-b5ce-4334ddcc536f','詩偈 一','龐藴','唐','唐诗','tang','','[]','一時復一時，步步向前移。',72,'全唐诗/poet.tang.53000.json','["一時復一時，步步向前移。", "無常有限分，早晚即不知。", "古人一交語，預辦沒貧兒。", "聞小須修道，莫待衰老時。", "邂逅符到來，賺你更無疑。", "勸君不肯聽，三塗真可悲。"]'),
('d373ed45-0516-428c-9e07-684c68e3a3ae','詩偈 二','龐藴','唐','唐诗','tang','','[]','一日復一日，百年漸漸畢。',48,'全唐诗/poet.tang.53000.json','["一日復一日，百年漸漸畢。", "急急除妄想，無念成真佛。", "更莫苦攀緣，窺他世上物。", "忽然無常至，累劫出不得。"]'),
('b483e2fe-1768-4ebf-8a76-b5e8e8de8a07','詩偈 三','龐藴','唐','唐诗','tang','','[]','一宿復一宿，光陰漸漸促。',48,'全唐诗/poet.tang.53000.json','["一宿復一宿，光陰漸漸促。", "報你心王道，依智莫依識。", "依智見真佛，依識入地獄。", "若淪六趣中，受苦無時足。"]'),
('424917aa-3cd2-4ecb-afbe-2e99fc89b821','詩偈 四','龐藴','唐','唐诗','tang','','[]','一年復一年，務在且遷延。',181,'全唐诗/poet.tang.53000.json','["一年復一年，務在且遷延。", "皮皺緣肉減，髮白髓枯乾。", "毛孔通風過，骨消椽梠寬。", "水微不耐熱，火少不耐寒。", "幻身如聚沫，四大亦非堅。", "更被癡狼使，無明曉夜煎。", "惟知念水草，心神被物纏。", "云何不懺悔，便道捨財錢。", "外頭遮曲語，望得免前愆。", "地獄應無事，準擬得生天。", "世間有這屬，冥道不如然。", "除非不作業，當拔罪根源。", "根空塵不實，內外絕因緣。", "積罪如山岳，慧火一時燃。", "須臾變灰燼，永劫更無煙。", "。"]'),
('c2fe22e2-6d88-4f00-9900-c1c77edfa8d2','詩偈 五','龐藴','唐','唐诗','tang','','[]','迷時三界有，悟即出囂纏。',60,'全唐诗/poet.tang.53000.json','["迷時三界有，悟即出囂纏。", "心無六入迹，清淨達本源。", "地獄成淨土，招手別諸天。", "報語三塗宅，共你更無緣。", "非論早與晚，悟理即無邊。"]'),
('e050389b-8222-4a30-8296-70c92908073e','詩偈 六','龐藴','唐','唐诗','tang','','[]','心如即是坐，境如即是禪。',36,'全唐诗/poet.tang.53000.json','["心如即是坐，境如即是禪。", "如如都不動，大道無中邊。", "若能如是達，所謂火中蓮。"]'),
('b1d6d9b4-a023-4c83-916a-d296a64047d4','詩偈 七','龐藴','唐','唐诗','tang','','[]','無求乃法眼，有念却成魔。',36,'全唐诗/poet.tang.53000.json','["無求乃法眼，有念却成魔。", "無求復無念，即是阿彌陀。", "真如共菩薩，總祇較無多。"]'),
('31d67755-44db-4858-84b2-cd2d4db10094','詩偈 八','龐藴','唐','唐诗','tang','','[]','鍊盡三山鐵，鎔銷五嶽銅。',36,'全唐诗/poet.tang.53000.json','["鍊盡三山鐵，鎔銷五嶽銅。", "林枯鳥自散，海竭絕魚龍。", "無師破戒行，有法盡皆空。"]'),
('6c70d1e8-0b91-493d-949c-b78468f5c97b','詩偈 九','龐藴','唐','唐诗','tang','','[]','菩薩無煩惱，衆生愛皺眉。',36,'全唐诗/poet.tang.53000.json','["菩薩無煩惱，衆生愛皺眉。", "無惱緣無賊，皺眉被賊欺。", "不須問師匠，心王應自知。"]'),
('42af3a9f-89fa-484f-ac92-836c69ef018d','詩偈 十','龐藴','唐','唐诗','tang','','[]','凡夫龢著事，不免三界輪。',24,'全唐诗/poet.tang.53000.json','["凡夫龢著事，不免三界輪。", "與說無生理，閉耳佯不聞。"]'),
('5af128bb-0046-41d3-9ecc-0b6b4744ede9','詩偈 十一','龐藴','唐','唐诗','tang','','[]','壁畫枉用色，不如脫空佛。',36,'全唐诗/poet.tang.53000.json','["壁畫枉用色，不如脫空佛。", "住法比無住，陰中對白日。", "不信有無言，看取波羅蜜。"]'),
('76e3f78b-5b01-44cc-956a-093c1d473ce9','詩偈 十二','龐藴','唐','唐诗','tang','','[]','見時如不見，聞時如不聞。',36,'全唐诗/poet.tang.53000.json','["見時如不見，聞時如不聞。", "喜時如不喜，瞋時如不瞋。", "一切盡歸如，自然無我人。"]'),
('8dad0079-4312-4134-9e6c-026fd7a53997','詩偈 十三','龐藴','唐','唐诗','tang','','[]','齋須實相齋，戒須實相戒。',36,'全唐诗/poet.tang.53000.json','["齋須實相齋，戒須實相戒。", "有相持齋戒，到頭歸敗壞。", "敗壞屬無常，從何免三界。"]'),
('90879c14-d694-4c92-ab8b-e8ddab87163e','詩偈 十四','龐藴','唐','唐诗','tang','','[]','心王不了事，遮莫向名山。',36,'全唐诗/poet.tang.53000.json','["心王不了事，遮莫向名山。", "縱令見佛像，實以不相關。", "猿猴見水月，捉月始知難。"]'),
('f8b72e6e-b8a9-460f-8843-745217feb4f8','詩偈 十五','龐藴','唐','唐诗','tang','','[]','緣事求解脫，累劫無出期。',36,'全唐诗/poet.tang.53000.json','["緣事求解脫，累劫無出期。", "直須入理性，成佛更無疑。", "雖然不受記，見是世尊兒。"]'),
('7fb01c8a-e129-44c3-9329-58146b3f097e','詩偈 十六','龐藴','唐','唐诗','tang','','[]','佛遣滅生滅，生滅長相隨。',36,'全唐诗/poet.tang.53000.json','["佛遣滅生滅，生滅長相隨。", "不學大人相，却作小孫兒。", "持心更覓佛，豈不是愚癡。"]'),
('00f3ce69-f667-4152-8b8e-174e1cb1d391','詩偈 十七','龐藴','唐','唐诗','tang','','[]','無事被他駡，佯佯耳不聞。',36,'全唐诗/poet.tang.53000.json','["無事被他駡，佯佯耳不聞。", "舌亦不須動，心亦不須瞋。", "關津無障礙，即是出纏人。"]'),
('d7ca8d9e-6721-4057-b5d7-7c6f0667c256','詩偈 十八','龐藴','唐','唐诗','tang','','[]','真如本無相，所得是凡流。',36,'全唐诗/poet.tang.53000.json','["真如本無相，所得是凡流。", "昔時爲父子，長大出外遊。", "今日相遇見，父少子白頭。"]'),
('62bed559-9eb9-4503-bf0c-e42f32f32c9e','詩偈 十九','龐藴','唐','唐诗','tang','','[]','一生解縛鈍，渾身納裏眠。',37,'全唐诗/poet.tang.53000.json','["一生解縛鈍，渾身納裏眠。", "心中無意識，耳無繩索牽。", "心本無繫縛，同塵亦無喧。", "。"]'),
('fcbaa0b6-a669-4fc9-b934-96b4673a7ebc','詩偈 二十','龐藴','唐','唐诗','tang','','[]','欲得真解脫，持刀且殺牛。',36,'全唐诗/poet.tang.53000.json','["欲得真解脫，持刀且殺牛。", "牛死人亦亡，佛亦不須求。", "全身空裏坐，即度死生流。"]'),
('06ffe225-a66b-4be7-a0df-ce35bfe4ba6f','詩偈 二十一','龐藴','唐','唐诗','tang','','[]','貪瞋不肯捨，徒勞讀釋經（《祖堂集》卷十五作「書」）。',26,'全唐诗/poet.tang.53000.json','["貪瞋不肯捨，徒勞讀釋經（《祖堂集》卷十五作「書」）。"]'),
('f72756c8-e93a-480b-b7c6-663b8214cba8','詩偈 二十二','龐藴','唐','唐诗','tang','','[]','取空是取（《祖堂集》作「空是」）色，取色色無常。',36,'全唐诗/poet.tang.53000.json','["取空是取（《祖堂集》作「空是」）色，取色色無常。", "色空非我有，端坐見家鄉。"]'),
('097cb97c-db74-437a-a9f5-ba29851959fb','詩偈 二十三','龐藴','唐','唐诗','tang','','[]','經體本無名，受持無色聲。',26,'全唐诗/poet.tang.53000.json','["經體本無名，受持無色聲。", "心依無相理，真是《金剛經》。"]'),
('0da6fee5-acae-4f32-be1e-4f6e4371dd1b','詩偈 二十四','龐藴','唐','唐诗','tang','','[]','孫兒正啼哭，母言來與金。',24,'全唐诗/poet.tang.53000.json','["孫兒正啼哭，母言來與金。", "捻他黃葉把，便是正聲音。"]'),
('63b6be45-ead4-432c-9bf1-6c2d9e6fde2a','詩偈 二十五','龐藴','唐','唐诗','tang','','[]','別淚成河海，骨如毘富山。',24,'全唐诗/poet.tang.53000.json','["別淚成河海，骨如毘富山。", "祇緣塵識法，所以遣心然。"]'),
('a8c138e8-f6a8-42c3-a6ca-cb118874d0dc','詩偈 二十六','龐藴','唐','唐诗','tang','','[]','前人若有事，我猶佯不知。',24,'全唐诗/poet.tang.53000.json','["前人若有事，我猶佯不知。", "何況他無問，讒舌強卑卑。"]'),
('b24b02f3-6c8e-45a7-b7f7-71e26e6f4b38','詩偈 二十七','龐藴','唐','唐诗','tang','','[]','勸君師子吼，莫學野干鳴。',24,'全唐诗/poet.tang.53000.json','["勸君師子吼，莫學野干鳴。", "若能香象起，感得鳳凰迎。"]'),
('17414b67-540e-4dee-9c2d-5888199c6fee','詩偈 二十八','龐藴','唐','唐诗','tang','','[]','一種學事業，亦來登選場。',24,'全唐诗/poet.tang.53000.json','["一種學事業，亦來登選場。", "祇緣口義錯，落第在他鄉。"]'),
('72385150-92ff-467b-bf5b-a1b02bb98321','詩偈 二十九','龐藴','唐','唐诗','tang','','[]','心王不了事，却被六賊使。',24,'全唐诗/poet.tang.53000.json','["心王不了事，却被六賊使。", "共賊作火下，無由出生死。"]'),
('6b7e1dc8-cf43-4b8e-b709-944480d8596b','詩偈 三十','龐藴','唐','唐诗','tang','','[]','別人終不賤，別寶終不貪。',24,'全唐诗/poet.tang.53000.json','["別人終不賤，別寶終不貪。", "祇今擔鐵漢，不肯博金銀。"]'),
('9650da0a-99e8-47f9-9952-7c22a74ee96a','詩偈 三十一','龐藴','唐','唐诗','tang','','[]','有男不肯婚，有女不肯嫁（《景德傳燈錄》卷八錄二句皆無「肯」字）。',61,'全唐诗/poet.tang.53000.json','["有男不肯婚，有女不肯嫁（《景德傳燈錄》卷八錄二句皆無「肯」字）。", "父子自團欒（《景德傳燈錄》作「大家團欒頭」），共說無生話。"]'),
('e830604a-d49a-470f-a609-b7e0d24d238b','詩偈 三十二','龐藴','唐','唐诗','tang','','[]','四性同一舍，三身同一室。',24,'全唐诗/poet.tang.53000.json','["四性同一舍，三身同一室。", "一切惡知識，總見彌陀佛。"]'),
('dfad49c8-5c92-4b6b-82f6-7a5e3c64968c','詩偈 三十三','龐藴','唐','唐诗','tang','','[]','教君一箇法，有事無處避。',24,'全唐诗/poet.tang.53000.json','["教君一箇法，有事無處避。", "若能如理修，存本却有利。"]'),
('316d3ef0-6e9e-44f3-b161-74dab02bf1df','詩偈 三十四','龐藴','唐','唐诗','tang','','[]','道是無爲道，修人自有爲。',25,'全唐诗/poet.tang.53000.json','["道是無爲道，修人自有爲。", "假即無頭數，真中實是稀。", "。"]'),
('30bdda3e-8d33-4ba9-9694-0723a9799289','詩偈 三十五','龐藴','唐','唐诗','tang','','[]','無求勝禮佛，知足勝持齋。',24,'全唐诗/poet.tang.53000.json','["無求勝禮佛，知足勝持齋。", "本自無薪火，何勞更拾柴。"]'),
('2be39c21-bec1-49b4-a50d-852025d8a5bd','詩偈 三十六','龐藴','唐','唐诗','tang','','[]','說事滿天下，入理實無多。',24,'全唐诗/poet.tang.53000.json','["說事滿天下，入理實無多。", "常被有爲縛，何日見彌陀。"]'),
('73993a3c-d2c6-4ad1-a41e-df8c7dcb20c3','詩偈 三十七','龐藴','唐','唐诗','tang','','[]','起時惟法起，行時共佛行。',24,'全唐诗/poet.tang.53000.json','["起時惟法起，行時共佛行。", "騰騰三界內，諸法自無生。"]'),
('41bc542d-aed1-4ab4-8f73-829e7331ef81','詩偈 三十八','龐藴','唐','唐诗','tang','','[]','大海淼無涯，衆生自著枷。',24,'全唐诗/poet.tang.53000.json','["大海淼無涯，衆生自著枷。", "無求出妙德，心生勞算沙。"]'),
('b6486f4b-1b43-474e-8ad9-72cfbf38ef57','詩偈 三十九','龐藴','唐','唐诗','tang','','[]','一念心清淨，處處蓮花開。',24,'全唐诗/poet.tang.53000.json','["一念心清淨，處處蓮花開。", "一華一淨土，一土一如來。"]'),
('a605187e-2144-43b8-bed2-05984694a7af','詩偈 四十','龐藴','唐','唐诗','tang','','[]','大唐三百六十州，我暫放閒乘興遊。',144,'全唐诗/poet.tang.53000.json','["大唐三百六十州，我暫放閒乘興遊。", "瞬息之間知事盡，若論入理更深幽。", "共外知識呷清水，總是妄想無骨頭。", "却歸東西山道去，不捨因緣騎牯牛。", "後望青山平似掌，前瞻漢水水東流。", "試問西域那提子，遺法慇懃無所求。", "自入大海歸火宅，不覺乘空失却牛。", "有人見我歸東土，我本元居西海頭。", "來去自然無障礙，出入生死有何憂。"]'),
('a9da582b-e09e-4038-9c61-63bed624019f','詩偈 四十一','龐藴','唐','唐诗','tang','','[]','無思無念是真空，妙德法身自見中。',105,'全唐诗/poet.tang.53000.json','["無思無念是真空，妙德法身自見中。", "應機接物契真智，十方世界總流通。", "通達無我無人法，人法不見有行蹤。", "神識自然無罣礙，廓周沙界等虛空。", "不假坐禪持戒律，超然解脫豈勞功。", "（按：《全唐詩》卷八一○收末四句爲一首，未完。", "）。"]'),
('8d16a723-24a2-4c9d-a34c-65adba6d4dca','詩偈 四十二','龐藴','唐','唐诗','tang','','[]','菩提般若名相假，湼槃真如亦是虛。',80,'全唐诗/poet.tang.53000.json','["菩提般若名相假，湼槃真如亦是虛。", "欲得心神真解脫，一切名相本來無。", "十方世界風塵淨，州州縣縣絕艱虞。", "王道蕩蕩無偏黨，舉國衆生同一如。", "不動干戈安萬姓，法王合掌髻中珠。"]'),
('d3904159-73da-4669-83c4-bc3ddd71d1fb','詩偈 四十三','龐藴','唐','唐诗','tang','','[]','空中自見清涼月，一光普照婆娑徹。',65,'全唐诗/poet.tang.53000.json','["空中自見清涼月，一光普照婆娑徹。", "此光湛然無去來，不增不減無生滅。", "爾是妙德現真身，剎那不起恆沙劫。", "無邊無盡如虛空，虛空無邊不可說。", "。"]'),
('825ce624-d5c9-4599-aa11-f497cd4a7f3a','詩偈 四十四','龐藴','唐','唐诗','tang','','[]','但自無心於萬物，何妨萬物常圍遶。',78,'全唐诗/poet.tang.53000.json','["但自無心於萬物，何妨萬物常圍遶。", "鐵牛不怕師子吼，恰似木人見花鳥。", "木人本體自無情，花鳥逢人亦不驚。", "心境如如祇箇（《緇門警訓》卷九作「遮」）是，何慮菩提道不成。"]'),
('e9e32e1a-1a69-4623-8592-937e868f2749','詩偈 四十五','龐藴','唐','唐诗','tang','','[]','清靜無爲無識塵，不捨內身妙法身。',64,'全唐诗/poet.tang.53000.json','["清靜無爲無識塵，不捨內身妙法身。", "祇爲衆生有漏習，權止草菴轉法輪。", "法輪常轉而人見，優曇時時一出現。", "無相真空妙法身，歷劫恆沙不遷變。"]'),
('c3f68972-29fe-4c0a-8fc5-f26c745cbf05','詩偈 四十六','龐藴','唐','唐诗','tang','','[]','莫求佛兮莫求人，但自心裏莫貪瞋。',64,'全唐诗/poet.tang.53000.json','["莫求佛兮莫求人，但自心裏莫貪瞋。", "貪瞋癡病前頓盡，便是如來的的親。", "內無垢兮外無塵，中間豁達無關津。", "神無障礙居三界，恰是琉璃處日輪。"]'),
('d5a53560-6563-47e0-a98a-c6f79bbb9d4e','詩偈 四十七','龐藴','唐','唐诗','tang','','[]','心王若解依真智，一切有無俱遣棄。',48,'全唐诗/poet.tang.53000.json','["心王若解依真智，一切有無俱遣棄。", "身隨世流心不流，夜來眼睡心不睡。", "天堂地獄總無情，任運幽玄到此地。"]'),
('1a8bb4df-756a-4232-b849-589fb4a174fe','詩偈 四十八','龐藴','唐','唐诗','tang','','[]','報汝世人莫癡憨，暫時權住此草菴。',48,'全唐诗/poet.tang.53000.json','["報汝世人莫癡憨，暫時權住此草菴。", "無想衣食飽暖後，世間有物不須貪。", "此身幻化如燈焰，須臾不覺即頭南。"]'),
('8c4274be-698b-4cc0-999e-ef8ec58e8c1a','詩偈 四十九','龐藴','唐','唐诗','tang','','[]','一切有求枉用功，想念真成著色空。',48,'全唐诗/poet.tang.53000.json','["一切有求枉用功，想念真成著色空。", "差之亳釐失千里，有生劫劫道難通。", "癡心望出三界外，不知元在鐵圍中。"]'),
('d7883a6a-e78b-4a23-8e6e-af5919632e52','詩偈 五十','龐藴','唐','唐诗','tang','','[]','二十部經兼戒律，執相依文常受持。',48,'全唐诗/poet.tang.53000.json','["二十部經兼戒律，執相依文常受持。", "生生獲得有爲果，隨在三界無出期。", "若能離相真入理，理中無念亦無思。"]'),
('9e9222f7-9fd0-4b4f-9d98-31b29920b8c3','詩偈 五十一','龐藴','唐','唐诗','tang','','[]','貝多葉裏優曇華，萬象皆如同一家。',49,'全唐诗/poet.tang.53000.json','["貝多葉裏優曇華，萬象皆如同一家。", "歡喜摘花不見菓，吉祥採菓不觀華。", "緣之本來元不識，法王呵之如稻麻。", "。"]'),
('2b147a01-f2d1-4467-b025-d6ac102ac8e1','詩偈 五十二','龐藴','唐','唐诗','tang','','[]','田舍老翁如聚落，眼耳鼻舌俱失却。',48,'全唐诗/poet.tang.53000.json','["田舍老翁如聚落，眼耳鼻舌俱失却。", "內外尋訪覓無蹤，舊時住處空寂寞。", "卻歸堂上問空王，總在此間學無作。"]'),
('0ab7bba0-3965-4f7d-adba-224faae94496','詩偈 五十三','龐藴','唐','唐诗','tang','','[]','黃葉飄零化作塵，本來非妄亦非真。',32,'全唐诗/poet.tang.53000.json','["黃葉飄零化作塵，本來非妄亦非真。", "有情故宅含秋色，無名君子湛然春。"]'),
('aa93a8bc-11c4-4d72-b9a4-d9a8a1e00110','詩偈 五十四','龐藴','唐','唐诗','tang','','[]','迷時愛欲心如火，心開悟理火成灰。',32,'全唐诗/poet.tang.53000.json','["迷時愛欲心如火，心開悟理火成灰。", "灰火本來同一體，當知妄盡即如來。"]'),
('75a85a26-201a-4fe3-aa8c-5685e10fb8ff','詩偈 五十五','龐藴','唐','唐诗','tang','','[]','真爲家貧無一物，此語總是空裏出。',32,'全唐诗/poet.tang.53000.json','["真爲家貧無一物，此語總是空裏出。", "出語還須歸本源，不敢違他過去佛。"]'),
('582ac73a-84ea-4189-9ad0-8a93f3d33574','詩偈 五十六','龐藴','唐','唐诗','tang','','[]','父子相守空山坐，無相如如寄有間。',32,'全唐诗/poet.tang.53000.json','["父子相守空山坐，無相如如寄有間。", "世人見靜元無靜，看似閑時亦不閑。"]'),
('2fbe63a0-17e3-41c2-9746-4f65023a5944','詩偈 五十七','龐藴','唐','唐诗','tang','','[]','八萬四千同一理，事相差別立異名。',32,'全唐诗/poet.tang.53000.json','["八萬四千同一理，事相差別立異名。", "十二圍陀及疏論，慇懃三六不須生。"]'),
('ac200f4b-fc78-44be-9f85-139577b11e30','詩偈 五十八','龐藴','唐','唐诗','tang','','[]','十方國土皆吾宅，長者大門常日開。',32,'全唐诗/poet.tang.53000.json','["十方國土皆吾宅，長者大門常日開。", "有識名人守院外，無心入理見如來。"]'),
('87d25f02-a7e4-4e65-9369-d5989ed74bae','詩偈 五十九','龐藴','唐','唐诗','tang','','[]','世人愛假不愛真，世人憐富却憎貧。',32,'全唐诗/poet.tang.53000.json','["世人愛假不愛真，世人憐富却憎貧。", "唯敬三塗八不淨，背却如來妙色身。"]'),
('21e0bf33-3bb3-4fcc-889f-49dccc9b41a3','詩偈 六十','龐藴','唐','唐诗','tang','','[]','更無別路超生死，前佛後佛同一般。',32,'全唐诗/poet.tang.53000.json','["更無別路超生死，前佛後佛同一般。", "舒即周流十方剎，歛時還在一毛端。"]'),
('562ce661-3585-4c4c-9c31-d6f8a029dff1','詩偈 六十一','龐藴','唐','唐诗','tang','','[]','唯有一門無鑰匙，伸縮低昂說是非。',32,'全唐诗/poet.tang.53000.json','["唯有一門無鑰匙，伸縮低昂說是非。", "但能宣得無生理，善巧方便亦從伊。"]'),
('bb88de30-051d-486a-b48f-49bf166425f5','詩偈 六十二','龐藴','唐','唐诗','tang','','[]','二乘皆曰不堪任，上士之人智慧深。',32,'全唐诗/poet.tang.53000.json','["二乘皆曰不堪任，上士之人智慧深。", "欲得神通等居士，無過無物總無心。"]'),
('afbbfec8-a3aa-4ea6-9949-506d2f98d226','雜句 一','龐藴','唐','唐诗','tang','','[]','行路易，行路易，內外中間依本智。',121,'全唐诗/poet.tang.53000.json','["行路易，行路易，內外中間依本智。", "本智無情法不生，無生即是入正理。", "非色非心放一光，空裏優曇顯心地。", "名爲智，智爲尊，心智通同達本源，萬物同歸不二門。", "有非有兮理常存，無非無兮無有根，未來諸佛亦如是，現在還同古世尊。", "三世俱皆無別道，佛佛相授至今傳。", "。"]'),
('4a7734bf-7571-4e44-b9c7-b7e3bb0c90ff','雜句 二','龐藴','唐','唐诗','tang','','[]','外無他兮內無自，不動干戈契佛智。',48,'全唐诗/poet.tang.53000.json','["外無他兮內無自，不動干戈契佛智。", "通達佛道行非道，不捨凡夫有爲事。", "有爲名相盡空華，無名無相出生死。"]'),
('17b699d1-0593-4a4d-842c-043bfd9d8dbd','雜句 三','龐藴','唐','唐诗','tang','','[]','余有一大衣，非是世間絹。',80,'全唐诗/poet.tang.53000.json','["余有一大衣，非是世間絹。", "衆色染不著，晶晶如素練。", "裁時不用刀，縫時不用線。", "常持不離身，有人自不見。", "三千世間遮寒暑，無情有情悉覆遍，如來持得此大衣，披了直入空王殿。"]'),
('f0d323b6-8196-4433-98c2-aac9e1bcde83','雜句 四','龐藴','唐','唐诗','tang','','[]','思思低思思，自歎一雙眉。',74,'全唐诗/poet.tang.53000.json','["思思低思思，自歎一雙眉。", "向他勝地坐，萬事總不知。", "六識若似眉，即得不思議。", "六識若嫌眉，論時沒腦癡。", "伊若去却眉，即被世人欺。", "饒你六識嘍囉漢，總成乞索兒。"]'),
('ecb8e458-a72e-4151-b601-945cc07e15b4','雜句 五','龐藴','唐','唐诗','tang','','[]','出一屋，入一屋，來來去去教他哭。',70,'全唐诗/poet.tang.53000.json','["出一屋，入一屋，來來去去教他哭。", "來去祇爲貪瞋癡，於今悟罷須知足。", "知足常須達本源，去却昔時惡知識。", "惡知識，將伊作，手力法施無前後，共護無生國。"]'),
('023ccd56-348e-4749-80b6-6e5af25ca435','雜句 六','龐藴','唐','唐诗','tang','','[]','無事失却心，走向門前覓。',160,'全唐诗/poet.tang.53000.json','["無事失却心，走向門前覓。", "借問舊知識，寂絕無蹤跡。", "却歸堂上審思看，改却衆生稱心安。", "不能出外求知識，自向家中入湼槃。", "大丈夫，昔日有，今日無，家計破除盡，贖得一羣奴。", "奴婢有六人，一人有六口。", "六六三十六，常隨我前後。", "我亦不拘伊，伊亦不敢走。", "若道菩提難，菩提亦不難。", "少欲知足毛頭寬，遠離財色神自安。", "分明了見三塗苦，世上名聞不相關。"]'),
('ae4d4e0d-049b-4b2b-b90a-cd0b029e3e82','雜句 七','龐藴','唐','唐诗','tang','','[]','難復難，持心離欲貪湼槃。',44,'全唐诗/poet.tang.53000.json','["難復難，持心離欲貪湼槃。", "一向他方求淨土，若論實行不相關。", "枉用功夫來去苦，畢竟到頭空色還。"]'),
('b258fee5-22d5-48ac-a6cb-3ab0c0886985','雜句 八','龐藴','唐','唐诗','tang','','[]','易復易，即此五陰成（《祖堂集》卷十五作「藴有」）真智。',73,'全唐诗/poet.tang.53000.json','["易復易，即此五陰成（《祖堂集》卷十五作「藴有」）真智。", "十方世界一乘同，無相法身豈有二。", "若捨煩惱覓（《五燈會元》卷三作「入」）菩提，不知何方有佛地。"]'),
('96716f27-b724-43cc-8eb4-1a3b1f7d3068','雜句 九','龐藴','唐','唐诗','tang','','[]','正中正，心王如如六根瑩。',33,'全唐诗/poet.tang.53000.json','["正中正，心王如如六根瑩。", "六塵空，六識淨，六六三十六，同歸大圓鏡。", "。"]'),
('65a901bd-0526-4aba-bdf8-a69134a100b6','雜句 十','龐藴','唐','唐诗','tang','','[]','阿難貝多葉，持來數千劫。',32,'全唐诗/poet.tang.53000.json','["阿難貝多葉，持來數千劫。", "匕寶藏中付迦葉，分爲十二部，析作三乘法。"]'),
('4e0d6ca0-a2c7-4cd2-a952-4e8ca708ac09','雜句 十一','龐藴','唐','唐诗','tang','','[]','非故亦非新，應化隨緣百億身。',30,'全唐诗/poet.tang.53000.json','["非故亦非新，應化隨緣百億身。", "若有真如一合相，一億還同一聚塵。"]'),
('7de524cb-ac3b-4e47-b082-476b4767047e','雜句 十二','龐藴','唐','唐诗','tang','','[]','珠從藏中現，顯赫呈光輝。',28,'全唐诗/poet.tang.53000.json','["珠從藏中現，顯赫呈光輝。", "昔日逃走爲窮子，今日還家作富兒。"]'),
('297ecd3a-3198-42af-b31b-f76248d54e86','雜句 十三','龐藴','唐','唐诗','tang','','[]','心依真智，理逐心行，理智無礙，心亦無生。',180,'全唐诗/poet.tang.53000.json','["心依真智，理逐心行，理智無礙，心亦無生。", "迷即有我，悟即無情。", "通達大智，諸法不成。", "五神無主，六國安寧。", "七死弗受，八鏡圓明。", "隨宜善化，總合佛經。", "過即已過，更莫再尋。", "現在不住，念念勿侵。", "未來未至，亦莫預斟。", "既無三世，心同佛心。", "依空默用，即是行深。", "無有少法，觸目平任。", "無戒可持，無垢可淨。", "洞達虛心，法無壽命。", "若能如是，圓通究竟。", "（以上七十五首皆見《龐居士語錄》卷下）。"]'),
('203b2569-bf7e-4eff-8c68-9fe1354362ec','居士見僧講金剛經至無我無人居士問云既無我無人是誰講誰聽座主無語迺與頌曰','龐藴','唐','唐诗','tang','','[]','無我復無人，作麽有疎親。',84,'全唐诗/poet.tang.53000.json','["無我復無人，作麽有疎親。", "勸師（《景德傳燈錄》卷八作「君」）休歷坐，不是（《景德傳燈錄》作「似」）直求真。", "金剛般若性，外絕一纖塵。", "我聞並信受，總是假名陳。", "（同前書卷上）。"]'),
('0667faa0-8c67-4529-b8f5-9b23deebdcba','與谷隱道者頌','龐藴','唐','唐诗','tang','','[]','焰火無魚下底鉤，覓魚無處笑君愁。',58,'全唐诗/poet.tang.53000.json','["焰火無魚下底鉤，覓魚無處笑君愁。", "可憐谷隱孜禪伯，被唾如今見亦羞。", "（同前）按：《全唐詩》卷八一○收此首，缺題，今重錄。"]'),
('e8672133-dca7-400f-9f90-0d841156eeab','詩偈 一','龐藴','唐','唐诗','tang','','[]','須彌頹，五嶽崩，大海竭，十方空。',81,'全唐诗/poet.tang.53000.json','["須彌頹，五嶽崩，大海竭，十方空。", "乾坤尚納毛頭裏，日月猶潛毫相中。", "此是西國那提子，示寂不起現神通。", "妙德啓口問不二，忘言入理顯真宗。", "（見吳越釋延壽《宗鏡錄》卷二三）。"]'),
('ac65b26f-999f-4386-9265-fe838895ae7c','詩偈 二','龐藴','唐','唐诗','tang','','[]','居士元無病，方丈現有疾。',105,'全唐诗/poet.tang.53000.json','["居士元無病，方丈現有疾。", "唯憂二乘者，緣事不得出。", "所以訶穢食，純說波羅蜜。", "上方一盂飯，氣滿於七日。", "不假日月光，心王照斯室。", "文殊問不二，忘言功自畢。", "過去即如然，現在還同一。", "若能達此理，無求總成佛。", "（見前書卷二五）。"]'),
('3ce312df-17a2-4b28-944a-c98edc0e5920','詩偈 三','龐藴','唐','唐诗','tang','','[]','心如境亦如，無實亦無虛。',44,'全唐诗/poet.tang.53000.json','["心如境亦如，無實亦無虛。", "有亦不管，無亦不居（《五燈會元》作「拘」）。", "不事賢聖，了事凡夫。"]'),
('2ece3bb7-c816-455e-ba76-7b07bcc229e9','詩偈 四','龐藴','唐','唐诗','tang','','[]','心若如，神自虛。',152,'全唐诗/poet.tang.53000.json','["心若如，神自虛。", "不服藥，病自除。", "病既除，自見蓮華如意珠。", "無勞事，莫駈駈。", "智者觀財色，了知如（《語錄》作「是」）幻虛。", "衣食支身命，相勸學如如。", "時至移庵去，無物可盈餘。", "（以上二首均見影印本日本花園大學圖書館藏高麗覆刻本南唐招慶寺靜筠二僧著《祖堂集》卷十五）（按：《龐居士語錄》卷中以後六句爲一首，似未全。", "）。"]'),
('ad065703-6e60-4d96-9356-1921853f5db4','詩偈 五','龐藴','唐','唐诗','tang','','[]','事上說佛國，此去十萬里。',82,'全唐诗/poet.tang.53000.json','["事上說佛國，此去十萬里。", "大海渺無邊，動即黑風起。", "往者雖千萬，達者無一二。", "忽遇本來人，不在陰陽里。", "（見日本《大正新修大藏經》第四八冊吳越釋延壽撰《萬善同歸集》卷上）。"]'),
('0ee4c7e6-ea49-492c-9663-5f063289f666','詩偈 六','龐藴','唐','唐诗','tang','','[]','護身須是殺，殺盡始安居。',35,'全唐诗/poet.tang.53000.json','["護身須是殺，殺盡始安居。", "會得箇中意，鐵船水上浮。", "（《五燈會元》卷三）。"]'),
('0d98757e-196d-4cba-a5b7-f3bd74077f45','詩偈 七','龐藴','唐','唐诗','tang','','[]','窮廝煎，餓廝吵，父子不同途，大家相脫卯。',274,'全唐诗/poet.tang.53000.json','["窮廝煎，餓廝吵，父子不同途，大家相脫卯。", "萬頃湘江洗不清，無生曲調何時了。", "（見《大正新修大藏經》四七冊宋《虛堂和尚語錄》卷十引）（按：《祖堂集》卷十五《龐居士傳》云：「平生樂道偈頌，可三百餘首，廣行於世。", "皆以言符至理，句闡玄猷，爲儒彥之珠金，乃緇流之篋寶。", "」）（〖1〗《景德傳燈錄》卷八本傳云：「有詩偈三百餘篇傳於世。", "」〖2〗《新唐書》卷五九《藝文志》三著錄龐藴《詩偈》三卷，注云：「字道玄，衡州衡陽人，貞元初人。", "三百餘篇。", "」〖3〗無名子《龐居士語錄詩頌序》云：「其餘玄談道頌，流傳人間，頗多散軼。", "今姑以所聞成編，釐爲二卷，永示將來，庶警後學。", "」）。"]'),
('a751fe18-a193-41c6-9867-0967e6ba2774','謁贈何國子監司籍堅','陽城','唐','唐诗','tang','','[]','久仰高明抱樸忠，倏傳馬首向城東。',85,'全唐诗/poet.tang.53000.json','["久仰高明抱樸忠，倏傳馬首向城東。", "錦袍光射三千里，汗史功高百二雄。", "童稚候門烹雀舌，黎老植杖盼菊松。", "皇天應欲逸家輔，故遣盤桓醉碧筒。", "（見光緒三年刊許清源纂《道州志》卷十一）。"]'),
('e84b9f55-c903-4bf2-914e-e6f3761f40bd','次韻答陽刺史城','何堅','唐','唐诗','tang','','[]','素履衡門秉直忠，挂冠金闕回江東。',64,'全唐诗/poet.tang.53000.json','["素履衡門秉直忠，挂冠金闕回江東。", "戢羽應知非健翮，守雌或可謂知雄。", "午夜鳴琴餐玄露，深山弄月友赤松。", "多感君侯歡導引，臨流遣興醉碧筒。"]'),
('9a7f6d13-0699-4d1e-92f0-9d03410aa692','除授太學國子監司籍之職因賦','何堅','唐','唐诗','tang','','[]','九重天子重英豪，御殿傳恩賜綠袍。',74,'全唐诗/poet.tang.53000.json','["九重天子重英豪，御殿傳恩賜綠袍。", "樂道直欲學商尹，致君恒切佐唐堯。", "瓊林日照宮花燦，金榜風搖姓字高。", "幸荷召頒入太學，相期聯步覲天朝。", "（見同前書卷十一）。"]'),
('dd95ade7-8a73-4cad-a66e-6f608409a7b9','漁父詞','顧況','唐','唐诗','tang','','[]','新婦磯邊月明，女兒浦口潮平，沙頭鷺宿魚驚。',106,'全唐诗/poet.tang.53000.json','["新婦磯邊月明，女兒浦口潮平，沙頭鷺宿魚驚。", "（見宋曾慥《樂府雅詞》卷中徐俯詞跋引、吳曾《能改齋漫錄》卷十六《水光山色漁父家風》引徐師川云引）（按：《全唐詩》卷二六七據《野客叢書》卷二一所錄，僅存前二句，今重錄。", "）。"]'),
('acef2d2d-cbcc-441c-8163-e1669a19b202','題梨花睡鴨圖','顧況','唐','唐诗','tang','','["\u592a\u6e56"]','昔年家住太湖西，常過吳興罨畫溪。',47,'全唐诗/poet.tang.53000.json','["昔年家住太湖西，常過吳興罨畫溪。", "水閣筠簾春似海，梨花影裏睡鳧鷖。", "（見《吳興藝文志補》卷四四）。"]'),
('de0b8a80-6ec4-44a2-bffb-d9f014d34a57','委羽山','顧況','唐','唐诗','tang','','[]','昔人乘鶴玉京遊，翮遺仙洞何悠悠。',76,'全唐诗/poet.tang.53000.json','["昔人乘鶴玉京遊，翮遺仙洞何悠悠。", "我來尋覓空彝猶，煙霞萬壑明清秋。", "何當騎麟翳鳳登瀛洲，倏忽能消萬古愁。", "（見《古今圖書集成·山川典》卷一二○《委羽山部》）。"]'),
('f3f45c6f-2929-4bd5-86b3-aef6979d311b','贈顧況詩','蘇州刺史','唐','唐诗','tang','','[]','辟彊東晉日，竹樹有名園。',90,'全唐诗/poet.tang.53000.json','["辟彊東晉日，竹樹有名園。", "年代更多主，池塘復裔孫。", "（見宋朱長文《吳郡圖經續紀》卷下）（〖1〗《吳郡圖經續記》：「辟彊園，唐時猶在。", "顧況嘗假以居。", "郡守贈詩曰〖略〗。", "」郡守姓名不詳。", "）。"]'),
('09650c65-e86e-487d-a9a3-40d093e1c22f','問如滿禪師 二','順宗皇帝李誦','唐','唐诗','tang','','[]','佛向王宮生，滅向雙林滅。',72,'全唐诗/poet.tang.53000.json','["佛向王宮生，滅向雙林滅。", "住世四十九，又言無法說。", "山河及大海，天地及日月。", "時至皆歸盡，誰言不生滅？", "疑情猶若斯，智者善分別。", "（《景德傳燈錄》卷六）。"]'),
('90279a2d-3bdf-4b90-afa3-8800ee9f50e3','','如滿','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('857ff0e0-111e-4aaa-8f8c-07fe00c6f198','答順宗皇帝問 一','如滿','唐','唐诗','tang','','[]','佛從無爲來，滅向無爲去。',72,'全唐诗/poet.tang.53000.json','["佛從無爲來，滅向無爲去。", "法身等虛空，常住無心處。", "有念歸無念，有住歸無住。", "來爲衆生來，去爲衆生去。", "清淨真如海，湛然體常住。", "智者善思惟，更勿生疑慮。"]'),
('4a408e27-755e-4962-a412-412205f11060','答順宗皇帝問 二','如滿','唐','唐诗','tang','','[]','佛體本無爲，迷情妄分別。',83,'全唐诗/poet.tang.53000.json','["佛體本無爲，迷情妄分別。", "法身等虛空，未曾有生滅。", "有緣佛出世，無緣佛入滅。", "處處化衆生，猶如水中月。", "非常亦非滅。", "生亦未曾生，滅亦未曾滅。", "了見無心處，自然無法說。", "（同前）。"]'),
('b273ac38-3a54-4667-a82f-b21233ec2ba1','山莊早春連雨即事','朱千乘','唐','唐诗','tang','','[]','崇朝竟日雨{風衰}{風衰}（疑），萬物萌牙春（疑）水災。',76,'全唐诗/poet.tang.53000.json','["崇朝竟日雨{風衰}{風衰}（疑），萬物萌牙春（疑）水災。", "白屋世情輕席戶，青山老大厭莓苔。", "常時楊柳煙中綻，今歲花枝雪未開。", "節往始知陽氣晚，和風不借後亭梅。"]'),
('b8fd8b82-4a57-46b4-a5e1-e2911191060f','早春霽後山莊即事','朱千乘','唐','唐诗','tang','','[]','插槿未成籬，啼鶯早已知。',117,'全唐诗/poet.tang.53000.json','["插槿未成籬，啼鶯早已知。", "日長春霽後，風暖柳煙宜。", "席戶門斜掩，漁舟釣直垂。", "久將松竹比，寧懼歲寒移。", "上藥幽前圃，繁花壓小枝。", "素琴延翫月，清渭酌臨池。", "守道安貧（疑）老，專經數欲奇。", "若爲裁二鬢，羞向鏡中窺。", "（日本藏唐抄本《新撰類林抄》卷四）。"]'),
('05b650af-52e3-45d0-8ea6-db4f22db5531','送日本國三藏空海上人朝宗我唐兼貢方物而歸海東詩（幷序）','朱千乘','唐','唐诗','tang','','[]','古貌宛休公，談真說苦空。',122,'全唐诗/poet.tang.53000.json','["古貌宛休公，談真說苦空。", "應傳六祖後，遠化島夷中。", "去歲朝秦闕，今春赴海東。", "威儀易舊體，文字冠儒宗。", "留學幽微旨，雲關護法崇。", "凌波無際礙，振錫路何窮。", "水宿鳴金磬，雲行侍玉童。", "承恩見明主，偏沐僧家風。", "（收入《弘法大師正傳》，見《弘法大師全集》第七卷）。"]'),
('76ce33cc-916b-4a82-a441-d8e74cbb6334','送空海上人朝謁後歸日本','朱少端','唐','唐诗','tang','','[]','禪客祖州來，中華謁帝回。',53,'全唐诗/poet.tang.53000.json','["禪客祖州來，中華謁帝回。", "騰空猶振錫，過海來浮杯。", "佛法逢人授，天書到國開。", "歸程數萬里，歸國信悠哉。", "（同前）。"]'),
('94e09911-749c-4013-bb41-fe1254cbc98d','奉送日本國使空海上人橘秀才朝獻後却還','曇靖','唐','唐诗','tang','','[]','異國桑門客，乘杯望斗星。',53,'全唐诗/poet.tang.53000.json','["異國桑門客，乘杯望斗星。", "來朝漢天子，歸譯竺乾經。", "萬里洪濤白，三春孤島青。", "到宮方奏對，圖像列王庭。", "（同前）。"]'),
('32204a07-f044-4a5e-9b7c-3225b224de83','奉送日本國使空海上人橘秀才朝獻後却還','鴻漸','唐','唐诗','tang','','[]','禪居一海間，鄉路祖州東。',53,'全唐诗/poet.tang.53000.json','["禪居一海間，鄉路祖州東。", "到國宣周禮，朝天得僧風。", "山冥魚梵遠，日正蜃樓空。", "人至非徐福，何由寄信通。", "（同前）。"]'),
('960525be-a6bc-463f-94b4-34785e2b16e9','奉送日本國使空海上人橘秀才朝獻後却還','鄭壬','唐','唐诗','tang','','[]','承化來中國，朝天是外臣。',87,'全唐诗/poet.tang.53000.json','["承化來中國，朝天是外臣。", "異才誰作侶，孤嶼自爲鄰。", "鴈塔歸殊域，鯨波涉巨津。", "他年續僧史，更載一賢人。", "（同前）（按：朱千乘等五人送空海歸國詩五首，均錄自張步雲《唐代逸詩輯存》。", "）。"]'),
('2fd9b2f6-c5c5-4e56-94e1-701de35f8965','贈釋空海歌','胡伯崇','唐','唐诗','tang','','[]','說四句，演毗尼，凡夫聽者盡歸依。',107,'全唐诗/poet.tang.53000.json','["說四句，演毗尼，凡夫聽者盡歸依。", "天假吾師多伎術，就中草聖最狂逸，不可得，難再見。", "（見日僧真濟《遍照發揮性靈集序》，見《日本古典文學大系》七一冊空海《性靈集》卷首）（按：《全唐詩逸》卷中錄此詩，缺末二句，今重錄。", "）。"]'),
('5c1e468d-3c2a-4c22-b7cb-9173015020ae','奉贈葉□郎新湖詩','余鼎','唐','唐诗','tang','','[]','賞眺新湖趣，澄漪寫物華。',66,'全唐诗/poet.tang.53000.json','["賞眺新湖趣，澄漪寫物華。", "采蘋經綠溆，垂釣倚枯槎。", "水動魚驚鳥，風搖蝶□花。", "宛然登興處，寧羨武陵家。", "（光緒《上虞縣志》卷三七《金石》）。"]'),
('a7bdab8b-ce63-4557-8d3c-064626ac893d','奉贈葉□郎新湖詩','汪仲陽','唐','唐诗','tang','','[]','平湖近闢千□□，物色如今滿面新。',81,'全唐诗/poet.tang.53000.json','["平湖近闢千□□，物色如今滿面新。", "風擺野花香撲撲，水澄絲柳影鱗鱗。", "高低菡萏分紅蘂，出沒鵁鶄間白蘋。", "迴首更看南北岸，不知何處不宜人。", "（以上二首，均爲陶敏先生錄示。", "）。"]'),
('ae72bfb9-b960-4aa7-9329-cd2d84552b5c','善卷祠','薛巽','唐','唐诗','tang','','[]','子長愛奇故不收，況乃著論非許由。',96,'全唐诗/poet.tang.53000.json','["子長愛奇故不收，況乃著論非許由。", "先生蹤跡重埋沒，引舜作證應點頭。", "天下大器尚不欲，萬古虛名豈願留？", "江北漫空山不靜，說著高風簪可投。", "（同治《武陵縣志》卷四八。", "本詩爲陶敏先生錄示，小傳亦從陶說。", "）。"]'),
('17d10833-7bf6-46fe-ad63-a70d4437ad3c','金燈','盧殷','唐','唐诗','tang','','[]','疎莖秋擁翠，幽豔夕添紅。',84,'全唐诗/poet.tang.53000.json','["疎莖秋擁翠，幽豔夕添紅。", "有月長燈在，無煙燼火同。", "香濃初受露，勢庳不知風。", "應笑金臺上，先隨曉漏終。", "（見令狐楚《御覽詩》）（按：《全唐詩》卷五六三誤收於盧溵下，今移正。", "）。"]'),
('5c3d970d-b8be-4600-844a-e0cda299e596','秋懷','段弘古','唐','唐诗','tang','','[]','野濶平收潦水香，園林恰似鄭公鄉。',84,'全唐诗/poet.tang.53000.json','["野濶平收潦水香，園林恰似鄭公鄉。", "懶雲未許寒風卷，落葉從他零露傷。", "夜靜猿聲添客淚，朝聞雁字引詩狂。", "生涯不共秋光老，濁酒丹經一釣航。", "（見同治十三年刊《直隸澧州志》卷二五）。"]'),
('7d2cf0f0-f99f-4347-adf2-e432061f1e05','孤竹','段弘古','唐','唐诗','tang','','[]','亭亭骨屹短墻顛，搖曳空明漾素妍。',90,'全唐诗/poet.tang.53000.json','["亭亭骨屹短墻顛，搖曳空明漾素妍。", "帶雨微添寒鶴淚，淩霜不受野雲憐。", "老松立地同高節，芳草何心弔[謫]（滴）仙。", "抱此孤根滋九畹，青山一道送流泉。", "（見道光刊本鄧顯鶴輯《沅湘耆舊集》卷二）。"]'),
('6bae868b-4a1c-4b45-b6e9-fa28dbb6acd1','登石傘峰','王承鄴','唐','唐诗','tang','','[]','作鎮得良牧，撫戎慙匪仁。',134,'全唐诗/poet.tang.53000.json','["作鎮得良牧，撫戎慙匪仁。", "每觀龔黃化，煦物如陽春。", "政簡似多暇，遊從邀衆賓。", "鳴騶鏡水畔，捨櫂耶溪津。", "偶茲逢勝境，頓覺離囂塵。", "丞相築室在，季方結廬新。", "登臨經絕頂，矚眺怡心神。", "金章照玉傘，龍節陵松鱗。", "笙歌入中流，聲角聞城闉。", "更吟瓊瑤篇，願言書諸紳。", "（見《會稽掇英總集》卷四）。"]'),
('e03ca858-c25a-4658-8f53-16252bec7227','登石傘峰','齊推','唐','唐诗','tang','','[]','能以郡中暇，不遺塵外蹤。',158,'全唐诗/poet.tang.53000.json','["能以郡中暇，不遺塵外蹤。", "嘯儔得鴛鴦，探策入雲松。", "緣徑歷空際，望崖來劍峰。", "況當會天人，復此陳歌鐘。", "賤子固多癖，偶茲安一峰。", "步林欣有適，築室幸可容。", "寧期樵牧處，忽與軒蓋逢。", "仰荷高興屬，俯慙危磴重。", "攀幽破巖靄，踐滑觸苔封。", "秋景山光動，寒叢菊艷濃。", "賞心愜觴酌，逸韻陶襟胸。", "仍叨勒名字，永紀今所從。", "（見《會稽掇英總集》卷四）。"]'),
('723daec8-8774-4106-b8f7-86e80a18282d','','路黃中','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('ec456771-0cc3-4ecf-82ab-f454a1f015e1','登石傘峰','路黃中','唐','唐诗','tang','','[]','總戎詣幽勝，天使相追隨。',158,'全唐诗/poet.tang.53000.json','["總戎詣幽勝，天使相追隨。", "躋山玉笥號，到峰石傘奇。", "接武白雲表，放情玄月時。", "恬曠薄沆瀣，峻極超崦嵫。", "平視羲和轡，俯觀朝夕池。", "巖中復何揖，坐位多所宜。", "鬱烈桂香眇，寅緣霞彩披。", "孤光逗綺翼，獨秀分瓊枝。", "靈氣達心久，華容招目移。", "遂忘日云暮，登降不知疲。", "眷言丘壑士，養節松竹滋。", "感激旌蓋顧，干以獻貞詞。", "（見《會稽掇英總集》卷四）。"]'),
('e5e635a0-7d08-44d6-9bc9-579016600b32','正月十五夜翫月詩 一','范傳正','唐','唐诗','tang','','[]','風淒城上樓。',6,'全唐诗/poet.tang.53000.json','["風淒城上樓。"]'),
('117ec536-0192-43f7-8531-0f545ccc7fa3','正月十五夜翫月詩 二','范傳正','唐','唐诗','tang','','[]','月滿庾公樓。',6,'全唐诗/poet.tang.53000.json','["月滿庾公樓。"]'),
('09aaeabc-7d34-4a68-b733-9a7af309c2bb','正月十五夜翫月詩 三','范傳正','唐','唐诗','tang','','[]','夕照下西樓。',27,'全唐诗/poet.tang.53000.json','["夕照下西樓。", "（均見《嘉泰吳興志》卷十三「明月樓」條）。"]'),
('696b87aa-48f4-4335-9bc2-861fe9b548b6','雲居寺','武元衡','唐','唐诗','tang','','[]','玉峰山下雲居寺，六百年來選佛場。',54,'全唐诗/poet.tang.53000.json','["玉峰山下雲居寺，六百年來選佛場。", "滿地白雲關不住，石泉流出落花香。", "（見光緒元年刊支恒春纂《松陽縣志》卷十一）。"]'),
('ff14212f-cf65-447c-a9ff-ff12378d9f02','奉酬竇三中丞見贈','劉伯翁','唐','唐诗','tang','','[]','多幸嘗陪侍玉墀，俄驚負譴阻天涯。',139,'全唐诗/poet.tang.53000.json','["多幸嘗陪侍玉墀，俄驚負譴阻天涯。", "今日相逢問榮悴，更嗟年輩颯然衰。", "（見《竇氏聯珠集·竇羣》附）（按：竇羣詩題爲《贈劉大兄院長》，劉詩下署「金州員外司馬劉伯翁」。", "岑仲勉先生《唐人行第錄》疑即兩《唐書》皆有傳之劉伯芻，然二書均未載伯芻貶金州事，尚無從定論。", "今仍題作劉伯翁，俟考詳。", "）。"]'),
('89152e41-bf8a-4870-83ee-bf2fe254390e','雲門寺（《禪》作「歸雲門」）','靈澈','唐','唐诗','tang','','[]','湖邊歸鶴（《禪》作「雁」）唳寥泬，僧房半倚秦峰缺。',127,'全唐诗/poet.tang.53000.json','["湖邊歸鶴（《禪》作「雁」）唳寥泬，僧房半倚秦峰缺。", "雲生幽石何逍遙，泉去疎林幾嗚咽。", "天寒猛虎叫巖月（《禪》作「雪」），松下無人空有雪（《禪》作「月」）。", "千年像教人不聞，燒（《禪》作「焚」）香獨爲鬼神說。", "（見《會稽掇英總集》卷七，以《古今禪藻集》卷三相校）。"]'),
('a781aa2b-af14-4da2-bbd7-d617b96f9481','謫汀州','靈澈','唐','唐诗','tang','','[]','青蠅爲弔客，黃耳（《紀事》作「黃犬」）寄家書。',55,'全唐诗/poet.tang.53000.json','["青蠅爲弔客，黃耳（《紀事》作「黃犬」）寄家書。", "（見《劉賓客文集》卷十九《澈上人文集紀》、《唐詩紀事》卷七二）。"]'),
('701754c3-baf0-406d-85a7-effe45f1c329','過秦松嶺','林藴','唐','唐诗','tang','','[]','散髮長林下，松風入太清。',60,'全唐诗/poet.tang.53000.json','["散髮長林下，松風入太清。", "空山容暮色，落葉起秋聲。", "世險江天窄，雲深草木平。", "從茲歸故土，勿作失羣鳴。", "（《閩詩錄甲集》卷一）。"]'),
('b40f55aa-a982-4d9e-bb7f-82aad8914f7a','答顏太守','林藴','唐','唐诗','tang','','[]','物力孤窮甚，無由蔽草廬。',86,'全唐诗/poet.tang.53000.json','["物力孤窮甚，無由蔽草廬。", "抱疴明盛世，丐食兵荒餘。", "馬革藏身拙，鴟夷報主疎。", "勉哉吾二子，太歲易消除。", "（見《王氏刊唐人集》收《林邵州遺集》，注云：「見鄭王臣《莆風清籟集》。", "」）。"]'),
('5c7a7fb3-ba6b-4079-8848-d82c80128a32','長句贈微之（題擬）','馬逢','唐','唐诗','tang','','[]','靈溪試爲訪金丹。',31,'全唐诗/poet.tang.53000.json','["靈溪試爲訪金丹。", "（見《元氏長慶集》卷十六《天壇上境》題注引）。"]'),
('5da00cac-9544-442b-b14f-1231ed6f5075','大滌山（題擬）','白元鑒','唐','唐诗','tang','','[]','天壇絕頂山，髣髴翠微間。',175,'全唐诗/poet.tang.53000.json','["天壇絕頂山，髣髴翠微間。", "跡久苔紋碎，雲根古木閒。", "丹成人已去，鶴駕未曾還。", "猶有簫吹響，時時下舊山。", "（見《咸淳臨安志》卷二四）（按：《全唐詩補逸》卷十八據《洞霄詩集》收《天壇》，爲此詩之別本，然四十字中有二十八字不同，今重錄。", "《咸淳臨安志》收《大滌洞》一首，首三句與《全唐詩補逸》不同，錄如次：「靈山實秀德，仙聖杳難親。", "水溜空巖石，……」餘同，不錄。", "）。"]'),
('aaeb58f6-a5a0-48b4-8154-6b657f0597d4','法堂','白元鑒','唐','唐诗','tang','','[]','高蹤遺可繼，虛室即流塵。',67,'全唐诗/poet.tang.53000.json','["高蹤遺可繼，虛室即流塵。", "越國曾封邑，蓬萊早會真。", "餘風生戶牖，殘影照江濱。", "化鶴年猶遠，空悲雲水親。", "（影印本《詩淵》第三冊第一五六九頁）。"]'),
('c52c91e2-80c0-4550-927f-dc048b50e762','新池','白元鑒','唐','唐诗','tang','','[]','昔嘗遊勝境，今喜盡幽蹤。',59,'全唐诗/poet.tang.53000.json','["昔嘗遊勝境，今喜盡幽蹤。", "丹滿鏡潭色，雲疏錦磧容。", "響中聞細溜，波裏見喬松。", "唯廣花源賞，人間不可逢。", "（同前第二○四三頁）。"]'),
('6c0b3f6c-d811-4171-b86f-01ad77f20e62','瀑布','白元鑒','唐','唐诗','tang','','[]','太極生柔德，雄姿不可名。',102,'全唐诗/poet.tang.53000.json','["太極生柔德，雄姿不可名。", "淩空虹永掛，瀉澗布長成。", "映日添霞色，當風振浪聲。", "潺潺雲水下，已得滌幽情。", "（同前第二一八○頁）（按：《全唐詩補逸》卷十八收白詩，有《講堂》、《瀑布》、《新池》諸詩，但內容均不同。", "）。"]'),
('dccf1672-c359-4746-b9ee-fd10bcdbc203','偈','隱峯','唐','唐诗','tang','','[]','獨絃琴子爲君彈，松栢長青不怕（《宋高僧傳》作「怯」）寒。',66,'全唐诗/poet.tang.53000.json','["獨絃琴子爲君彈，松栢長青不怕（《宋高僧傳》作「怯」）寒。", "金鑛相和性自別，任向君前試取看。", "（見《祖堂集》卷十五、《宋高僧傳》卷二一）。"]'),
('9d1b452c-66cd-4e4e-96c3-570f07597d33','臨化示偈（題擬）','無了','唐','唐诗','tang','','[]','八十年來辨東西（《五燈會元》作「西東」），如今不要白頭公（《五燈會元》作「翁」）。',94,'全唐诗/poet.tang.53000.json','["八十年來辨東西（《五燈會元》作「西東」），如今不要白頭公（《五燈會元》作「翁」）。", "非長非短非大小，還與諸人性相同。", "無來無去兼無住，了却本來自性空。", "（見《祖堂集》卷十五、《五燈會元》卷三）。"]'),
('75cf76a5-c159-49d3-9689-07635475fce7','讚馬氏子','粲和尚','唐','唐诗','tang','','[]','豐姿窈窕鬢欲斜，賺煞郎君念法華。',51,'全唐诗/poet.tang.53000.json','["豐姿窈窕鬢欲斜，賺煞郎君念法華。", "一把骨頭挑去後，不知明月落誰家。", "（見《全閩詩話》卷十二引《感應傳》）。"]'),
('c84ef65e-df87-4fe7-9273-d58b7f6ff528','零陵寺井欄讚','郭通','唐','唐诗','tang','','[]','此是南山石，將來造井欄。',84,'全唐诗/poet.tang.53000.json','["此是南山石，將來造井欄。", "流傳千萬代，各結佛家緣。", "盡意修功德，應無朽壞年。", "同霑勝福者，超于彌勒前。", "（《江蘇金石志》卷五、《寶鐵齋金石文字跋尾》卷上、《靈芬館詩話》卷六）。"]'),
('d08a0431-1d8c-482e-a279-1b4db9ef2c7f','夜','林藻','唐','唐诗','tang','','[]','久絕白雲信，愁心如水長。',60,'全唐诗/poet.tang.53000.json','["久絕白雲信，愁心如水長。", "蛩鳴萬戶月，鴉步一溪霜。", "不識紅塵險，安知皓首狂。", "擣衣中夜望，今古事尋常。", "（《莆風清籟集》卷一）。"]'),
('7c43298a-fdba-4617-9e8e-d149526ac25a','晚泊鄞陽','林藻','唐','唐诗','tang','','[]','孤帆高樓鄞陽城，萬頃清流一應聲。',69,'全唐诗/poet.tang.53000.json','["孤帆高樓鄞陽城，萬頃清流一應聲。", "青鬢初隨衰草謝，白雲還傍故山行。", "夢中美酒酬枚乘，江上秋風屬屈平。", "愧我一生潦倒甚，全無佳句答長庚。", "（同前）。"]'),
('8098d8ef-7329-4cdc-ba0e-afc1baf9343f','爲樵','林藻','唐','唐诗','tang','','[]','致政慚輕舉，爲樵亦易窮。',61,'全唐诗/poet.tang.53000.json','["致政慚輕舉，爲樵亦易窮。", "文章還古道，禮數逐秋風。", "獨鶴千松下，萬航一水中。", "最憐當路草，衰敗與人同。", "（《莆風清籟集》卷六十）。"]'),
('f0bfa33c-dca3-4f70-8ce6-8c6f78759376','題桂林七星巖棲霞洞詩（題擬）','懷信','唐','唐诗','tang','','[]','石古苔痕厚，巖深日影悠。',219,'全唐诗/poet.tang.53000.json','["石古苔痕厚，巖深日影悠。", "參禪因久坐，老佛總無愁。", "（見桂林市文物管理局編《桂林石刻》第一冊）（按：《桂林石刻》編者注：「右摩崖在七星巖口，高一尺五寸，寬九寸，徑一寸五分。", "原石已毀，據舊搨本校錄。", "」詩末署「釋懷信書」。", "同書又載《南溪山元巖磨崖題名》云：「懷信、覺救、惟則、惟亮、無等、無業，元和十二年九同遊。", "業記。", "」今據以確定作者之時代。", "《宋高僧傳》卷十九有《唐揚州西靈塔寺懷信傳》，爲會昌間人。", "時代雖相接，然無從證明即此詩作者，故不取。", "）。"]'),
('13ef86ad-f91d-4cd8-b9dd-9fc9ea7f5a13','石塘路有懷院中諸公','權德輿','唐','唐诗','tang','','[]','迴合千峰裏，晴光似畫圖。',49,'全唐诗/poet.tang.53000.json','["迴合千峰裏，晴光似畫圖。", "征車隨反照，候吏暎寒蕪。", "石瀨侵行徑，溪雲拂路隅。", "未酬知己分，寧敢學潛夫。", "。"]'),
('92104bfa-69cf-4f80-b450-211ee30081b4','曉發桐廬','權德輿','唐','唐诗','tang','','[]','客路去漫漫，桐溪上水灘。',69,'全唐诗/poet.tang.53000.json','["客路去漫漫，桐溪上水灘。", "扣船乘曉月，欹枕聽迴灘。", "煙重江楓濕，沙平宿鷺寒。", "閑吟試一望，疑在畫屏看。", "（均見《四部叢刊》本《權載之文集》卷六）。"]'),
('388fbdfc-ca06-4c12-9798-74b48d02c4d6','越州觀察使差人問師以禪住持依律住持師以偈答','靈默','唐','唐诗','tang','','[]','寂寂不持律，滔滔不坐禪。',36,'全唐诗/poet.tang.53000.json','["寂寂不持律，滔滔不坐禪。", "儼茶兩三垸，意在钁頭邊。", "（見《祖堂集》卷十五）。"]'),
('7c3a9493-2be2-4fcc-92c2-83726b3e5241','牧護歌','蘇溪和尚','唐','唐诗','tang','','[]','聽說衲僧牧護，任運逍遙無住。',275,'全唐诗/poet.tang.53000.json','["聽說衲僧牧護，任運逍遙無住。", "一條百納瓶盂，便是生涯調度。", "爲求至理參尋，不憚寒暑辛苦。", "還曾四海周遊，山水風雲滿肚。", "內除戒律精嚴，不學威儀行步。", "三乘笑我無能，我笑三乘謾做。", "智人權立階梯，大道本無迷悟。", "達者不假修治，不在能言能語。", "披麻目視雲霄，遮莫王侯不顧。", "道人本體如然，不是知佛去處。", "生也猶如著衫，死也還同脫袴。", "生也無喜無憂，八風豈能驚怖。", "外相猶似癡人，肚裏非常峭措。", "活計原無一錢，敢與君王鬬富。", "愚人擺手憎嫌，智者點頭相許。", "那知傀儡牽抽，歌舞盡由行主。", "一言爲報諸人，打破畫瓶歸去。", "（《景德傳燈錄》卷三十）（按：此詩原署云：「蘇溪和尚，即五洩小師也。", "」）。"]'),
('a5c09fcc-4307-43c3-affb-c171d8368dd0','坐禪銘','大義','唐','唐诗','tang','','["\u6cf0\u5c71"]','參禪學道幾般樣，要在當人能擇上。',390,'全唐诗/poet.tang.53000.json','["參禪學道幾般樣，要在當人能擇上。", "莫只忘形與死心，此箇難醫病最深。", "直須坐究探淵源，此道古今天下傳。", "正坐端然如泰山，巍巍不要守空閑。", "直須提起吹毛利，要剖西來第一義。", "瞠却眼兮剔起眉，反覆看渠渠是誰。", "還如捉賊須見贓，不怕賊理深處藏。", "有智捉獲剎那頃，無智經年不見影。", "深嗟兀坐常如死，千年萬歲只如此。", "若將此等當禪宗，拈花微笑喪家風。", "黑山下坐死水浸，大地漫漫如何禁。", "若是鐵眼銅睛漢，把手心頭能自判。", "直須著到悟爲期，哮吼一聲獅子兒。", "君不見磨磚作鏡喻有由，車不行兮在打牛。", "又不見巖前湛水萬丈清，沈沈寂寂杳無聲。", "一朝魚龍來攪動，波翻浪湧真堪重。", "譬如靜坐不用工，何年及第悟心空？", "急下手兮高著眼，管取今生教了辦。", "若還默默恣如愚，知君未解作工夫。", "抖擻精神著意看，無形無影悟不難。", "此是十分真用意，勇猛丈夫却須記。", "切莫聽道不須參，古聖孜孜爲指南。", "雖然舊閣閑田地，一度贏來得也未。", "要識坐禪不動尊，風行草偃悉皆論。"]'),
('ad966410-467f-4374-9aea-512c36703ac1','頌','大義','唐','唐诗','tang','','[]','直下識玄旨，羅紋結角是。',56,'全唐诗/poet.tang.53000.json','["直下識玄旨，羅紋結角是。", "不識玄旨人，徒勞逐所示。", "䲺䲺鳥，守空池，魚從脚下過，䲺䲺總不知。", "（見《祖堂集》卷十五）。"]'),
('d5097365-c21b-438c-b8fb-649dfc843ba8','偈','新羅僧','唐','唐诗','tang','','[]','三千里路禮師顏，師已歸真塔已關。',45,'全唐诗/poet.tang.53000.json','["三千里路禮師顏，師已歸真塔已關。", "鬼神哭泣嗟無主，空山只見水潺湲。", "（見《江西詩徵》卷八七）。"]'),
('df70a211-0607-416b-a5f8-5548a892431f','催妝詩','張仲素','唐','唐诗','tang','','[]','舜耕餘草木，禹鑿舊山川。',65,'全唐诗/poet.tang.53000.json','["舜耕餘草木，禹鑿舊山川。", "（見《說郛》卷三二高懌《羣居解頤》、卷六五宋無和子《善謔集》、《古今說海》本陸游《避暑漫抄》引《解頤》）。"]'),
('fdde7968-530e-4272-aaba-9cc10bd0b131','弄珠吟','慧藏','唐','唐诗','tang','','[]','落落明珠耀百千，森蘿萬像鏡中懸。',213,'全唐诗/poet.tang.53000.json','["落落明珠耀百千，森蘿萬像鏡中懸。", "光透三千越大千，四生六類一靈源。", "凡聖聞珠誰不羨，瞥起心求渾不見。", "對面看珠不識珠，尋珠逐物當時變。", "千般萬般況珠喻，珠離百非超四句。", "只這珠生是不生，非爲無生珠始住。", "如意珠，大圓鏡，亦有人中（《宗》作「中人」）喚作性。", "分身百億我珠分，無始本淨如今淨。", "日用真珠是佛陀，何勞逐物浪波波。", "隱現則（《宗》作「即」）今無二相，對面看珠識得摩（《宗》作「麽」）。", "（見《祖堂集》卷十四，《宗鏡錄》卷十一收末九句）。"]'),
('0b4a5ffd-678e-45f4-94ea-37603690e60f','','米嶺和尚','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('1ef71ad9-28ff-4a01-a13d-715a489a2272','遺偈','米嶺和尚','唐','唐诗','tang','','[]','祖祖不思議，不許常住世。',45,'全唐诗/poet.tang.53000.json','["祖祖不思議，不許常住世。", "大衆審思惟，畢竟祇這是。", "（《景德傳燈錄》卷八、《五燈會元》卷三）。"]'),
('482c4ed8-01c9-432a-bd5f-51485cdd223a','冶山二十詠（幷序） 天泉池','裴次元','唐','唐诗','tang','','[]','魚鱗息枯池，廣之使涵泳。',294,'全唐诗/poet.tang.53000.json','["魚鱗息枯池，廣之使涵泳。", "疏鑿得蒙泉，澄明覩明鏡。", "（《淳熙三山志》卷一）（按：《淳熙三山志》云：「唐元和八年，刺史裴次元于其〖指冶山〗南闢爲毬場，即山爲亭，作詩題于其壁。", "」次錄其序之大略，幷云二十首的詩題是：《望京山》、《觀海亭》、《雙檜嶺》、《登山路》、《天泉池》、《翫琴臺》、《筯竹巖》、《枇杷川》、《荻蘆崗》、《桃花塢》、《芳茗原》、《山陰亭》、《含清洞》、《紅蕉坪》、《越壑橋》、《獨秀峰》、《篔簹坳》、《八角亭》、《椒盤石》、《白土谷》。", "詩各一章，章六句。", "今存者惟《淳熙三山志》所錄之《天泉池》四句及《望京樓》二句，後者已收入《全唐詩》卷四六六。", "《淳熙三山志》另錄馮審所作記。", "）。"]'),
('b5a33b6e-86e7-4550-b63f-58fe096ed97b','','李直方','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('68480a0c-827d-466e-ae02-c05e048d58e6','句','李直方','唐','唐诗','tang','','[]','峴山依舊遠，漢水遶城流。',30,'全唐诗/poet.tang.53000.json','["峴山依舊遠，漢水遶城流。", "（見《輿地紀勝》卷八二《襄陽府》）。"]'),
('de40ad3f-6a45-41d1-ba7c-266f0f0b447f','壺公山','潘存實','唐','唐诗','tang','','[]','雙旌牧清源，吟看壺公翠。',63,'全唐诗/poet.tang.53000.json','["雙旌牧清源，吟看壺公翠。", "（見黃滔《黃御史公集》卷四《壺公山》詩注、《輿地紀勝》卷一三五、《莆陽比事》卷一、《記纂淵海》卷十）。"]'),
('63986f07-a554-460e-8021-a8cc32f62f6e','九日夜','陸暢','唐','唐诗','tang','','[]','燈下竹煙看更碧，月間花色不分紅。',34,'全唐诗/poet.tang.53000.json','["燈下竹煙看更碧，月間花色不分紅。", "（《千載佳句》卷上《天象部·夜》）。"]'),
('a93ea851-c7ad-49b4-9b3f-c3751ac8bc78','答問附歌','柳宗元','唐','唐诗','tang','','[]','堯舜之修兮，禹益之憂兮，能者任而愚者休兮。',83,'全唐诗/poet.tang.53000.json','["堯舜之修兮，禹益之憂兮，能者任而愚者休兮。", "蹮蹮蓬藋，樂吾（一作「夫」）囚兮，文墨之彬彬（一本作「申申」），足以申吾愁兮。", "已乎已乎，曷之求乎！（見《柳河東集》卷十五）。"]'),
('c7356ac5-7155-426c-9c77-b2d58924e4e3','送賈山人南遊歌（幷序）','柳宗元','唐','唐诗','tang','','[]','充乎其居，或以匱己之虛，（一作「或躓其塗，匱乎己之虛」。',102,'全唐诗/poet.tang.53000.json','["充乎其居，或以匱己之虛，（一作「或躓其塗，匱乎己之虛」。", "蜀本云：「或以」字下疑脫「兩」字）。", "或盈其廬。", "孰匱孰充，爲泰爲窮，君子烏乎取以寧其躬！若君者之於道而已爾，世孰知其從容耶！（見《柳河東集》卷二五）。"]'),
('292023d3-faf8-494b-a865-91bd027b2f3b','送元暠師詩（幷序）','柳宗元','唐','唐诗','tang','','[]','侯門辭必服，忍位取悲增。',87,'全唐诗/poet.tang.53000.json','["侯門辭必服，忍位取悲增。", "去魯心猶在，從周力未能。", "家山餘五柳，人世遍千燈。", "莫讓金錢施，無生道自弘。", "（中華書局校點本《柳宗元集》附錄《外集補遺》錄自宋乾道永州本《柳柳州外集》）。"]'),
('e08606f6-74f2-4291-a196-2893bc523ea7','秋懷','滕倪','唐','唐诗','tang','','[]','嫋嫋芙蓉枝，灼灼當秋好。',82,'全唐诗/poet.tang.53000.json','["嫋嫋芙蓉枝，灼灼當秋好。", "嚴霜一以冽，日夜色枯槁。", "詎惟華葉衰，柯條不自保。", "斬刈同束薪，秋江迹如掃。", "時事多推移，江流去浩浩。", "（見民國二十年戴鴻熙纂《湯溪縣志》卷十九）。"]'),
('ebd40ecb-2d6b-4a13-ac99-f8aebf258686','月桂','李正封','唐','唐诗','tang','','[]','片月轉洪濛，扶疎萬古同。',95,'全唐诗/poet.tang.53000.json','["片月轉洪濛，扶疎萬古同。", "根非生下土，葉不墜西風。", "每向圓時足，還隨缺處空。", "影令羣木外，香滿一輪[中]（木）。", "未種丹霄日，應虛白兔宮。", "何時得羽化，細得問元宮。", "（見《古今合璧事類備要前集》卷一）。"]'),
('43cb6959-228d-4f35-8cc3-4a3a92eb083f','句','李正封','唐','唐诗','tang','','[]','三月後方有，百花中更無。',27,'全唐诗/poet.tang.53000.json','["三月後方有，百花中更無。", "（見《錦繡萬花谷前集》卷七）。"]'),
('10ee82aa-b836-44bf-b577-6c43299964d7','欲歸山留別韓潮州愈偈','大顛','唐','唐诗','tang','','[]','辭君莫恠歸山早，爲憶松蘿對月宮。',43,'全唐诗/poet.tang.53000.json','["辭君莫恠歸山早，爲憶松蘿對月宮。", "臺殿不將金鏁閉，來時自有白雲封。", "（見《祖堂集》卷五）。"]'),
('b8409991-fa99-41ad-ac97-d310c699c4e0','洗鉢潭','邢允中','唐','唐诗','tang','','[]','潭水澄初地，長爲洗鉢供。',48,'全唐诗/poet.tang.53000.json','["潭水澄初地，長爲洗鉢供。", "已能降虎豹，不問攬魚龍。", "濺沫溪莎碧，疏流石瀨重。", "此中清淨理，繼跡有禪宗。"]'),
('7516bc7a-17ad-49a1-9758-5f58a3e75680','駐錫峯','邢允中','唐','唐诗','tang','','[]','高峯常駐錫，靈異見當年。',76,'全唐诗/poet.tang.53000.json','["高峯常駐錫，靈異見當年。", "卓立驚沙界，光輝動梵天。", "鶴飛青靄外，龍護赤嵐邊。", "丈室仍相對，重來果夙緣。", "（見董慶酉《四明詩幹》卷中。", "邢允中詩承張靖龍同志錄示）。"]'),
('dabd1488-a0f5-4607-bfc1-3abbccea5536','禹廟神座頃服金紫苹自到鎮申牒禮司重加袞冕今因祈雨偶成八韻','薛苹','唐','唐诗','tang','','[]','玉座新規盛，金章舊制非。',389,'全唐诗/poet.tang.53000.json','["玉座新規盛，金章舊制非。", "列城初執禮，清廟重垂衣。", "不覩千箱詠，翻愁五稼微。", "祇將蘋藻潔，寧在餼牢肥。", "徙市行應謬，焚巫事亦違，至誠期必感，昭報意猶希。", "海日明朱檻，谿煙濕畫旗。", "迴瞻郡城路，未欲背山歸。", "（《會稽掇英總集》卷八）（〖1〗《歐陽文忠公文集》卷一四二《集古錄跋尾》卷九《唐薛苹唱和詩》〖大和中〗云：「右薛苹唱和詩，其間馮宿、馮定、李紳皆唐顯人，靈澈以詩名後世，皆人所想見者，然詩皆不及苹，豈唱者得於自然，和者牽於強作耶！」〖2〗《寶刻叢編》卷十三引歐陽棐《集古錄目》云：「《唐禹廟詩》，唐浙東觀察使越州刺史薛苹詩，不著書人名氏。", "苹初至鎮，易禹廟金紫服以冠冕，後因祈雨，作此詩，其和者鹽鐵轉運崔述等凡十七首。", "」按：岑仲勉先生《貞石證史·薛苹唱和詩即禹廟詩》對此詩考證甚詳，可參看。", "惟訂歐陽修云「大和中」刻石爲誤，實未察《集古錄跋尾》著錄年歲，爲刻石時間而非寫作時間，爲小疵耳。", "）。"]'),
('037f89ed-b9ed-4a75-acce-90a4edb6e3ca','謁禹廟','崔詞','唐','唐诗','tang','','[]','（按：崔詞疑即與薛苹同題禹廟十七人之一。',155,'全唐诗/poet.tang.53000.json','["（按：崔詞疑即與薛苹同題禹廟十七人之一。", "）惟舜禪功始，惟堯錫命初。", "九州方奠畫，萬壑遂橫疏。", "受籙嘗開洞，過門不下車。", "諸侯會玉帛，滄海薦圖書。", "玄默將遺世，崇高亦厭居。", "耘田自有鳥，濬澤豈爲魚。", "家及三王嗣，殷囚百代如。", "靈容肅清宇，袞服閉荒墟。", "棗徑愁雲暮，松扉撤祭餘。", "叨榮陵寢邑，懷古益躊躇。", "（見《會稽掇英總集》卷八）。"]'),
('91c0b434-e230-4e51-9c9d-dc053eb31edd','歷山','羊士諤','唐','唐诗','tang','','[]','（按：《全唐詩》卷三三二收此二句，缺題，今重錄。',95,'全唐诗/poet.tang.53000.json','["（按：《全唐詩》卷三三二收此二句，缺題，今重錄。", "）風泉（《歷代詩話續編》本《詩人主客圖》作「前」）留古顏（《全唐詩》作「韻」），笙磬想遺音。", "（見汲古閣本《唐詩紀事》卷四三引《詩人主客圖》）。"]'),
('f7f1f1f8-4c02-453e-9220-9b45248901c5','','崔備','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('54b05242-72c3-4a04-b005-41e992ee0a94','寄羊士諤永寧里居（題擬）','崔備','唐','唐诗','tang','','[]','圖書鎖塵閣，符節守山城。',61,'全唐诗/poet.tang.53000.json','["圖書鎖塵閣，符節守山城。", "（見江標影宋書棚本《羊士諤詩集》收《酬禮部崔員外備獨永寧里弊居見寄來詩云圖書鎖塵閣符節守山城》）。"]'),
('947ff270-e244-4b3a-acdf-e4a5fd1a684c','放少師行脚時頌','自在','唐','唐诗','tang','','[]','放汝南行入大津，碧潭深處養金鱗。',32,'全唐诗/poet.tang.53000.json','["放汝南行入大津，碧潭深處養金鱗。", "等閑莫與凡魚伴，直透龍門便出身。"]'),
('2e633eae-203f-42c1-9dc8-033d9ebbd81f','三個不歸頌','自在','唐','唐诗','tang','','[]','（按：《全唐詩續補遺》據《鑑誡錄》卷十《高僧諭》條，錄伏牛上人《三傷頌》三首，擬傳云「王蜀時高僧」。',151,'全唐诗/poet.tang.53000.json','["（按：《全唐詩續補遺》據《鑑誡錄》卷十《高僧諭》條，錄伏牛上人《三傷頌》三首，擬傳云「王蜀時高僧」。", "今檢《宋高僧傳》卷十一《唐洛京伏牛山自在傳》云：「所著《三傷歌》，辭理俱美，警發迷蒙，有益於代。", "」後接述王蜀乾德間人引此歌事。", "《三傷歌》即《三傷頌》，可知三詩皆元和間自在作，王蜀時另無伏牛上人其人。", "）。"]'),
('20b23aca-bd46-4911-ae61-0f788b1dd8c4','三個不歸頌 一','自在','唐','唐诗','tang','','[]','割愛慈親異俗迷，如雲似鶴更高飛。',32,'全唐诗/poet.tang.53000.json','["割愛慈親異俗迷，如雲似鶴更高飛。", "五湖四海隨緣去，到處爲家一不歸。"]'),
('1ab30411-e9d3-4c1d-9849-970b41162bb6','三個不歸頌 二','自在','唐','唐诗','tang','','[]','苦節勞形守法威，幸逢知識決玄微。',32,'全唐诗/poet.tang.53000.json','["苦節勞形守法威，幸逢知識決玄微。", "慧燈初照昏衢朗，唯報自親二不歸。"]'),
('2fa3f6c1-8505-4d1f-b9fd-1408e3dfc127','三個不歸頌 三','自在','唐','唐诗','tang','','[]','峭壁幽嵒往復希，片雲孤月每相依。',49,'全唐诗/poet.tang.53000.json','["峭壁幽嵒往復希，片雲孤月每相依。", "經行宴坐閑無事，樂道逍遙三不歸。", "（以上四首均見《祖堂集》卷十五）。"]'),
('d18e506f-1860-4d82-a2e9-dd491f2274b7','答伏牛和尚（題擬）','伏牛小師','唐','唐诗','tang','','[]','魚龍未變志常存，變了還教海氣渾。',76,'全唐诗/poet.tang.53000.json','["魚龍未變志常存，變了還教海氣渾。", "兩眼不曾窺小水，一心專擬透龍門。", "千迴下網終難繫，萬度垂鉤誓不天。", "待我一朝鱗甲備，解將雲雨灑乾坤。", "（見《祖堂集》卷十五）。"]'),
('cec0bab7-7728-463f-b791-9a20912843cf','句','張署','唐','唐诗','tang','','[]','越羅巴錦不勝春。',55,'全唐诗/poet.tang.53000.json','["越羅巴錦不勝春。", "（見《分門纂類唐宋時賢千家詩選》卷十六聞人詳正《集句》引）（按：《宋詩紀事》卷六九引作張曙）。"]'),
('4e7c0c24-04ad-47c8-bb67-cec9f788c84d','同竇羣雪中寓直（題擬）','韋貫之','唐','唐诗','tang','','[]','耿耿風雪暮，直廬未掩扉。',74,'全唐诗/poet.tang.53000.json','["耿耿風雪暮，直廬未掩扉。", "詠蘭幽助興，儷玉粲相輝。", "氣勁琴韻切，夜深鑪火微。", "雖殊江海遠，即此戀彤闈。", "（見《竇氏聯珠集》。", "題下原署「吏部員外郎韋貫之」）。"]'),
('81230142-adb7-4004-a6f0-9e79c58e2588','顏魯公挽歌詞','柳登','唐','唐诗','tang','','[]','殺身終不恨，歸喪遂如生。',73,'全唐诗/poet.tang.53000.json','["殺身終不恨，歸喪遂如生。", "（《唐語林》卷六）（按：《唐語林》原稱柳常侍作，此從周勛初先生《唐語林校證》說。", "據周考，此段文字出自韋絢《戎幕閑談》。", "）。"]'),
('14cdd9ca-176b-4083-8dff-23a976815d88','沙堤葬母','李頭陀','唐','唐诗','tang','','[]','守堤三年念生緣，種樹爲陰出世恩。',44,'全唐诗/poet.tang.53000.json','["守堤三年念生緣，種樹爲陰出世恩。", "劃石寄言相矚付，一重孫付一重孫。", "（《閩詩錄甲集》卷四）。"]'),
('76d232e6-4b8a-4bad-8e25-c2f23fc2af1f','孤寂吟','天然','唐','唐诗','tang','','[]','時人見余守孤寂，爲言一生無所益。',400,'全唐诗/poet.tang.53000.json','["時人見余守孤寂，爲言一生無所益。", "余則閑吟孤寂章，始知光陰不虛擲。", "不棄光陰須努力，此言雖說人不識。", "識者同爲一路行，豈可顛墜緣榛棘。", "榛棘茫茫何是邊，只爲終朝盡衆喧。", "衆喧不覺無涯際，哀哉真實不虛傳。", "傳之響之只不聞，猶如燈燭合盂盆。", "共知總有光明在，看時未免暗昏昏。", "昏昏不覺一生了，斯類塵沙比不少。", "直似潭中吞鈎魚，何異空中盪羅鳥。", "此患由來實是長，四維上下遠茫茫。", "倏忽之間迷病死，塵勞難脫哭愴愴。", "愴愴哀怨終無益，只爲將身居痛室。", "到此之時悔何及，雲泥未可訪孤寂。", "孤寂宇宙窮爲良，長吟高臥一閑堂。", "不慮寒風吹落葉，豈愁霜草遍遭霜。", "但看松竹歲寒心，四時不變流清音。", "春夏暫爲羣木暎，秋冬方見鬱高林。", "故知世相有剛柔，何必將心清濁流。", "二時麁糖隨緣過，一身遮莫布毛裘。", "隨風逐浪住東西，豈愁地迮與天低（此字原寫作「{伭右上爲一}」）。", "時人未解將爲錯，余則了然自不迷。", "不迷須有不迷心，看時淺淺用時深。", "此个真珠若採得，豈同樵夫負黃金。"]'),
('58021e79-d3c8-436d-aba2-a8f00bf90683','翫珠吟','天然','唐','唐诗','tang','','[]','識得衣中寶，無明醉（伯作「酒」）自惺（《燈錄》、《通載》、伯作「醒」）。',887,'全唐诗/poet.tang.53000.json','["識得衣中寶，無明醉（伯作「酒」）自惺（《燈錄》、《通載》、伯作「醒」）。", "百骸俱（《燈錄》、《宗鏡錄》作「雖」）潰散（伯作「悔盡」），一物鎮長靈。", "知（《通載》作「智」）境渾非體（伯作「智劍揮非體」），尋（伯、《燈錄》、《通載》作「神」）珠不定（伯作「見」）形。", "悟即（伯、《燈錄》、《通載》作「則」）三身佛，迷疑萬卷經。", "在心心豈（《燈錄》、《通載》、伯作「可」）測，居（《燈錄》、《通載》作「歷」）耳耳難聽。", "罔像先天地，淵玄（《燈錄》、《通載》作「玄泉」，伯作「懸泉」）出杳冥（伯作「名」）。", "本剛非鍛（伯作「斷」）鍊，元淨（《燈錄》、《通載》作「鏡」）莫澄停（伯作「亭」、《燈錄》、《通載》作「渟」）。", "盤泊（《通載》作「礴」）逾（伯作「轉」，《燈錄》、《通載》作「輪」）朝日，玲瓏（伯作「鈴鑨」）暎曉星。", "瑞光流不滅，真澄（伯作「氣」）濁還清（《燈錄》、《通載》作「真氣觸還生」）。", "鑒照崆峒（伯作「空洞」）寂，勞（《燈錄》、《通載》、伯作「羅」）籠法界明。", "剉（《燈錄》作「挫」，伯作「春」）凡功不滅（伯作「狹」），超聖果非盈。", "龍女心親獻，虵（《燈錄》、《通載》作「闍」）王口自傾（伯作「經」，《燈錄》、《通載》作「呈」）。", "護鵝人却活，黃雀義（《燈錄》、《通載》作「意」）猶輕。", "解語非關舌，能言不是聲。", "絕邊彌瀚（《燈錄》、《通載》作「汗」）漫，三（《燈錄》、《通載》作「無」）際等空平。", "演教非爲教（《燈錄》、《通載》作「說」），聞名不（《燈錄》作「勿」，《通載》作「忽」）認名。", "（伯無以上四句）。", "二（伯、《通載》、《燈錄》作「兩」）邊俱不（《通載》作「莫」）立（伯作「守」），中道不須行。", "見月休看（《燈錄》、《通載》作「觀」）指（伯作「紙」），歸（伯作「知」，《燈錄》、《通載》作「還」）家罷問程（伯作「逞」）。", "識心豈測（《燈錄》作「心則」，伯、《通載》作「心即」）佛，何佛更堪成。", "（按：《景德傳燈錄》卷三十收丹霞和尚《翫珠吟二首》，此爲其二。", "另伯三五九七卷、《佛祖歷代通載》卷十六亦收此詩。", "異文並注出。", "《宗鏡錄》卷四十收「百骸雖潰散，一物鎮長靈」二句，題作《般若吟》，不注作者名。"]'),
('66d5d596-8f34-4d15-a60e-72257f7b1784','又頌','天然','唐','唐诗','tang','','[]','丹霞有一寶，藏之歲月久。',96,'全唐诗/poet.tang.53000.json','["丹霞有一寶，藏之歲月久。", "從來人不識，余自獨防守。", "山河無隔碍，光明處處透。", "體寂常湛然，瑩澈無塵垢。", "世間採取人，顛狂逐路走。", "余則爲渠說，撫掌笑破口。", "忽遇解空人，放曠在林藪。", "相逢不擎出，舉意便知有。"]'),
('86006ae3-a6e8-41eb-9a0c-b4d7fdd2608f','驪龍珠吟','天然','唐','唐诗','tang','','[]','驪龍珠，驪龍珠，光明𪹥（疑即「燦」字）爛與人殊。',280,'全唐诗/poet.tang.53000.json','["驪龍珠，驪龍珠，光明𪹥（疑即「燦」字）爛與人殊。", "十方世界無求處，縱然求得亦非珠。", "珠本有，不昇沉，時人不識外追尋。", "行盡天涯自疲寂，不如體取自家心。", "莫求覓，損功夫，轉求轉滅轉元無。", "恰如渴鹿趁陽燄，又似狂人在道途。", "須自體，了分明，了得不用更磨瑩。", "深知不是人間得，非論六類及生靈。", "虛用意，損精神，不如閑處絕纖塵。", "停心息意珠常在，莫向途中別問人。", "自迷失，珠元在，此个驪龍終不改。", "雖然埋在五陰山，自是時人生懈怠。", "不識珠，每拋擲，却向驪龍前作客。", "不知身是主人公，棄却驪龍別處覓。", "認取寶，自家珍，此珠元是本來人。", "拈得翫弄無窮盡，始覺驪龍本不貧。", "若能曉了驪珠後，只這驪珠在我身。"]'),
('6b43a41b-825f-45d9-963d-d40c99cdd83b','弄珠吟（《景德傳燈錄》卷三十作《翫珠吟二首》之一）','天然','唐','唐诗','tang','','[]','般若神（《燈錄》作「靈」）珠妙難測，法性海中親認得。',616,'全唐诗/poet.tang.53000.json','["般若神（《燈錄》作「靈」）珠妙難測，法性海中親認得。", "隱現時游五藴山（《燈錄》作「隱顯常游五藴中」），內外光明大神力。", "此珠無狀非大小，晝夜圓明悉能照。", "（《燈錄》作「此珠非大亦非小，晝夜光明皆悉照」。", "）用時無處復無蹤（《燈錄》作「覓時無物又無蹤」），行住（《燈錄》作「起坐」）相隨常了了。", "先聖相傳相指授，信此珠人世希有。", "智者號明不離珠，迷人將珠不識走。", "（以上四句，《傳燈錄》作「黃帝曾遊于赤水，爭聽爭求都不遂。", "罔像無心却得珠，能見能聞是虛僞。", "」）吾師權指喻摩尼，採人無數入（《燈錄》作「溺」）春池。", "爭拈瓦礫將爲寶，智者安然而得之。", "言下非近亦非遠（《燈錄》作「森羅萬象光中現」），體用如如轉無轉。", "萬機珠對（《燈錄》作「消遣」）寸心中，一切時中巧方便。", "皇帝曾遊於赤水，視聽爭求都不遂。", "罔像無心却得珠，能見能聞是虛僞。", "非自心，非因緣，妙中之妙玄中玄。", "森羅萬像光中現，尋之不見有根源。", "（《燈錄》無以上九句）燒六賊（《宗鏡錄》卷七六「賊」下有「兮」字），爍四（《燈錄》作「衆」）魔，能摧我山（《宗鏡錄》作「摧我山兮」）竭愛（《燈錄》作「我」）河。", "龍女靈山親獻佛，貧兒衣裏幾（《宗鏡錄》作「枉」，《燈錄》作「下任」）蹉{趷右下爲也}。", "亦非性，亦非心（《燈錄》二「非」字皆作「名」），非性非心超古今。", "體絕名言名不得（《燈錄》作「全體明時明不得」），權時題作《弄珠吟》。", "（以上皆見影印日本花園大學圖書館藏高麗覆刻本南唐招慶寺靜筠二僧著《祖堂集》卷四）。"]'),
('3adcc3ac-7ed9-4bf8-afc9-478b09a3edf4','過施水庵','李諤','唐','唐诗','tang','','[]','勝地開闌若，幽尋信短筇。',80,'全唐诗/poet.tang.53000.json','["勝地開闌若，幽尋信短筇。", "僧貧祇施水，客至但聞鐘。", "講坐天花滿，香臺翠靄重。", "何當謝塵紱，白社此相從。", "（見明李培等萬曆十四年修《秀水縣志》卷八、《檇李詩繫》卷三七）。"]'),
('f9e6826e-db80-4654-95d4-3ee2876b079a','白烏呈瑞賦附歌','孟簡','唐','唐诗','tang','','[]','素德式昭兮何寫奕，玄質從化兮爲潔白。',47,'全唐诗/poet.tang.53000.json','["素德式昭兮何寫奕，玄質從化兮爲潔白。", "符仁孝兮叶佳冊，見祥瑞兮流聖澤。", "（見《文苑英華》卷八九）。"]'),
('5f27adc0-0d2c-4bb7-b917-3c9225be6cc1','謁禹廟','孟簡','唐','唐诗','tang','','[]','九土昔淪墊，八方抱殷憂。',232,'全唐诗/poet.tang.53000.json','["九土昔淪墊，八方抱殷憂。", "哲王受《洪範》，羣物承天休。", "源委有所在，勤勞會東州。", "稽山何峻極，清廟居上頭。", "律度非外事，辛壬寧少留。", "歌謠自不去，覆載將何求？", "靈長表遠績，經啓蒙宏猷。", "孰敢備佐命，天吳與陽侯。", "玄功餘玉帛，茂實結松楸。", "蓋影庇風雨，湖光搖冕旒。", "質明簫鼓作，通昔禮容脩。", "騂牢設舊物，洿水配庶羞。", "深沈本建極，傲很亦思柔。", "陰怪尚奔走，靈徒如獻酬。", "怳疑仙駕動，靜見宿雲收。", "竹樹依積潤，菰蒲託清流。", "謬茲領百越，忽復歷三秋。", "丹懇諒可薦，庶幾無年尤。", "（見《會稽掇英總集》卷八）。"]'),
('4cf3bb3d-b449-49ed-9400-61f9629c7eef','臨蒸諸葛亮宅（題擬）','蔣防','唐','唐诗','tang','','[]','始有諸葛翁，柯亭寄翠靄。',29,'全唐诗/poet.tang.53000.json','["始有諸葛翁，柯亭寄翠靄。", "（見《輿地紀勝》卷五五《衡州》）。"]'),
('606ed089-ce9f-459b-a513-bb4fc2e52cbf','太常寺觀舞聖壽樂','徐元弼','唐','唐诗','tang','','[]','舞字傳新慶，人文邁舊章。',117,'全唐诗/poet.tang.53000.json','["舞字傳新慶，人文邁舊章。", "冲融和氣洽，悠遠聖功長。", "盛德流無外，時時樂未央。", "日華增顧眄，風物助低昂。", "翥鳳方齊首，高鴻忽繼行。", "雲門與茲曲，同是奉陶唐。", "（《文苑英華》卷一八四）（按：《全唐詩》卷七八一誤以作者爲徐元鼎，無事跡，今改正重錄。", "）。"]'),
('bc507994-aa97-4958-b4d0-d2eccc6be598','登石傘峰（幷序）','陳諫','唐','唐诗','tang','','[]','賢相昔未遇，耶溪藏臥龍。',158,'全唐诗/poet.tang.53000.json','["賢相昔未遇，耶溪藏臥龍。", "宛然東山居，已韻西林鐘。", "仲氏亦遐曠，爾來習高蹤。", "楊公偶閒暇，中貴同遊從。", "曲渚擁騶馭，迴潭轉艨艟。", "既登寅緣岸，遂踐岧嶤峰。", "徑側縈巨石，磴危攀茂松。", "傘開自羅列，笥閉誰箴封？", "迥立霄漢表，俯看嚴嶂重。", "遠村暮杳杳，秋海晴溶溶。", "染翰紀勝絕，飛觴暢心胸。", "仍聞待新月，歸櫂何從容。", "（見《會稽掇英總集》卷四）。"]'),
('fafcd344-a74f-4b79-84c0-15d3d6f51fb9','題京兆大興善寺釋南素院','玄幽','唐','唐诗','tang','','[]','三萬蓮經三十春，半生不踏院門塵。',78,'全唐诗/poet.tang.53000.json','["三萬蓮經三十春，半生不踏院門塵。", "（見《宋高僧傳》卷二五。", "又見《酉陽雜俎續集》卷五）（按：《全唐詩》卷八五一錄二句，僅題作《逸句》，作者亦缺事跡，今重錄。", "）。"]'),
('400be168-382c-43da-a86b-aeedce8d038c','送李愿歸盤谷歌','韓愈','唐','唐诗','tang','','[]','盤之中，維子之宮；盤之土，維子之稼；盤之泉，可濯可沿；盤之阻，誰爭子所！窈而深，廓其有容；繚而曲，如往而復。',159,'全唐诗/poet.tang.53000.json','["盤之中，維子之宮；盤之土，維子之稼；盤之泉，可濯可沿；盤之阻，誰爭子所！窈而深，廓其有容；繚而曲，如往而復。", "嗟盤之樂兮樂且無央，虎豹遠跡兮蛟龍遁藏，鬼神守護兮呵禁不祥，飲且食兮壽而康，無不足兮奚所望！膏吾車兮秣吾馬，從子於盤兮終吾生以徜徉！（《四部叢刊》影元刻本《朱文公校昌黎先生集》卷十九《送李愿歸盤谷序》附此歌）。"]'),
('b56c9ed7-af9b-4f63-bf6e-d694ea59d337','袁氏先廟碑附詩','韓愈','唐','唐诗','tang','','[]','袁自陳分，初尚蹇連（方云：作「連連」）。',305,'全唐诗/poet.tang.53000.json','["袁自陳分，初尚蹇連（方云：作「連連」）。", "越秦造漢，博士發論。", "司徒任德，忍不錮人。", "收功厥後，五公重尊。", "晉氏于南，來處華下。", "鴻臚、孝侯，用適操捨。", "南州勤治，取最不懈。", "當陽耽經，唯義之畏。", "石州烈烈，學專春秋。", "懿哉咸寧，不名一休。", "趨難避成，與時泛浮。", "是生孝子，天子之宰，出把（或作「祀」、或作「持」）將符，羣（或作「郡」）州承楷。", "數（或作「教」）以立廟，祿以備器。", "由曾及考，同堂異置。", "栢版松楹，其筵（或作「業」）肆肆。", "維袁之廟，孝孫之爲。", "順勢即宜，以諏以龜。", "以平其巇，屋牆持持。", "孝孫來享，來拜廟庭。", "陟堂進室，親登籩鉶。", "肩臑胉骼，其樽玄清。", "降登受胙，于慶爾（方作「示」，非是）成。", "維曾維祖，維考之施。", "于汝孝嗣，以報以祗。"]'),
('0a49feac-2823-4bf7-93df-0a13b028f497','南海神廟碑附詩','韓愈','唐','唐诗','tang','','[]','南海陰（或作「之」）墟，祝融之宅，即祀于旁。',316,'全唐诗/poet.tang.53000.json','["南海陰（或作「之」）墟，祝融之宅，即祀于旁。", "帝命南伯：「吏惰不躬，正自令公，明用享錫，右（《唐文粹》作「祐」）我家邦。", "」惟明天子，惟慎厥使，我公在官，神人致喜。", "海嶺之陬，既足既濡，胡不均弘，俾執事樞。", "公行勿遲，公無遽歸。", "匪我私公，神人具依。", "（同前書卷三一，校以《唐文粹》卷五十所錄示）（〖1〗清陸耀遹《金石續編》卷七據石刻錄此碑，題作《南海廣利王碑》，云碑在廣州府，元和十五陳諫書。", "按：就常理言，碑末所附韻文或稱銘，或稱頌，稱詩者較少見。", "然韓愈性好奇，碑末附詩，不止一見。", "碑文云：「咸願刻廟石以著厥美而繫以詩。", "乃作詩曰〖略〗。", "」各本《韓集》、清人所錄石刻、《文苑英華》卷八七九、《唐文粹》等所載碑文，均作詩而不作銘，故仍錄出之。", "）。"]'),
('1bcbe334-71c8-42da-92b0-502ea0941261','處州孔子廟碑附詩','韓愈','唐','唐诗','tang','','[]','惟此廟學，鄴侯所作。',152,'全唐诗/poet.tang.53000.json','["惟此廟學，鄴侯所作。", "厥初庳下，神不以宇。", "生（《唐文粹》作「先」）師所處，亦窘寒暑。", "乃新斯宮，神降其獻。", "講讀有常，不誡用勸。", "揭揭元[哲]（誓），有師之尊。", "羣聖嚴嚴，大法以存。", "像圖孔肖，咸在斯堂。", "以瞻以儀，俾不[或]（惑）忘。", "後之君子，無廢成美。", "琢詞碑石，以贊攸始。", "（同前書卷三一。", "據《唐文粹》卷五一校改）。"]'),
('eaef090a-c731-44fb-8d03-829ed9237e25','柳州羅池廟詩（題擬）','韓愈','唐','唐诗','tang','','[]','荔子丹兮蕉黃（「蕉」下或有「葉」字，或有「子」字），雜肴蔬兮進侯堂。',617,'全唐诗/poet.tang.53000.json','["荔子丹兮蕉黃（「蕉」下或有「葉」字，或有「子」字），雜肴蔬兮進侯堂。", "侯之船兮兩旗，度中流兮風泊之，待侯不來兮不知我悲。", "侯乘駒兮入廟，慰我民兮不嚬以笑。", "鵝之山兮柳之水，桂樹團團兮白石齒齒。", "侯朝出遊兮暮來歸，春與猿吟兮秋鶴與飛。", "（《唐文粹》及歐陽修所見《韓集》均作「秋與鶴飛」。", "《集古錄跋尾》卷八錄碑文作「秋鶴與飛」，歐疑碑文有誤。", "沈括《夢溪筆談》卷十四以爲此用《楚辭》相錯成文格，今從其說。", "）北方之人兮爲侯是非，千秋萬歲兮侯無我違。", "福我兮壽我，驅厲鬼兮山之左。", "下無濕兮高無乾，秔稌充羨兮蛇蛟結蟠。", "我民報事兮無怠其始，自今兮欽于世世。", "（同前書卷三一、《唐文粹》卷五二《柳州羅池廟碑》附）（〖1〗《柳州羅池廟碑》云：「三年孟秋辛卯，侯降于州之後堂，歐陽翼等見而拜之。", "其夕，夢翼而告之曰：『館我於羅池。", "』其日景辰，廟成，大祭。", "過客李儀醉酒，慢侮堂上，得疾，扶出廟門即死。", "明年春，魏忠、歐陽翼使謝寧來京師，請書其事于石。", "余謂柳侯生能澤其民，死能驚動禍福之，以食其土，可謂靈也已。", "作迎享送神詩遺柳民，俾歌以祀焉而幷刻之。", "……其詞曰〖詞略〗。", "」《湖南通志·金石》六著錄嘉定刻此碑，題作《唐羅池廟享神詞碑》，附魏紹芳跋此爲享神詩。", "《唐詩別裁集》卷七收入。", "朱東潤師主編《中國歷代文學作品選》中編第一冊收此詩，題作《柳州羅池廟詩》，解題云：「此廟建成後，韓愈爲撰《柳州羅池廟碑》，詩就附在碑文的後面。", "詩效《楚辭·九歌》體，作爲祭祀中迎神、送神時歌唱之用。"]'),
('2ccdef67-d539-4b6c-b7e7-1da6645d9de0','唐故江南西道觀察使中大夫洪州刺史兼御史中丞上柱國賜紫金魚袋贈左散騎常侍太原王公神道碑銘附詩','韓愈','唐','唐诗','tang','','[]','生人之治，本乎斯文。',397,'全唐诗/poet.tang.53000.json','["生人之治，本乎斯文。", "有事其末，而忘其源，切近昧陋，道由是堙。", "有志其本，而泥古陳，當用而迂，乖戾不伸。", "較是二者，其過也均。", "其美王公，志儒之本，達士之經。", "秩秩而積，涵涵而停。", "韡爲華英（一作「英華」），不矜不盈。", "孰播其馨？孰發其明？介然而居，士友以傾。", "敷文帝階，擢列侍從，以忠遠名，有直有諷。", "辨遏堅（或作「聖」）懇，巨邪不用。", "秀出班行，乃動帝目。", "帝省竭心，恩顧日渥。", "翔于郎署，鶱于禁密。", "發帝之令，簡古而蔚。", "不比于權，以直友冤，敲撼挫揠，竟遭斥奔。", "久淹于外，歷守大藩。", "所至極思，必悉利病，萎枯以膏，燠暍（或作「暘」）以醒，坦之敞之，必絕其徑，浚之詠之，使安其泳。", "帝思其文，復命掌誥。", "公潛謂人：「此職宜少，豈無凋郡，庸以自效。", "」上藉（或作「籍」）其實，俾統于洪。", "逋滯攸除，姦訛革風，祛蔽于目，釋負于躬。", "方乎（或作「平」）所部，禁絕浮屠。", "風雨順易，秔稻盈疇。", "人得其所（或作「饒」），乃恬乃謳（或作「謠」）。"]'),
('21184d89-cfe5-43f2-8535-a7c03af1f87d','曹成王碑附詩','韓愈','唐','唐诗','tang','','[]','太支十三，曹於弟季。',159,'全唐诗/poet.tang.53000.json','["太支十三，曹於弟季。", "或亡或微，曹始就事。", "曹之祖王，畏塞絕遷。", "零王黎公，不聞僅存。", "子父易封，三王守名。", "延延百載，以有成王。", "成王之作，一自其躬。", "文被明章，武薦畯功。", "蘇枯弱彊，齦其姦猖。", "以報於宗，以昭於王。", "王亦有子，處王之所，唯舊之視，蹶蹶陛陛。", "實取實似，刻詩其碑，爲示無止。", "（同前書卷二八）（按：碑云：「乃序而詩之。", "」）。"]'),
('2984e222-5b2e-4fdc-b3b4-1b68d9f5c0d7','遊祝融峯','韓愈','唐','唐诗','tang','','["\u8861\u5c71"]','祝融萬丈拔地起，欲見不見輕烟裏。',110,'全唐诗/poet.tang.53000.json','["祝融萬丈拔地起，欲見不見輕烟裏。", "山翁愛山不肯歸，愛山醉眠山根底。", "山童尋着不敢驚，沉吟爲怕山翁嗔。", "夢迴抖擻下山去，一徑蘿月松風清。", "（嘉靖《衡山府志》卷二。", "陶敏先生錄示此詩，幷云：「此詩風格不類韓詩，疑僞，姑錄以存疑。", "」）。"]'),
('1455f0de-369f-46f1-8903-9b0fbca47b93','題西白澗','韓愈','唐','唐诗','tang','','[]','太行之下清且淺，一水盤桓紆山轉。',301,'全唐诗/poet.tang.53000.json','["太行之下清且淺，一水盤桓紆山轉。", "千峰萬壑不可數，異草幽花幾曾見。", "波中白日隱出明，風翻不動浮雲輕。", "翠巒玉女下雙鶴，笑倚秋練開新晴。", "又疑武陵溪上原，桃花溪盡空潺湲。", "幽泉間復逗嵒側，噴珠潄玉相交喧。", "羣猿見之走絕壁，緣峰虛梯弗勞力。", "鳴禽迴面背人飛，爲是從來不相識。", "杖藜因貪仰面看，礙石牽蘿錯移屐。", "路窮屈曲疑欲回，迤邐屏開一重碧。", "殘樽遇坐酒即傾，旋摘山菓都無名。", "題詩且欲盡佳句，能歌翻詠仙難成。", "天門幽深十里西，無奈落日催人歸。", "誰能可屬天宮事，爲我乞取須臾期。", "上天無梯日不顧，牢落歸來壇未暮。", "閉門下馬一衾寒，夢想魂馳在何處。", "（見《古今圖書集成·山川典》卷四八《太行山部》、乾隆廿四年刊蕭應植纂《濟源縣志》卷十六）。"]'),
('972e5ce7-adee-475e-9d7c-d50e7c85b2a9','別韓湘（附存）','韓愈','唐','唐诗','tang','','[]','未爲世用古來多，如子雄文世孰過。',93,'全唐诗/poet.tang.53000.json','["未爲世用古來多，如子雄文世孰過。", "好待功成身退後，却抽身去臥煙蘿。", "（見《青瑣高議別集》卷四）（按：此詩似出後人僞託。", "然韓湘仙事，始於唐時，此詩爲唐人或宋人作，今已無從辨明，姑錄存於此。", "）。"]'),
('b8cdc1b0-af9a-4fa7-af69-43814d12e1c3','題遊息洞（題擬）','韓愈','唐','唐诗','tang','','[]','所樂非吾獨，人人共此情。',87,'全唐诗/poet.tang.53000.json','["所樂非吾獨，人人共此情。", "往來三伏裏，試酌一泓清。", "（見民國廿七年刊朱汝珍纂《陽山縣志》卷十七《金石》）（按：《陽山縣志》錄《陸志》云：「右詩字大一寸五分，在遊息洞口石壁。", "」）。"]'),
('7896449d-b347-4fee-ac6e-6d1a3ad1d1eb','歌行一首','法藏','唐','唐诗','tang','','[]','古人重義不重金，曲高和寡勿（《宗鏡錄》、《偈頌》作「無」）知音。',730,'全唐诗/poet.tang.53000.json','["古人重義不重金，曲高和寡勿（《宗鏡錄》、《偈頌》作「無」）知音。", "今時志（《宗鏡錄》、《偈頌》作「學」）士還如此，語默動用跡難尋。", "所嗟世上歧路者，終日崎嶇狂（《宗鏡錄》、《偈頌》作「枉」）用心。", "平坦旃檀不肯收，要須登險（《宗鏡錄》作「陟」）訪椿林。", "窮子捨父遠逃逝，却於本舍絕知音。", "貧女宅中無價寶，却將秤賣他人（《宗鏡錄》、《偈頌》作「小秤買他」）金。", "心無相，用還（《偈頌》作「能」）深，無常境界不能侵。", "運用能隨高與下，靈光且（《偈頌》作「元」）不是浮沉。", "無相無（《偈頌》、《宗鏡錄》無此字）心能運曜，應聲應色隨方照。", "雖在方而不在方，任運高低總能妙。", "亦（《偈頌》、《宗鏡錄》作「尋」）無頭，復無尾，靈（《偈頌》、《宗鏡錄》作「焰」）光運運從何起？", "只今起者便是心（《偈頌》、《宗鏡錄》作「祇者如今全是心」），心用明時更何你（《偈頌》、《宗鏡錄》作「心用明心心復爾」）。", "不居方，無（一作「何」）處覓，運用無蹤復無跡。", "識取如今明覓（《偈頌》作「密」）人，終朝莫慢（《偈頌》作「漫」，《宗鏡錄》作「謾」）別求的。", "懃（《宗鏡錄》作「勸」）心學，近藂林，莫將病眼認花針。", "說教本窮無相理，廣讀元來不識心。", "了（《偈頌》、《宗鏡錄》作「識」）取心，識（《偈頌》、《宗鏡錄》作「了」）取境，了心識境（《偈頌》、《宗鏡錄》作「識心了境」）禪河淨。", "但（《宗鏡錄》作「若」，《偈頌》作「知」）能了境便識心，萬法都如闥婆影。", "勸且學，莫爲師，不用登高向下窺。", "平源不用金剛鑽，劍刃之中錯下錐。", "向前來，莫人我，山僧有曲無人和。", "了空無相即法師（《偈頌》作「了境心空即法王」），不用綾羅將作幡（《偈頌》作「爲播」）。", "可中了，大希奇，大人幽邃不思議。", "（《偈頌》三句作「大幽邃，不思議，可中學得大希奇」）。"]'),
('a82dd98f-215e-44db-aa6f-9a32caed5b6f','濾水羅賦附歌','白行簡','唐','唐诗','tang','','[]','玉巵無當兮安可擬，風飄有聲兮不足比。',48,'全唐诗/poet.tang.53000.json','["玉巵無當兮安可擬，風飄有聲兮不足比。", "惟濾羅之用也大哉，故去此而取彼。", "（見《文苑英華》卷一一○）。"]'),
('a432674b-f1fd-434d-9b87-c6916ae4c8a2','見杭州烏窠和尚後作（題擬）','白行簡','唐','唐诗','tang','','[]','白頭居士對禪師，正是楞嚴三昧時。',43,'全唐诗/poet.tang.53000.json','["白頭居士對禪師，正是楞嚴三昧時。", "一物也無百味足，恒沙能有幾人知？", "（見《祖堂集》卷三）。"]'),
('0d6e4be2-4076-4992-910d-2e548f625d92','登石傘峰','衛中行','唐','唐诗','tang','','[]','威鳳昔未起，茲山嘉氣深。',158,'全唐诗/poet.tang.53000.json','["威鳳昔未起，茲山嘉氣深。", "逶迤抱川阜，蘿蔦方沈沈。", "龍節稍巖徑，星軒伴幽尋。", "嘗聞謝公事，今嘉昭曠心。", "絕頂上巍峨，秋晨好登臨。", "蘆洲辨微色，天籟聞虛吟。", "支策睇歸湖，舒情凝遠岑。", "徘徊繞靈傘，登坐延芳襟。", "溪路鏁重扃，松門交翠陰。", "貞姿在空谷，瑞色仍棲林。", "晚靄覆迴汀，輕橈環碧潯。", "探奇幸陪唱，願繼咸池音。", "（見《會稽掇英總集》卷四）。"]'),
('4634aecd-e198-4b0a-b020-2997508f0083','贈白使君樂天（題擬）','次休','唐','唐诗','tang','','[]','聞有餘霞千萬首，何妨一句乞閒人。',40,'全唐诗/poet.tang.53000.json','["聞有餘霞千萬首，何妨一句乞閒人。", "（見《白氏長慶集》卷二四《答次休上人》題注引）。"]'),
('611ec8dd-6e4f-47a6-8bf2-f0f730bd2fa7','及第後返閉戶窮（下缺）','歐陽袞','唐','唐诗','tang','','[]','爲學心雖滿，知君如掩扉。',25,'全唐诗/poet.tang.53000.json','["爲學心雖滿，知君如掩扉。", "（見《吟窗雜錄》卷四四）。"]'),
('6d0b3e5b-a67c-4bb0-bfd2-40ec3e22c2de','范忠韓喜得劉先生詩','劉叉','唐','唐诗','tang','','[]','玉尺沈埋久，得之銘篆深。',43,'全唐诗/poet.tang.53000.json','["玉尺沈埋久，得之銘篆深。", "指磨露正色，扣擊吐哀音。", "（《後村詩話續集》卷二引《劉叉集》）。"]'),
('c6f64e69-ee41-4c39-838d-fe417f154e39','暑中即事','孔仲良','唐','唐诗','tang','','[]','雲起松關作遠山，一庭細草未曾刪。',45,'全唐诗/poet.tang.53000.json','["雲起松關作遠山，一庭細草未曾刪。", "吏書抱去琴聲靜，驄使何須采下艱。", "（《莆風清籟集》卷五七）。"]'),
('11a6acf6-d766-443e-b86e-64b94f3fa8dd','','薛昌朝','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.53000.json','["。"]'),
('d31f92e5-c5fc-4401-bf9e-c01611d8495c','紫閣','薛昌朝','唐','唐诗','tang','','[]','閣下寒溪漲碧湍，閣前蒼翠數峯環。',87,'全唐诗/poet.tang.53000.json','["閣下寒溪漲碧湍，閣前蒼翠數峯環。", "危梯續蹬穿松外，細竹分泉落石間（卷九作「前」）。", "好鳥啁啾爭喚客，亂雲開合巧藏山。", "獨來應爲禪僧笑，少有人能伴我閑。", "（《類編長安志》卷三、卷九）。"]'),
('4a5e4dbc-93c9-44dc-9652-ed00d4830e2c','同觀察使張公仲方大和元年夏禱雨歸至聖泉寺作（題擬）','李敬彝','唐','唐诗','tang','','[]','雨隨青嶂合，雲拂畫旗來。',85,'全唐诗/poet.tang.53000.json','["雨隨青嶂合，雲拂畫旗來。", "（見《淳熙三山志》卷八、《閩都記》卷十一）（〖1〗《淳熙三山志》云：「今詩牌在聖泉。", "」同作者爲張仲方、李貽孫、彭城三人，《全唐詩》僅收仲方詩。", "）。"]'),
('c803a9b4-3e34-49cd-848d-841bee579ff1','同觀察使張公仲方大和元年夏禱雨歸至聖泉寺作','彭城','唐','唐诗','tang','','[]','雲陰隨雨度，桂馥逐風來。',17,'全唐诗/poet.tang.53000.json','["雲陰隨雨度，桂馥逐風來。", "（同前）。"]'),
('bead88f9-a9d4-4e54-a773-4a4589d9073a','宿猿洞','徐凝','唐','唐诗','tang','','[]','萬屋人家雲閣下，一屏煙水石橋西。',34,'全唐诗/poet.tang.53000.json','["萬屋人家雲閣下，一屏煙水石橋西。", "（見《輿地紀勝》卷一二八《福州》）。"]'),
('da30a4ad-7ae6-4326-ab13-63d7eca80475','題瀑布詩三首 一','王師閔','唐','唐诗','tang','','[]','殷勤[對]綠醽，閑坐繞沙[汀]。',41,'全唐诗/poet.tang.53000.json','["殷勤[對]綠醽，閑坐繞沙[汀]。", "怪來喧語笑，一派落青屏。", "（缺字據《永樂大典》補）。"]'),
('08ead037-48e5-4913-b677-cc242a81584f','題瀑布詩三首 二','王師閔','唐','唐诗','tang','','[]','嵌崆（《輿地紀勝》作「空」）石洞古，飄灑玉泉吐。',36,'全唐诗/poet.tang.53000.json','["嵌崆（《輿地紀勝》作「空」）石洞古，飄灑玉泉吐。", "飛流勢不定，散作松間雨。"]'),
('3f098f6e-dab8-46fe-b6bb-921342f9d9eb','題瀑布詩三首 三','王師閔','唐','唐诗','tang','','[]','清明雲日開，山路足莓苔。',331,'全唐诗/poet.tang.53000.json','["清明雲日開，山路足莓苔。", "瀑溜千尋落，乘閑一看來。", "（見劉喜海《金石苑》卷二。", "《輿地紀勝》卷一五七《資州》錄第二首。", "張忱石先生告：《永樂大典》卷九七六六引《成都府志》錄第一首，今據以校補。", "）（〖1〗《金石苑》云：「高約二尺，廣三尺六寸，十二行，行七字，字徑寸餘至二寸不等。", "正書。", "下端石殘缺。", "」石刻題下署：「資□刺史王師閔。", "」末署：「大和二年正月七日。", "」〖2〗劉喜海跋云：「右詩刻在資州。", "此西巖龍潭瀑布詩也，見王象之《碑目》。", "王師閔爲資州刺史，史失載。", "」〖3〗《輿地紀勝》云：「唐王師閔守資中，政有能聲。", "嘗游西巖，留《瀑布詩》於石壁。", "其一曰〖錄第二首，略〗。", "」按：據《輿地紀勝》及《永樂大典》所錄詩，知石刻除稍有漫漶外，大致完整。", "《金石苑》謂「下端石殘缺」，未允。", "）。"]'),
('a1b18f20-e709-4ec9-b9d5-0b479ed6958e','謝人送鯽魚鱠','楊巨源','唐','唐诗','tang','','[]','君家一筯萬錢𢬵，分我銀絲侑客歡。',82,'全唐诗/poet.tang.53000.json','["君家一筯萬錢𢬵，分我銀絲侑客歡。", "芳餌得來珍丙穴，金刀落處照辛盤。", "腹空羞迫詩肩瘦，鱗活能生酒面寒。", "玉手行廚如許巧，說教魚婢學應難。", "（影印本《詩淵》第一冊第一一三頁）。"]'),
('703dafdf-761a-4cc8-a12a-d363fc468ab5','謝人送粽','楊巨源','唐','唐诗','tang','','[]','來時三月春猶在，到日端陽節又臨。',42,'全唐诗/poet.tang.53000.json','["來時三月春猶在，到日端陽節又臨。", "珍重主人意勤腆，滿槃角黍細包金。", "（同前第一五六頁）。"]'),
('9a9a79ca-3381-4318-b8aa-582cd13d0686','別薛柳二員外','楊巨源','唐','唐诗','tang','','[]','江上月明胡雁過，淮南木落楚山多。',35,'全唐诗/poet.tang.53000.json','["江上月明胡雁過，淮南木落楚山多。", "（《千載佳句》卷上《四時部·暮秋》）。"]'),
('84db1bf0-0201-4d06-b77f-541a5fae140e','太原寒食觀仗上嚴司空','楊巨源','唐','唐诗','tang','','[]','天倚王師靜沙漠，年年寒食幷州樂。',72,'全唐诗/poet.tang.53000.json','["天倚王師靜沙漠，年年寒食幷州樂。", "珠華相壓駕重（下缺。", "見上海圖書館藏明抄本《古今歲時雜詠》卷十一，末注：「以下古本缺二頁。", "」《四庫全書》本無。", "）。"]'),
('b343abd3-e591-4021-a017-22f95d9c85c1','贈盧洺州','楊巨源','唐','唐诗','tang','','[]','三刀夢益州，一箭取遼城。',75,'全唐诗/poet.tang.53000.json','["三刀夢益州，一箭取遼城。", "（見《白氏長慶集》卷十五《贈楊秘書巨源》自注）（按：《全唐詩》卷三三三收此二句，缺題，係源出《唐詩紀事》卷三五，今重錄之。", "）。"]'),
('4a4bc504-daaa-49bf-bd5a-e05cc6c33136','句','楊巨源','唐','唐诗','tang','','[]','思出秦雲外，恩生漢水東。',29,'全唐诗/poet.tang.53000.json','["思出秦雲外，恩生漢水東。", "（《輿地紀勝》卷八二《襄陽府》）。"]'),
('4ebac523-db9f-44a0-8b91-e07aa17940ce','秪（疑當作「抵」）剡','韋處厚','唐','唐诗','tang','','[]','秋渚涵容碧，秋水刷眼青。',59,'全唐诗/poet.tang.53000.json','["秋渚涵容碧，秋水刷眼青。", "排頭烟樹老，撲面水風腥。", "上瀨復下瀨，長亭仍短亭。", "夜船明月好，客夢滿流螢。", "（《記纂淵海》卷九）。"]'),
('f4283fcf-ab19-4ef0-a7c9-254c8cc70d51','又','韋處厚','唐','唐诗','tang','','[]','船撑鑑湖月，路指沃洲雲。',17,'全唐诗/poet.tang.53000.json','["船撑鑑湖月，路指沃洲雲。", "（同前）。"]'),
('bf6787ee-1b9f-44d9-b2de-3d369f2f3f38','句','韋處厚','唐','唐诗','tang','','[]','緣崖踏石層。',39,'全唐诗/poet.tang.53000.json','["緣崖踏石層。", "（見李壁《王荆文公詩箋注》卷三十《次韻吳季野題岳上人澄心亭》引）。"]'),
('9933a8ea-a39c-4b88-9d62-3a6b08acfd96','曜日頌','惟儼','唐','唐诗','tang','','[]','遍身烘爛更何人？臥棘森森一智真。',42,'全唐诗/poet.tang.53000.json','["遍身烘爛更何人？臥棘森森一智真。", "爲報你來須體妙，時中不擬宛然新。", "（《祖堂集》卷四）。"]'),
('62adf161-bdc4-4fc7-9637-9087d4376266','李獨攜酒見訪','李涉','唐','唐诗','tang','','[]','曉齋獨坐霜景寒，草堂逸士來相干。',139,'全唐诗/poet.tang.53000.json','["曉齋獨坐霜景寒，草堂逸士來相干。", "風神左峭心意濶。", "自言山中新醖熟，手挈一壺兼一軸。", "果然文字稱儀容，已覺建安風彩俗。", "嗟予潦倒身無成，偶因章句生浮名。", "就中憐愛李景儉，酒狂大語欺奴兵。", "老夫昔逐巴江岸，唱得《竹枝》腸欲斷。", "爲君試發一聲看，九派煙霞愁漫漫。", "（影印本《詩淵》第一冊一三一頁）。"]'),
('4fa1fa68-ce29-40ed-9fc5-291ad34d02c0','贈蘇小','李涉','唐','唐诗','tang','','[]','地人仙人家洛浦，聞道新年年十五。',154,'全唐诗/poet.tang.53000.json','["地人仙人家洛浦，聞道新年年十五。", "巧轉明眸雙劍連，開粧一面千花吐。", "流蘇帳，雲母屏，碧羅作卷花亭亭。", "崑崙阿母暗鈎引，東海麻姑投姓名。", "梭能織詩箏解語，鴛鴦難稱煙波侶。", "偶逢曼倩巧言詞，不覺投花忽相許。", "自言夫婿心不骨，黃金買笑輕侯王。", "掌中看舞腰欲斷，暗裏聽歌愁滿堂。", "莫學爲雲去無跡，巫山高高接天碧。", "（同前第五五一頁）。"]'),
('1401f2ab-6fd5-40ac-bc0d-2a74585423be','商州（題擬）','李涉','唐','唐诗','tang','','[]','宮址蔓生草，洞門低枕泉。',36,'全唐诗/poet.tang.53000.json','["宮址蔓生草，洞門低枕泉。", "廢興人目擊，何處是神仙？", "（《記纂淵海》卷二四）。"]'),
('a8c8f722-fade-4c44-a264-5e4dcf7860bd','遊棲巖寺','李益','唐','唐诗','tang','','[]','晚上梯延洞，通宵興莫窮。',73,'全唐诗/poet.tang.53000.json','["晚上梯延洞，通宵興莫窮。", "高明千嶂月，清爽一巖風。", "坐久衣衫潤，吟餘物象空。", "舉頭星可摘，疑在廣寒宮。", "（見《古今圖書集成·山川典》卷三五《中條山部》）。"]'),
('4ce17904-ffc5-43ce-9e03-5b68c86f504a','詠諸葛亮（題擬）','鄭絪','唐','唐诗','tang','','[]','草廬龍舊臥，花府鳳曾棲。',30,'全唐诗/poet.tang.53000.json','["草廬龍舊臥，花府鳳曾棲。", "（見《輿地紀勝》卷八二《襄陽府》）。"]'),
('26a00696-d734-481c-95bf-5a7325306553','小庭水植率爾成詩','錢徽','唐','唐诗','tang','','["\u957f\u6c5f"]','泓然一缶水，下與㘭堂接。',113,'全唐诗/poet.tang.53000.json','["泓然一缶水，下與㘭堂接。", "青菰八九枝，圓荷四五葉。", "動搖香風至，顧盼野心愜。", "行可採芙蓉，長江詎云涉。", "（見錢仲聯《韓昌黎詩繫年集釋》卷九《奉和錢七兄曹長盆池所植》附）（按：宋方崧卿《韓集舉正》卷三云：「錢徽也。", "唐本具錢詩於前。", "」）。"]'),
('34ce1d75-a527-47c6-9d68-071249ebf061','同樂天登青龍寺上方望藍田山絕句（題擬）','錢徽','唐','唐诗','tang','','[]','偶來上寺因高望，松雪分明見舊山。',48,'全唐诗/poet.tang.53000.json','["偶來上寺因高望，松雪分明見舊山。", "（見《白氏長慶集》卷十一《登龍昌上寺望江南山懷錢舍人》自注引）。"]'),
('44edf6d6-1339-4b32-ad55-c3c1ccbdbba4','題從生假山','薛濤','唐','唐诗','tang','','[]','宅相多能好自持，愛山攢石倚庭陲。',85,'全唐诗/poet.tang.53000.json','["宅相多能好自持，愛山攢石倚庭陲。", "銅梁公阜□□□，□□□□□□□。", "（見北京圖書館藏《分門纂類唐歌詩》宋刻殘本，轉錄自張篷舟《薛濤詩箋·後記》。", "《宛委別藏》本將此詩刪棄。", "）。"]'),
('66a9344c-5075-4057-992b-1bf234c877e5','登石傘峰','楊於陵','唐','唐诗','tang','','[]','夙志慕遐嶠，偶時叨撫封。',158,'全唐诗/poet.tang.53000.json','["夙志慕遐嶠，偶時叨撫封。", "幸茲秋成候，得與心期從。", "宛在洲渚外，稍躋林嶺重。", "紫垣感嘉惠，丹壑暢幽蹤。", "之子綽有裕，結廬枕前峰。", "亭臺互虧蔽，物象分輕濃。", "玉傘踐危石，苔枝棲古松。", "登攀逐羣彥，息偃慙衰容。", "閶闔如可接，靈仙疑暫逢。", "海帆去的的，霜雁來噰噰。", "赫奕護軍重，導迎裨將恭。", "迴舟遲新月，鼙鼓迎疏鐘。", "（見《會稽掇英總集》卷四）。"]'),
('e0d2669a-f307-40dd-93e3-bb1a607c6fde','習家池大堤詩（題擬）','楊於陵','唐','唐诗','tang','','[]','習氏蹤誰寄，羊氏道可躋。',30,'全唐诗/poet.tang.53000.json','["習氏蹤誰寄，羊氏道可躋。", "（見《輿地紀勝》卷八二《襄陽府》）。"]'),
('5b5e9ee9-2aad-4632-aacc-96ff702ef0b7','句','楊於陵','唐','唐诗','tang','','[]','雲歛荆門近，江平峴首低。',46,'全唐诗/poet.tang.53000.json','["雲歛荆門近，江平峴首低。", "（《記纂淵海》卷十二）（按：此二句與前「習氏」二句疑出同一首詩。", "）。"]'),
('145b3d1e-c28e-4e7b-975f-e68410985198','詠陀羅山','張籍','唐','唐诗','tang','','[]','鑿開混沌露元氣，散布森羅彌梵天。',44,'全唐诗/poet.tang.53000.json','["鑿開混沌露元氣，散布森羅彌梵天。", "雲外無時不閒在，樓居何處得超然。", "（《記纂淵海》卷二三）。"]'),
('2c9a2809-eb92-46db-bdea-5c6071efe4f1','夢好梨花歌','王建','唐','唐诗','tang','','[]','薄薄落落霧（別本作「路」）不分，夢中喚作梨花雲。',296,'全唐诗/poet.tang.53000.json','["薄薄落落霧（別本作「路」）不分，夢中喚作梨花雲。", "瑤池水光蓬萊雪，青葉白花相次發。", "不從地上生枝柯，合在天頭遶宮闕。", "天風微微吹不破，白艷却愁香涴露。", "玉房綵女齊看來，錯認仙山鶴飛過。", "落花散粉飄滿空，梨花顏色同不同。", "眼穿臂短取不得，取得亦如從夢中。", "無人爲我解此夢，梨花一曲心珍重。", "（見宋張邦基《墨莊漫錄》卷六）（按：《墨莊漫錄》：「東坡作梅花詞云：『高情已逐曉雲空，不與梨花同夢。", "』注云：『唐王建有《夢看梨花雲詩》。", "』予求王建詩，行世甚少，唯印行本一卷，乃無此篇。", "後得之於晏元獻《類要》中。", "後又得建全集七卷，乃得全篇，題云《夢好梨花歌》。", "〖詩略〗或誤傳爲王昌齡，非也。", "」另參本書卷九王昌齡詩附按。", "）。"]'),
('5d4ab9ea-cbda-4e59-a334-511bb7bc4703','讚碎金','王建','唐','唐诗','tang','','[]','一軸零書則（斯六一九卷作「時」）未多，要來不得（斯六一九卷作「問」）那人何？',107,'全唐诗/poet.tang.53000.json','["一軸零書則（斯六一九卷作「時」）未多，要來不得（斯六一九卷作「問」）那人何？", "從頭至尾無閑字，勝看真（斯六一九卷作「珍」）珠一百螺。", "（見斯六二○四卷《字寶碎金》末附，署「吏部郎中王建」。", "斯六一九卷署「王建郎中」。", "）。"]'),
('b44a084d-e344-44df-b389-dc787b0c3dcb','靈隱寺','盧元輔','唐','唐诗','tang','','[]','長松晉家樹，絕頂客兒亭。',27,'全唐诗/poet.tang.53000.json','["長松晉家樹，絕頂客兒亭。", "（見《淳祐臨安志》殘本卷八）。"]'),
('65e59a5e-22ff-4e8b-9dac-6abe0dc89622','夢遊仙賦附詩 一','沈亞之','唐','唐诗','tang','','[]','白日低兮春塘滿，紅華芳兮草芽短。',32,'全唐诗/poet.tang.53000.json','["白日低兮春塘滿，紅華芳兮草芽短。", "菱結帶兮荇含絲，設遨遊兮遵佳期。"]'),
('c8c0748a-1f6e-4450-abb6-1c0eb6b978b6','夢遊仙賦附詩 二','沈亞之','唐','唐诗','tang','','[]','穠光醉兮，昏緜緜焉。',38,'全唐诗/poet.tang.53000.json','["穠光醉兮，昏緜緜焉。", "與久樂萬年春，留連兮其未央。", "（均見《沈下賢文集》卷一）。"]'),
('02bdd88e-91cf-4845-a993-23dffd5fd146','湘中怨解載鄭生愁吟','沈亞之','唐','唐诗','tang','','[]','情無垠兮蕩洋洋，懷佳期兮屬三湘。',29,'全唐诗/poet.tang.53000.json','["情無垠兮蕩洋洋，懷佳期兮屬三湘。", "（見《沈下賢文集》卷二）。"]'),
('1137cf3c-0588-433a-8e26-2dd4e30a0b93','觀元相公花飲（一作「宴」）','直言','唐','唐诗','tang','','[]','尺八調悲銀字管，琵琶聲送紫檀槽。',94,'全唐诗/poet.tang.53000.json','["尺八調悲銀字管，琵琶聲送紫檀槽。", "（《千載佳句》卷下《宴喜部·管絃》）（按：此詩署「僧直言」。", "同書卷上作「僧直玄」，《和漢朗詠集》卷下作「僧亘玄」，《全唐詩逸》卷中作「真元」。", "未詳孰是。", "）。"]'),
('ddcf0184-5551-4707-8e56-a7599c9dad49','再酬復言和誇州宅','元稹','唐','唐诗','tang','','[]','會稽天下本無儔，任取蘇杭作輩流。',90,'全唐诗/poet.tang.53000.json','["會稽天下本無儔，任取蘇杭作輩流。", "斷髮儀刑千古學，奔濤（一作「騰」）翻動萬人憂。", "石緣類鬼名羅剎，寺爲因墳號虎丘。", "莫著詩章遠牽引，由來北郡似南州。", "（見宋孔延之編《會稽掇英總集》卷一）。"]'),
('23b02d63-237c-476b-98bc-a1de6f2c2651','遊雲門','元稹','唐','唐诗','tang','','[]','遙泉滴滴度更遲，秋夜霜天入竹扉。',40,'全唐诗/poet.tang.53000.json','["遙泉滴滴度更遲，秋夜霜天入竹扉。", "明月自隨山影去，清風長送白雲歸。", "（同前書卷六）。"]'),
('f1b3f154-3006-4ae8-9d7a-c9c19c5785ae','題法華山天衣寺','元稹','唐','唐诗','tang','','[]','馬踏紅塵古塞平，出門誰不爲功名。',40,'全唐诗/poet.tang.53000.json','["馬踏紅塵古塞平，出門誰不爲功名。", "到頭爭似棲禪客，林下無言過一生。", "（同前書卷八）。"]'),
('f7193680-7c8b-4114-9f53-94679d21998d','拜禹廟','元稹','唐','唐诗','tang','','[]','恢能咨岳日，悲慕羽山秋。',205,'全唐诗/poet.tang.53000.json','["恢能咨岳日，悲慕羽山秋。", "父陷功仍繼，君名禮不讎。", "洪水襄陵後，玄圭菲食由。", "已甘魚父子，翻荷粒咽喉。", "古廟蒼煙冷，寒亭翠柏稠。", "馬泥真骨動，龍畫活睛留。", "祀典稽千聖，孫謀絕一丘。", "道雖污世載，恩豈酌沈浮。", "洞穴探常近，圖書即可求。", "德崇人不惰，風在俗斯柔。", "茭色湖光上，泉聲雨脚收。", "歌詩呈志義，簫鼓凟清猷。", "史亦明勳最，時方怒校酋。", "還希四載術，將以拯虔劉。", "（同前）（按：以上四首，卞孝萱《元稹年譜》、冀勤校《元稹集》均出揭出。", "）。"]'),
('34cf8a1c-d01d-4cee-8931-3190ef964898','奉使往蜀路傍見山花吟寄樂天（題擬） 一','元稹','唐','唐诗','tang','','[]','深紅山木艷丹雲，路遠無由摘寄君。',32,'全唐诗/poet.tang.53000.json','["深紅山木艷丹雲，路遠無由摘寄君。", "恰似牡丹如許大，淺深看取石榴裙。"]'),
('5303babc-7d62-4841-bf82-5a0754cccf6b','奉使往蜀路傍見山花吟寄樂天（題擬） 二','元稹','唐','唐诗','tang','','[]','向前已說深紅木，更有輕紅說向君。',65,'全唐诗/poet.tang.53000.json','["向前已說深紅木，更有輕紅說向君。", "深葉淺花何所似，薄妝愁坐碧羅裙。", "（人民文學出版社刊周本淳校點本《詩話總龜》卷二七引《唐賢抒情》）。"]'),
('8b1d9337-94a4-47bd-88e7-a9e871839c3c','封書','元稹','唐','唐诗','tang','','[]','每書題作上都字，悵望關東無限情。',51,'全唐诗/poet.tang.53000.json','["每書題作上都字，悵望關東無限情。", "寂寞此心新雨後，槐花高樹晚蟬聲。", "（《千載佳句》卷上《四時部·早秋》）。"]'),
('925022af-7405-45d7-8395-55a65e1d0e58','春詞','元稹','唐','唐诗','tang','','[]','一雙玉手十三弦，移柱高低落鬢邊。',52,'全唐诗/poet.tang.53000.json','["一雙玉手十三弦，移柱高低落鬢邊。", "即問向來彈了曲，羞人不道《想夫憐》。", "（《千載佳句》卷下《宴喜部·箏》）。"]'),
('cd8ac46f-d5aa-4ae9-9636-78fd0166eb25','詠鶯','元稹','唐','唐诗','tang','','[]','天下金衣侶，還能貺草萊。',59,'全唐诗/poet.tang.53000.json','["天下金衣侶，還能貺草萊。", "風流晉王謝，言語漢鄒枚。", "公等久安在，今絕何處來？", "山禽正嘈雜，慰我日徘徊。", "（《夢梁錄》卷十八）。"]'),
('000e5022-c53c-43d4-8020-175679690fb1','石榴花','元稹','唐','唐诗','tang','','[]','寥落山榴深映葉，紅霞淺帶碧霄雲。',95,'全唐诗/poet.tang.53000.json','["寥落山榴深映葉，紅霞淺帶碧霄雲。", "麴塵枝下年年見，別似衣裳不似裙。", "（《永樂大典》卷八二一引《甕牖閑評》引）（〖1〗以上二詩據《古籍整理出版情況簡報》一六六期刊冀勤同志《元稹佚詩續輯》錄出。", "）。"]'),
('b60f5792-b691-4a6b-a858-f9db017291c7','送晏秀才歸江陵','元稹','唐','唐诗','tang','','[]','長堤纖草河邊綠，近郭新鶯竹裏啼。',35,'全唐诗/poet.tang.53000.json','["長堤纖草河邊綠，近郭新鶯竹裏啼。", "（《千載佳句》卷上《四時部·早春》）。"]'),
('83e3986e-e013-4360-a2d0-b95a4d00eb95','早春書情','元稹','唐','唐诗','tang','','[]','空城月落方知曉，淺水荷香始覺春。',29,'全唐诗/poet.tang.53000.json','["空城月落方知曉，淺水荷香始覺春。", "（同前《四時部·春情》）。"]'),
('1f1b5863-c7bc-4bfe-bfa1-4d878f332865','雨後書情','元稹','唐','唐诗','tang','','[]','溪上懶蒲藏釣艇，窗前新筍長漁竿。',29,'全唐诗/poet.tang.53000.json','["溪上懶蒲藏釣艇，窗前新筍長漁竿。", "（同前《四時部·暮春》）。"]'),
('9b575286-dab3-4ba9-a979-f72b771acf07','雨後感懷','元稹','唐','唐诗','tang','','[]','雲際日光分萬井，煙消山色露千峰。',29,'全唐诗/poet.tang.53000.json','["雲際日光分萬井，煙消山色露千峰。", "（同前《天象部·晴霽》）。"]'),
