('4a466a56-a0ad-4e65-9b7d-9ea02b668efb','崔徽歌 一','元稹','唐','唐诗','tang','','[]','崔徽本不是娼家，教歌按舞娼家長。',32,'全唐诗/poet.tang.53000.json','["崔徽本不是娼家，教歌按舞娼家長。", "使君知有不自由，坐在顯時立在掌。"]'),
('0eef3043-363b-46b9-8c6c-dc54353f5c53','崔徽歌 二','元稹','唐','唐诗','tang','','[]','有客有客名丘夏，善寫儀容得艷姿。',80,'全唐诗/poet.tang.53000.json','["有客有客名丘夏，善寫儀容得艷姿。", "爲徽持此寄敬中，以死報郎爲終始。", "（以上見《綠窗新話》卷上）（按：《全唐詩》卷四二三收以上二節，有缺誤，又誤連作一首，今重錄。", "）。"]'),
('fd36d087-f11b-4ff7-90cc-50bd413010f4','崔徽歌 三','元稹','唐','唐诗','tang','','[]','眼明正似琉璃瓶，心蕩秋水橫波清。',42,'全唐诗/poet.tang.53000.json','["眼明正似琉璃瓶，心蕩秋水橫波清。", "（見施元之等《注東坡先生詩》卷十五《百步洪》注引）。"]'),
('37e506de-dbc8-46d0-9fda-2b661b028150','崔徽歌 四','元稹','唐','唐诗','tang','','[]','吏感徽心關鎖開。',75,'全唐诗/poet.tang.53000.json','["吏感徽心關鎖開。", "（見任淵《山谷詩注》卷九《出禮部試院王才元惠梅花三種皆妙絕戲答三首》注引）（按：以上五題皆據冀勤校《元稹集·外集》卷七《續補》一。", "）。"]'),
('c7e75660-2a43-4282-940e-d86084f29494','崔徽歌 五','元稹','唐','唐诗','tang','','[]','鳳凰寶釵爲郎戴。',34,'全唐诗/poet.tang.53000.json','["鳳凰寶釵爲郎戴。", "（見陳元龍《片玉集注》卷二《秋蘂香》注引元微之詩）。"]'),
('5fec5c61-1422-455b-9ff3-6a6e4c3cd13a','崔徽歌 六','元稹','唐','唐诗','tang','','[]','舞態低迷誤招拍。',28,'全唐诗/poet.tang.53000.json','["舞態低迷誤招拍。", "（同前書卷八《蝶戀花》之二注引崔徽詩）。"]'),
('36e575e7-1c74-4e86-b29d-66526f56ea22','崔徽歌 七','元稹','唐','唐诗','tang','','[]','鳳釵亂折金鈿碎。',56,'全唐诗/poet.tang.53000.json','["鳳釵亂折金鈿碎。", "（同前書卷二《憶舊遊》注引元徽之詩）（按：以上三句，《元氏長慶集》不收，似皆《崔徽歌》佚文。", "）。"]'),
('f35303d7-2581-485e-be93-66803dcbb4ec','和浙西李大夫晚下北固山喜松徑成陰悵然懷古偶題臨江亭','元稹','唐','唐诗','tang','','[]','自公鎮南徐，三換營門柳。',58,'全唐诗/poet.tang.53000.json','["自公鎮南徐，三換營門柳。", "（《嘉定鎮江志》卷十四）（按：傅璇琮先生《李德裕年譜》寶曆元年譜錄出二句，詩題亦從傳說。", "）。"]'),
('16947d3c-6d33-4e1f-ae20-ad9501605642','句','元稹','唐','唐诗','tang','','[]','無妙思帝里，不合厭杭州。',34,'全唐诗/poet.tang.53000.json','["無妙思帝里，不合厭杭州。", "（俞文豹《吹劍三錄》。", "此則亦從冀勤同志說）。"]'),
('f2718164-27ca-4bb8-bc8b-2f20f5ceed58','詠廿四氣詩 立春正月節','元稹','唐','唐诗','tang','','[]','春冬移律呂，天地換星霜。',48,'全唐诗/poet.tang.53000.json','["春冬移律呂，天地換星霜。", "間泮游魚躍，和風待柳芳。", "早梅迎雨水，殘雪怯朝陽。", "萬物含新意，同歡聖日長。"]'),
('6098ea5c-d715-44fe-9b40-7ec6d4761e42','詠廿四氣詩 雨水正月中','元稹','唐','唐诗','tang','','[]','雨水洗春容，平田已見龍。',48,'全唐诗/poet.tang.53000.json','["雨水洗春容，平田已見龍。", "祭魚盈浦嶼，歸雁□山峰。", "雲色輕還重，風光淡又濃。", "向春入二月，花色影重重。"]'),
('4a0457b2-c06c-4b05-9f99-84e81f2c64f3','詠廿四氣詩 驚蟄二月節','元稹','唐','唐诗','tang','','[]','陽氣初驚蟄，韶光大（一作「天」）地周。',75,'全唐诗/poet.tang.53000.json','["陽氣初驚蟄，韶光大（一作「天」）地周。", "桃花開蜀錦，鷹老化春（一作「爲」）鳩。", "時候爭催迫，萌芽牙{丿爲丶}（一作「護」）矩修。", "人間務生事，耕種滿田疇。", "。"]'),
('64a527c4-c502-43c9-9e83-7035c1ffaa2f','詠廿四氣詩 春分二月中','元稹','唐','唐诗','tang','','[]','二氣莫交爭，春分雨處行。',48,'全唐诗/poet.tang.53000.json','["二氣莫交爭，春分雨處行。", "雨來看電影，雲過聽雷聲。", "山色連天碧，林花向日明。", "樑間玄鳥語，欲似解人情。"]'),
('d6bf8979-799a-4cc3-9895-26c6bed3bb87','詠廿四氣詩 清明三月節','元稹','唐','唐诗','tang','','[]','清明來向晚，山淥正光華。',56,'全唐诗/poet.tang.53000.json','["清明來向晚，山淥正光華。", "楊柳先飛絮，梧桐續放花。", "鴽聲知化鼠，虹影指天涯。", "已識風雲意，寧愁雨穀（一作「穀雨」）賒。"]'),
('49ca5cb1-857a-4cb0-8682-0a9b6e2deba3','詠廿四氣詩 穀雨春光曉','元稹','唐','唐诗','tang','','[]','穀雨春光曉，山川黛色青。',48,'全唐诗/poet.tang.53000.json','["穀雨春光曉，山川黛色青。", "葉間鳴戴勝，澤水長浮萍。", "暖屋生蠶蟻，喧風引麥葶。", "鳴鳩徒拂羽，信矣不堪聽。"]'),
('741080f2-7dfb-40cb-8bf8-f336f3e05527','詠廿四氣詩 立夏四月節','元稹','唐','唐诗','tang','','[]','欲知春與夏，仲[呂]（侶）啓朱明。',60,'全唐诗/poet.tang.53000.json','["欲知春與夏，仲[呂]（侶）啓朱明。", "蚯蚓誰教出，王苽自合生。", "簾（一作「簇」）蠶呈蠒樣，林鳥哺雛聲。", "漸覺雲峰好，徐徐帶雨行。"]'),
('b774a770-4e4c-44ef-a330-3b1e34be457f','詠廿四氣詩 小滿四月中','元稹','唐','唐诗','tang','','[]','小滿氣全時，如何靡草衰。',54,'全唐诗/poet.tang.53000.json','["小滿氣全時，如何靡草衰。", "田家私黍稷，方伯問蠶絲。", "杏麥修鐮釤，錋苽{下爲爪}竪棘籬。", "向來看苦菜，獨秀也何爲？", "。"]'),
('b99676f3-9508-4056-a22b-f7f123a2721e','詠廿四氣詩 芒種五月節','元稹','唐','唐诗','tang','','[]','芒種看今日，螗螂應節生。',48,'全唐诗/poet.tang.53000.json','["芒種看今日，螗螂應節生。", "彤雲高下影，鷃鳥往來聲。", "淥沼蓮花放，炎風暑雨情。", "相逢問蠶麥，幸得稱人情。"]'),
('21fc31a5-a1de-493c-98d6-5b0fe8b2c379','詠廿四氣詩 夏至五月中','元稹','唐','唐诗','tang','','[]','處處聞蟬響，須知五月中。',48,'全唐诗/poet.tang.53000.json','["處處聞蟬響，須知五月中。", "龍潛淥水坑，火助太陽宮。", "過雨頻飛電，行雲屢帶虹。", "蕤賓移去後，二氣各西東。"]'),
('dee2c6e2-11fd-4893-8c00-11be94308e97','詠廿四氣詩 小暑六月節','元稹','唐','唐诗','tang','','[]','倏忽溫風至，因循小暑來。',48,'全唐诗/poet.tang.53000.json','["倏忽溫風至，因循小暑來。", "竹喧先覺雨，山暗已聞雷。", "戶牖深青靄，階庭長綠苔。", "鷹鸇新習學，蟋蟀莫相催。"]'),
('6f757815-c2c7-4ea3-adca-8ee5ee78d7bb','詠廿四氣詩 大暑六月中','元稹','唐','唐诗','tang','','[]','大暑三秋近，林鐘九夏移。',48,'全唐诗/poet.tang.53000.json','["大暑三秋近，林鐘九夏移。", "桂輪開子夜，螢火照空時。", "苽菓邀儒客，菰蒲長墨池。", "絳紗渾卷上，經史待風吹。"]'),
('8e57fffd-020a-4abf-ad38-1d0718d93fe0','詠廿四氣詩 立秋七月節','元稹','唐','唐诗','tang','','[]','不期朱夏盡，涼吹暗迎秋。',36,'全唐诗/poet.tang.53000.json','["不期朱夏盡，涼吹暗迎秋。", "天漢成橋鵲，星娥會玉樓。", "寒聲喧耳外，白露滴林頭。"]'),
('f62c486f-70ce-436f-8ec8-df42d55c5b17','詠廿四氣詩 處暑七月中','元稹','唐','唐诗','tang','','[]','向來鷹祭鳥，漸覺白藏深。',48,'全唐诗/poet.tang.53000.json','["向來鷹祭鳥，漸覺白藏深。", "葉下空驚吹，天高不見心。", "氣收禾黍熟，風靜草蟲吟。", "緩酌罇中酒，容調膝上琴。"]'),
('42d0a2f0-257e-462a-af6b-4d07a7d3cbd6','詠廿四氣詩 白露八月節','元稹','唐','唐诗','tang','','[]','露霑蔬草白，天氣轉青高。',57,'全唐诗/poet.tang.53000.json','["露霑蔬草白，天氣轉青高。", "葉下和秋吹，驚看兩鬢毛（一作「毫」）。", "養羞因野鳥，爲客[訝]蓬蒿。", "火急收田種，晨昏莫辭勞。"]'),
('597ddf1c-f6e4-4925-9a4e-89357e00407c','詠廿四氣詩 秋分八月中','元稹','唐','唐诗','tang','','[]','琴彈南呂調，風色已高清。',45,'全唐诗/poet.tang.53000.json','["琴彈南呂調，風色已高清。", "雲[散]飄颻影，雷收振怒聲。", "乾坤能靜肅，寒暑喜（一作「合」）均平。"]'),
('9769c1be-a929-4357-a1ef-f03ba25451ad','詠廿四氣詩 寒露九月節','元稹','唐','唐诗','tang','','[]','寒露驚秋晚，朝看菊漸黃。',48,'全唐诗/poet.tang.53000.json','["寒露驚秋晚，朝看菊漸黃。", "千家風掃葉，萬里雁隨陽。", "化蛤悲羣鳥，收田畏早霜。", "因知松柏志，冬夏色蒼蒼。"]'),
('f68448b8-ee1f-45f6-baac-0ed517f98c21','詠廿四氣詩 霜降九月中','元稹','唐','唐诗','tang','','[]','風卷晴霜（一作「清雲」）盡，空天萬里霜。',56,'全唐诗/poet.tang.53000.json','["風卷晴霜（一作「清雲」）盡，空天萬里霜。", "野豺先祭月，仙菊遇重陽。", "秋色悲疏木，鴻鳴憶故鄉。", "誰知一罇酒，能使百秋亡。"]'),
('c00bc0b1-bb19-4325-9f5e-f7d92d4e1c3d','詠廿四氣詩 立冬十月節','元稹','唐','唐诗','tang','','[]','霜降向人寒，輕冰淥水漫。',55,'全唐诗/poet.tang.53000.json','["霜降向人寒，輕冰淥水漫。", "蟾將纖（一作「輕」）影出，雁帶幾行殘。", "田種收藏了，衣裘製造看。", "野鷄投水日，化蜃不將難。"]'),
('14230988-6c4f-4b82-bb77-7bb87b6a0009','詠廿四氣詩 小雪十月中','元稹','唐','唐诗','tang','','[]','莫怪虹無影，如今小雪時。',55,'全唐诗/poet.tang.53000.json','["莫怪虹無影，如今小雪時。", "陰陽依上下，寒暑喜分離。", "滿月光天漢，長風響樹枝。", "橫琴對淥醑，猶（一作「獨」）自歛愁眉。"]'),
('1ea669e8-e189-4999-883f-564db644a82c','詠廿四氣詩 大雪十一月節','元稹','唐','唐诗','tang','','[]','積陰成大雪，看處亂霏霏。',48,'全唐诗/poet.tang.53000.json','["積陰成大雪，看處亂霏霏。", "玉管鳴寒夜，披書曉絳帷。", "黃鐘隨氣改，鷃鳥不鳴時。", "何限蒼生類，依依惜暮暉。"]'),
('cf479f27-19c9-49e7-a77f-8fe6639f1986','詠廿四氣詩 冬至十一月中','元稹','唐','唐诗','tang','','[]','二氣俱生處，周家正立年。',43,'全唐诗/poet.tang.53000.json','["二氣俱生處，周家正立年。", "歲星瞻北極，舜（一作「景」）日照南天。", "拜慶朝金殿，歡娛列綺筵。"]'),
('dee40f3a-7197-460a-993a-d0fdd09466b6','詠廿四氣詩 小寒十二月節','元稹','唐','唐诗','tang','','[]','小寒連大呂，歡鵲壘新巢。',48,'全唐诗/poet.tang.53000.json','["小寒連大呂，歡鵲壘新巢。", "拾食尋河曲，銜紫遶樹梢。", "霜鷹近北首，雊雉隱藂茅。", "莫怪嚴凝切，春冬正月交。"]'),
('27c94d4c-3e76-4bf9-84ec-b9b8d1098497','詠廿四氣詩 大寒十二月中','元稹','唐','唐诗','tang','','[]','臘酒自盈罇，金爐獸炭溫。',253,'全唐诗/poet.tang.53000.json','["臘酒自盈罇，金爐獸炭溫。", "大寒宜近火，無事莫開門。", "冬與春交替，星周月詎存？", "明朝換新律，梅柳待陽春。", "（見伯二六二四、斯三八八○卷）（按：此組詩存兩個鈔本。", "伯二六二四卷較完整，卷首題「盧相公詠廿四氣詩」。", "斯三八八○卷卷首已缺雨水、春分、穀雨、小滿、夏至〖此首僅存末八字〗等五首，卷末題：「甲辰年夏月上旬寫記。", "元相公撰，李慶君書。", "」今以伯二六二四卷爲底本，以斯三八八○卷參校。", "至其作者，二書有異。", "元相公可確定爲元稹，盧相公不詳爲誰。", "究爲誰作，今已難甄辨。", "亦有可能元、盧二人皆爲依託之名。", "今姑從一說錄附元稹之末。", "）。"]'),
('481bdeb3-2162-40cc-b07d-dcc760122ad1','霍小玉歌 一','李惟','唐','唐诗','tang','','[]','衣飄荳蔻減濃香，臉射芙蓉失嬌色。',44,'全唐诗/poet.tang.53000.json','["衣飄荳蔻減濃香，臉射芙蓉失嬌色。", "（明刻本宋佚名《錦繡萬花谷前集》卷十七引《霍小玉歌》）。"]'),
('ae479974-a7a3-4eb5-b7e0-04d52a146b02','霍小玉歌 二','李惟','唐','唐诗','tang','','[]','粧成落日捲簾坐，小玉焚香羅帳深。',28,'全唐诗/poet.tang.53000.json','["粧成落日捲簾坐，小玉焚香羅帳深。", "（見同書同卷引李惟詩）。"]'),
('eed6313c-5664-4ab4-b04a-7de9d8a2fd3a','霍小玉歌 三','李惟','唐','唐诗','tang','','[]','西北檻前掛鸚鵡，籠中報道李郎來。',124,'全唐诗/poet.tang.53000.json','["西北檻前掛鸚鵡，籠中報道李郎來。", "（見宋陳元龍《片玉集注》卷一《荔枝香》注引《麗情集》引《小玉歌》）（按：此詩作者之推定，與本書卷二十二崔珏《灼灼歌》相類，可參看。", "《新唐書》卷七二《宰相世系表》載李義琛孫、李綰子名惟，約爲盛君時人，當非此詩作者。", "）。"]'),
('714cd9e4-fb33-468d-b7fa-4c3de2393aa7','招李夫人魂賦附楚詞 一','謝觀','唐','唐诗','tang','','[]','白玉潔兮紅蘭芳，忽玉折兮蘭已傷。',32,'全唐诗/poet.tang.53000.json','["白玉潔兮紅蘭芳，忽玉折兮蘭已傷。", "魂兮勿復遊他方，盍歸來兮慰我皇。"]'),
('b48ddd13-8007-4715-ac4a-5c6eb1930a49','招李夫人魂賦附楚詞 二','謝觀','唐','唐诗','tang','','[]','彩雲裾兮流霞袂，倏而來兮忽而逝。',47,'全唐诗/poet.tang.53000.json','["彩雲裾兮流霞袂，倏而來兮忽而逝。", "魂兮勿復遊四裔，[盍]歸來兮膺萬歲。", "（見《文苑英華》卷九六）。"]'),
('6a927dda-4bcb-49da-9cb9-72e1bdb92487','偈 一','普化和尚','唐','唐诗','tang','','[]','少室人不識，金陵又再來。',24,'全唐诗/poet.tang.53000.json','["少室人不識，金陵又再來。", "臨濟一隻眼，到處爲人開。"]'),
('2e9f981d-730c-4040-91a2-dd10bd84f3ea','偈 二','普化和尚','唐','唐诗','tang','','[]','河陽新婦子，木塔老婆禪。',35,'全唐诗/poet.tang.53000.json','["河陽新婦子，木塔老婆禪。", "臨濟小廝兒，却具一隻眼。", "（《五燈會元》卷四）。"]'),
('576443e4-9250-4e8a-84d9-d39c311822ab','十二月四日寄樂天（題擬）','崔玄亮','唐','唐诗','tang','','[]','共相呼喚醉歸來。',40,'全唐诗/poet.tang.53000.json','["共相呼喚醉歸來。", "（見《白氏長慶集》卷二一《答崔賓客晦叔十二月四日見寄》題注引）。"]');
